  return `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`;
}

function completeSidebarAvatarOptions(
  category: SidebarAvatarCategoryId,
  labelPrefix: string,
  baseOptions: SidebarAvatarOption[],
  fallbackFactory: (index: number) => string
) {
  const options = [...baseOptions];
  while (options.length < SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY) {
    const index = options.length;
    options.push({
      id: `${category}-fallback-${index + 1}`,
      label: `${labelPrefix} ${index + 1}`,
      category,
      url: fallbackFactory(index)
    });
  }
  return options.slice(0, SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY);
}

function buildSidebarAvatarPresetOptions(): Record<SidebarAvatarCategoryId, SidebarAvatarOption[]> {
  const pixelGenerated = Array.from({ length: SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY }, (_, index) => ({
    id: `pixel-generated-${index + 1}`,
    label: `像素风 ${index + 1}`,
    category: "pixel" as SidebarAvatarCategoryId,
    url: createPixelAvatarDataUrl(index)
  }));
  const illustrationFromPool = agentAvatarPool
    .slice(0, SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY)
    .map((url, index) => ({
      id: `illustration-pool-${index + 1}`,
      label: `插画 ${index + 1}`,
      category: "illustration" as SidebarAvatarCategoryId,
      url
    }));

  const pixel = completeSidebarAvatarOptions("pixel", "像素风", pixelGenerated, (index) => createPixelAvatarDataUrl(index));
  const illustration = completeSidebarAvatarOptions("illustration", "插画", illustrationFromPool, (index) =>
    createLabelAvatarDataUrl(`IL${index + 1}`, "#ff9a7d", "#ff5f8f")
  );

  const animal = completeSidebarAvatarOptions(
    "animal",
    "动物",
    Array.from({ length: SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY }, (_, index) => ({
      id: `animal-${index + 1}`,
      label: `动物 ${index + 1}`,
      category: "animal" as SidebarAvatarCategoryId,
      url: createAnimalAvatarDataUrl(index)
    })),
    (index) => createAnimalAvatarDataUrl(index)
  );

  const handDrawn = completeSidebarAvatarOptions(
    "cute",
    "手绘风",
    Array.from({ length: SIDEBAR_AVATAR_PRESET_COUNT_PER_CATEGORY }, (_, index) => ({
      id: `handdrawn-${index + 1}`,
      label: `手绘风 ${index + 1}`,
      category: "cute" as SidebarAvatarCategoryId,
      url: createHandDrawnAvatarDataUrl(index)
    })),
    (index) => createHandDrawnAvatarDataUrl(index)
  );

  return {
    pixel,
    illustration,
    animal,
    cute: handDrawn
  };
}

function normalizeChatUserGroupName(value: string) {
  return value.trim().replace(/\s+/g, " ").slice(0, 24);
}

function normalizeChatConversationGroupPolicy(raw: unknown): ChatConversationGroupPolicy {
  return raw === "open" ? "open" : CHAT_CONVERSATION_GROUP_DEFAULT_POLICY;
}

function normalizeChatConversationGroupAllowFrom(raw: unknown) {
  if (!Array.isArray(raw)) {
    return [...CHAT_CONVERSATION_GROUP_DEFAULT_ALLOW_FROM];
  }
  const tokens = raw
    .map((item) => (typeof item === "string" ? item.trim().toLowerCase() : ""))
    .filter(Boolean);
  const deduped = Array.from(new Set(tokens)).slice(0, 40);
  return deduped.length > 0 ? deduped : [...CHAT_CONVERSATION_GROUP_DEFAULT_ALLOW_FROM];
}

function normalizeChatConversationGroupActivationCommand(raw: unknown) {
  const fallback = CHAT_CONVERSATION_GROUP_DEFAULT_ACTIVATION_COMMAND;
  if (typeof raw !== "string") {
    return fallback;
  }
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return fallback;
  }
  if (trimmed.startsWith("/")) {
    return trimmed.slice(0, 32);
  }
  return `/${trimmed}`.slice(0, 32);
}

function normalizeChatConversationGroupHistoryLimit(raw: unknown) {
  const parsed = typeof raw === "number" && Number.isFinite(raw) ? Math.floor(raw) : CHAT_CONVERSATION_GROUP_DEFAULT_HISTORY_LIMIT;
  return Math.max(CHAT_CONVERSATION_GROUP_MIN_HISTORY_LIMIT, Math.min(CHAT_CONVERSATION_GROUP_MAX_HISTORY_LIMIT, parsed));
}

function normalizeChatUserGroup(raw: unknown): ChatUserGroup | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Partial<ChatUserGroup>;
  const id = typeof candidate.id === "string" ? candidate.id.trim() : "";
  const name = typeof candidate.name === "string" ? normalizeChatUserGroupName(candidate.name) : "";
  if (!id || !name) {
    return null;
  }
  const createdAt =
    typeof candidate.createdAt === "number" && Number.isFinite(candidate.createdAt)
      ? Math.max(0, Math.floor(candidate.createdAt))
      : Date.now();
  return {
    id,
    name,
    createdAt
  };
}

function normalizeChatConversationGroup(raw: unknown): ChatConversationGroup | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Partial<ChatConversationGroup>;
  const id = typeof candidate.id === "string" ? candidate.id.trim() : "";
  const name = typeof candidate.name === "string" ? normalizeChatUserGroupName(candidate.name) : "";
  if (!id || !name) {
    return null;
  }
  const members = Array.isArray(candidate.memberAgentIds)
    ? candidate.memberAgentIds
        .map((memberId) => (typeof memberId === "string" ? memberId.trim() : ""))
        .filter(Boolean)
    : [];
  const dedupedMembers = Array.from(new Set(members)).slice(0, 30);
  const ownerCandidate = typeof candidate.ownerAgentId === "string" ? candidate.ownerAgentId.trim() : "";
  const ownerAgentId = ownerCandidate && dedupedMembers.includes(ownerCandidate) ? ownerCandidate : dedupedMembers[0] ?? null;
  const groupPolicy = normalizeChatConversationGroupPolicy((candidate as { groupPolicy?: unknown }).groupPolicy);
  const allowFrom = normalizeChatConversationGroupAllowFrom((candidate as { allowFrom?: unknown }).allowFrom);
  const requireMention =
    typeof (candidate as { requireMention?: unknown }).requireMention === "boolean"
      ? Boolean((candidate as { requireMention?: unknown }).requireMention)
      : CHAT_CONVERSATION_GROUP_DEFAULT_REQUIRE_MENTION;
  const activationCommand = normalizeChatConversationGroupActivationCommand(
    (candidate as { activationCommand?: unknown }).activationCommand
  );
  const historyLimit = normalizeChatConversationGroupHistoryLimit((candidate as { historyLimit?: unknown }).historyLimit);
  const createdAt =
    typeof candidate.createdAt === "number" && Number.isFinite(candidate.createdAt)
      ? Math.max(0, Math.floor(candidate.createdAt))
      : Date.now();
  return {
    id,
    name,
    memberAgentIds: dedupedMembers,
    ownerAgentId,
    groupPolicy,
    allowFrom,
    requireMention,
    activationCommand,
    historyLimit,
    createdAt
  };
}

function normalizeChatUserCustomAgentKind(raw: unknown): ChatUserCustomAgentKind {
  return raw === "staff" ? "staff" : "friend";
}

function normalizeChatUserCustomAgentKnowledgeScope(raw: unknown): ChatUserCustomAgentKnowledgeScope | undefined {
  if (raw === "general" || raw === "specific" || raw === "document") {
    return raw;
  }
  return undefined;
}

function normalizeChatUserCustomAgent(raw: unknown): ChatUserCustomAgent | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Partial<ChatUserCustomAgent>;
  const agentId = typeof candidate.agentId === "string" ? candidate.agentId.trim() : "";
  const displayName = typeof candidate.displayName === "string" ? normalizeChatUserGroupName(candidate.displayName) : "";
  if (!agentId || !displayName || isProtectedStaffAgentId(agentId)) {
    return null;
  }
  const createdAt =
    typeof candidate.createdAt === "number" && Number.isFinite(candidate.createdAt)
      ? Math.max(0, Math.floor(candidate.createdAt))
      : Date.now();
  const kind = normalizeChatUserCustomAgentKind(candidate.kind);
  const normalizeOptionalField = (value: unknown) => (typeof value === "string" ? value.trim().slice(0, 200) : "");
  const roleLabel = normalizeOptionalField(candidate.roleLabel);
  const channel = normalizeOptionalField(candidate.channel);
  const workspace = normalizeOptionalField(candidate.workspace);
  const currentWork = normalizeOptionalField(candidate.currentWork);
  const scheduledLabel = normalizeOptionalField(candidate.scheduledLabel);
  const mission = typeof candidate.mission === "string" ? candidate.mission.trim().slice(0, 1200) : "";
  const tasks = Array.isArray(candidate.tasks)
    ? candidate.tasks
        .map((task) => (typeof task === "string" ? task.trim() : ""))
        .filter(Boolean)
        .slice(0, CREATE_EMPLOYEE_MAX_TASKS)
    : [];
  const knowledgeScope = normalizeChatUserCustomAgentKnowledgeScope(candidate.knowledgeScope);
  const specificDomain = typeof candidate.specificDomain === "string" ? candidate.specificDomain.trim().slice(0, 240) : "";

  return {
    agentId,
    displayName,
    createdAt,
    kind,
    roleLabel: roleLabel || undefined,
    channel: channel || undefined,
    workspace: workspace || undefined,
    currentWork: currentWork || undefined,
    scheduledLabel: scheduledLabel || undefined,
    mission: mission || undefined,
    tasks: tasks.length > 0 ? tasks : undefined,
    knowledgeScope,
    specificDomain: specificDomain || undefined
  };
}

function loadChatUserCustomAgents() {
  const raw = safeStorageGet(CHAT_USER_CUSTOM_AGENTS_STORAGE_KEY);
  if (!raw) {
    return [] as ChatUserCustomAgent[];
  }
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [] as ChatUserCustomAgent[];
    }
    const deduped = new Map<string, ChatUserCustomAgent>();
    for (const item of parsed) {
      const normalized = normalizeChatUserCustomAgent(item);
      if (!normalized) {
        continue;
      }
      const dedupeKey = normalized.agentId.toLowerCase();
      if (deduped.has(dedupeKey)) {
        continue;
      }
      deduped.set(dedupeKey, normalized);
      if (deduped.size >= 200) {
        break;
      }
    }
    return Array.from(deduped.values()).sort((left, right) => left.createdAt - right.createdAt);
  } catch {
    return [] as ChatUserCustomAgent[];
  }
}

function loadChatConversationGroups() {
  const raw = safeStorageGet(CHAT_CONVERSATION_GROUPS_STORAGE_KEY);
  if (!raw) {
    return [] as ChatConversationGroup[];
  }
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [] as ChatConversationGroup[];
    }
    const deduped = new Map<string, ChatConversationGroup>();
    for (const item of parsed) {
      const normalized = normalizeChatConversationGroup(item);
      if (!normalized) {
        continue;
      }
      const dedupeKey = normalized.id.toLowerCase();
      if (deduped.has(dedupeKey)) {
        continue;
      }
      deduped.set(dedupeKey, normalized);
      if (deduped.size >= 100) {
        break;
      }
    }
    return Array.from(deduped.values()).sort((left, right) => left.createdAt - right.createdAt);
  } catch {
    return [] as ChatConversationGroup[];
  }
}

function createDefaultPinnedChatUserGroup(): ChatUserGroup {
  return {
    id: CHAT_USER_PINNED_GROUP_ID,
    name: "置顶",
    createdAt: 0
  };
}

function loadChatUserGroups() {
  const raw = safeStorageGet(CHAT_USER_GROUPS_STORAGE_KEY);
  if (!raw) {
    return [createDefaultPinnedChatUserGroup()];
  }
  try {
    const parsed = JSON.parse(raw);
    const list = Array.isArray(parsed)
      ? parsed.map((item) => normalizeChatUserGroup(item)).filter((item): item is ChatUserGroup => item !== null)
      : [];
    const deduped = new Map<string, ChatUserGroup>();
    for (const group of list) {
      if (!deduped.has(group.id)) {
        deduped.set(group.id, group);
      }
    }
    const pinned = deduped.get(CHAT_USER_PINNED_GROUP_ID) ?? createDefaultPinnedChatUserGroup();
    const others = Array.from(deduped.values())
      .filter((group) => group.id !== CHAT_USER_PINNED_GROUP_ID)
      .sort((left, right) => left.createdAt - right.createdAt)
      .slice(0, 20);
    return [pinned, ...others];
  } catch {
    return [createDefaultPinnedChatUserGroup()];
  }
}

function loadChatUserGroupMembership() {
  const raw = safeStorageGet(CHAT_USER_GROUP_MEMBERSHIP_STORAGE_KEY);
  if (!raw) {
    return {} as Record<string, string>;
  }
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {} as Record<string, string>;
    }
    const entries = Object.entries(parsed as Record<string, unknown>)
      .map(([agentId, groupId]) => {
        if (typeof groupId !== "string") {
          return null;
        }
        const normalizedAgentId = agentId.trim();
        const normalizedGroupId = groupId.trim();
        if (!normalizedAgentId || !normalizedGroupId) {
          return null;
        }
        return [normalizedAgentId, normalizedGroupId] as const;
      })
      .filter((entry): entry is readonly [string, string] => entry !== null);
    return Object.fromEntries(entries) as Record<string, string>;
  } catch {
    return {} as Record<string, string>;
  }
}

function loadChatUserAgentOrder() {
  const raw = safeStorageGet(CHAT_USER_AGENT_ORDER_STORAGE_KEY);
  if (!raw) {
    return [] as string[];
  }
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [] as string[];
    }
    const seen = new Set<string>();
    const order: string[] = [];
    for (const item of parsed) {
      if (typeof item !== "string") {
        continue;
      }
      const normalizedAgentId = item.trim();
      if (!normalizedAgentId || seen.has(normalizedAgentId)) {
        continue;
      }
      seen.add(normalizedAgentId);
      order.push(normalizedAgentId);
      if (order.length >= 300) {
        break;
      }
    }
    return order;
  } catch {
    return [] as string[];
  }
}

function loadChatUserCollapsedSections() {
  const raw = safeStorageGet(CHAT_USER_COLLAPSED_SECTIONS_STORAGE_KEY);
  if (!raw) {
    return {} as Record<string, boolean>;
  }
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {} as Record<string, boolean>;
    }
    const entries = Object.entries(parsed as Record<string, unknown>)
      .map(([sectionId, isCollapsed]) => {
        const normalizedSectionId = sectionId.trim();
        if (!normalizedSectionId || isCollapsed !== true) {
          return null;
        }
        return [normalizedSectionId, true] as const;
      })
      .filter((entry): entry is readonly [string, true] => entry !== null);
    return Object.fromEntries(entries) as Record<string, boolean>;
  } catch {
    return {} as Record<string, boolean>;
  }
}

function persistChatUserGroupMembership() {
  safeStorageSet(CHAT_USER_GROUP_MEMBERSHIP_STORAGE_KEY, JSON.stringify(chatUserGroupMembership.value));
}

function persistChatUserAgentOrder() {
  safeStorageSet(CHAT_USER_AGENT_ORDER_STORAGE_KEY, JSON.stringify(chatUserAgentOrder.value));
}

function persistChatUserCollapsedSections() {
  safeStorageSet(CHAT_USER_COLLAPSED_SECTIONS_STORAGE_KEY, JSON.stringify(chatUserCollapsedSections.value));
}

function persistChatUserCustomAgents() {
  safeStorageSet(CHAT_USER_CUSTOM_AGENTS_STORAGE_KEY, JSON.stringify(chatUserCustomAgents.value));
}

function persistChatConversationGroups() {
  safeStorageSet(CHAT_CONVERSATION_GROUPS_STORAGE_KEY, JSON.stringify(chatConversationGroups.value));
}

function createChatConversationGroupId() {
  return `group-chat-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function getChatConversationGroupAgentId(groupId: string) {
  return `${CHAT_CONVERSATION_GROUP_AGENT_PREFIX}${groupId.trim()}`;
}

function getChatConversationGroupIdFromAgentId(agentId: string) {
  const normalized = agentId.trim();
  if (!normalized.startsWith(CHAT_CONVERSATION_GROUP_AGENT_PREFIX)) {
    return null;
  }
  const groupId = normalized.slice(CHAT_CONVERSATION_GROUP_AGENT_PREFIX.length).trim();
  return groupId || null;
}

function isChatConversationGroupAgentId(agentId: string) {
  return Boolean(getChatConversationGroupIdFromAgentId(agentId));
}

function findChatConversationGroupByName(name: string) {
  const normalized = normalizeChatUserGroupName(name).toLowerCase();
  if (!normalized) {
    return null;
  }
  return chatConversationGroups.value.find((group) => group.name.toLowerCase() === normalized) ?? null;
}

function createChatConversationGroup(name: string, memberAgentIds: string[], ownerAgentId: string) {
  const normalizedName = normalizeChatUserGroupName(name);
  if (!normalizedName) {
    return null;
  }
  if (findChatConversationGroupByName(normalizedName)) {
    return null;
  }
  const dedupedMembers = Array.from(new Set(memberAgentIds.map((item) => item.trim()).filter(Boolean))).slice(0, 30);
  const normalizedOwnerAgentId = ownerAgentId.trim();
  if (!normalizedOwnerAgentId || !dedupedMembers.includes(normalizedOwnerAgentId)) {
    return null;
  }
  const nextGroup: ChatConversationGroup = {
    id: createChatConversationGroupId(),
    name: normalizedName,
    memberAgentIds: dedupedMembers,
    ownerAgentId: normalizedOwnerAgentId,
    groupPolicy: CHAT_CONVERSATION_GROUP_DEFAULT_POLICY,
    allowFrom: [...CHAT_CONVERSATION_GROUP_DEFAULT_ALLOW_FROM],
    requireMention: CHAT_CONVERSATION_GROUP_DEFAULT_REQUIRE_MENTION,
    activationCommand: CHAT_CONVERSATION_GROUP_DEFAULT_ACTIVATION_COMMAND,
    historyLimit: CHAT_CONVERSATION_GROUP_DEFAULT_HISTORY_LIMIT,
    createdAt: Date.now()
  };
  chatConversationGroups.value = [...chatConversationGroups.value, nextGroup]
    .sort((left, right) => left.createdAt - right.createdAt)
    .slice(-100);
  persistChatConversationGroups();
  return nextGroup;
}

function syncChatConversationGroupsWithMembers(memberPool: AgentListItem[]) {
  const validMemberIds = new Set(
    memberPool
      .filter((item) => !isChatConversationGroupAgentId(item.agentId))
      .map((item) => item.agentId.trim())
      .filter(Boolean)
  );
  let changed = false;
  const nextGroups = chatConversationGroups.value.map((group) => {
    const nextMembers = group.memberAgentIds.filter((memberId) => validMemberIds.has(memberId));
    const nextOwnerAgentId =
      group.ownerAgentId && nextMembers.includes(group.ownerAgentId) ? group.ownerAgentId : nextMembers[0] ?? null;
    if (nextMembers.length === group.memberAgentIds.length && nextOwnerAgentId === group.ownerAgentId) {
      return group;
    }
    changed = true;
    return {
      ...group,
      memberAgentIds: nextMembers,
      ownerAgentId: nextOwnerAgentId
    } satisfies ChatConversationGroup;
  });
  if (!changed) {
    return;
  }
  chatConversationGroups.value = nextGroups;
  persistChatConversationGroups();
}

function findChatConversationGroupByAgentId(agentId: string | null) {
  const normalized = (agentId ?? "").trim();
  if (!normalized) {
    return null;
  }
  const groupId = getChatConversationGroupIdFromAgentId(normalized);
  if (!groupId) {
    return null;
  }
  return chatConversationGroups.value.find((group) => group.id === groupId) ?? null;
}

function getConversationGroupMembersByAgentId(agentId: string) {
  const group = findChatConversationGroupByAgentId(agentId);
  if (!group) {
    return [] as AgentListItem[];
  }
  return getChatConversationGroupMembers(group);
}

function getConversationGroupPreviewMembers(agentId: string, limit = 3) {
  return getConversationGroupMembersByAgentId(agentId).slice(0, Math.max(1, limit));
}

function getConversationGroupMemberCount(agentId: string) {
  return getConversationGroupMembersByAgentId(agentId).length;
}

function remapChatConversationGroupAgents() {
  const baseAgents = agents.value.filter((agent) => !isChatConversationGroupAgentId(agent.agentId));
  const mappedConversationGroups = chatConversationGroups.value.map((group) => mapChatConversationGroupAgent(group, baseAgents));
  agents.value = [...baseAgents, ...mappedConversationGroups];
  syncChatUserAgentOrder();
}

function pruneChatUserGroupMembership() {
  const validGroupIds = new Set(chatUserGroups.value.map((group) => group.id));
  const nextEntries = Object.entries(chatUserGroupMembership.value).filter((entry) => validGroupIds.has(entry[1]));
  if (nextEntries.length === Object.keys(chatUserGroupMembership.value).length) {
    return;
  }
  chatUserGroupMembership.value = Object.fromEntries(nextEntries) as Record<string, string>;
  persistChatUserGroupMembership();
}

function syncChatUserAgentOrder() {
  if (agents.value.length === 0) {
    return;
  }
  const knownAgentIds = agents.value
    .map((agent) => agent.agentId.trim())
    .filter((agentId) => agentId.length > 0);
  const knownIdSet = new Set(knownAgentIds);
  const seen = new Set<string>();
  const nextOrder: string[] = [];

  for (const agentId of chatUserAgentOrder.value) {
    const normalizedAgentId = agentId.trim();
    if (!normalizedAgentId || seen.has(normalizedAgentId) || !knownIdSet.has(normalizedAgentId)) {
      continue;
    }
    seen.add(normalizedAgentId);
    nextOrder.push(normalizedAgentId);
  }

  for (const agentId of knownAgentIds) {
    if (seen.has(agentId)) {
      continue;
    }
    seen.add(agentId);
    nextOrder.push(agentId);
  }

  if (
    nextOrder.length === chatUserAgentOrder.value.length &&
    nextOrder.every((agentId, index) => chatUserAgentOrder.value[index] === agentId)
  ) {
    return;
  }

  chatUserAgentOrder.value = nextOrder;
  persistChatUserAgentOrder();
}

function persistChatUserGroups() {
  safeStorageSet(CHAT_USER_GROUPS_STORAGE_KEY, JSON.stringify(chatUserGroups.value));
  pruneChatUserGroupMembership();
}

function createChatUserGroupId() {
  return `group-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function findChatUserGroupByName(name: string) {
  const normalized = normalizeChatUserGroupName(name).toLowerCase();
  if (!normalized) {
    return null;
  }
  return chatUserGroups.value.find((group) => group.name.toLowerCase() === normalized) ?? null;
}

function createChatUserGroup(name: string) {
  const normalizedName = normalizeChatUserGroupName(name);
  if (!normalizedName) {
    return null;
  }
  const existing = findChatUserGroupByName(normalizedName);
  if (existing) {
    return existing;
  }
  const nextGroup: ChatUserGroup = {
    id: createChatUserGroupId(),
    name: normalizedName,
    createdAt: Date.now()
  };
  const pinned = chatUserGroups.value.find((group) => group.id === CHAT_USER_PINNED_GROUP_ID) ?? null;
  const others = chatUserGroups.value.filter((group) => group.id !== CHAT_USER_PINNED_GROUP_ID);
  chatUserGroups.value = pinned ? [pinned, ...others, nextGroup] : [...chatUserGroups.value, nextGroup];
  persistChatUserGroups();
  return nextGroup;
}

function deleteChatUserGroup(groupId: string) {
  const normalizedGroupId = groupId.trim();
  if (!normalizedGroupId || normalizedGroupId === CHAT_USER_PINNED_GROUP_ID) {
    return false;
  }
  const hasTargetGroup = chatUserGroups.value.some((group) => group.id === normalizedGroupId);
  if (!hasTargetGroup) {
    return false;
  }

  chatUserGroups.value = chatUserGroups.value.filter((group) => group.id !== normalizedGroupId);
  persistChatUserGroups();

  if (chatUserCollapsedSections.value[normalizedGroupId]) {
    const nextCollapsedSections = { ...chatUserCollapsedSections.value };
    delete nextCollapsedSections[normalizedGroupId];
    chatUserCollapsedSections.value = nextCollapsedSections;
    persistChatUserCollapsedSections();
  }
  return true;
}

function getChatUserGroupName(agentId: string) {
  const groupId = chatUserGroupMembership.value[agentId];
  if (!groupId) {
    return "未分组";
  }
  const matched = chatUserGroups.value.find((group) => group.id === groupId) ?? null;
  return matched?.name ?? "未分组";
}

function setAgentChatUserGroup(agentId: string, groupId: string) {
  const normalizedAgentId = agentId.trim();
  const normalizedGroupId = groupId.trim();
  if (!normalizedAgentId || !normalizedGroupId) {
    return;
  }
  if (chatUserGroupMembership.value[normalizedAgentId] === normalizedGroupId) {
    return;
  }
  chatUserGroupMembership.value = {
    ...chatUserGroupMembership.value,
    [normalizedAgentId]: normalizedGroupId
  };
  persistChatUserGroupMembership();
}

function clearAgentChatUserGroup(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId || !(normalizedAgentId in chatUserGroupMembership.value)) {
    return;
  }
  const nextMembership = { ...chatUserGroupMembership.value };
  delete nextMembership[normalizedAgentId];
  chatUserGroupMembership.value = nextMembership;
  persistChatUserGroupMembership();
}

function getChatUserAgentOrderIndexMap() {
  const indexMap = new Map<string, number>();
  for (let index = 0; index < chatUserAgentOrder.value.length; index += 1) {
    const agentId = chatUserAgentOrder.value[index];
    if (!agentId || indexMap.has(agentId)) {
      continue;
    }
    indexMap.set(agentId, index);
  }
  return indexMap;
}

function sortAgentsByChatUserOrder(items: AgentListItem[]) {
  if (items.length <= 1) {
    return items;
  }
  const orderIndexMap = getChatUserAgentOrderIndexMap();
  return [...items].sort((left, right) => {
    const leftOrder = orderIndexMap.get(left.agentId);
    const rightOrder = orderIndexMap.get(right.agentId);
    if (typeof leftOrder === "number" && typeof rightOrder === "number") {
      return leftOrder - rightOrder;
    }
    if (typeof leftOrder === "number") {
      return -1;
    }
    if (typeof rightOrder === "number") {
      return 1;
    }
    return 0;
  });
}

function moveChatUserAgentOrderBeforeTarget(sourceAgentId: string, targetAgentId: string) {
  const normalizedSourceId = sourceAgentId.trim();
  const normalizedTargetId = targetAgentId.trim();
  if (!normalizedSourceId || !normalizedTargetId || normalizedSourceId === normalizedTargetId) {
    return;
  }

  syncChatUserAgentOrder();
  const nextOrder = [...chatUserAgentOrder.value];
  const sourceIndex = nextOrder.indexOf(normalizedSourceId);
  const targetIndex = nextOrder.indexOf(normalizedTargetId);
  if (sourceIndex < 0 || targetIndex < 0 || sourceIndex === targetIndex) {
    return;
  }

  const [draggedAgentId] = nextOrder.splice(sourceIndex, 1);
  const insertionIndex = nextOrder.indexOf(normalizedTargetId);
  if (!draggedAgentId || insertionIndex < 0) {
    return;
  }
  nextOrder.splice(insertionIndex, 0, draggedAgentId);
  chatUserAgentOrder.value = nextOrder;
  persistChatUserAgentOrder();
}

function isChatUserSectionCollapsed(sectionId: string) {
  const normalizedSectionId = sectionId.trim();
  if (!normalizedSectionId) {
    return false;
  }
  return chatUserCollapsedSections.value[normalizedSectionId] === true;
}

function toggleChatUserSectionCollapsed(sectionId: string) {
  const normalizedSectionId = sectionId.trim();
  if (!normalizedSectionId) {
    return;
  }
  const currentlyCollapsed = chatUserCollapsedSections.value[normalizedSectionId] === true;
  const nextCollapsedSections = { ...chatUserCollapsedSections.value };
  if (currentlyCollapsed) {
    delete nextCollapsedSections[normalizedSectionId];
  } else {
    nextCollapsedSections[normalizedSectionId] = true;
  }
  chatUserCollapsedSections.value = nextCollapsedSections;
  persistChatUserCollapsedSections();
}

function normalizeSidebarSettingsAppearance(raw: string | null): SidebarSettingsAppearance {
  if (raw === "light" || raw === "dark" || raw === "system") {
    return raw;
  }
  return "system";
}

function normalizeSidebarThemePreset(raw: string | null): SidebarThemePreset {
  if (raw === "elegant" || raw === "frosted" || raw === "pure-white") {
    return raw;
  }
  return "elegant";
}

function resolveSystemThemeMode(): SidebarThemeMode {
  if (typeof window === "undefined" || typeof window.matchMedia !== "function") {
    return "day";
  }
  return window.matchMedia("(prefers-color-scheme: dark)").matches ? "night" : "day";
}

function normalizeSidebarThemeMode(raw: string | null): SidebarThemeMode {
  if (raw === "day" || raw === "night") {
    return raw;
  }
  return resolveSystemThemeMode();
}

function normalizeSidebarSettingsLanguage(raw: string | null): SidebarSettingsLanguage {
  if (raw === "zh-CN" || raw === "en-US") {
    return raw;
  }
  return "zh-CN";
}

function normalizeRoleWorkflowSavedVersion(raw: unknown): RoleWorkflowSavedVersion | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Record<string, unknown>;
  const id = typeof candidate.id === "string" ? candidate.id.trim() : "";
  const contentZh = typeof candidate.contentZh === "string" ? candidate.contentZh : "";
  const savedAt =
    typeof candidate.savedAt === "number" && Number.isFinite(candidate.savedAt)
      ? Math.floor(candidate.savedAt)
      : 0;
  if (!id || !savedAt) {
    return null;
  }
  return {
    id,
    contentZh,
    savedAt
  };
}

function normalizeRoleWorkflowOverride(raw: unknown): RoleWorkflowOverride | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Record<string, unknown>;
  const nameZh = typeof candidate.nameZh === "string" ? candidate.nameZh : undefined;
  const workflowZh = typeof candidate.workflowZh === "string" ? candidate.workflowZh : undefined;
  const detailContentZh = typeof candidate.detailContentZh === "string" ? candidate.detailContentZh : undefined;
  const detailVersions = Array.isArray(candidate.detailVersions)
    ? candidate.detailVersions
        .map(normalizeRoleWorkflowSavedVersion)
        .filter((version): version is RoleWorkflowSavedVersion => Boolean(version))
        .sort((left, right) => right.savedAt - left.savedAt)
        .slice(0, 3)
    : [];

  if (!nameZh && !workflowZh && !detailContentZh && detailVersions.length === 0) {
    return null;
  }

  const normalized: RoleWorkflowOverride = {};
  if (nameZh) {
    normalized.nameZh = nameZh;
  }
  if (workflowZh) {
    normalized.workflowZh = workflowZh;
  }
  if (typeof detailContentZh === "string") {
    normalized.detailContentZh = detailContentZh;
  }
  if (detailVersions.length > 0) {
    normalized.detailVersions = detailVersions;
  }
  return normalized;
}

function loadRoleWorkflowOverrides() {
  const raw = safeStorageGet(ROLE_WORKFLOW_OVERRIDES_STORAGE_KEY);
  if (!raw) {
    return {} as Record<string, RoleWorkflowOverride>;
  }
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {} as Record<string, RoleWorkflowOverride>;
    }
    const normalizedEntries = Object.entries(parsed as Record<string, unknown>)
      .map(([roleId, override]) => [roleId, normalizeRoleWorkflowOverride(override)] as const)
      .filter((entry): entry is readonly [string, RoleWorkflowOverride] => Boolean(entry[1]));
    return Object.fromEntries(normalizedEntries) as Record<string, RoleWorkflowOverride>;
  } catch {
    return {} as Record<string, RoleWorkflowOverride>;
  }
}

function persistRoleWorkflowOverrides() {
  safeStorageSet(ROLE_WORKFLOW_OVERRIDES_STORAGE_KEY, JSON.stringify(roleWorkflowOverrides.value));
}

function normalizeTaskProjectName(value: string) {
  return value.trim();
}

function buildTaskProjectList(items: string[]) {
  const unique = new Set<string>();
  const result = [DEFAULT_TASK_PROJECT_NAME];
  for (const item of items) {
    const normalized = normalizeTaskProjectName(item);
    if (!normalized || normalized === DEFAULT_TASK_PROJECT_NAME || unique.has(normalized)) {
      continue;
    }
    unique.add(normalized);
    result.push(normalized);
  }
  return result;
}

function loadTaskProjectsFromStorage() {
  const parsed = (() => {
    try {
      return JSON.parse(safeStorageGet(taskProjectStorageKey) ?? "[]");
    } catch {
      return [];
    }
  })();
  if (!Array.isArray(parsed)) {
    return [DEFAULT_TASK_PROJECT_NAME];
  }
  return buildTaskProjectList(parsed.filter((item): item is string => typeof item === "string"));
}

function saveTaskProjectsToStorage(projects: string[]) {
  const payload = buildTaskProjectList(projects).filter((project) => project !== DEFAULT_TASK_PROJECT_NAME);
  safeStorageSet(taskProjectStorageKey, JSON.stringify(payload));
}

function isTaskInProject(task: TaskRecord, projectName: string) {
  const normalizedProject = normalizeTaskProjectName(task.project);
  if (projectName === DEFAULT_TASK_PROJECT_NAME) {
    return !normalizedProject || normalizedProject === DEFAULT_TASK_PROJECT_NAME;
  }
  return normalizedProject === projectName;
}

function getTaskStatusWeight(status: TaskBoardStatus) {
  const weightMap: Record<TaskBoardStatus, number> = {
    todo: 0,
    in_progress: 1,
    in_review: 2,
    done: 3,
    cancelled: 4
  };
  return weightMap[status];
}

function getTaskPriorityWeight(priority: TaskRecord["priority"]) {
  if (priority === "p0") return 0;
  if (priority === "p1") return 1;
  return 2;
}

function sortTaskRecords(items: TaskRecord[]) {
  return [...items].sort((left, right) => {
    const statusWeight = getTaskStatusWeight(left.status) - getTaskStatusWeight(right.status);
    if (statusWeight !== 0) {
      return statusWeight;
    }
    const priorityWeight = getTaskPriorityWeight(left.priority) - getTaskPriorityWeight(right.priority);
    if (priorityWeight !== 0) {
      return priorityWeight;
    }
    if (left.dueAt !== right.dueAt) {
      return left.dueAt - right.dueAt;
    }
    return right.updatedAt - left.updatedAt;
  });
}

function sortTaskRecordsForColumn(items: TaskRecord[]) {
  return [...items].sort((left, right) => {
    const priorityWeight = getTaskPriorityWeight(left.priority) - getTaskPriorityWeight(right.priority);
    if (priorityWeight !== 0) {
      return priorityWeight;
    }
    if (left.dueAt !== right.dueAt) {
      return left.dueAt - right.dueAt;
    }
    return right.updatedAt - left.updatedAt;
  });
}

function syncTaskProjectNamesFromTasks() {
  const storageProjects = loadTaskProjectsFromStorage();
  const taskProjects = taskItems.value
    .map((task) => normalizeTaskProjectName(task.project))
    .filter((item) => item && item !== DEFAULT_TASK_PROJECT_NAME);
  const nextProjects = buildTaskProjectList([...storageProjects, ...taskProjects]);
  taskProjectNames.value = nextProjects;
  saveTaskProjectsToStorage(nextProjects);
  if (!taskProjectNames.value.includes(activeTaskProject.value)) {
    activeTaskProject.value = DEFAULT_TASK_PROJECT_NAME;
  }
}

function resetTaskDraftForm() {
  taskDraftTitle.value = "";
  taskDraftSummary.value = "";
  taskDraftOwner.value = "Commander";
  taskDraftPriority.value = "p1";
}

function updateTaskRecord(nextTask: Omit<TaskRecord, "updatedAt">) {
  taskItems.value = upsertTask(taskItems.value, nextTask);
  syncTaskProjectNamesFromTasks();
}

function getTauriNamespace(): TauriNamespace | null {
  if (typeof window === "undefined") {
    return null;
  }
  return (window as Window & { __TAURI__?: TauriNamespace }).__TAURI__ ?? null;
}

function getTauriInvoke(): TauriInvoke | null {
  if (typeof window === "undefined") {
    return null;
  }
  const runtime = window as Window & {
    __TAURI__?: TauriNamespace;
    __TAURI_INTERNALS__?: {
      invoke?: TauriInvoke;
    };
  };
  return runtime.__TAURI__?.core?.invoke ?? runtime.__TAURI_INTERNALS__?.invoke ?? null;
}

function getTauriConvertFileSrc(): ((filePath: string, protocol?: string) => string) | null {
  if (typeof window === "undefined") {
    return null;
  }
  const runtime = window as Window & {
    __TAURI__?: TauriNamespace;
    __TAURI_INTERNALS__?: {
      convertFileSrc?: (filePath: string, protocol?: string) => string;
    };
  };
  return runtime.__TAURI__?.core?.convertFileSrc ?? runtime.__TAURI_INTERNALS__?.convertFileSrc ?? null;
}

function getTauriWindow(): TauriWindowApi | null {
  return getTauriNamespace()?.window?.getCurrentWindow?.() ?? null;
}

function cloneStartupOpenClawSteps() {
  return STARTUP_OPENCLAW_STEPS_BASE.map((step) => ({
    ...step,
    status: "pending" as StartupInstallStepStatus
  }));
}

function resetStartupOpenClawSteps() {
  startupOpenClawSteps.value = cloneStartupOpenClawSteps();
}

function setStartupOpenClawStepStatus(stepIndex: number, status: StartupInstallStepStatus) {
  startupOpenClawSteps.value = startupOpenClawSteps.value.map((step, index) =>
    index === stepIndex
      ? {
          ...step,
          status
        }
      : step
  );
}

function setStartupOpenClawStepInstalling(stepIndex: number) {
  startupOpenClawSteps.value = startupOpenClawSteps.value.map((step, index) => {
    if (index < stepIndex && step.status !== "done") {
      return {
        ...step,
        status: "done" as StartupInstallStepStatus
      };
    }
    if (index === stepIndex) {
      return {
        ...step,
        status: "installing" as StartupInstallStepStatus
      };
    }
    if (index > stepIndex && step.status !== "pending") {
      return {
        ...step,
        status: "pending" as StartupInstallStepStatus
      };
    }
    return step;
  });
}

function markStartupOpenClawStepDone(stepIndex: number) {
  setStartupOpenClawStepStatus(stepIndex, "done");
}

function markStartupOpenClawStepFailed(stepIndex: number) {
  setStartupOpenClawStepStatus(stepIndex, "failed");
}

function markStartupOpenClawAllDone() {
  startupOpenClawSteps.value = startupOpenClawSteps.value.map((step) => ({
    ...step,
    status: "done" as StartupInstallStepStatus
  }));
}

function getStartupOpenClawStepBadge(step: StartupInstallStep) {
  if (step.status === "failed") {
    return "失败";
  }
  if (step.status === "installing") {
    return step.etaLabel || "进行中";
  }
  if (step.status === "pending") {
    return step.etaLabel;
  }
  return "";
}

function sleepMs(durationMs: number) {
  return new Promise<void>((resolve) => {
    window.setTimeout(resolve, durationMs);
  });
}

async function waitForStartupGatewayOnline(invoke: TauriInvoke, maxAttempts = 18, waitMs = 800) {
  let lastSnapshot: GatewayHealthSnapshotResponse | null = null;
  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    try {
      const result = (await invoke("check_openclaw_gateway")) as GatewayHealthSnapshotResponse;
      lastSnapshot = result;
      if ((result.status ?? "").trim().toLowerCase() === "online") {
        return result;
      }
    } catch {
      // Ignore transient check failures while gateway is starting.
    }
    if (attempt < maxAttempts - 1) {
      await sleepMs(waitMs);
    }
  }
  return lastSnapshot;
}

function appendStartupRuntimeStatusLogs(
  append: (...entries: Array<string | undefined>) => void,
  tag: string,
  runtimeStatus: OpenClawRuntimeStatusResponse | null | undefined
) {
  if (!runtimeStatus) {
    return;
  }
  append(
    `[${tag}]`,
    runtimeStatus.command,
    runtimeStatus.detail,
    runtimeStatus.stdout,
    runtimeStatus.stderr
  );
}

async function checkStartupOpenClawRuntimeStatus(invoke: TauriInvoke) {
  return (await invoke("check_openclaw_runtime_status")) as OpenClawRuntimeStatusResponse;
}

async function applyLockedStartupProviderConfig(invoke: TauriInvoke) {
  await invoke("save_openclaw_provider_config", {
    config: {
      providerId: LOCKED_STARTUP_OPENCLAW_PROVIDER.providerId,
      protocol: LOCKED_STARTUP_OPENCLAW_PROVIDER.protocol,
      apiKind: LOCKED_STARTUP_OPENCLAW_PROVIDER.apiKind,
      baseUrl: LOCKED_STARTUP_OPENCLAW_PROVIDER.baseUrl,
      model: LOCKED_STARTUP_OPENCLAW_PROVIDER.model,
      apiKey: LOCKED_STARTUP_OPENCLAW_PROVIDER.apiKey
    }
  });
}

async function runStartupOpenClawRepair(
  invoke: TauriInvoke,
  initialStatus: OpenClawRuntimeStatusResponse | null = null,
  options: StartupOpenClawRunOptions = {}
) {
  const runInBackground = options.background === true;
  startupOpenClawOverlayVisible.value = !runInBackground;
  startupOpenClawInstalling.value = true;
  startupOpenClawInstallError.value = "";
  startupOpenClawRuntimeLogs.value = "";
  startupOpenClawShowManualActions.value = false;
  resetStartupOpenClawSteps();

  const appendStartupOpenClawRuntimeLogs = (...entries: Array<string | undefined>) => {
    startupOpenClawRuntimeLogs.value = [startupOpenClawRuntimeLogs.value, ...entries]
      .filter((item) => Boolean(item && item.trim()))
      .join("\n\n");
  };

  appendStartupRuntimeStatusLogs(appendStartupOpenClawRuntimeLogs, "status-check-before-repair", initialStatus);

  try {
    startupOpenClawStatusText.value = "正在检测环境...";
    setStartupOpenClawStepInstalling(0);
    markStartupOpenClawStepDone(0);

    startupOpenClawStatusText.value = "正在准备 Node.js...";
    setStartupOpenClawStepInstalling(1);
    await sleepMs(180);
    markStartupOpenClawStepDone(1);

    startupOpenClawStatusText.value = "检测到状态异常，正在自动修复...";
    setStartupOpenClawStepInstalling(2);
    const autoFixResult = (await invoke("run_lobster_action", { action: "auto_fix" })) as LobsterActionResult;
    appendStartupOpenClawRuntimeLogs(
      "[auto-fix]",
      autoFixResult.command,
      autoFixResult.stdout,
      autoFixResult.stderr
    );
    if (!autoFixResult.success) {
      throw new Error(autoFixResult.detail || "OpenClaw 自动修复失败。");
    }
    markStartupOpenClawStepDone(2);

    startupOpenClawStatusText.value = "正在配置 AI 大模型...";
    setStartupOpenClawStepInstalling(3);
    try {
      await applyLockedStartupProviderConfig(invoke);
    } catch {
      // Keep repair flow running even if provider defaults cannot be updated.
    }
    markStartupOpenClawStepDone(3);

    startupOpenClawStatusText.value = "正在重启并校验服务...";
    setStartupOpenClawStepInstalling(4);
    const restartResult = (await invoke("run_lobster_action", { action: "restart_gateway" })) as LobsterActionResult;
    appendStartupOpenClawRuntimeLogs(
      "[restart-gateway]",
      restartResult.command,
      restartResult.stdout,
      restartResult.stderr
    );
    if (!restartResult.success) {
      const startResult = (await invoke("run_lobster_action", { action: "start_gateway" })) as LobsterActionResult;
      appendStartupOpenClawRuntimeLogs(
        "[start-gateway]",
        startResult.command,
        startResult.stdout,
        startResult.stderr
      );
      if (!startResult.success) {
        throw new Error(startResult.detail || restartResult.detail || "OpenClaw 网关修复失败。");
      }
    }

    const repairedStatus = await checkStartupOpenClawRuntimeStatus(invoke);
    appendStartupRuntimeStatusLogs(appendStartupOpenClawRuntimeLogs, "status-check-after-repair", repairedStatus);
    if (!repairedStatus.installed || !repairedStatus.healthy) {
      throw new Error(repairedStatus.detail || "OpenClaw 修复后状态仍异常。");
    }

    const gateway = await waitForStartupGatewayOnline(invoke, 12, 600);
    if (!gateway || gateway.status.trim().toLowerCase() !== "online") {
      throw new Error(gateway?.detail?.trim() || "OpenClaw 网关未就绪。");
    }
    markStartupOpenClawStepDone(4);

    startupOpenClawStatusText.value = "OpenClaw 状态已修复并连接完成。";
    startupOpenClawOverlayVisible.value = false;
  } catch (error) {
    const activeStepIndex = startupOpenClawSteps.value.findIndex((step) => step.status === "installing");
    if (activeStepIndex >= 0) {
      markStartupOpenClawStepFailed(activeStepIndex);
    }
    startupOpenClawInstallError.value = error instanceof Error ? error.message : "OpenClaw 修复失败。";
    startupOpenClawStatusText.value = "OpenClaw 自动修复失败，请重试。";
    startupOpenClawOverlayVisible.value = true;
  } finally {
    startupOpenClawInstalling.value = false;
  }
}

async function runStartupOpenClawInstall(invoke: TauriInvoke, options: StartupOpenClawRunOptions = {}) {
  const runInBackground = options.background === true;
  startupOpenClawOverlayVisible.value = !runInBackground;
  startupOpenClawInstalling.value = true;
  startupOpenClawInstallError.value = "";
  startupOpenClawRuntimeLogs.value = "";
  startupOpenClawShowManualActions.value = false;
  resetStartupOpenClawSteps();

  const appendStartupOpenClawRuntimeLogs = (...entries: Array<string | undefined>) => {
    startupOpenClawRuntimeLogs.value = [startupOpenClawRuntimeLogs.value, ...entries]
      .filter((item) => Boolean(item && item.trim()))
      .join("\n\n");
  };

  try {
    startupOpenClawStatusText.value = "正在检测环境...";
    setStartupOpenClawStepInstalling(0);
    let environmentCheckNotice = "";
    let environmentBlockingError = "";
    try {
      const installGuide = (await invoke("load_lobster_install_guide")) as {
        ready?: boolean;
        checks?: Array<{ title?: string; status?: string; detail?: string }>;
      };
      const failedChecks = (installGuide.checks ?? []).filter((item) => item.status === "failed");
      if (failedChecks.length > 0 || installGuide.ready === false) {
        const failedDetail = failedChecks
          .map((item) => `${item.title || "检查项"}：${item.detail || "未通过"}`)
          .join("；");
        environmentBlockingError = failedDetail ? `环境检查未通过：${failedDetail}` : "环境检查未通过。";
      }
    } catch (error) {
      environmentCheckNotice =
        error instanceof Error && error.message.trim()
          ? `环境检查不可用，将继续安装：${error.message}`
          : "环境检查不可用，将继续安装。";
    }
    if (environmentBlockingError) {
      markStartupOpenClawStepFailed(0);
      startupOpenClawStatusText.value = "环境检查未通过，已停止自动安装。";
      startupOpenClawRuntimeLogs.value = environmentBlockingError;
      throw new Error(`${environmentBlockingError} 请先修复后再重试安装。`);
    }
    markStartupOpenClawStepDone(0);
    if (environmentCheckNotice) {
      startupOpenClawRuntimeLogs.value = environmentCheckNotice;
    }

    startupOpenClawStatusText.value = "正在准备 Node.js...";
    setStartupOpenClawStepInstalling(1);
    await sleepMs(240);
    markStartupOpenClawStepDone(1);

    startupOpenClawStatusText.value = "正在安装 openClaw...";
    setStartupOpenClawStepInstalling(2);
    let installResult: LobsterActionResult;
    try {
      installResult = (await invoke("run_lobster_action", { action: "install" })) as LobsterActionResult;
    } catch (error) {
      const detail =
        error instanceof Error && error.message.trim() ? error.message : "openClaw 安装命令执行异常。";
      installResult = {
        action: "install",
        command: "run_lobster_action install",
        success: false,
        detail,
        exitCode: null,
        stdout: "",
        stderr: detail,
        durationMs: 0,
        backupPath: null
      };
    }
    appendStartupOpenClawRuntimeLogs(installResult.command, installResult.stdout, installResult.stderr);
    if (!installResult.success) {
      const installFailureOutput = [installResult.detail, installResult.stderr].filter(Boolean).join("\n");
      const isRuntimeBlockingFailure =
        installFailureOutput.includes("Node 版本过低") ||
        installFailureOutput.includes("运行条件不满足") ||
        installFailureOutput.includes("OPENCLAW_NODE_PATH");
      if (isRuntimeBlockingFailure) {
        throw new Error(
          `${
            installResult.detail || "openClaw 安装失败。"
          } 检测到运行环境阻断错误，已跳过自动修复与重试。请先修复 Node 运行时后再安装。`
        );
      }

      startupOpenClawStatusText.value = "安装遇到问题，正在自动修复...";
      try {
        const autoFixResult = (await invoke("run_lobster_action", { action: "auto_fix" })) as LobsterActionResult;
        appendStartupOpenClawRuntimeLogs(
          "[auto-fix]",
          autoFixResult.command,
          autoFixResult.stdout,
          autoFixResult.stderr
        );
        if (!autoFixResult.success) {
          appendStartupOpenClawRuntimeLogs("auto-fix 未完全成功，将继续重试安装。", autoFixResult.detail);
        }
      } catch (error) {
        const detail =
          error instanceof Error && error.message.trim() ? error.message : "auto-fix 执行异常，将继续重试安装。";
        appendStartupOpenClawRuntimeLogs("[auto-fix]", detail);
      }

      startupOpenClawStatusText.value = "自动修复完成，正在重试安装...";
      let retryInstallResult: LobsterActionResult;
      try {
        retryInstallResult = (await invoke("run_lobster_action", { action: "install" })) as LobsterActionResult;
      } catch (error) {
        const detail =
          error instanceof Error && error.message.trim() ? error.message : "重试安装命令执行异常。";
        retryInstallResult = {
          action: "install",
          command: "run_lobster_action install",
          success: false,
          detail,
          exitCode: null,
          stdout: "",
          stderr: detail,
          durationMs: 0,
          backupPath: null
        };
      }
      appendStartupOpenClawRuntimeLogs(
        "[retry-install]",
        retryInstallResult.command,
        retryInstallResult.stdout,
        retryInstallResult.stderr
      );
      installResult = retryInstallResult;
      if (!installResult.success) {
        throw new Error(`${installResult.detail || "openClaw 安装失败。"}（已自动修复并重试一次）`);
      }
    }
    markStartupOpenClawStepDone(2);

    startupOpenClawStatusText.value = "正在配置 AI 大模型...";
    setStartupOpenClawStepInstalling(3);
    await applyLockedStartupProviderConfig(invoke);
    markStartupOpenClawStepDone(3);

    startupOpenClawStatusText.value = "正在启动并连接服务...";
    setStartupOpenClawStepInstalling(4);
    const [gateway, snapshot] = await Promise.all([
      waitForStartupGatewayOnline(invoke),
      invoke("load_lobster_snapshot").then((result) => result as LobsterSnapshotResponse)
    ]);
    if (!snapshot.openclawInstalled) {
      throw new Error("OpenClaw 安装校验失败，请重试。");
    }
    if (!gateway || gateway.status.trim().toLowerCase() !== "online") {
      throw new Error(gateway?.detail?.trim() || "OpenClaw 网关未就绪。");
    }
    markStartupOpenClawStepDone(4);

    startupOpenClawStatusText.value = "OpenClaw 已安装并连接完成。";
    startupOpenClawOverlayVisible.value = false;
  } catch (error) {
    const activeStepIndex = startupOpenClawSteps.value.findIndex((step) => step.status === "installing");
    if (activeStepIndex >= 0) {
      markStartupOpenClawStepFailed(activeStepIndex);
    }
    startupOpenClawInstallError.value = error instanceof Error ? error.message : "OpenClaw 安装失败。";
    startupOpenClawStatusText.value = "OpenClaw 自动安装失败，请重试。";
    startupOpenClawOverlayVisible.value = true;
  } finally {
    startupOpenClawInstalling.value = false;
  }
}

async function ensureStartupOpenClawReady(options: StartupOpenClawRunOptions = {}) {
  const runInBackground = options.background === true;
  const invoke = getTauriInvoke();
  if (!invoke) {
    return;
  }

  let snapshot: LobsterSnapshotResponse;
  try {
    snapshot = (await invoke("load_lobster_snapshot")) as LobsterSnapshotResponse;
  } catch (error) {
    startupOpenClawInstallError.value = error instanceof Error ? error.message : "无法检测 OpenClaw 安装状态。";
    startupOpenClawStatusText.value = "OpenClaw 安装检测失败，请重试。";
    startupOpenClawShowManualActions.value = false;
    startupOpenClawOverlayVisible.value = true;
    return;
  }

  const openInstallUiEveryLaunch = snapshot.installWizardOpenEveryLaunch === true;
  if (!snapshot.openclawInstalled) {
    startupOpenClawShowManualActions.value = false;
    startupOpenClawStatusText.value = "检测到未安装 OpenClaw，正在自动安装...";
    await runStartupOpenClawInstall(invoke, options);
    return;
  }

  try {
    await applyLockedStartupProviderConfig(invoke);
  } catch {
    // Keep app usable even if default provider write fails.
  }

  let runtimeStatus: OpenClawRuntimeStatusResponse | null = null;
  try {
    runtimeStatus = await checkStartupOpenClawRuntimeStatus(invoke);
  } catch (error) {
    runtimeStatus = {
      installed: true,
      healthy: false,
      status: "status_command_failed",
      command: "check_openclaw_runtime_status",
      detail: error instanceof Error ? error.message : "无法获取 OpenClaw 运行状态。",
      exitCode: null,
      stdout: "",
      stderr: error instanceof Error ? error.message : "",
      gatewayPort: null
    };
  }

  if (runtimeStatus.installed && runtimeStatus.healthy) {
    if (openInstallUiEveryLaunch && !runInBackground) {
      const versionText = snapshot.openclawVersion?.trim() ? snapshot.openclawVersion.trim() : "未知";
      startupOpenClawStatusText.value = "已启用每次启动显示安装界面。";
      startupOpenClawInstallError.value = "";
      startupOpenClawRuntimeLogs.value = [
        `检测结果：OpenClaw 已安装（版本 ${versionText}）。`,
        `运行状态：${runtimeStatus.detail}`,
        runtimeStatus.command ? `状态命令：${runtimeStatus.command}` : "",
        "你可以点击“重新安装”再次执行安装流程，或点击“继续使用”进入应用。"
      ]
        .filter((line) => Boolean(line && line.trim()))
        .join("\n");
      startupOpenClawShowManualActions.value = true;
      startupOpenClawOverlayVisible.value = true;
      startupOpenClawInstalling.value = false;
      markStartupOpenClawAllDone();
    }
    return;
  }

  if (!runtimeStatus.installed) {
    startupOpenClawShowManualActions.value = false;
    startupOpenClawStatusText.value = "检测到未安装 OpenClaw，正在自动安装...";
    await runStartupOpenClawInstall(invoke, options);
    return;
  }

  startupOpenClawShowManualActions.value = false;
  startupOpenClawStatusText.value = "检测到 OpenClaw 状态异常，正在自动修复...";
  await runStartupOpenClawRepair(invoke, runtimeStatus, options);
}

function scheduleStartupOpenClawReadyCheck() {
  const runCheck = () => {
    void ensureStartupOpenClawReady({ background: true });
  };
  if (typeof window === "undefined") {
    runCheck();
    return;
  }
  if (typeof window.requestAnimationFrame === "function") {
    window.requestAnimationFrame(() => {
      window.setTimeout(runCheck, 0);
    });
    return;
  }
  window.setTimeout(runCheck, 0);
}

function scheduleInitialChatPageBootstrap() {
  const runBootstrap = async () => {
    await Promise.all([loadAgents(), refreshDashboardData(), loadSidebarSettingsAppVersion()]);
    await scrollMessagesToBottom();
    await nextTick();
    resizeChatComposerInput();
  };
  if (typeof window === "undefined") {
    void runBootstrap();
    return;
  }
  if (typeof window.requestAnimationFrame === "function") {
    window.requestAnimationFrame(() => {
      window.setTimeout(() => {
        void runBootstrap();
      }, 0);
    });
    return;
  }
  window.setTimeout(() => {
    void runBootstrap();
  }, 0);
}

async function retryStartupOpenClawInstall() {
  const invoke = getTauriInvoke();
  if (!invoke || startupOpenClawInstalling.value) {
    return;
  }
  if (startupOpenClawInstallError.value.trim()) {
    await ensureStartupOpenClawReady({ background: false });
    return;
  }
  await runStartupOpenClawInstall(invoke, { background: false });
}

function dismissStartupOpenClawOverlay() {
  if (startupOpenClawInstalling.value) {
    return;
  }
  startupOpenClawShowManualActions.value = false;
  startupOpenClawOverlayVisible.value = false;
}

function createMessageId(prefix: string) {
  return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

function createSessionId() {
  return `session-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function stripRuntimeSessionInstanceSuffix(value: string) {
  const source = value.trim();
  if (!source) {
    return "";
  }
  return source.replace(/::session-[a-z0-9-]+$/i, "");
}

function normalizeRuntimeSessionKeyForAgent(sessionKeyRaw: string, agentId: string) {
  const sessionKey = sessionKeyRaw.trim().toLowerCase();
  if (!sessionKey) {
    return "";
  }
  const normalizedAgentId = normalizeConversationKeyPart(agentId);
  const expectedPrefix = `agent:${normalizedAgentId}:`;
  if (!sessionKey.startsWith(expectedPrefix)) {
    return "";
  }
  return sessionKey;
}

function buildScopedRuntimeSessionKey(conversationScopeKey: string, agentId: string) {
  const normalizedAgentId = normalizeConversationKeyPart(agentId);
  const baseSessionKey = resolveOpenClawRuntimeSessionKey(conversationScopeKey);
  const sessionPrefix = `agent:${normalizedAgentId}:`;
  const baseTargetRaw =
    baseSessionKey && baseSessionKey.startsWith(sessionPrefix) ? baseSessionKey.slice(sessionPrefix.length) : normalizedAgentId;
  const baseTarget = stripRuntimeSessionInstanceSuffix(baseTargetRaw) || normalizedAgentId;
  const nextSessionId = normalizeConversationKeyPart(createSessionId());
  return `agent:${normalizedAgentId}:${baseTarget}::${nextSessionId}`;
}

function resolveRuntimeSessionKeyForConversation(conversationScopeKey: string, agentId: string) {
  const explicitSessionKey = normalizeRuntimeSessionKeyForAgent(currentSessionId.value, agentId);
  if (explicitSessionKey) {
    return explicitSessionKey;
  }
  return resolveOpenClawRuntimeSessionKey(conversationScopeKey);
}

function normalizeConversationKeyPart(value: string) {
  return value.trim().toLowerCase() || "unknown";
}

function buildAgentConversationScopeKey(agentId: string) {
  return `agent:${normalizeConversationKeyPart(agentId)}`;
}

function buildChannelConversationScopeKey(agentId: string, channelSession: ChannelPaneChatItem) {
  const normalizedType = normalizeChannelPaneType(channelSession.channelType);
  const channelType = normalizeConversationKeyPart(normalizedType || channelSession.catalogId || channelSession.channelType);
  const accountId = normalizeConversationKeyPart(channelSession.accountId);
  const ownerAgentId = normalizeConversationKeyPart(agentId);
  return `channel:${channelType}:${accountId}:${ownerAgentId}`;
}

function resolveConversationScopeKey(agentId: string | null, channelSession: ChannelPaneChatItem | null) {
  const normalizedAgentId = (agentId ?? "").trim();
  if (!normalizedAgentId) {
    return null;
  }
  if (channelSession?.channelType === VIRTUAL_OPENCLAW_SESSION_CHANNEL_TYPE) {
    return normalizeStoredConversationScopeKey(channelSession.accountId || channelSession.id);
  }
  if (!channelSession) {
    return buildAgentConversationScopeKey(normalizedAgentId);
  }
  return buildChannelConversationScopeKey(normalizedAgentId, channelSession);
}

function chatStorageKeyFor(conversationScopeKey: string) {
  return `${CHAT_STORAGE_PREFIX}.${conversationScopeKey}`;
}

function sessionStorageKeyFor(conversationScopeKey: string) {
  return `${SESSION_STORAGE_PREFIX}.${conversationScopeKey}`;
}

function chatArchiveStorageKeyFor(conversationScopeKey: string) {
  return `${CHAT_ARCHIVE_STORAGE_PREFIX}.${conversationScopeKey}`;
}

function legacyChatStorageKeyForAgent(agentId: string) {
  return `${CHAT_STORAGE_PREFIX}.${agentId}`;
}

function legacySessionStorageKeyForAgent(agentId: string) {
  return `${SESSION_STORAGE_PREFIX}.${agentId}`;
}

function legacyChatArchiveStorageKeyForAgent(agentId: string) {
  return `${CHAT_ARCHIVE_STORAGE_PREFIX}.${agentId}`;
}

function stripRoleLabel(name: string) {
  return name.replace(/[（(][^）)]*[）)]$/, "").trim();
}

function escapeRegExp(value: string) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function getChatMentionSearchText(agent: AgentListItem) {
  return stripRoleLabel(agent.displayName).trim().toLowerCase();
}

function parseChatMentionContext(text: string, cursor: number) {
  if (!Number.isFinite(cursor) || cursor < 0 || cursor > text.length) {
    return null;
  }
  const beforeCursor = text.slice(0, cursor);
  const atIndex = beforeCursor.lastIndexOf("@");
  if (atIndex < 0) {
    return null;
  }
  if (atIndex > 0) {
    const prevChar = beforeCursor[atIndex - 1];
    if (prevChar && /[A-Za-z0-9_]/.test(prevChar)) {
      return null;
    }
  }
  const rawKeyword = beforeCursor.slice(atIndex + 1);
  if (/[\s\r\n\t]/.test(rawKeyword)) {
    return null;
  }
  return {
    startIndex: atIndex,
    keyword: rawKeyword.trim()
  };
}

function containsGroupMention(text: string, target: string) {
  const normalizedTarget = target.trim();
  if (!normalizedTarget) {
    return false;
  }
  const pattern = new RegExp(
    `(^|[^A-Za-z0-9_])@${escapeRegExp(normalizedTarget)}(?=$|[\\s,，。!！?？:：;；、)）\\]】}>》])`,
    "i"
  );
  return pattern.test(text);
}

function resolveMentionedGroupMembers(text: string, members: AgentListItem[]) {
  const content = text.trim();
  if (!content.includes("@")) {
    return [] as AgentListItem[];
  }
  const mentionAllMatched = CHAT_MENTION_ALL_KEYWORDS.some((token) => containsGroupMention(content, token));
  if (mentionAllMatched) {
    return [...members];
  }
  const deduped = new Map<string, AgentListItem>();
  for (const member of members) {
    const displayName = stripRoleLabel(member.displayName);
    const matched = containsGroupMention(content, displayName) || containsGroupMention(content, member.agentId);
    if (!matched) {
      continue;
    }
    if (!deduped.has(member.agentId)) {
      deduped.set(member.agentId, member);
    }
  }
  return Array.from(deduped.values());
}

function formatChatConversationGroupAllowFromInput(allowFrom: string[]) {
  const deduped = Array.from(new Set(allowFrom.map((item) => item.trim().toLowerCase()).filter(Boolean)));
  return deduped.length > 0 ? deduped.join(", ") : CHAT_CONVERSATION_GROUP_DEFAULT_ALLOW_FROM.join(", ");
}

function parseChatConversationGroupAllowFromInput(raw: string) {
  const values = raw
    .split(/[,\n]/g)
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
  const deduped = Array.from(new Set(values)).slice(0, 40);
  return deduped.length > 0 ? deduped : [...CHAT_CONVERSATION_GROUP_DEFAULT_ALLOW_FROM];
}

function matchesGroupAllowFromRule(source: string, rule: string) {
  if (!rule || rule === "*") {
    return true;
  }
  if (rule.endsWith("*")) {
    const prefix = rule.slice(0, -1);
    return prefix ? source.startsWith(prefix) : true;
  }
  return source === rule;
}

function isConversationGroupSourceAllowed(group: ChatConversationGroup, source: string) {
  if (group.groupPolicy === "open") {
    return true;
  }
  return group.allowFrom.some((rule) => matchesGroupAllowFromRule(source, rule));
}

function resolveGroupMessageSourceKey(channelSession: ChannelPaneChatItem | null) {
  if (!channelSession) {
    return "local:manual";
  }
  if (channelSession.channelType === VIRTUAL_OPENCLAW_SESSION_CHANNEL_TYPE) {
    const target = normalizeConversationKeyPart(channelSession.accountId || channelSession.id);
    return `session:${target}`;
  }
  const channelType = normalizeConversationKeyPart(
    normalizeChannelPaneType(channelSession.channelType) || channelSession.channelType || channelSession.catalogId
  );
  const accountId = normalizeConversationKeyPart(channelSession.accountId || "default");
  return `channel:${channelType}:${accountId}`;
}

function isConversationGroupActivationCommand(text: string, group: ChatConversationGroup) {
  const command = normalizeChatConversationGroupActivationCommand(group.activationCommand);
  const normalizedText = text.trim().toLowerCase();
  if (!normalizedText || !command) {
    return false;
  }
  return normalizedText === command || normalizedText.startsWith(`${command} `);
}

function buildGroupMemberSessionKey(group: ChatConversationGroup, memberAgentId: string, sourceKey: string) {
  const normalizedSource = normalizeConversationKeyPart(sourceKey.replace(/:/g, "-"));
  return `group:${normalizedSource}:${normalizeConversationKeyPart(group.id)}:${normalizeConversationKeyPart(memberAgentId)}`;
}

function inferStatusTone(statusLabel: string): AgentStatusTone {
  const value = statusLabel.trim().toLowerCase();
  if (!value) {
    return "online";
  }
  if (value.includes("offline") || value.includes("离线") || value.includes("断开")) {
    return "offline";
  }
  if (value.includes("busy") || value.includes("运行") || value.includes("执行") || value.includes("处理中") || value.includes("调度")) {
    return "busy";
  }
  return "online";
}

function inferGroupKind(displayName: string, roleLabel: string): AgentGroupKind {
  const text = `${displayName} ${roleLabel}`.toLowerCase();
  if (text.includes("群") || text.includes("group")) {
    return "group";
  }
  return "staff";
}

function formatTimeLabel(timestamp: number) {
  return new Date(timestamp).toLocaleTimeString("zh-CN", {
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  });
}

function normalizeRole(value: unknown): ChatRole | null {
  return value === "assistant" || value === "user" || value === "system" ? value : null;
}

function normalizeStatus(value: unknown): ChatStatus {
  if (value === "pending" || value === "done" || value === "error") {
    return value;
  }
  return "done";
}

function normalizeToolStatus(value: unknown): ChatToolStatus | undefined {
  if (value === "running" || value === "done" || value === "error") {
    return value;
  }
  return undefined;
}

function createChatAttachmentId() {
  return `att-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function normalizeChatComposerFileExtension(fileName: string) {
  const normalized = fileName.trim().toLowerCase();
  const dotIndex = normalized.lastIndexOf(".");
  if (dotIndex < 0 || dotIndex >= normalized.length - 1) {
    return "";
  }
  return normalized.slice(dotIndex + 1);
}

function resolveChatComposerFallbackFileName(file: File, index: number) {
  const mimeType = file.type.trim().toLowerCase();
  if (mimeType.startsWith("image/")) {
    const extension = mimeType.split("/")[1] || "png";
    return `粘贴图片-${Date.now()}-${index + 1}.${extension}`;
  }
  const extension = normalizeChatComposerFileExtension(file.name);
  if (extension) {
    return `附件-${Date.now()}-${index + 1}.${extension}`;
  }
  return `附件-${Date.now()}-${index + 1}`;
}

function resolveChatComposerFileDisplayName(file: File, index: number) {
  const normalized = file.name.trim();
  if (normalized) {
    return normalized;
  }
  return resolveChatComposerFallbackFileName(file, index);
}

function resolveChatComposerFileLocalPath(file: File) {
  const candidatePath = (file as File & { path?: unknown }).path;
  if (typeof candidatePath !== "string") {
    return "";
  }
  const normalized = normalizeDetectedFilePath(candidatePath);
  if (!normalized || !isAbsoluteLocalPath(normalized)) {
    return "";
  }
  return normalized;
}

function resolveDetectedFileKindFromMimeType(mimeTypeRaw: string) {
  const mimeType = mimeTypeRaw.trim().toLowerCase();
  if (!mimeType) {
    return "other" as ChatDetectedFileKind;
  }
  if (mimeType.startsWith("image/")) {
    return "image" as ChatDetectedFileKind;
  }
  if (mimeType.startsWith("audio/")) {
    return "audio" as ChatDetectedFileKind;
  }
  if (mimeType.startsWith("video/")) {
    return "video" as ChatDetectedFileKind;
  }
  if (mimeType === "text/html" || mimeType === "application/xhtml+xml") {
    return "html" as ChatDetectedFileKind;
  }
  return "other" as ChatDetectedFileKind;
}

function resolveChatComposerAttachmentDetectedKind(attachment: Pick<ChatComposerAttachment, "name" | "type">) {
  const fromMimeType = resolveDetectedFileKindFromMimeType(attachment.type);
  if (fromMimeType !== "other") {
    return fromMimeType;
  }
  const extension = normalizeChatComposerFileExtension(attachment.name);
  return extension ? resolveDetectedFileKind(extension) : "other";
}

function revokeChatAttachmentLocalPreviewObjectUrl(objectUrl: string) {
  if (!objectUrl || typeof URL === "undefined" || typeof URL.revokeObjectURL !== "function") {
    return;
  }
  try {
    URL.revokeObjectURL(objectUrl);
  } catch {
    // Ignore object URL cleanup failures.
  }
}

function setChatAttachmentLocalPreview(attachmentId: string, preview: ChatAttachmentLocalPreview | null) {
  const current = chatAttachmentLocalPreviews.value[attachmentId];
  if (current?.objectUrl && (!preview || current.objectUrl !== preview.objectUrl)) {
    revokeChatAttachmentLocalPreviewObjectUrl(current.objectUrl);
  }

  if (!preview) {
    if (!current) {
      return;
    }
    const snapshot = { ...chatAttachmentLocalPreviews.value };
    delete snapshot[attachmentId];
    chatAttachmentLocalPreviews.value = snapshot;
    return;
  }

  chatAttachmentLocalPreviews.value = {
    ...chatAttachmentLocalPreviews.value,
    [attachmentId]: preview
  };
}

function registerChatAttachmentLocalPreview(attachmentId: string, attachment: ChatComposerAttachment, file: File) {
  if (typeof URL === "undefined" || typeof URL.createObjectURL !== "function") {
    return;
  }
  const kind = resolveChatComposerAttachmentDetectedKind(attachment);
  if (kind !== "image" && kind !== "audio" && kind !== "video" && kind !== "html") {
    return;
  }

  const objectUrl = URL.createObjectURL(file);
  setChatAttachmentLocalPreview(attachmentId, {
    objectUrl,
    kind
  });
}

function hasChatAttachmentReference(attachmentId: string) {
  if (chatAttachments.value.some((attachment) => attachment.id === attachmentId)) {
    return true;
  }
  return chatMessages.value.some((message) => (message.attachments ?? []).some((attachment) => attachment.id === attachmentId));
}

function pruneUnusedChatAttachmentLocalPreviews() {
  const entries = Object.entries(chatAttachmentLocalPreviews.value);
  if (entries.length === 0) {
    return;
  }
  let changed = false;
  const next: Record<string, ChatAttachmentLocalPreview> = {};
  for (const [attachmentId, preview] of entries) {
    if (!hasChatAttachmentReference(attachmentId)) {
      revokeChatAttachmentLocalPreviewObjectUrl(preview.objectUrl);
      changed = true;
      continue;
    }
    next[attachmentId] = preview;
  }
  if (changed) {
    chatAttachmentLocalPreviews.value = next;
  }
}

function clearAllChatAttachmentLocalPreviews() {
  for (const preview of Object.values(chatAttachmentLocalPreviews.value)) {
    revokeChatAttachmentLocalPreviewObjectUrl(preview.objectUrl);
  }
  chatAttachmentLocalPreviews.value = {};
}

function isSupportedChatComposerFile(file: File) {
  const mimeType = file.type.trim().toLowerCase();
  if (mimeType.startsWith("image/") || mimeType.startsWith("audio/") || mimeType.startsWith("video/") || mimeType.startsWith("text/")) {
    return true;
  }
  if (CHAT_COMPOSER_ACCEPTED_MIME_TYPES.has(mimeType)) {
    return true;
  }
  const extension = normalizeChatComposerFileExtension(file.name);
  return extension ? CHAT_COMPOSER_ACCEPTED_EXTENSIONS.has(extension) : false;
}

function formatUnsupportedChatComposerFileMessage(file: File, index: number) {
  return `文件「${resolveChatComposerFileDisplayName(file, index)}」暂不支持发送。`;
}

function hasDataTransferFiles(dataTransfer: DataTransfer | null | undefined) {
  if (!dataTransfer) {
    return false;
  }
  if (dataTransfer.files && dataTransfer.files.length > 0) {
    return true;
  }
  return Array.from(dataTransfer.types || []).includes("Files");
}

function collectFilesFromDataTransfer(dataTransfer: DataTransfer | null | undefined): File[] {
  if (!dataTransfer) {
    return [];
  }
  const deduped = new Set<string>();
  const output: File[] = [];
  const append = (file: File | null) => {
    if (!file) {
      return;
    }
    const identity = `${file.name}::${file.size}::${file.type}::${file.lastModified}`;
    if (deduped.has(identity)) {
      return;
    }
    deduped.add(identity);
    output.push(file);
  };
  if (dataTransfer.items && dataTransfer.items.length > 0) {
    for (const item of Array.from(dataTransfer.items)) {
      if (item.kind !== "file") {
        continue;
      }
      append(item.getAsFile());
    }
  }
  if (dataTransfer.files && dataTransfer.files.length > 0) {
    for (const file of Array.from(dataTransfer.files)) {
      append(file);
    }
  }
  return output;
}

function normalizeChatComposerLocalPathCandidate(rawPath: string | null | undefined) {
  if (!rawPath) {
    return "";
  }
  const normalized = normalizeDetectedFilePath(rawPath);
  if (!normalized || !isAbsoluteLocalPath(normalized)) {
    return "";
  }
  return normalized;
}

function sanitizeChatAttachmentWorkspaceHint(rawWorkspace: string | null | undefined) {
  const normalized = (rawWorkspace ?? "").trim();
  if (!normalized || normalized === "—" || normalized === "-") {
    return "";
  }
  return normalizeChatComposerLocalPathCandidate(normalized);
}

function readAttachmentFileAsDataUrl(file: File) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = typeof reader.result === "string" ? reader.result : "";
      if (!result.startsWith("data:")) {
        reject(new Error("文件编码失败。"));
        return;
      }
      resolve(result);
    };
    reader.onerror = () => {
      reject(new Error("文件读取失败。"));
    };
    reader.readAsDataURL(file);
  });
}

async function persistChatClipboardFileToLocalPath(file: File, displayName: string) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return "";
  }
  if (file.size <= 0) {
    return "";
  }
  const dataUrl = await readAttachmentFileAsDataUrl(file);
  const workspace = sanitizeChatAttachmentWorkspaceHint(activeAgent.value?.workspace ?? "");
  const savedPath = (await invoke("persist_chat_attachment_data_url", {
    fileName: displayName,
    dataUrl,
    workspace: workspace || null
  })) as string;
  return normalizeChatComposerLocalPathCandidate(savedPath);
}

async function resolveClipboardAttachmentLocalPaths(files: File[]) {
  if (files.length === 0) {
    return [] as string[];
  }
  const results = await Promise.all(
    files.map(async (file, index) => {
      const existingLocalPath = resolveChatComposerFileLocalPath(file);
      if (existingLocalPath) {
        return existingLocalPath;
      }
      const kind = resolveDetectedFileKindFromMimeType(file.type);
      if (kind !== "image") {
        return "";
      }
      const displayName = resolveChatComposerFileDisplayName(file, index);
      try {
        return await persistChatClipboardFileToLocalPath(file, displayName);
      } catch {
        return "";
      }
    })
  );
  return results;
}

function resetChatComposerDragState() {
  chatComposerDragDepth.value = 0;
  isChatComposerDragOver.value = false;
}

function formatAttachmentSize(size: number) {
  if (!Number.isFinite(size) || size <= 0) {
    return "0 B";
  }
  if (size < 1024) {
    return `${Math.round(size)} B`;
  }
  if (size < 1024 * 1024) {
    return `${(size / 1024).toFixed(1)} KB`;
  }
  return `${(size / (1024 * 1024)).toFixed(1)} MB`;
}

function normalizeAttachment(raw: unknown): ChatComposerAttachment | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const candidate = raw as Partial<ChatComposerAttachment>;
  const name = typeof candidate.name === "string" ? candidate.name.trim() : "";
  if (!name) {
    return null;
  }
  const size = typeof candidate.size === "number" && Number.isFinite(candidate.size) ? Math.max(0, candidate.size) : 0;
  const type = typeof candidate.type === "string" ? candidate.type : "";
  const rawLocalPath = typeof candidate.localPath === "string" ? normalizeDetectedFilePath(candidate.localPath) : "";
  const localPath = rawLocalPath && isAbsoluteLocalPath(rawLocalPath) ? rawLocalPath : undefined;
  return {
    id: typeof candidate.id === "string" && candidate.id.trim() ? candidate.id : createChatAttachmentId(),
    name,
    size,
    type,
    localPath
  };
}

function normalizeMessageAttachments(raw: unknown): ChatComposerAttachment[] | undefined {
  if (!Array.isArray(raw)) {
    return undefined;
  }
  const list = raw.map((item) => normalizeAttachment(item)).filter((item): item is ChatComposerAttachment => item !== null);
  return list.length > 0 ? list : undefined;
}

function formatAttachmentSummaryForPrompt(attachments: ChatComposerAttachment[]) {
  if (attachments.length === 0) {
    return "";
  }
  const details = attachments.map((attachment) => {
    const base = `${attachment.name} (${formatAttachmentSize(attachment.size)})`;
    const localPath = normalizeChatComposerLocalPathCandidate(attachment.localPath);
    if (!localPath) {
      return base;
    }
    return `${base} [localPath: ${localPath}]`;
  });
  return `[附件: ${details.join("；")}]`;
}

const CHAT_LOCAL_USER_DUPLICATE_WINDOW_MS = 4 * 1000;

function buildLocalAttachmentSignature(attachments: ChatComposerAttachment[]) {
  if (attachments.length === 0) {
    return "";
  }
  return attachments
    .map((attachment) => `${attachment.name.trim().toLowerCase()}|${Math.max(0, Math.floor(attachment.size))}`)
    .sort()
    .join(";");
}

function normalizeLocalUserMessageDedupText(text: string, attachments: ChatComposerAttachment[]) {
  const normalizedText = text.replace(/\s+/g, " ").trim();
  if (normalizedText) {
    return normalizedText;
  }
  return attachments.length > 0 ? "(附件)" : "";
}

function isRecentDuplicateUserSubmit(text: string, attachments: ChatComposerAttachment[], nowMs: number) {
  const dedupText = normalizeLocalUserMessageDedupText(text, attachments);
  if (!dedupText) {
    return false;
  }
  const dedupAttachmentSignature = buildLocalAttachmentSignature(attachments);
  for (let index = chatMessages.value.length - 1; index >= 0; index -= 1) {
    const item = chatMessages.value[index];
    if (!item || item.role !== "user" || item.status !== "done") {
      continue;
    }
    const createdAt = typeof item.createdAt === "number" && Number.isFinite(item.createdAt) ? item.createdAt : 0;
    if (createdAt <= 0 || nowMs - createdAt > CHAT_LOCAL_USER_DUPLICATE_WINDOW_MS) {
      if (createdAt > 0) {
        break;
      }
      continue;
    }
    const existingText = normalizeLocalUserMessageDedupText(item.text, item.attachments ?? []);
    const existingAttachmentSignature = buildLocalAttachmentSignature(item.attachments ?? []);
    if (existingText === dedupText && existingAttachmentSignature === dedupAttachmentSignature) {
      return true;
    }
  }
  return false;
}

function stripLeadingUntrustedMetadataEnvelope(text: string) {
  const normalized = text.replace(/\r\n/g, "\n");
  const hasMetadataMarker = /\(untrusted metadata\):/i.test(normalized);
  const hasCodeBlock = /```(?:json)?/i.test(normalized);
  const likelyEnvelopeStart = /^System:\s*\[/.test(normalized) || /^[^\n]*\(untrusted metadata\):/i.test(normalized);
  if (!hasMetadataMarker || !hasCodeBlock || !likelyEnvelopeStart) {
    return text;
  }

  let rest = normalized;
  rest = rest.replace(/^System:[\s\S]*?\n{2}/, "");

  const metadataSectionPattern = /^[^\n]*\(untrusted metadata\):\s*\n```(?:json)?\n[\s\S]*?\n```(?:\n{1,2})?/i;
  let previous = "";
  while (rest !== previous) {
    previous = rest;
    rest = rest.replace(metadataSectionPattern, "");
  }

  return rest.trimStart();
}

function stripLeadingMessageIdLabel(text: string) {
  const normalized = text.replace(/\r\n/g, "\n");
  const markerPattern = /^\s*\[(?:message|msg)[_\s-]?id\s*[:：]\s*[^\]\n]+\]\s*(?:\n+)?/i;
  let rest = normalized;
  let previous = "";
  while (rest !== previous) {
    previous = rest;
    rest = rest.replace(markerPattern, "");
  }
  return rest.trimStart();
}

function stripLeadingChannelSenderIdLabel(text: string) {
  const normalized = text.replace(/\r\n/g, "\n");
  const labeledSenderPattern =
    /^\s*(?:feishu:(?:direct|group):)?(?:user:|chat:)?((?:ou|oc)_[a-z0-9]{8,})\s*(?:[:：-]\s*|\s+)([\s\S]+)$/i;
  const labeledSenderMatch = normalized.match(labeledSenderPattern);
  if (labeledSenderMatch?.[2]?.trim()) {
    return labeledSenderMatch[2].trimStart();
  }

  const compactSenderPattern = /^\s*((?:ou|oc)_[a-z0-9]{16,})(?=[\u4e00-\u9fff])/i;
  const compactSenderMatch = normalized.match(compactSenderPattern);
  if (compactSenderMatch?.[1]) {
    const rest = normalized.slice(compactSenderMatch[0].length).trimStart();
    if (rest) {
      return rest;
    }
  }

  return text;
}

function extractLatestUserLineFromPromptEnvelope(text: string) {
  const normalized = text.replace(/\r\n/g, "\n");
  const markerPattern = /\[Current message - respond to this\]/i;
  const markerMatch = markerPattern.exec(normalized);
  const scope = markerMatch ? normalized.slice(markerMatch.index + markerMatch[0].length) : normalized;

  const userLinePattern = /^(?:User|用户)\s*[:：]\s*(.+)$/gim;
  let lastContent = "";
  let matched: RegExpExecArray | null = null;
  while ((matched = userLinePattern.exec(scope)) !== null) {
    const content = (matched[1] ?? "").trim();
    if (content) {
      lastContent = content;
    }
  }
  return lastContent;
}

function stripChatContextEnvelope(text: string) {
  const normalized = text.replace(/\r\n/g, "\n");
  const hasContextHeader = /^\s*\[Chat messages since your last reply - for context\]/i.test(normalized);
  const hasCurrentMarker = /\[Current message - respond to this\]/i.test(normalized);
  const hasConversationTurns = /(?:^|\n)(?:User|用户)\s*[:：]/i.test(normalized) && /(?:^|\n)(?:Assistant|助手)\s*[:：]/i.test(normalized);
  if (!hasContextHeader && !hasCurrentMarker && !hasConversationTurns) {
    return text;
  }

  const extractedCurrentMessage = extractLatestUserLineFromPromptEnvelope(normalized);
  if (extractedCurrentMessage) {
    return extractedCurrentMessage;
  }
  return text;
}

function sanitizeMessageTextForDisplay(rawText: string) {
  return stripChatContextEnvelope(
    stripLeadingChannelSenderIdLabel(stripLeadingMessageIdLabel(stripLeadingUntrustedMetadataEnvelope(rawText)))
  ).trim();
}

const chatMarkdownRenderCache = new Map<string, string>();
const chatDetectedFilesCache = new Map<string, ChatDetectedFile[]>();

function setLimitedCacheEntry<T>(cache: Map<string, T>, key: string, value: T, maxEntries: number) {
  cache.set(key, value);
  if (cache.size <= maxEntries) {
    return value;
  }
  const firstKey = cache.keys().next().value;
  if (typeof firstKey === "string") {
    cache.delete(firstKey);
  }
  return value;
}

function escapeHtml(raw: string) {
  return raw
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function escapeHtmlAttribute(raw: string) {
  return escapeHtml(raw).replace(/`/g, "&#96;");
}

function encodeTextForHtmlDataAttribute(raw: string) {
  return escapeHtmlAttribute(encodeURIComponent(raw));
}

function sanitizeMarkdownHref(rawHref: string) {
  const candidate = rawHref.trim().replace(/&amp;/g, "&");
  if (!candidate) {
    return null;
  }
  if (
    candidate.startsWith("http://") ||
    candidate.startsWith("https://") ||
    candidate.startsWith("mailto:") ||
    candidate.startsWith("file://")
  ) {
    return candidate;
  }
  return null;
}

function renderInlineMarkdown(raw: string) {
  const codeTokens: string[] = [];
  const withTokens = raw.replace(/`([^`]+?)`/g, (_match: string, codeText: string) => {
    const token = `@@CODE_${codeTokens.length}@@`;
    const encodedCodeText = encodeTextForHtmlDataAttribute(codeText);
    codeTokens.push(
      `<span class="message-md-inline-code"><code>${escapeHtml(codeText)}</code><button type="button" class="message-md-copy message-md-inline-code__copy" data-copy-code="${encodedCodeText}">复制</button></span>`
    );
    return token;
  });
  let html = escapeHtml(withTokens);
  html = html.replace(/\[([^\]]+)\]\(([^)\s]+)\)/g, (_match: string, label: string, href: string) => {
    const normalizedHref = sanitizeMarkdownHref(href);
    if (!normalizedHref) {
      return label;
    }
    return `<a href="${escapeHtmlAttribute(normalizedHref)}" target="_blank" rel="noopener noreferrer">${label}</a>`;
  });
  html = html.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  html = html.replace(/(^|[^*])\*([^*\n]+)\*(?!\*)/g, "$1<em>$2</em>");
  html = html.replace(/~~([^~]+)~~/g, "<del>$1</del>");
  for (let index = 0; index < codeTokens.length; index += 1) {
    html = html.replace(`@@CODE_${index}@@`, codeTokens[index]);
  }
  return html;
}

function sanitizeMarkdownLanguage(raw: string) {
  return raw.trim().replace(/[^a-z0-9_-]+/gi, "").slice(0, 24);
}

function renderMarkdownToHtml(markdown: string) {
  const normalized = markdown.replace(/\r\n/g, "\n").replace(/\r/g, "\n").trim();
  if (!normalized) {
    return "";
  }

  const cached = chatMarkdownRenderCache.get(normalized);
  if (typeof cached === "string") {
    return cached;
  }

  const lines = normalized.split("\n");
  const blocks: string[] = [];
  const paragraphLines: string[] = [];
  const quoteLines: string[] = [];
  let listType: "ul" | "ol" | null = null;
  let listItems: string[] = [];
  let inCodeBlock = false;
  let codeLanguage = "";
  let codeLines: string[] = [];

  const flushParagraph = () => {
    if (paragraphLines.length === 0) {
      return;
    }
    const text = paragraphLines.map((line) => renderInlineMarkdown(line.trim())).join("<br />");
    blocks.push(`<p>${text}</p>`);
    paragraphLines.length = 0;
  };

  const flushQuote = () => {
    if (quoteLines.length === 0) {
      return;
    }
    const content = quoteLines.map((line) => renderInlineMarkdown(line)).join("<br />");
    blocks.push(`<blockquote><p>${content}</p></blockquote>`);
    quoteLines.length = 0;
  };

  const flushList = () => {
    if (!listType || listItems.length === 0) {
      listType = null;
      listItems = [];
      return;
    }
    blocks.push(`<${listType}>${listItems.map((item) => `<li>${item}</li>`).join("")}</${listType}>`);
    listType = null;
    listItems = [];
  };

  const flushCodeBlock = () => {
    if (!inCodeBlock) {
      return;
    }
    const languageClass = codeLanguage ? ` class="language-${escapeHtmlAttribute(codeLanguage)}"` : "";
    const codeText = codeLines.join("\n");
    const encodedCodeText = encodeTextForHtmlDataAttribute(codeText);
    blocks.push(
      `<div class="message-md-codeblock"><button type="button" class="message-md-copy message-md-codeblock__copy" data-copy-code="${encodedCodeText}">复制</button><pre><code${languageClass}>${escapeHtml(codeText)}</code></pre></div>`
    );
    inCodeBlock = false;
    codeLanguage = "";
    codeLines = [];
  };

  const flushTextBlocks = () => {
    flushParagraph();
    flushQuote();
    flushList();
  };

  for (const line of lines) {
    const trimmed = line.trim();

    if (inCodeBlock) {
      if (/^```/.test(trimmed)) {
        flushCodeBlock();
      } else {
        codeLines.push(line);
      }
      continue;
    }

    const fenceMatch = trimmed.match(/^```([a-z0-9_-]+)?\s*$/i);
    if (fenceMatch) {
      flushTextBlocks();
      inCodeBlock = true;
      codeLanguage = sanitizeMarkdownLanguage(fenceMatch[1] ?? "");
      codeLines = [];
      continue;
    }

    if (!trimmed) {
      flushTextBlocks();
      continue;
    }

    const headingMatch = trimmed.match(/^(#{1,6})\s+(.+)$/);
    if (headingMatch) {
      flushTextBlocks();
      const level = headingMatch[1].length;
      blocks.push(`<h${level}>${renderInlineMarkdown(headingMatch[2].trim())}</h${level}>`);
      continue;
    }

    if (/^(?:-{3,}|\*{3,}|_{3,})$/.test(trimmed)) {
      flushTextBlocks();
      blocks.push("<hr />");
      continue;
    }

    const quoteMatch = line.match(/^\s*>\s?(.*)$/);
    if (quoteMatch) {
      flushParagraph();
      flushList();
      quoteLines.push(quoteMatch[1].trim());
      continue;
    }
    flushQuote();

    const orderedMatch = line.match(/^\s*\d+[.)]\s+(.+)$/);
    if (orderedMatch) {
      flushParagraph();
      if (listType !== "ol") {
        flushList();
        listType = "ol";
      }
      listItems.push(renderInlineMarkdown(orderedMatch[1].trim()));
      continue;
    }

    const unorderedMatch = line.match(/^\s*[-*+]\s+(.+)$/);
    if (unorderedMatch) {
      flushParagraph();
      if (listType !== "ul") {
        flushList();
        listType = "ul";
      }
      listItems.push(renderInlineMarkdown(unorderedMatch[1].trim()));
      continue;
    }

    flushList();
    paragraphLines.push(line);
  }

  flushTextBlocks();
  flushCodeBlock();
  const rendered = blocks.join("");
  return setLimitedCacheEntry(chatMarkdownRenderCache, normalized, rendered, CHAT_MARKDOWN_RENDER_CACHE_MAX);
}

function shouldRenderMessageAsMarkdown(message: AgentChatMessage) {
  return message.role === "assistant" || message.role === "system";
}

function stripTrailingPathTokens(rawPath: string) {
  let result = rawPath.trim();
  while (result.length > 0) {
    const tail = result.slice(-1);
    if (!CHAT_FILE_PATH_TRAILING_TOKENS.has(tail)) {
      break;
    }
    result = result.slice(0, -1);
  }
  return result;
}

function normalizeDetectedFilePath(rawPath: string) {
  let normalized = rawPath.trim();
  if (
    normalized.length >= 2 &&
    ((normalized.startsWith('"') && normalized.endsWith('"')) || (normalized.startsWith("'") && normalized.endsWith("'")))
  ) {
    normalized = normalized.slice(1, -1).trim();
  }
  return stripTrailingPathTokens(normalized);
}

function isAbsoluteLocalPath(path: string) {
  return path.startsWith("/") || /^[a-z]:[\\/]/i.test(path);
}

function resolveDetectedFileKind(extension: string): ChatDetectedFileKind {
  const normalized = extension.trim().toLowerCase();
  if (CHAT_FILE_IMAGE_EXTENSIONS.has(normalized)) {
    return "image";
  }
  if (CHAT_FILE_AUDIO_EXTENSIONS.has(normalized)) {
    return "audio";
  }
  if (CHAT_FILE_VIDEO_EXTENSIONS.has(normalized)) {
    return "video";
  }
  if (CHAT_FILE_HTML_EXTENSIONS.has(normalized)) {
    return "html";
  }
  return "other";
}

function encodePathForFileUrl(path: string) {
  return path
    .split("/")
    .map((segment, index) => {
      if (index === 0 && segment === "") {
        return "";
      }
      if (/^[a-z]:$/i.test(segment)) {
        return segment;
      }
      return encodeURIComponent(segment);
    })
    .join("/");
}

function buildLocalFilePreviewUrls(path: string) {
  const normalized = path.trim();
  const candidates: string[] = [];
  const seen = new Set<string>();
  const pushCandidate = (value: string | null | undefined) => {
    const candidate = (value ?? "").trim();
    if (!candidate || seen.has(candidate)) {
      return;
    }
    seen.add(candidate);
    candidates.push(candidate);
  };

  const convertFileSrc = getTauriConvertFileSrc();
  if (convertFileSrc) {
    try {
      pushCandidate(convertFileSrc(normalized));
    } catch {
      // Keep fallback previews below.
    }
    try {
      pushCandidate(convertFileSrc(normalized, "asset"));
    } catch {
      // Keep fallback previews below.
    }
  }

  if (normalized.startsWith("/")) {
    pushCandidate(`file://${encodePathForFileUrl(normalized)}`);
    pushCandidate(`file://${normalized}`);
    return candidates;
  }
  if (/^[a-z]:[\\/]/i.test(normalized)) {
    const windowsPath = normalized.replace(/\\/g, "/");
    pushCandidate(`file:///${encodePathForFileUrl(windowsPath)}`);
    pushCandidate(`file:///${windowsPath}`);
    return candidates;
  }
  return candidates;
}

function decodeFileUrlToPath(rawUrl: string) {
  const source = stripTrailingPathTokens(rawUrl.trim());
  if (!/^file:\/\//i.test(source)) {
    return null;
  }
  try {
    const url = new URL(source);
    if (url.protocol !== "file:") {
      return null;
    }
    let pathname = decodeURIComponent(url.pathname || "");
    if (/^\/[a-z]:/i.test(pathname)) {
      pathname = pathname.slice(1);
    }
    if (url.hostname && url.hostname !== "localhost") {
      const hostPath = pathname.startsWith("/") ? pathname : `/${pathname}`;
      return `//${url.hostname}${hostPath}`;
    }
    return pathname || null;
  } catch {
    const fallback = source.replace(/^file:\/\/+/, "/");
    try {
      return decodeURIComponent(fallback);
    } catch {
      return fallback;
    }
  }
}

function extractDetectedFilesFromText(text: string) {
  const normalizedText = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  if (!normalizedText.trim()) {
    return [] as ChatDetectedFile[];
  }
  const cached = chatDetectedFilesCache.get(normalizedText);
  if (cached) {
    return cached;
  }

  const files: ChatDetectedFile[] = [];
  const seen = new Set<string>();
  const addDetectedPath = (rawPath: string) => {
    const normalizedPath = normalizeDetectedFilePath(rawPath);
    if (!normalizedPath || !isAbsoluteLocalPath(normalizedPath)) {
      return;
    }
    const extension = normalizedPath.includes(".") ? normalizedPath.split(".").pop()?.toLowerCase() ?? "" : "";
    if (!extension) {
      return;
    }
    const id = normalizedPath.toLowerCase();
    if (seen.has(id)) {
      return;
    }
    seen.add(id);
    const kind = resolveDetectedFileKind(extension);
    files.push({
      id,
      normalizedPath,
      extension,
      kind,
      previewUrls: buildLocalFilePreviewUrls(normalizedPath)
    });
  };

  CHAT_FILE_UNIX_PATH_PATTERN.lastIndex = 0;
  let unixMatch: RegExpExecArray | null = null;
  while ((unixMatch = CHAT_FILE_UNIX_PATH_PATTERN.exec(normalizedText)) !== null) {
    if (unixMatch[1]) {
      addDetectedPath(unixMatch[1]);
    }
  }

  CHAT_FILE_WINDOWS_PATH_PATTERN.lastIndex = 0;
  let windowsMatch: RegExpExecArray | null = null;
  while ((windowsMatch = CHAT_FILE_WINDOWS_PATH_PATTERN.exec(normalizedText)) !== null) {
    if (windowsMatch[1]) {
      addDetectedPath(windowsMatch[1]);
    }
  }

  CHAT_FILE_URL_PATTERN.lastIndex = 0;
  let fileUrlMatch: RegExpExecArray | null = null;
  while ((fileUrlMatch = CHAT_FILE_URL_PATTERN.exec(normalizedText)) !== null) {
    const decodedPath = decodeFileUrlToPath(fileUrlMatch[1] ?? "");
    if (decodedPath) {
      addDetectedPath(decodedPath);
    }
  }

  return setLimitedCacheEntry(chatDetectedFilesCache, normalizedText, files, CHAT_FILE_DETECTION_CACHE_MAX);
}

function getMessageDisplayHtml(message: AgentChatMessage) {
  const displayText = getMessageDisplayText(message);
  if (!displayText) {
    return "";
  }
  if (shouldRenderMessageAsMarkdown(message)) {
    return renderMarkdownToHtml(displayText);
  }
  return `<p>${escapeHtml(displayText).replace(/\n/g, "<br />")}</p>`;
}

function markMarkdownCopyButtonCopied(button: HTMLButtonElement) {
  const originalText = button.textContent ?? "复制";
  button.textContent = "已复制";
  button.classList.add("is-copied");
  window.setTimeout(() => {
    button.textContent = originalText;
    button.classList.remove("is-copied");
  }, 1200);
}

function decodeMarkdownCopyPayload(raw: string) {
  if (!raw) {
    return "";
  }
  try {
    return decodeURIComponent(raw);
  } catch {
    return "";
  }
}

async function handleMessageBubbleActionClick(event: MouseEvent) {
  const target = event.target;
  if (!(target instanceof HTMLElement)) {
    return;
  }
  const button = target.closest(".message-md-copy[data-copy-code]");
  if (!(button instanceof HTMLButtonElement)) {
    return;
  }

  event.preventDefault();
  event.stopPropagation();
  const payload = decodeMarkdownCopyPayload(button.getAttribute("data-copy-code") ?? "");
  if (!payload.trim()) {
    showChatAgentDeleteNotice("当前代码块暂无可复制内容。");
    return;
  }

  try {
    await writeTextToClipboard(payload);
    markMarkdownCopyButtonCopied(button);
  } catch {
    showChatAgentDeleteNotice("复制失败，请重试。");
  }
}

function buildDetectedFileFromAttachment(attachment: ChatComposerAttachment): ChatDetectedFile | null {
  const displayName = attachment.name.trim();
  if (!displayName) {
    return null;
  }

  const previewState = chatAttachmentLocalPreviews.value[attachment.id];
  const localPath = attachment.localPath?.trim() ?? "";
  const extension = normalizeChatComposerFileExtension(displayName) || normalizeChatComposerFileExtension(localPath) || "bin";
  const kind = previewState?.kind ?? resolveChatComposerAttachmentDetectedKind(attachment);
  if (kind === "other") {
    return null;
  }

  const previewUrls: string[] = [];
  if (previewState?.objectUrl) {
    previewUrls.push(previewState.objectUrl);
  } else if (localPath && isAbsoluteLocalPath(localPath)) {
    previewUrls.push(...buildLocalFilePreviewUrls(localPath));
  }

  return {
    id: `attachment:${attachment.id}`,
    normalizedPath: localPath || displayName,
    extension,
    kind,
    previewUrls
  };
}

function getMessageDetectedFiles(message: AgentChatMessage) {
  if (message.status === "pending" || isRuntimeToolMessage(message)) {
    return [] as ChatDetectedFile[];
  }
  const files: ChatDetectedFile[] = [];
  const dedupedIds = new Set<string>();
  const dedupedPaths = new Set<string>();

  for (const attachment of message.attachments ?? []) {
    const detected = buildDetectedFileFromAttachment(attachment);
    if (!detected) {
      continue;
    }
    const normalizedPathKey = detected.normalizedPath.trim().toLowerCase();
    if (dedupedIds.has(detected.id) || (normalizedPathKey && dedupedPaths.has(normalizedPathKey))) {
      continue;
    }
    dedupedIds.add(detected.id);
    if (normalizedPathKey) {
      dedupedPaths.add(normalizedPathKey);
    }
    files.push(detected);
  }

  for (const detected of extractDetectedFilesFromText(getMessageDisplayText(message))) {
    const normalizedPathKey = detected.normalizedPath.trim().toLowerCase();
    if (dedupedIds.has(detected.id) || (normalizedPathKey && dedupedPaths.has(normalizedPathKey))) {
      continue;
    }
    dedupedIds.add(detected.id);
    if (normalizedPathKey) {
      dedupedPaths.add(normalizedPathKey);
    }
    files.push(detected);
  }

  return files;
}

function getDetectedFilePreviewErrorKey(file: ChatDetectedFile) {
  if (file.id.startsWith("attachment:")) {
    return `${file.kind}:${file.id}`;
  }
  return `${file.kind}:${file.normalizedPath}`;
}

function supportsDetectedFilePreviewKind(file: ChatDetectedFile) {
  return file.kind !== "other";
}

function isAttachmentDetectedFile(file: ChatDetectedFile) {
  return file.id.startsWith("attachment:");
}

function shouldShowDetectedFileHeader(file: ChatDetectedFile) {
  return !isAttachmentDetectedFile(file);
}

function shouldPreferBackendPreview(file: ChatDetectedFile) {
  if (file.previewUrls.some((url) => url.startsWith("blob:") || url.startsWith("data:"))) {
    return false;
  }
  return file.kind === "image" || file.kind === "audio" || file.kind === "video";
}

function doesDetectedVideoSupportHoverControl() {
  if (typeof window === "undefined" || typeof window.matchMedia !== "function") {
    return true;
  }
  return window.matchMedia("(hover: hover) and (pointer: fine)").matches;
}

function hasDetectedFilePreviewError(file: ChatDetectedFile) {
  return Boolean(chatFilePreviewLoadErrors.value[getDetectedFilePreviewErrorKey(file)]);
}

function setDetectedFilePreviewErrorState(file: ChatDetectedFile, next: boolean) {
  const key = getDetectedFilePreviewErrorKey(file);
  if (next) {
    chatFilePreviewLoadErrors.value = {
      ...chatFilePreviewLoadErrors.value,
      [key]: true
    };
    return;
  }
  if (!chatFilePreviewLoadErrors.value[key]) {
    return;
  }
  const snapshot = { ...chatFilePreviewLoadErrors.value };
  delete snapshot[key];
  chatFilePreviewLoadErrors.value = snapshot;
}

function getDetectedFileBackendPreviewUrl(file: ChatDetectedFile) {
  return chatFilePreviewBackendDataUrls.value[getDetectedFilePreviewErrorKey(file)] ?? null;
}

function isDetectedFileBackendPreviewLoading(file: ChatDetectedFile) {
  return Boolean(chatFilePreviewBackendLoading.value[getDetectedFilePreviewErrorKey(file)]);
}

function getDetectedFileBackendPreviewErrorMessage(file: ChatDetectedFile) {
  return chatFilePreviewBackendErrorMessages.value[getDetectedFilePreviewErrorKey(file)] ?? "";
}

function setDetectedVideoPreviewHover(file: ChatDetectedFile, next: boolean) {
  if (!isVideoDetectedFile(file)) {
    return;
  }
  const key = getDetectedFilePreviewErrorKey(file);
  const shouldShow = doesDetectedVideoSupportHoverControl() ? next : true;
  if (Boolean(chatVideoPreviewHoverStates.value[key]) === shouldShow) {
    return;
  }
  chatVideoPreviewHoverStates.value = {
    ...chatVideoPreviewHoverStates.value,
    [key]: shouldShow
  };
}

function isDetectedVideoPreviewControlsVisible(file: ChatDetectedFile) {
  if (!isVideoDetectedFile(file)) {
    return false;
  }
  if (!doesDetectedVideoSupportHoverControl()) {
    return true;
  }
  return Boolean(chatVideoPreviewHoverStates.value[getDetectedFilePreviewErrorKey(file)]);
}

function ensureDetectedVideoFirstFrame(video: HTMLVideoElement) {
  if (video.dataset.previewFrameReady === "1") {
    return;
  }
  if (!Number.isFinite(video.duration) || video.duration <= 0) {
    return;
  }
  if (video.currentTime > 0.0001) {
    video.dataset.previewFrameReady = "1";
    return;
  }
  const targetTime = Math.min(0.05, Math.max(video.duration - 0.01, 0.001));
  const handleSeeked = () => {
    video.pause();
    video.dataset.previewFrameReady = "1";
  };
  video.addEventListener("seeked", handleSeeked, { once: true });
  try {
    video.currentTime = targetTime;
  } catch {
    video.dataset.previewFrameReady = "1";
  }
}

function handleDetectedVideoLoadedData(event: Event) {
  const target = event.currentTarget;
  if (!(target instanceof HTMLVideoElement)) {
    return;
  }
  ensureDetectedVideoFirstFrame(target);
}

async function requestDetectedFileBackendPreview(file: ChatDetectedFile) {
  const key = getDetectedFilePreviewErrorKey(file);
  if (
    file.kind === "other" ||
    chatFilePreviewBackendDataUrls.value[key] ||
    chatFilePreviewBackendLoading.value[key] ||
    chatFilePreviewBackendErrorMessages.value[key]
  ) {
    return;
  }

  const invoke = getTauriInvoke();
  if (!invoke) {
    chatFilePreviewBackendErrorMessages.value = {
      ...chatFilePreviewBackendErrorMessages.value,
      [key]: "当前环境不支持本地预览权限通道。"
    };
    setDetectedFilePreviewErrorState(file, true);
    return;
  }

  chatFilePreviewBackendLoading.value = {
    ...chatFilePreviewBackendLoading.value,
    [key]: true
  };

  try {
    const payload = (await invoke("read_local_media_file", {
      path: file.normalizedPath
    })) as LocalMediaFilePayload;
    const dataUrl = typeof payload.dataUrl === "string" ? payload.dataUrl.trim() : "";
    if (!dataUrl.startsWith("data:")) {
      throw new Error("预览数据为空。");
    }

    chatFilePreviewBackendDataUrls.value = {
      ...chatFilePreviewBackendDataUrls.value,
      [key]: dataUrl
    };

    if (chatFilePreviewBackendErrorMessages.value[key]) {
      const nextMessages = { ...chatFilePreviewBackendErrorMessages.value };
      delete nextMessages[key];
      chatFilePreviewBackendErrorMessages.value = nextMessages;
    }
    setDetectedFilePreviewErrorState(file, false);
  } catch (error) {
    chatFilePreviewBackendErrorMessages.value = {
      ...chatFilePreviewBackendErrorMessages.value,
      [key]: resolveUnknownErrorMessage(error, "预览加载失败，请确认文件存在并且应用有读取权限。")
    };
    setDetectedFilePreviewErrorState(file, true);
  } finally {
    if (chatFilePreviewBackendLoading.value[key]) {
      const nextLoading = { ...chatFilePreviewBackendLoading.value };
      delete nextLoading[key];
      chatFilePreviewBackendLoading.value = nextLoading;
    }
  }
}

function getDetectedFilePreviewUrl(file: ChatDetectedFile) {
  if (file.kind === "other") {
    return null;
  }

  const backendPreviewUrl = getDetectedFileBackendPreviewUrl(file);
  if (backendPreviewUrl) {
    return backendPreviewUrl;
  }

  const key = getDetectedFilePreviewErrorKey(file);
  const hasBackendError = Boolean(chatFilePreviewBackendErrorMessages.value[key]);
  if (shouldPreferBackendPreview(file) && !hasBackendError) {
    void requestDetectedFileBackendPreview(file);
    return null;
  }

  if (file.previewUrls.length === 0) {
    void requestDetectedFileBackendPreview(file);
    return null;
  }

  const currentIndex = Math.max(0, Math.floor(chatFilePreviewUrlIndexes.value[key] ?? 0));
  if (currentIndex >= file.previewUrls.length) {
    void requestDetectedFileBackendPreview(file);
    return null;
  }
  return file.previewUrls[currentIndex] ?? null;
}

function markDetectedFilePreviewError(file: ChatDetectedFile) {
  const key = getDetectedFilePreviewErrorKey(file);

  if (getDetectedFileBackendPreviewUrl(file)) {
    setDetectedFilePreviewErrorState(file, true);
    return;
  }

  const currentIndex = Math.max(0, Math.floor(chatFilePreviewUrlIndexes.value[key] ?? 0));
  const nextIndex = currentIndex + 1;
  if (nextIndex < file.previewUrls.length) {
    chatFilePreviewUrlIndexes.value = {
      ...chatFilePreviewUrlIndexes.value,
      [key]: nextIndex
    };
    return;
  }
  chatFilePreviewUrlIndexes.value = {
    ...chatFilePreviewUrlIndexes.value,
    [key]: file.previewUrls.length
  };
  void requestDetectedFileBackendPreview(file);
}

function canPreviewDetectedFile(file: ChatDetectedFile) {
  return Boolean(getDetectedFilePreviewUrl(file));
}

function getDetectedFilePreviewHint(file: ChatDetectedFile) {
  if (file.kind === "other") {
    return `暂不支持 .${file.extension} 预览。`;
  }
  if (isDetectedFileBackendPreviewLoading(file)) {
    return "正在尝试通过本地权限通道加载预览...";
  }
  const backendErrorMessage = getDetectedFileBackendPreviewErrorMessage(file);
  if (backendErrorMessage) {
    return backendErrorMessage;
  }
  if (hasDetectedFilePreviewError(file)) {
    return "预览加载失败，请确认文件存在并且应用有读取权限。";
  }
  return "当前文件暂不可预览。";
}

function isImageDetectedFile(file: ChatDetectedFile) {
  return file.kind === "image";
}

function isAudioDetectedFile(file: ChatDetectedFile) {
  return file.kind === "audio";
}

function isVideoDetectedFile(file: ChatDetectedFile) {
  return file.kind === "video";
}

function isHtmlDetectedFile(file: ChatDetectedFile) {
  return file.kind === "html";
}

function buildOpenClawMessageContent(message: AgentChatMessage) {
  const normalizedText = sanitizeMessageTextForDisplay(message.text);
  if (message.role !== "user" || !message.attachments || message.attachments.length === 0) {
    return normalizedText;
  }
  const summary = formatAttachmentSummaryForPrompt(message.attachments);
  if (!summary) {
    return normalizedText;
  }
  const baseText = normalizedText === "(附件)" ? "" : normalizedText;
  return baseText ? `${baseText}\n\n${summary}` : summary;
}

function getMessageDisplayText(message: AgentChatMessage) {
  if (message.role === "user" && message.text.trim() === "(附件)" && message.attachments && message.attachments.length > 0) {
    return "";
  }
  return sanitizeMessageTextForDisplay(message.text);
}

function isRuntimeToolMessage(message: AgentChatMessage) {
  return message.kind === "runtime_tool";
}

function normalizeMessage(raw: unknown): AgentChatMessage | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }

  const candidate = raw as Partial<AgentChatMessage>;
  const role = normalizeRole(candidate.role);
  if (!role || typeof candidate.text !== "string") {
    return null;
  }
  const kind: ChatMessageKind = candidate.kind === "runtime_tool" ? "runtime_tool" : "default";
  const toolName = typeof candidate.toolName === "string" && candidate.toolName.trim() ? candidate.toolName.trim() : undefined;
  const toolStatus = normalizeToolStatus(candidate.toolStatus);
  const toolInput = typeof candidate.toolInput === "string" && candidate.toolInput.trim() ? candidate.toolInput.trim() : undefined;
  const toolOutput =
    typeof candidate.toolOutput === "string" && candidate.toolOutput.trim() ? candidate.toolOutput.trim() : undefined;
  const attachments = normalizeMessageAttachments((candidate as { attachments?: unknown }).attachments);

  return {
    id: typeof candidate.id === "string" && candidate.id.trim() ? candidate.id : createMessageId("msg"),
    role,
    text: sanitizeMessageTextForDisplay(candidate.text),
    status: normalizeStatus(candidate.status),
    createdAt: typeof candidate.createdAt === "number" && Number.isFinite(candidate.createdAt) ? candidate.createdAt : Date.now(),
    attachments,
    kind,
    toolName,
    toolStatus,
    toolInput,
    toolOutput
  };
}

function isLegacyWelcomeMessage(message: AgentChatMessage) {
  if (message.id.startsWith("welcome-")) {
    return true;
  }
  if (message.role !== "assistant") {
    return false;
  }
  const text = message.text.trim();
  if (!text) {
    return false;
  }
  return text === "请选择一个 Agent 开始对话。" || (text.startsWith("已切换到 ") && text.endsWith("，可以直接发送消息并由该 Agent 执行。"));
}

function createWelcomeMessages(_agent: AgentListItem | null): AgentChatMessage[] {
  return [];
}

type ConversationStorageReadOptions = {
  legacyAgentId?: string | null;
};

function loadChatHistory(conversationScopeKey: string, options: ConversationStorageReadOptions = {}) {
  const primaryRaw = safeStorageGet(chatStorageKeyFor(conversationScopeKey));
  const legacyRaw = options.legacyAgentId ? safeStorageGet(legacyChatStorageKeyForAgent(options.legacyAgentId)) : null;
  const raw = primaryRaw && primaryRaw.trim() ? primaryRaw : legacyRaw;
  if (!raw) {
    return [] as AgentChatMessage[];
  }

  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [] as AgentChatMessage[];
    }

    return parsed
      .map((item) => normalizeMessage(item))
      .filter((item): item is AgentChatMessage => item !== null)
      .filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item));
  } catch {
    return [] as AgentChatMessage[];
  }
}

function loadChatArchives(conversationScopeKey: string, options: ConversationStorageReadOptions = {}) {
  const primaryRaw = safeStorageGet(chatArchiveStorageKeyFor(conversationScopeKey));
  const legacyRaw = options.legacyAgentId ? safeStorageGet(legacyChatArchiveStorageKeyForAgent(options.legacyAgentId)) : null;
  const raw = primaryRaw && primaryRaw.trim() ? primaryRaw : legacyRaw;
  if (!raw) {
    return [] as ChatArchiveRecord[];
  }
  try {
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [] as ChatArchiveRecord[];
    }
    return parsed
      .map((entry) => {
        if (!entry || typeof entry !== "object") {
          return null;
        }
        const candidate = entry as Partial<ChatArchiveRecord> & { messages?: unknown[] };
        if (!Array.isArray(candidate.messages)) {
          return null;
        }
        const messages = candidate.messages
          .map((item) => normalizeMessage(item))
          .filter((item): item is AgentChatMessage => item !== null)
          .filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item));
        if (messages.length === 0) {
          return null;
        }
        return {
          id: typeof candidate.id === "string" && candidate.id.trim() ? candidate.id : createMessageId("archive"),
          archivedAt:
            typeof candidate.archivedAt === "number" && Number.isFinite(candidate.archivedAt) ? candidate.archivedAt : Date.now(),
          title: typeof candidate.title === "string" && candidate.title.trim() ? candidate.title : "会话归档",
          messages
        } satisfies ChatArchiveRecord;
      })
      .filter((item): item is ChatArchiveRecord => item !== null)
      .slice(0, 60);
  } catch {
    return [] as ChatArchiveRecord[];
  }
}

function persistChatArchives(conversationScopeKey: string, archives: ChatArchiveRecord[]) {
  safeStorageSet(chatArchiveStorageKeyFor(conversationScopeKey), JSON.stringify(archives.slice(0, 60)));
}

function loadSessionId(conversationScopeKey: string, options: ConversationStorageReadOptions = {}) {
  const key = sessionStorageKeyFor(conversationScopeKey);
  const existing = safeStorageGet(key);
  if (existing && existing.trim()) {
    return existing;
  }

  const legacyExisting = options.legacyAgentId ? safeStorageGet(legacySessionStorageKeyForAgent(options.legacyAgentId)) : null;
  if (legacyExisting && legacyExisting.trim()) {
    safeStorageSet(key, legacyExisting);
    return legacyExisting;
  }

  const next = createSessionId();
  safeStorageSet(key, next);
  return next;
}

function peekSessionId(conversationScopeKey: string, options: ConversationStorageReadOptions = {}) {
  const existing = safeStorageGet(sessionStorageKeyFor(conversationScopeKey));
  if (existing && existing.trim()) {
    return existing.trim();
  }
  const legacyExisting = options.legacyAgentId ? safeStorageGet(legacySessionStorageKeyForAgent(options.legacyAgentId)) : null;
  if (legacyExisting && legacyExisting.trim()) {
    return legacyExisting.trim();
  }
  return "";
}

function persistChatHistory(conversationScopeKey: string) {
  const stableMessages = chatMessages.value.filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item));
  safeStorageSet(chatStorageKeyFor(conversationScopeKey), JSON.stringify(stableMessages));
  safeStorageSet(sessionStorageKeyFor(conversationScopeKey), currentSessionId.value || createSessionId());
}

function getOpenClawMessages(items: AgentChatMessage[]): OpenClawMessage[] {
  return items
    .filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item))
    .filter((item) => !isRuntimeToolMessage(item) && !item.id.startsWith("runtime-tool-") && !item.toolName)
    .filter((item) => item.role === "assistant" || item.role === "user" || item.role === "system")
    .map((item) => ({ role: item.role, content: buildOpenClawMessageContent(item) }))
    .filter((item) => item.content.trim().length > 0);
}

function getAgentInitial(agent: AgentListItem) {
  const name = stripRoleLabel(agent.displayName);
  return name.charAt(0).toUpperCase() || "A";
}

function hashAgentSeed(value: string) {
  let hash = 0;
  for (let index = 0; index < value.length; index += 1) {
    hash = (hash * 31 + value.charCodeAt(index)) >>> 0;
  }
  return hash;
}

function formatLobsterNumberBySeed(seed: string) {
  const normalizedSeed = seed.trim().toLowerCase() || "dragonclaw";
  const mixedHash = hashAgentSeed(`${normalizedSeed}|lobster`);
  const numeric = 100000000 + (mixedHash % 900000000);
  const raw = String(numeric).padStart(9, "0");
  return `${raw.slice(0, 3)} ${raw.slice(3, 6)} ${raw.slice(6, 9)}`;
}

function getAgentAvatarUrl(agent: AgentListItem) {
  const customAvatar = sidebarAgentAvatarOverrides.value[agent.agentId];
  if (typeof customAvatar === "string" && customAvatar.trim()) {
    return customAvatar.trim();
  }
  if (agentAvatarPool.length === 0) {
    return null;
  }
  const seed = `${agent.agentId}|${stripRoleLabel(agent.displayName)}`.trim().toLowerCase();
  const avatarIndex = hashAgentSeed(seed || "agent") % agentAvatarPool.length;
  return agentAvatarPool[avatarIndex] ?? null;
}

function getAgentMeta(agentId: string): AgentChatMeta {
  return (
    agentMetaMap.value[agentId] ?? {
      preview: "暂无会话",
      timeLabel: "--:--",
      unread: 0
    }
  );
}

function setAgentMeta(agentId: string, patch: Partial<AgentChatMeta>) {
  const current = getAgentMeta(agentId);
  agentMetaMap.value = {
    ...agentMetaMap.value,
    [agentId]: {
      ...current,
      ...patch
    }
  };
}

function refreshAgentMetaFromHistory(agentId: string, messages: AgentChatMessage[], fallback: string) {
  const stable = messages.filter(
    (item) => item.status !== "pending" && !isLegacyWelcomeMessage(item) && !isRuntimeToolMessage(item)
  );
  const latest = stable[stable.length - 1];
  if (!latest) {
    setAgentMeta(agentId, {
      preview: fallback || "暂无会话",
      timeLabel: "--:--"
    });
    return;
  }

  const latestPreview =
    latest.text.trim() ||
    (latest.attachments && latest.attachments.length > 0 ? `[附件 ${latest.attachments.length} 个]` : "") ||
    fallback ||
    "暂无会话";
  setAgentMeta(agentId, {
    preview: latestPreview,
    timeLabel: formatTimeLabel(latest.createdAt)
  });
}

function mapSnapshotMember(member: StaffMemberSnapshot): AgentListItem {
  const statusLabel = member.statusLabel || "在线";
  const normalizedAgentId = member.agentId.trim().toLowerCase();
  const displayName =
    normalizedAgentId === "main" ? MAIN_STAFF_DISPLAY_NAME : member.displayName || member.agentId;
  return {
    agentId: member.agentId,
    displayName,
    roleLabel: member.roleLabel || "未标注角色",
    channel: member.channel || "main",
    model: member.model || "llm/petclaw-1.0",
    workspace: member.workspace || "—",
    toolsProfile: member.toolsProfile || "default",
    toolsEnabledCount: typeof member.toolsEnabledCount === "number" ? member.toolsEnabledCount : null,
    statusLabel,
    statusTone: inferStatusTone(statusLabel),
    currentWorkLabel: member.currentWorkLabel || "正在处理什么",
    currentWork: member.currentWork || member.currentWorkLabel || "暂无工作描述",
    recentOutput: member.recentOutput || "",
    scheduledLabel: member.scheduledLabel || "",
    groupKind: inferGroupKind(member.displayName || member.agentId, member.roleLabel || "")
  };
}

function mapFallbackMember() {
  const fallbackMembers = loadStaff();

  return fallbackMembers.map((member) => {
    const statusLabel = member.status === "busy" ? "忙碌" : member.status === "offline" ? "离线" : "在线";
    const normalizedAgentId = member.id.trim().toLowerCase();
    return {
      agentId: member.id,
      displayName: normalizedAgentId === "main" ? MAIN_STAFF_DISPLAY_NAME : member.name,
      roleLabel: member.role,
      channel: "local",
      model: "llm/petclaw-1.0",
      workspace: member.workspace || "control-center",
      toolsProfile: "default",
      toolsEnabledCount: null,
      statusLabel,
      statusTone: inferStatusTone(statusLabel),
      currentWorkLabel: "正在处理什么",
      currentWork: member.focus || "暂无工作描述",
      recentOutput: "",
      scheduledLabel: member.status === "offline" ? "未排班" : "值班中",
      groupKind: inferGroupKind(member.name, member.role)
    } satisfies AgentListItem;
  });
}

function mapChatUserCustomAgent(agent: ChatUserCustomAgent): AgentListItem {
  const kind = normalizeChatUserCustomAgentKind(agent.kind);
  if (kind === "staff") {
    return {
      agentId: agent.agentId,
      displayName: agent.displayName,
      roleLabel: agent.roleLabel?.trim() || "数字员工",
      channel: agent.channel?.trim() || "custom",
      model: "llm/petclaw-1.0",
      workspace: agent.workspace?.trim() || "employee-studio",
      toolsProfile: "default",
      toolsEnabledCount: null,
      statusLabel: "在线",
      statusTone: "online",
      currentWorkLabel: "擅长方向",
      currentWork: agent.currentWork?.trim() || "等待分配任务",
      recentOutput: "",
      scheduledLabel: agent.scheduledLabel?.trim() || "随时可用",
      groupKind: "staff"
    };
  }

  return {
    agentId: agent.agentId,
    displayName: agent.displayName,
    roleLabel: "虾友",
    channel: "friend",
    model: "llm/petclaw-1.0",
    workspace: "personal",
    toolsProfile: "default",
    toolsEnabledCount: null,
    statusLabel: "在线",
    statusTone: "online",
    currentWorkLabel: "最近状态",
    currentWork: "等待开始聊天",
    recentOutput: "",
    scheduledLabel: "随时可聊",
    groupKind: "staff"
  };
}

function resolveChatConversationGroupMembers(group: ChatConversationGroup, memberPool: AgentListItem[]) {
  if (group.memberAgentIds.length === 0) {
    return [] as AgentListItem[];
  }
  const memberMap = new Map(
    memberPool
      .filter((agent) => !isChatConversationGroupAgentId(agent.agentId))
      .map((agent) => [agent.agentId.trim(), agent] as const)
      .filter(([agentId]) => agentId.length > 0)
  );
  return group.memberAgentIds
    .map((memberId) => memberMap.get(memberId))
    .filter((item): item is AgentListItem => Boolean(item));
}

function getChatConversationGroupMembers(group: ChatConversationGroup) {
  return resolveChatConversationGroupMembers(group, agents.value);
}

function formatChatConversationGroupMemberSummary(group: ChatConversationGroup, memberPool: AgentListItem[]) {
  const members = resolveChatConversationGroupMembers(group, memberPool);
  if (members.length === 0) {
    return "暂无成员";
  }
  const names = members.map((member) => stripRoleLabel(member.displayName));
  if (names.length <= 3) {
    return names.join("、");
  }
  return `${names.slice(0, 3).join("、")} 等 ${names.length} 人`;
}

function mapChatConversationGroupAgent(group: ChatConversationGroup, memberPool: AgentListItem[]): AgentListItem {
  const members = resolveChatConversationGroupMembers(group, memberPool);
  const memberCount = members.length;
  const memberSummary = formatChatConversationGroupMemberSummary(group, memberPool);
  const hasOffline = members.some((member) => member.statusTone === "offline");
  const hasBusy = members.some((member) => member.statusTone === "busy");
  const statusTone: AgentStatusTone = hasOffline ? "offline" : hasBusy ? "busy" : "online";
  const statusLabel =
    memberCount === 0 ? "无成员" : statusTone === "offline" ? `${memberCount} 人（部分离线）` : `${memberCount} 人在线`;
  return {
    agentId: getChatConversationGroupAgentId(group.id),
    displayName: group.name,
    roleLabel: `群聊 · ${memberCount} 人`,
    channel: "群聊",
    model: "group-chat",
    workspace: "group-chat",
    toolsProfile: "group-chat",
    toolsEnabledCount: null,
    statusLabel,
    statusTone,
    currentWorkLabel: "群成员",
    currentWork: memberSummary,
    recentOutput: "",
    scheduledLabel: memberCount > 0 ? (group.requireMention ? "仅@触发" : "全员可触发") : "待添加成员",
    groupKind: "group"
  };
}

function createChatUserCustomAgentId(displayName: string, kind: ChatUserCustomAgentKind = "friend") {
  const slug = displayName
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/-{2,}/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 18);
  const suffix = Math.random().toString(36).slice(2, 6);
  const base = slug || Date.now().toString(36);
  const prefix = kind === "staff" ? "staff" : "friend";
  return `${prefix}-${base}-${suffix}`;
}

type CreateChatUserCustomAgentOptions = {
  kind?: ChatUserCustomAgentKind;
  roleLabel?: string;
  channel?: string;
  workspace?: string;
  currentWork?: string;
  scheduledLabel?: string;
  mission?: string;
  tasks?: string[];
  knowledgeScope?: ChatUserCustomAgentKnowledgeScope;
  specificDomain?: string;
};

function createOrGetChatUserCustomAgent(displayName: string, options: CreateChatUserCustomAgentOptions = {}) {
  const normalizedDisplayName = normalizeChatUserGroupName(displayName);
  if (!normalizedDisplayName) {
    return null;
  }
  const kind = normalizeChatUserCustomAgentKind(options.kind);
  const normalizeOptionalField = (value: unknown, maxLength = 200) => (typeof value === "string" ? value.trim().slice(0, maxLength) : "");
  const roleLabel = normalizeOptionalField(options.roleLabel);
  const channel = normalizeOptionalField(options.channel);
  const workspace = normalizeOptionalField(options.workspace);
  const currentWork = normalizeOptionalField(options.currentWork);
  const scheduledLabel = normalizeOptionalField(options.scheduledLabel);
  const mission = normalizeOptionalField(options.mission, 1200);
  const tasks = Array.isArray(options.tasks)
    ? options.tasks
        .map((task) => normalizeOptionalField(task, 80))
        .filter(Boolean)
        .slice(0, CREATE_EMPLOYEE_MAX_TASKS)
    : [];
  const specificDomain = normalizeOptionalField(options.specificDomain, 240);
  const knowledgeScope = normalizeChatUserCustomAgentKnowledgeScope(options.knowledgeScope);

  const existingAgent =
    agents.value.find(
      (agent) => equalsIgnoreCase(stripRoleLabel(agent.displayName), normalizedDisplayName) || equalsIgnoreCase(agent.agentId, normalizedDisplayName)
    ) ?? null;
  if (existingAgent) {
    return existingAgent;
  }

  const existingCustom =
    chatUserCustomAgents.value.find(
      (item) => equalsIgnoreCase(item.displayName, normalizedDisplayName) || equalsIgnoreCase(item.agentId, normalizedDisplayName)
    ) ?? null;
  if (existingCustom) {
    const mergedCustomAgent: ChatUserCustomAgent = {
      ...existingCustom,
      kind,
      roleLabel: roleLabel || undefined,
      channel: channel || undefined,
      workspace: workspace || undefined,
      currentWork: currentWork || undefined,
      scheduledLabel: scheduledLabel || undefined,
      mission: mission || undefined,
      tasks: tasks.length > 0 ? tasks : undefined,
      knowledgeScope,
      specificDomain: specificDomain || undefined
    };
    const changed =
      JSON.stringify({
        kind: existingCustom.kind ?? "friend",
        roleLabel: existingCustom.roleLabel ?? "",
        channel: existingCustom.channel ?? "",
        workspace: existingCustom.workspace ?? "",
        currentWork: existingCustom.currentWork ?? "",
        scheduledLabel: existingCustom.scheduledLabel ?? "",
        mission: existingCustom.mission ?? "",
        tasks: existingCustom.tasks ?? [],
        knowledgeScope: existingCustom.knowledgeScope ?? "",
        specificDomain: existingCustom.specificDomain ?? ""
      }) !==
      JSON.stringify({
        kind: mergedCustomAgent.kind ?? "friend",
        roleLabel: mergedCustomAgent.roleLabel ?? "",
        channel: mergedCustomAgent.channel ?? "",
        workspace: mergedCustomAgent.workspace ?? "",
        currentWork: mergedCustomAgent.currentWork ?? "",
        scheduledLabel: mergedCustomAgent.scheduledLabel ?? "",
        mission: mergedCustomAgent.mission ?? "",
        tasks: mergedCustomAgent.tasks ?? [],
        knowledgeScope: mergedCustomAgent.knowledgeScope ?? "",
        specificDomain: mergedCustomAgent.specificDomain ?? ""
      });
    if (changed) {
      chatUserCustomAgents.value = chatUserCustomAgents.value.map((item) =>
        equalsIgnoreCase(item.agentId, existingCustom.agentId) ? mergedCustomAgent : item
      );
      persistChatUserCustomAgents();
    }
    const existingInPane = agents.value.find((agent) => equalsIgnoreCase(agent.agentId, existingCustom.agentId)) ?? null;
    if (existingInPane) {
      const mappedExisting = mapChatUserCustomAgent(mergedCustomAgent);
      agents.value = agents.value.map((agent) => (equalsIgnoreCase(agent.agentId, mappedExisting.agentId) ? mappedExisting : agent));
      syncChatUserAgentOrder();
      return mappedExisting;
    }
    const mappedExisting = mapChatUserCustomAgent(mergedCustomAgent);
    agents.value = [...agents.value, mappedExisting];
    syncChatUserAgentOrder();
    return mappedExisting;
  }

  const knownIds = new Set(
    [...agents.value, ...chatUserCustomAgents.value.map((item) => mapChatUserCustomAgent(item))]
      .map((agent) => agent.agentId.trim().toLowerCase())
      .filter(Boolean)
  );
  let nextAgentId = createChatUserCustomAgentId(normalizedDisplayName, kind);
  while (knownIds.has(nextAgentId.toLowerCase())) {
    nextAgentId = createChatUserCustomAgentId(normalizedDisplayName, kind);
  }

  const nextCustomAgent: ChatUserCustomAgent = {
    agentId: nextAgentId,
    displayName: normalizedDisplayName,
    createdAt: Date.now(),
    kind,
    roleLabel: roleLabel || undefined,
    channel: channel || undefined,
    workspace: workspace || undefined,
    currentWork: currentWork || undefined,
    scheduledLabel: scheduledLabel || undefined,
    mission: mission || undefined,
    tasks: tasks.length > 0 ? tasks : undefined,
    knowledgeScope,
    specificDomain: specificDomain || undefined
  };
  const sortedCustomAgents = [...chatUserCustomAgents.value, nextCustomAgent].sort((left, right) => left.createdAt - right.createdAt);
  chatUserCustomAgents.value = sortedCustomAgents.slice(-200);
  persistChatUserCustomAgents();

  const mapped = mapChatUserCustomAgent(nextCustomAgent);
  agents.value = [...agents.value, mapped];
  syncChatUserAgentOrder();
  return mapped;
}

async function loadAgents() {
  const invoke = getTauriInvoke();
  let loadedAgents: AgentListItem[] = [];

  if (invoke) {
    try {
      const result = (await invoke("load_staff_snapshot")) as StaffSnapshotResponse;
      missionStatement.value = result.missionStatement || missionStatement.value;
      staffSourceDetail.value = result.detail || "Agent 列表已更新。";
      loadedAgents = Array.isArray(result.members) ? result.members.map(mapSnapshotMember) : [];
    } catch (error) {
      staffSourceDetail.value = error instanceof Error ? error.message : "读取 Agent 列表失败，已切换本地数据。";
    }
  }

  if (loadedAgents.length === 0) {
    loadedAgents = mapFallbackMember();
    if (!invoke) {
      staffSourceDetail.value = "当前环境不支持 runtime staff snapshot，已使用本地员工数据。";
    }
  }

  if (chatUserCustomAgents.value.length > 0) {
    const knownAgentIds = new Set(loadedAgents.map((agent) => agent.agentId.trim().toLowerCase()).filter(Boolean));
    for (const customAgent of chatUserCustomAgents.value) {
      const mappedAgent = mapChatUserCustomAgent(customAgent);
      const normalizedAgentId = mappedAgent.agentId.trim().toLowerCase();
      if (!normalizedAgentId || knownAgentIds.has(normalizedAgentId)) {
        continue;
      }
      knownAgentIds.add(normalizedAgentId);
      loadedAgents.push(mappedAgent);
    }
  }

  syncChatConversationGroupsWithMembers(loadedAgents);
  if (chatConversationGroups.value.length > 0) {
    const mappedConversationGroups = chatConversationGroups.value.map((group) => mapChatConversationGroupAgent(group, loadedAgents));
    loadedAgents = [...loadedAgents, ...mappedConversationGroups];
  }

  loadedAgents.sort((left, right) => {
    const toneWeight = { online: 0, busy: 1, offline: 2 } as const;
    const toneDiff = toneWeight[left.statusTone] - toneWeight[right.statusTone];
    if (toneDiff !== 0) {
      return toneDiff;
    }
    return stripRoleLabel(left.displayName).localeCompare(stripRoleLabel(right.displayName), "zh-CN");
  });

  agents.value = loadedAgents;
  syncChatUserAgentOrder();

  for (const agent of loadedAgents) {
    const defaultConversationScopeKey = resolveConversationScopeKey(agent.agentId, null);
    if (!defaultConversationScopeKey) {
      continue;
    }
    const readOptions: ConversationStorageReadOptions = isChatConversationGroupAgentId(agent.agentId)
      ? {}
      : { legacyAgentId: agent.agentId };
    const history = loadChatHistory(defaultConversationScopeKey, readOptions);
    if (history.length > 0) {
      agentHistories.value[defaultConversationScopeKey] = history;
    }
    refreshAgentMetaFromHistory(agent.agentId, history, agent.currentWork);
  }

  if (!selectedAgentId.value || !loadedAgents.some((agent) => agent.agentId === selectedAgentId.value)) {
    switchAgent(loadedAgents[0]?.agentId ?? null);
  }
}

async function scrollMessagesToBottom() {
  await nextTick();
  if (messageScroller.value) {
    messageScroller.value.scrollTop = messageScroller.value.scrollHeight;
  }
}

type SwitchAgentOptions = {
  channelSession?: ChannelPaneChatItem | null;
  force?: boolean;
};

type RefreshUtilityModalOptions = {
  keepContentVisible?: boolean;
};

function switchAgent(agentId: string | null, options: SwitchAgentOptions = {}) {
  if (!agentId) {
    return;
  }

  const previousAgentId = selectedAgentId.value;
  const previousChannelSession = activeChannelChatSession.value;
  const nextChannelSession = options.channelSession ?? null;
  const sameAgent = previousAgentId ? equalsIgnoreCase(previousAgentId, agentId) : false;
  const sameChannelSession = (previousChannelSession?.id ?? "") === (nextChannelSession?.id ?? "");
  if (!options.force && sameAgent && sameChannelSession) {
    return;
  }

  const previousConversationScopeKey = resolveConversationScopeKey(previousAgentId, previousChannelSession);
  if (previousConversationScopeKey) {
    agentHistories.value[previousConversationScopeKey] = [...chatMessages.value];
    persistChatHistory(previousConversationScopeKey);
  }

  const nextConversationScopeKey = resolveConversationScopeKey(agentId, nextChannelSession);
  if (!nextConversationScopeKey) {
    return;
  }

  selectedAgentId.value = agentId;
  activeChannelChatSession.value = nextChannelSession ? { ...nextChannelSession } : null;
  const loadOptions: ConversationStorageReadOptions = nextChannelSession ? {} : { legacyAgentId: agentId };
  currentSessionId.value = loadSessionId(nextConversationScopeKey, loadOptions);
  runtimeToolSyncContext.value = null;
  expandedRuntimeToolMessages.value = {};
  clearRuntimeToolSyncRetryTimer();

  const cachedHistory = agentHistories.value[nextConversationScopeKey];
  const loadedHistory =
    cachedHistory && cachedHistory.length > 0 ? cachedHistory : loadChatHistory(nextConversationScopeKey, loadOptions);

  const active = agents.value.find((item) => item.agentId === agentId) ?? null;
  chatMessages.value = loadedHistory.length > 0 ? [...loadedHistory] : createWelcomeMessages(active);
  chatAttachments.value = [];
  chatComposerError.value = "";
  resetChatMentionState();

  setAgentMeta(agentId, { unread: 0 });
  if (utilityModalType.value) {
    void refreshUtilityModalData(utilityModalType.value);
  } else if (isHistoryPanelActive.value) {
    void refreshUtilityModalData("history", { keepContentVisible: true });
  } else if (isLogsPanelActive.value || isSidebarLogsOpen.value) {
    void refreshUtilityModalData("logs");
  }
  void scrollMessagesToBottom();
}

function handleNewChat() {
  const activeId = selectedAgentId.value;
  const conversationScopeKey = resolveConversationScopeKey(activeId, activeChannelChatSession.value);
  if (!activeId || !conversationScopeKey) {
    return;
  }

  const active = agents.value.find((item) => item.agentId === activeId) ?? null;
  chatMessages.value = createWelcomeMessages(active);
  chatAttachments.value = [];
  chatComposerError.value = "";
  resetChatMentionState();
  runtimeToolSyncContext.value = null;
  expandedRuntimeToolMessages.value = {};
  clearRuntimeToolSyncRetryTimer();
  const parsedScope = parseConversationScope(conversationScopeKey);
  currentSessionId.value =
    parsedScope?.kind === "agent" ? buildScopedRuntimeSessionKey(conversationScopeKey, activeId) : createSessionId();
  persistChatHistory(conversationScopeKey);
  agentHistories.value[conversationScopeKey] = [...chatMessages.value];
  refreshAgentMetaFromHistory(activeId, chatMessages.value, active?.currentWork || "暂无会话");
  void scrollMessagesToBottom();
}

