  createChatUserGroupDraft.value = "";
  createChatUserGroupError.value = "";
  createChatUserGroupSearch.value = "";
  createChatUserGroupSelectedAgentIds.value = [];
  createChatUserGroupOwnerAgentId.value = "";
}

function openConversationGroupRenameModal() {
  const group = activeConversationGroup.value;
  if (!group) {
    return;
  }
  conversationGroupRenameDraft.value = group.name;
  conversationGroupRenameError.value = "";
  isConversationGroupRenameModalOpen.value = true;
}

function closeConversationGroupRenameModal() {
  isConversationGroupRenameModalOpen.value = false;
  conversationGroupRenameDraft.value = "";
  conversationGroupRenameError.value = "";
}

function handleConversationGroupRenameSubmit() {
  const group = activeConversationGroup.value;
  if (!group) {
    closeConversationGroupRenameModal();
    return;
  }
  const normalizedName = normalizeChatUserGroupName(conversationGroupRenameDraft.value);
  if (!normalizedName) {
    conversationGroupRenameError.value = "请输入群聊名称（最多 24 个字符）。";
    return;
  }
  const duplicated = findChatConversationGroupByName(normalizedName);
  if (duplicated && duplicated.id !== group.id) {
    conversationGroupRenameError.value = "团队名称已存在，请换一个名称。";
    return;
  }
  if (normalizedName === group.name) {
    closeConversationGroupRenameModal();
    return;
  }
  chatConversationGroups.value = chatConversationGroups.value.map((item) =>
    item.id === group.id
      ? {
          ...item,
          name: normalizedName
        }
      : item
  );
  persistChatConversationGroups();
  remapChatConversationGroupAgents();
  closeConversationGroupRenameModal();
}

function updateConversationGroupById(groupId: string, updater: (group: ChatConversationGroup) => ChatConversationGroup) {
  const normalizedGroupId = groupId.trim();
  if (!normalizedGroupId) {
    return;
  }
  let changed = false;
  const nextGroups = chatConversationGroups.value.map((group) => {
    if (group.id !== normalizedGroupId) {
      return group;
    }
    const nextGroup = updater(group);
    if (nextGroup !== group) {
      changed = true;
    }
    return nextGroup;
  });
  if (!changed) {
    return;
  }
  chatConversationGroups.value = nextGroups;
  persistChatConversationGroups();
  remapChatConversationGroupAgents();
}

function handleActiveConversationGroupPolicyChange(rawPolicy: string) {
  const group = activeConversationGroup.value;
  if (!group) {
    return;
  }
  const nextPolicy = normalizeChatConversationGroupPolicy(rawPolicy);
  if (group.groupPolicy === nextPolicy) {
    return;
  }
  updateConversationGroupById(group.id, (target) => ({
    ...target,
    groupPolicy: nextPolicy
  }));
}

function handleActiveConversationGroupRequireMentionChange(checked: boolean) {
  const group = activeConversationGroup.value;
  if (!group || group.requireMention === checked) {
    return;
  }
  updateConversationGroupById(group.id, (target) => ({
    ...target,
    requireMention: checked
  }));
}

function handleActiveConversationGroupAllowFromChange(rawValue: string) {
  const group = activeConversationGroup.value;
  if (!group) {
    return;
  }
  const nextAllowFrom = parseChatConversationGroupAllowFromInput(rawValue);
  const current = formatChatConversationGroupAllowFromInput(group.allowFrom);
  const next = formatChatConversationGroupAllowFromInput(nextAllowFrom);
  if (current === next) {
    return;
  }
  updateConversationGroupById(group.id, (target) => ({
    ...target,
    allowFrom: nextAllowFrom
  }));
}

function handleActiveConversationGroupActivationCommandChange(rawValue: string) {
  const group = activeConversationGroup.value;
  if (!group) {
    return;
  }
  const nextCommand = normalizeChatConversationGroupActivationCommand(rawValue);
  if (group.activationCommand === nextCommand) {
    return;
  }
  updateConversationGroupById(group.id, (target) => ({
    ...target,
    activationCommand: nextCommand
  }));
}

function handleActiveConversationGroupHistoryLimitChange(rawValue: string) {
  const group = activeConversationGroup.value;
  if (!group) {
    return;
  }
  const numericValue = Number(rawValue);
  const nextHistoryLimit = normalizeChatConversationGroupHistoryLimit(
    Number.isFinite(numericValue) ? numericValue : group.historyLimit
  );
  if (group.historyLimit === nextHistoryLimit) {
    return;
  }
  updateConversationGroupById(group.id, (target) => ({
    ...target,
    historyLimit: nextHistoryLimit
  }));
}

function handleCreateChatUserGroupSubmit() {
  const normalizedName = normalizeChatUserGroupName(createChatUserGroupDraft.value);
  if (!normalizedName) {
    createChatUserGroupError.value = "请输入团队名称（最多 24 个字符）。";
    void nextTick(() => {
      createChatUserGroupInputRef.value?.focus();
    });
    return;
  }

  const selectableIds = new Set(createChatUserGroupSelectableAgents.value.map((agent) => agent.agentId));
  const selectedAgentIds = Array.from(
    new Set(createChatUserGroupSelectedAgentIds.value.map((agentId) => agentId.trim()).filter((agentId) => selectableIds.has(agentId)))
  );
  if (selectedAgentIds.length === 0) {
    createChatUserGroupError.value = "请至少选择 1 位成员。";
    return;
  }
  if (selectedAgentIds.length > CREATE_CHAT_USER_GROUP_MAX_MEMBERS) {
    createChatUserGroupError.value = `最多选择 ${CREATE_CHAT_USER_GROUP_MAX_MEMBERS} 位成员。`;
    return;
  }
  const normalizedOwnerAgentId = createChatUserGroupOwnerAgentId.value.trim();
  const ownerAgentId = selectedAgentIds.includes(normalizedOwnerAgentId) ? normalizedOwnerAgentId : (selectedAgentIds[0] ?? "");
  createChatUserGroupOwnerAgentId.value = ownerAgentId;

  const group = createChatConversationGroup(normalizedName, selectedAgentIds, ownerAgentId);
  if (!group) {
    createChatUserGroupError.value = "团队名称已存在，请换一个名称。";
    return;
  }

  remapChatConversationGroupAgents();
  const targetGroupAgentId = getChatConversationGroupAgentId(group.id);
  const mappedGroupAgent = agents.value.find((item) => item.agentId === targetGroupAgentId) ?? null;

  if (activeSection.value !== "chat") {
    activeSection.value = "chat";
  }

  closeCreateChatUserGroupModal();
  activeAgentPaneTab.value = "group";
  switchAgent(mappedGroupAgent?.agentId ?? targetGroupAgentId, { force: true });
}

function isCreateChatUserGroupMemberSelected(agentId: string) {
  return createChatUserGroupSelectedAgentIds.value.includes(agentId);
}

function isCreateChatUserGroupOwner(agentId: string) {
  return createChatUserGroupOwnerAgentId.value === agentId;
}

function handleCreateChatUserGroupOwnerSelect(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId || !createChatUserGroupSelectedAgentIds.value.includes(normalizedAgentId)) {
    return;
  }
  createChatUserGroupOwnerAgentId.value = normalizedAgentId;
  createChatUserGroupError.value = "";
}

function handleCreateChatUserGroupMemberToggle(agentId: string, selected: boolean) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId) {
    return;
  }
  createChatUserGroupError.value = "";
  const nextSelectedIds = new Set(createChatUserGroupSelectedAgentIds.value);
  if (selected) {
    if (!nextSelectedIds.has(normalizedAgentId) && nextSelectedIds.size >= CREATE_CHAT_USER_GROUP_MAX_MEMBERS) {
      createChatUserGroupError.value = `最多选择 ${CREATE_CHAT_USER_GROUP_MAX_MEMBERS} 位成员。`;
      return;
    }
    nextSelectedIds.add(normalizedAgentId);
  } else {
    nextSelectedIds.delete(normalizedAgentId);
  }
  createChatUserGroupSelectedAgentIds.value = Array.from(nextSelectedIds);
  syncCreateChatUserGroupOwnerWithSelection();
}

function handleCreateChatUserGroupSelectAllMembers() {
  const allIds = createChatUserGroupFilteredAgents.value.map((agent) => agent.agentId);
  createChatUserGroupSelectedAgentIds.value = allIds.slice(0, CREATE_CHAT_USER_GROUP_MAX_MEMBERS);
  syncCreateChatUserGroupOwnerWithSelection();
  if (allIds.length > CREATE_CHAT_USER_GROUP_MAX_MEMBERS) {
    createChatUserGroupError.value = `已选择前 ${CREATE_CHAT_USER_GROUP_MAX_MEMBERS} 位成员。`;
  } else {
    createChatUserGroupError.value = "";
  }
}

function handleCreateChatUserGroupClearMembers() {
  createChatUserGroupSelectedAgentIds.value = [];
  syncCreateChatUserGroupOwnerWithSelection();
  createChatUserGroupError.value = "";
}

function isActiveConversationGroupOwner(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId) {
    return false;
  }
  return activeConversationGroup.value?.ownerAgentId === normalizedAgentId;
}

function handleDeleteChatUserGroup(groupId: string) {
  const targetGroup = chatUserGroups.value.find((group) => group.id === groupId) ?? null;
  if (!targetGroup || targetGroup.id === CHAT_USER_PINNED_GROUP_ID) {
    return;
  }
  if (typeof window !== "undefined" && typeof window.confirm === "function") {
    const confirmed = window.confirm(`确定删除分组「${targetGroup.name}」吗？组内成员会回到“全部聊天”。`);
    if (!confirmed) {
      return;
    }
  }
  deleteChatUserGroup(targetGroup.id);
}

function handleAssignAgentToChatUserGroup(agentId: string) {
  if (typeof window === "undefined") {
    return;
  }
  const currentGroupName = getChatUserGroupName(agentId);
  const input = window.prompt("输入分组名称（留空可移出分组）", currentGroupName === "未分组" ? "" : currentGroupName);
  if (input === null) {
    return;
  }
  const normalizedName = normalizeChatUserGroupName(input);
  if (!normalizedName) {
    clearAgentChatUserGroup(agentId);
    return;
  }
  const group = createChatUserGroup(normalizedName);
  if (!group) {
    return;
  }
  setAgentChatUserGroup(agentId, group.id);
}

function getChatUserCustomAgentById(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId) {
    return null;
  }
  return chatUserCustomAgents.value.find((item) => equalsIgnoreCase(item.agentId, normalizedAgentId)) ?? null;
}

function isChatUserCustomAgent(agentId: string) {
  return Boolean(getChatUserCustomAgentById(agentId));
}

function removeChatUserCustomAgent(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId || isProtectedStaffAgentId(normalizedAgentId)) {
    return false;
  }

  const nextCustomAgents = chatUserCustomAgents.value.filter((item) => !equalsIgnoreCase(item.agentId, normalizedAgentId));
  if (nextCustomAgents.length === chatUserCustomAgents.value.length) {
    return false;
  }
  chatUserCustomAgents.value = nextCustomAgents;
  persistChatUserCustomAgents();

  const nextMembershipEntries = Object.entries(chatUserGroupMembership.value).filter(
    ([memberAgentId]) => !equalsIgnoreCase(memberAgentId, normalizedAgentId)
  );
  if (nextMembershipEntries.length !== Object.keys(chatUserGroupMembership.value).length) {
    chatUserGroupMembership.value = Object.fromEntries(nextMembershipEntries) as Record<string, string>;
    persistChatUserGroupMembership();
  }

  const nextOrder = chatUserAgentOrder.value.filter((existingAgentId) => !equalsIgnoreCase(existingAgentId, normalizedAgentId));
  if (nextOrder.length !== chatUserAgentOrder.value.length) {
    chatUserAgentOrder.value = nextOrder;
    persistChatUserAgentOrder();
  }

  return true;
}

function removeFallbackStaffAgent(agentId: string) {
  const normalizedAgentId = agentId.trim();
  if (!normalizedAgentId || isProtectedStaffAgentId(normalizedAgentId)) {
    return false;
  }
  const fallbackMembers = loadStaff();
  const matched = fallbackMembers.find((item) => equalsIgnoreCase(item.id, normalizedAgentId)) ?? null;
  if (!matched) {
    return false;
  }
  deleteStaff(fallbackMembers, matched.id);
  return true;
}

function closeChatAgentDeleteConfirmModal() {
  if (isChatAgentDeleteConfirming.value) {
    return;
  }
  forceCloseChatAgentDeleteConfirmModal();
}

function forceCloseChatAgentDeleteConfirmModal() {
  isChatAgentDeleteConfirmModalOpen.value = false;
  chatAgentDeleteConfirmTarget.value = null;
}

function removeChatConversationGroupByAgentId(agentId: string) {
  const groupId = getChatConversationGroupIdFromAgentId(agentId);
  if (!groupId) {
    return null;
  }
  const targetGroup = chatConversationGroups.value.find((group) => group.id === groupId) ?? null;
  if (!targetGroup) {
    return null;
  }
  chatConversationGroups.value = chatConversationGroups.value.filter((group) => group.id !== groupId);
  persistChatConversationGroups();
  return targetGroup;
}

function clearChatAgentDeleteNoticeTimer() {
  if (typeof window !== "undefined" && chatAgentDeleteNoticeTimer > 0) {
    window.clearTimeout(chatAgentDeleteNoticeTimer);
    chatAgentDeleteNoticeTimer = 0;
  }
}

function showChatAgentDeleteNotice(message: string) {
  const normalized = message.trim();
  if (!normalized) {
    return;
  }
  chatAgentDeleteNotice.value = normalized;
  clearChatAgentDeleteNoticeTimer();
  if (typeof window !== "undefined") {
    chatAgentDeleteNoticeTimer = window.setTimeout(() => {
      chatAgentDeleteNotice.value = "";
      chatAgentDeleteNoticeTimer = 0;
    }, CHAT_AGENT_DELETE_NOTICE_DURATION_MS);
  }
}

function handleChatAgentContextMenuDelete() {
  const target = resolveChatAgentContextMenuTarget();
  closeChatAgentContextMenu();
  if (!target) {
    staffSourceDetail.value = "未找到可删除的目标，请重试。";
    chatComposerError.value = "未找到可删除的目标，请重试。";
    return;
  }
  if (isProtectedStaffAgentId(target.agentId)) {
    const message = "主控员工 main 受保护，不能删除。";
    staffSourceDetail.value = message;
    chatComposerError.value = message;
    showChatAgentDeleteNotice(message);
    return;
  }
  chatAgentDeleteConfirmTarget.value = target;
  isChatAgentDeleteConfirmModalOpen.value = true;
}

async function handleChatAgentDeleteConfirmSubmit() {
  if (isChatAgentDeleteConfirming.value) {
    return;
  }
  const target = chatAgentDeleteConfirmTarget.value;
  if (!target) {
    forceCloseChatAgentDeleteConfirmModal();
    return;
  }
  const targetCustomAgent = getChatUserCustomAgentById(target.agentId);
  const targetCustomKind = normalizeChatUserCustomAgentKind(targetCustomAgent?.kind);

  const displayName = stripRoleLabel(target.displayName) || target.agentId;
  chatComposerError.value = "";
  isChatAgentDeleteConfirming.value = true;
  let successMessage = "";

  try {
    if (target.groupKind === "group") {
      const removedGroup = removeChatConversationGroupByAgentId(target.agentId);
      if (!removedGroup) {
        throw new Error("未找到可删除的群聊。");
      }
      successMessage = `已删除群聊「${displayName}」。`;
    } else {
      if (isChatUserCustomAgent(target.agentId)) {
        const removed = removeChatUserCustomAgent(target.agentId);
        if (!removed) {
          throw new Error("未找到可删除的自定义员工。");
        }
        successMessage = targetCustomKind === "staff" ? `已删除自定义员工「${displayName}」。` : `已删除虾友「${displayName}」。`;
      } else {
        const invoke = getTauriInvoke();
        if (invoke) {
          try {
            const detail = (await invoke("remove_role_workflow_agent", {
              agentId: target.agentId,
              deleteFiles: true
            })) as string;
            successMessage = detail?.trim() || `已删除员工「${displayName}」。`;
          } catch (runtimeError) {
            const removedFallback = removeFallbackStaffAgent(target.agentId);
            if (!removedFallback) {
              throw runtimeError;
            }
            successMessage = `已删除本地员工「${displayName}」。`;
          }
        } else {
          const removedFallback = removeFallbackStaffAgent(target.agentId);
          if (!removedFallback) {
            throw new Error("当前环境不支持删除数字员工。");
          }
          successMessage = `已删除本地员工「${displayName}」。`;
        }
      }
    }
    if (!successMessage && target.groupKind === "group") {
      successMessage = `已删除群聊「${displayName}」。`;
    } else if (!successMessage) {
      successMessage = `已删除员工「${displayName}」。`;
    }
    staffSourceDetail.value = successMessage;
    showChatAgentDeleteNotice(successMessage);
    await loadAgents();
    chatComposerError.value = "";
    forceCloseChatAgentDeleteConfirmModal();
  } catch (error) {
    const message = error instanceof Error ? error.message : target.groupKind === "group" ? "删除群聊失败。" : "删除数字员工失败。";
    staffSourceDetail.value = message;
    chatComposerError.value = message;
  } finally {
    isChatAgentDeleteConfirming.value = false;
  }
}

function handleChatUserAgentDragStart(sectionId: string, agentId: string, event: DragEvent) {
  const normalizedSectionId = sectionId.trim();
  const normalizedAgentId = agentId.trim();
  if (!normalizedSectionId || !normalizedAgentId) {
    return;
  }
  chatUserDragSectionId.value = normalizedSectionId;
  chatUserDragAgentId.value = normalizedAgentId;
  chatUserDragOverAgentId.value = normalizedAgentId;

  if (event.dataTransfer) {
    event.dataTransfer.effectAllowed = "move";
    event.dataTransfer.setData("text/plain", normalizedAgentId);
  }
}

function handleChatUserAgentDragOver(sectionId: string, agentId: string, event: DragEvent) {
  if (!chatUserDragAgentId.value || chatUserDragSectionId.value !== sectionId) {
    return;
  }
  chatUserDragOverAgentId.value = agentId;
  if (event.dataTransfer) {
    event.dataTransfer.dropEffect = "move";
  }
}

function handleChatUserAgentDrop(sectionId: string, targetAgentId: string) {
  const dragSourceAgentId = chatUserDragAgentId.value;
  if (!dragSourceAgentId || !targetAgentId || chatUserDragSectionId.value !== sectionId) {
    handleChatUserAgentDragEnd();
    return;
  }
  if (dragSourceAgentId !== targetAgentId) {
    moveChatUserAgentOrderBeforeTarget(dragSourceAgentId, targetAgentId);
  }
  handleChatUserAgentDragEnd();
}

function handleChatUserAgentDragEnd() {
  chatUserDragSectionId.value = null;
  chatUserDragAgentId.value = null;
  chatUserDragOverAgentId.value = null;
}

function triggerChatAttachmentPicker() {
  if (!activeAgent.value || isSending.value || isVoiceRecording.value || isVoiceRecordingProcessing.value) {
    return;
  }
  chatAttachmentInputRef.value?.click();
}

function clearVoiceRecordingTimer() {
  if (voiceRecordingTimer === null) {
    return;
  }
  window.clearInterval(voiceRecordingTimer);
  voiceRecordingTimer = null;
}

function stopVoiceRecorderStreamTracks() {
  if (!voiceRecorderStream) {
    return;
  }
  for (const track of voiceRecorderStream.getTracks()) {
    try {
      track.stop();
    } catch {
      // Ignore track stop failures.
    }
  }
  voiceRecorderStream = null;
}

function resetVoiceRecorderRuntimeState() {
  clearVoiceRecordingTimer();
  stopVoiceRecorderStreamTracks();
  voiceRecorder = null;
  voiceRecorderMimeType = "";
  voiceRecorderChunks = [];
  voiceRecordingStartedAtMs = null;
  voiceRecordingElapsedSeconds.value = 0;
  isVoiceRecording.value = false;
}

function tickVoiceRecordingElapsedSeconds() {
  if (voiceRecordingStartedAtMs === null) {
    voiceRecordingElapsedSeconds.value = 0;
    return;
  }
  const elapsedSeconds = Math.max(0, Math.floor((Date.now() - voiceRecordingStartedAtMs) / 1000));
  voiceRecordingElapsedSeconds.value = elapsedSeconds;
  if (elapsedSeconds >= CHAT_VOICE_MAX_DURATION_SECONDS) {
    void finishVoiceRecording();
  }
}

function startVoiceRecordingTimer() {
  clearVoiceRecordingTimer();
  tickVoiceRecordingElapsedSeconds();
  voiceRecordingTimer = window.setInterval(() => {
    tickVoiceRecordingElapsedSeconds();
  }, 300);
}

function resolveVoiceRecordingMimeType() {
  if (typeof MediaRecorder === "undefined" || typeof MediaRecorder.isTypeSupported !== "function") {
    return "";
  }
  const candidates = [
    "audio/webm;codecs=opus",
    "audio/ogg;codecs=opus",
    "audio/mp4",
    "audio/webm",
    "audio/ogg",
    "audio/wav"
  ];
  return candidates.find((item) => MediaRecorder.isTypeSupported(item)) ?? "";
}

function resolveVoiceRecordingFileExtensionFromMimeType(mimeTypeRaw: string) {
  const normalized = mimeTypeRaw.trim().toLowerCase().split(";")[0] ?? "";
  if (normalized === "audio/mp4" || normalized === "audio/x-m4a" || normalized === "audio/m4a") {
    return "m4a";
  }
  if (normalized === "audio/ogg") {
    return "ogg";
  }
  if (normalized === "audio/wav" || normalized === "audio/x-wav") {
    return "wav";
  }
  if (normalized === "audio/mpeg") {
    return "mp3";
  }
  if (normalized === "audio/aac") {
    return "aac";
  }
  if (normalized === "audio/flac") {
    return "flac";
  }
  return "webm";
}

function readBlobAsDataUrl(blob: Blob) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = typeof reader.result === "string" ? reader.result : "";
      if (!result.startsWith("data:")) {
        reject(new Error("语音编码失败。"));
        return;
      }
      resolve(result);
    };
    reader.onerror = () => {
      reject(new Error("语音读取失败。"));
    };
    reader.readAsDataURL(blob);
  });
}

async function persistRecordedVoiceBlobToLocalPath(fileName: string, blob: Blob) {
  const invoke = getTauriInvoke();
  if (!invoke || blob.size <= 0) {
    return "";
  }
  const dataUrl = await readBlobAsDataUrl(blob);
  const workspace = sanitizeChatAttachmentWorkspaceHint(activeAgent.value?.workspace ?? "");
  const savedPath = (await invoke("persist_chat_attachment_data_url", {
    fileName,
    dataUrl,
    workspace: workspace || null
  })) as string;
  return normalizeChatComposerLocalPathCandidate(savedPath);
}

function resolveVoiceRecordingErrorMessage(error: unknown) {
  if (typeof DOMException !== "undefined" && error instanceof DOMException) {
    if (error.name === "NotAllowedError" || error.name === "PermissionDeniedError") {
      return "未获得麦克风权限，请在系统设置里允许后重试。";
    }
    if (error.name === "NotFoundError" || error.name === "DevicesNotFoundError") {
      return "未检测到可用麦克风设备。";
    }
    if (error.name === "NotReadableError" || error.name === "TrackStartError") {
      return "麦克风当前不可用，可能被其他应用占用。";
    }
    if (error.name === "NotSupportedError") {
      return "当前环境暂不支持语音录制。";
    }
  }
  return resolveUnknownErrorMessage(error, "无法开始录音，请检查麦克风权限后重试。");
}

async function finalizeVoiceRecordingAndSubmit(chunks: Blob[], mimeTypeHint: string) {
  if (chunks.length === 0) {
    isVoiceRecordingProcessing.value = false;
    chatComposerError.value = "未捕获到语音内容，请重试。";
    return;
  }

  isVoiceRecordingProcessing.value = true;
  try {
    const normalizedMimeType = (mimeTypeHint.trim() || chunks[0]?.type?.trim() || "audio/webm").trim();
    const audioBlob = new Blob(chunks, { type: normalizedMimeType });
    if (audioBlob.size <= 0) {
      chatComposerError.value = "语音内容为空，请重试。";
      return;
    }
    if (audioBlob.size > CHAT_COMPOSER_MAX_ATTACHMENT_SIZE) {
      chatComposerError.value = "语音文件超过 10 MB 限制，请缩短录音时长后重试。";
      return;
    }

    const extension = resolveVoiceRecordingFileExtensionFromMimeType(normalizedMimeType);
    const fileName = `${CHAT_VOICE_FILE_PREFIX}-${Date.now()}.${extension}`;
    const recordedFile = new File([audioBlob], fileName, {
      type: normalizedMimeType,
      lastModified: Date.now()
    });

    let localPath = "";
    try {
      localPath = await persistRecordedVoiceBlobToLocalPath(fileName, audioBlob);
    } catch {
      localPath = "";
    }

    const previousAttachmentCount = chatAttachments.value.length;
    appendChatComposerFiles([recordedFile], {
      localPaths: [localPath]
    });
    const appended = chatAttachments.value.length > previousAttachmentCount;
    if (!appended) {
      if (!chatComposerError.value) {
        chatComposerError.value = "语音文件添加失败，请重试。";
      }
      return;
    }

    if (!activeAgent.value) {
      chatComposerError.value = "语音已添加到附件，请先选择聊天对象后发送。";
      return;
    }
    if (isSending.value || isSubmittingChat.value) {
      chatComposerError.value = "语音已添加到附件，请在当前消息发送完成后再发送。";
      return;
    }

    chatComposerError.value = "";
    await submitChat();
  } catch (error) {
    chatComposerError.value = resolveUnknownErrorMessage(error, "语音处理失败，请重试。");
  } finally {
    isVoiceRecordingProcessing.value = false;
  }
}

async function startVoiceRecording() {
  if (isVoiceRecording.value || isVoiceRecordingProcessing.value) {
    return;
  }
  if (chatAttachments.value.length >= CHAT_COMPOSER_MAX_ATTACHMENT_COUNT) {
    chatComposerError.value = `最多添加 ${CHAT_COMPOSER_MAX_ATTACHMENT_COUNT} 个附件。`;
    return;
  }
  if (typeof window === "undefined" || typeof navigator === "undefined") {
    chatComposerError.value = "当前环境不支持语音录制。";
    return;
  }
  if (!navigator.mediaDevices?.getUserMedia || typeof MediaRecorder === "undefined") {
    chatComposerError.value = "当前环境暂不支持语音录制。";
    return;
  }

  chatComposerError.value = "";
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }
    });
    const preferredMimeType = resolveVoiceRecordingMimeType();
    const recorder = preferredMimeType ? new MediaRecorder(stream, { mimeType: preferredMimeType }) : new MediaRecorder(stream);

    voiceRecorder = recorder;
    voiceRecorderStream = stream;
    voiceRecorderMimeType = recorder.mimeType || preferredMimeType || "audio/webm";
    voiceRecorderChunks = [];

    recorder.ondataavailable = (event: BlobEvent) => {
      if (event.data && event.data.size > 0) {
        voiceRecorderChunks.push(event.data);
      }
    };
    recorder.onerror = (event: Event) => {
      const runtimeError = (event as Event & { error?: unknown }).error;
      chatComposerError.value = resolveVoiceRecordingErrorMessage(runtimeError ?? null);
      isVoiceRecordingProcessing.value = false;
      resetVoiceRecorderRuntimeState();
    };
    recorder.onstop = () => {
      const chunks = [...voiceRecorderChunks];
      const mimeType = voiceRecorderMimeType;
      resetVoiceRecorderRuntimeState();
      void finalizeVoiceRecordingAndSubmit(chunks, mimeType);
    };

    recorder.start(CHAT_VOICE_RECORDER_TIMESLICE_MS);
    voiceRecordingStartedAtMs = Date.now();
    voiceRecordingElapsedSeconds.value = 0;
    isVoiceRecording.value = true;
    isVoiceRecordingProcessing.value = false;
    startVoiceRecordingTimer();
  } catch (error) {
    isVoiceRecordingProcessing.value = false;
    resetVoiceRecorderRuntimeState();
    chatComposerError.value = resolveVoiceRecordingErrorMessage(error);
  }
}

async function finishVoiceRecording() {
  const recorder = voiceRecorder;
  if (!recorder || recorder.state === "inactive") {
    return;
  }
  clearVoiceRecordingTimer();
  isVoiceRecordingProcessing.value = true;
  try {
    recorder.stop();
  } catch (error) {
    isVoiceRecordingProcessing.value = false;
    resetVoiceRecorderRuntimeState();
    chatComposerError.value = resolveUnknownErrorMessage(error, "结束录音失败，请重试。");
  }
}

function cancelVoiceRecording() {
  const recorder = voiceRecorder;
  if (recorder) {
    recorder.onstop = null;
    recorder.ondataavailable = null;
    recorder.onerror = null;
    if (recorder.state !== "inactive") {
      try {
        recorder.stop();
      } catch {
        // Ignore stop failures during cleanup.
      }
    }
  }
  isVoiceRecordingProcessing.value = false;
  resetVoiceRecorderRuntimeState();
}

function handleVoiceSendClick() {
  if (!activeAgent.value || isSending.value || isSubmittingChat.value || isVoiceRecordingProcessing.value) {
    return;
  }
  if (isVoiceRecording.value) {
    void finishVoiceRecording();
    return;
  }
  void startVoiceRecording();
}

function removeChatAttachment(attachmentId: string) {
  chatAttachments.value = chatAttachments.value.filter((attachment) => attachment.id !== attachmentId);
  pruneUnusedChatAttachmentLocalPreviews();
}

function appendChatComposerFiles(files: FileList | File[], options: ChatComposerAppendFilesOptions = {}) {
  const source = Array.from(files);
  if (source.length === 0) {
    return;
  }
  const remainCount = CHAT_COMPOSER_MAX_ATTACHMENT_COUNT - chatAttachments.value.length;
  if (remainCount <= 0) {
    chatComposerError.value = `最多添加 ${CHAT_COMPOSER_MAX_ATTACHMENT_COUNT} 个附件。`;
    return;
  }

  const accepted: ChatComposerAttachment[] = [];
  const candidates = source.slice(0, remainCount);
  let rejectedMessage = "";
  for (const [index, file] of candidates.entries()) {
    const attachmentName = resolveChatComposerFileDisplayName(file, index);
    if (!isSupportedChatComposerFile(file)) {
      if (!rejectedMessage) {
        rejectedMessage = formatUnsupportedChatComposerFileMessage(file, index);
      }
      continue;
    }
    if (file.size > CHAT_COMPOSER_MAX_ATTACHMENT_SIZE) {
      if (!rejectedMessage) {
        rejectedMessage = `文件「${attachmentName}」超过 10 MB 限制。`;
      }
      continue;
    }
    const attachmentId = createChatAttachmentId();
    const nextAttachment: ChatComposerAttachment = {
      id: attachmentId,
      name: attachmentName,
      size: file.size,
      type: file.type || ""
    };
    const localPathCandidate = options.localPaths?.[index] ?? "";
    const localPath =
      resolveChatComposerFileLocalPath(file) || normalizeChatComposerLocalPathCandidate(localPathCandidate);
    if (localPath) {
      nextAttachment.localPath = localPath;
    }
    registerChatAttachmentLocalPreview(attachmentId, nextAttachment, file);
    accepted.push({
      ...nextAttachment
    });
  }
  if (source.length > remainCount && !rejectedMessage) {
    rejectedMessage = `最多添加 ${CHAT_COMPOSER_MAX_ATTACHMENT_COUNT} 个附件。`;
  }
  if (accepted.length === 0) {
    if (rejectedMessage) {
      chatComposerError.value = rejectedMessage;
    }
    return;
  }
  chatAttachments.value = [...chatAttachments.value, ...accepted];
  chatComposerError.value = rejectedMessage;
}

function handleChatAttachmentInputChange(event: Event) {
  const input = event.target as HTMLInputElement | null;
  const files = input?.files;
  if (files && files.length > 0) {
    appendChatComposerFiles(files);
  }
  if (input) {
    input.value = "";
  }
}

async function handleChatComposerPaste(event: ClipboardEvent) {
  if (!activeAgent.value || isSending.value) {
    return;
  }
  const files = collectFilesFromDataTransfer(event.clipboardData);
  if (files.length === 0) {
    return;
  }
  event.preventDefault();
  const localPaths = await resolveClipboardAttachmentLocalPaths(files);
  appendChatComposerFiles(files, {
    localPaths
  });
}

function handleChatComposerDragEnter(event: DragEvent) {
  if (!activeAgent.value || isSending.value || !hasDataTransferFiles(event.dataTransfer)) {
    return;
  }
  chatComposerDragDepth.value += 1;
  isChatComposerDragOver.value = true;
}

function handleChatComposerDragOver(event: DragEvent) {
  if (!activeAgent.value || isSending.value || !hasDataTransferFiles(event.dataTransfer)) {
    resetChatComposerDragState();
    return;
  }
  if (event.dataTransfer) {
    event.dataTransfer.dropEffect = "copy";
  }
  isChatComposerDragOver.value = true;
}

function handleChatComposerDragLeave(event: DragEvent) {
  if (!hasDataTransferFiles(event.dataTransfer)) {
    return;
  }
  chatComposerDragDepth.value = Math.max(0, chatComposerDragDepth.value - 1);
  if (chatComposerDragDepth.value === 0) {
    isChatComposerDragOver.value = false;
  }
}

function handleChatComposerDrop(event: DragEvent) {
  if (!activeAgent.value || isSending.value) {
    resetChatComposerDragState();
    return;
  }
  const files = collectFilesFromDataTransfer(event.dataTransfer);
  if (files.length > 0) {
    appendChatComposerFiles(files);
  }
  resetChatComposerDragState();
}

function resizeChatComposerInput() {
  const textarea = chatComposerInputRef.value;
  if (!textarea) {
    return;
  }

  const computedStyle = window.getComputedStyle(textarea);
  const lineHeight = Number.parseFloat(computedStyle.lineHeight) || Number.parseFloat(computedStyle.fontSize) * 1.5 || 22;
  const paddingTop = Number.parseFloat(computedStyle.paddingTop) || 0;
  const paddingBottom = Number.parseFloat(computedStyle.paddingBottom) || 0;
  const borderTop = Number.parseFloat(computedStyle.borderTopWidth) || 0;
  const borderBottom = Number.parseFloat(computedStyle.borderBottomWidth) || 0;
  const minHeight = lineHeight * CHAT_COMPOSER_MIN_ROWS + paddingTop + paddingBottom + borderTop + borderBottom;
  const maxHeight = lineHeight * CHAT_COMPOSER_MAX_ROWS + paddingTop + paddingBottom + borderTop + borderBottom;

  textarea.style.height = "auto";
  const nextHeight = Math.min(maxHeight, Math.max(minHeight, textarea.scrollHeight));
  textarea.style.height = `${nextHeight}px`;
  textarea.style.overflowY = textarea.scrollHeight > maxHeight + 1 ? "auto" : "hidden";
}

function resetChatMentionState() {
  chatMentionStartIndex.value = null;
  chatMentionQuery.value = "";
  chatMentionActiveIndex.value = 0;
}

function syncChatMentionFromComposer() {
  const textarea = chatComposerInputRef.value;
  if (!textarea || !activeAgentIsConversationGroup.value) {
    resetChatMentionState();
    return;
  }
  const selectionStart = textarea.selectionStart ?? chatInput.value.length;
  const selectionEnd = textarea.selectionEnd ?? selectionStart;
  if (selectionStart !== selectionEnd) {
    resetChatMentionState();
    return;
  }
  const context = parseChatMentionContext(chatInput.value, selectionStart);
  if (!context) {
    resetChatMentionState();
    return;
  }
  const changed = chatMentionStartIndex.value !== context.startIndex || chatMentionQuery.value !== context.keyword;
  chatMentionStartIndex.value = context.startIndex;
  chatMentionQuery.value = context.keyword;
  if (changed) {
    chatMentionActiveIndex.value = 0;
  }
}

function moveChatMentionActiveIndex(offset: number) {
  const total = chatMentionCandidates.value.length;
  if (total <= 0) {
    return;
  }
  chatMentionActiveIndex.value = (chatMentionActiveIndex.value + offset + total) % total;
}

function applyChatMentionCandidate(candidate: ChatMentionCandidate) {
  const textarea = chatComposerInputRef.value;
  if (!textarea || chatMentionStartIndex.value === null) {
    return;
  }
  const cursor = textarea.selectionStart ?? chatInput.value.length;
  const context = parseChatMentionContext(chatInput.value, cursor);
  if (!context) {
    resetChatMentionState();
    return;
  }
  const before = chatInput.value.slice(0, context.startIndex);
  const after = chatInput.value.slice(cursor);
  const mentionText = `@${candidate.mentionValue}`;
  const needsTrailingSpace = after.length === 0 || !/^[\s,，。!！?？:：;；、)）\]】}>》]/.test(after);
  const spacer = needsTrailingSpace ? " " : "";
  const nextValue = `${before}${mentionText}${spacer}${after}`;
  const nextCursor = (before + mentionText + spacer).length;
  chatInput.value = nextValue;
  resetChatMentionState();
  void nextTick(() => {
    textarea.focus();
    textarea.setSelectionRange(nextCursor, nextCursor);
    resizeChatComposerInput();
  });
}

function handleChatComposerInput() {
  resizeChatComposerInput();
  syncChatMentionFromComposer();
}

function handleChatComposerCursorActivity() {
  syncChatMentionFromComposer();
}

function handleChatComposerBlur() {
  window.setTimeout(() => {
    resetChatMentionState();
  }, 0);
}

function handleChatComposerKeydown(event: KeyboardEvent) {
  if (isChatMentionDropdownVisible.value) {
    if (event.key === "ArrowDown") {
      event.preventDefault();
      moveChatMentionActiveIndex(1);
      return;
    }
    if (event.key === "ArrowUp") {
      event.preventDefault();
      moveChatMentionActiveIndex(-1);
      return;
    }
    if ((event.key === "Enter" || event.key === "Tab") && !event.shiftKey && !event.isComposing) {
      const candidate = chatMentionCandidates.value[chatMentionActiveIndex.value] ?? chatMentionCandidates.value[0];
      if (candidate) {
        event.preventDefault();
        applyChatMentionCandidate(candidate);
        return;
      }
    }
    if (event.key === "Escape") {
      event.preventDefault();
      resetChatMentionState();
      return;
    }
  }

  if (event.key !== "Enter" || event.shiftKey || event.isComposing) {
    return;
  }

  event.preventDefault();
  void submitChat();
}

function parseGroupSpeakerPrefix(text: string) {
  const match = text.trim().match(/^【([^】]+)】\s*/);
  if (!match) {
    return null;
  }
  const speaker = match[1]?.trim() ?? "";
  if (!speaker) {
    return null;
  }
  return {
    speaker,
    content: text.replace(/^【[^】]+】\s*/, "").trim()
  };
}

function buildGroupConversationTranscript(messages: AgentChatMessage[], historyLimit = CHAT_CONVERSATION_GROUP_DEFAULT_HISTORY_LIMIT) {
  const normalizedHistoryLimit = Math.max(
    CHAT_CONVERSATION_GROUP_MIN_HISTORY_LIMIT,
    Math.min(CHAT_CONVERSATION_GROUP_MAX_HISTORY_LIMIT, Math.floor(historyLimit))
  );
  const stable = messages
    .filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item) && !isRuntimeToolMessage(item))
    .filter((item) => item.role === "assistant" || item.role === "user")
    .slice(-normalizedHistoryLimit);
  if (stable.length === 0) {
    return "";
  }
  return stable
    .map((message) => {
      if (message.role === "user") {
        const content = buildOpenClawMessageContent(message).trim();
        return `用户：${content || "(空消息)"}`;
      }
      const parsed = parseGroupSpeakerPrefix(message.text);
      const speaker = parsed?.speaker || "群成员";
      const content = (parsed?.content || message.text).trim();
      return `${speaker}：${content || "(空消息)"}`;
    })
    .join("\n");
}

function buildGroupMemberPromptMessages(
  group: ChatConversationGroup,
  member: AgentListItem,
  messages: AgentChatMessage[],
  options: { wasMentioned: boolean; sourceKey: string; sessionKey: string }
): OpenClawMessage[] {
  const memberName = stripRoleLabel(member.displayName);
  const memberNames = getChatConversationGroupMembers(group)
    .map((item) => stripRoleLabel(item.displayName))
    .filter(Boolean);
  const transcript = buildGroupConversationTranscript(messages, group.historyLimit);
  const memberScopeText = memberNames.length > 0 ? memberNames.join("、") : "暂无";
  const context = {
    chatType: "group",
    groupName: group.name,
    groupId: group.id,
    groupMembers: memberNames,
    groupPolicy: group.groupPolicy,
    requireMention: group.requireMention,
    wasMentioned: options.wasMentioned,
    source: options.sourceKey,
    activationCommand: group.activationCommand,
    sessionKey: options.sessionKey
  };
  return [
    {
      role: "system",
      content:
        `你是群聊「${group.name}」中的成员「${memberName}」。` +
        `群成员有：${memberScopeText}。` +
        "请只代表你自己发言，不要代替其他成员回复，语气自然简洁。\n\n" +
        `群上下文(JSON)：${JSON.stringify(context)}`
    },
    {
      role: "user",
      content:
        `以下是群聊最近消息（按时间顺序）：\n${transcript || "(暂无历史消息)"}\n\n` +
        `请以「${memberName}」身份，回复最后一条来自用户的消息。`
    }
  ];
}

async function submitChat() {
  const text = chatInput.value.trim();
  const pendingAttachments = [...chatAttachments.value];
  const activeAgent = agents.value.find((item) => item.agentId === selectedAgentId.value) ?? null;
  const conversationScopeKey = resolveConversationScopeKey(activeAgent?.agentId ?? null, activeChannelChatSession.value);
  const activeConversationGroup = findChatConversationGroupByAgentId(activeAgent?.agentId ?? null);

  if (
    (!text && pendingAttachments.length === 0) ||
    isSending.value ||
    isSubmittingChat.value ||
    !activeAgent ||
    !conversationScopeKey
  ) {
    return;
  }

  isSubmittingChat.value = true;
  try {
    const userContent = buildChannelMessageMirrorContent(text, pendingAttachments);
    const startedAt = Date.now();
    if (isRecentDuplicateUserSubmit(text, pendingAttachments, startedAt)) {
      return;
    }
  if (activeConversationGroup) {
    const groupMembers = getChatConversationGroupMembers(activeConversationGroup);
    if (groupMembers.length === 0) {
      chatComposerError.value = "该团队暂无可用成员，请先重新创建团队。";
      return;
    }
    const groupSourceKey = resolveGroupMessageSourceKey(activeChannelChatSession.value);
    if (!isConversationGroupSourceAllowed(activeConversationGroup, groupSourceKey)) {
      chatComposerError.value = `当前群策略拒绝来源「${groupSourceKey}」，请在群设置 allowFrom 中放行。`;
      return;
    }
    const mentionedMembers = resolveMentionedGroupMembers(text, groupMembers);
    const activationTriggered = isConversationGroupActivationCommand(text, activeConversationGroup);
    const replyMembers =
      mentionedMembers.length > 0
        ? mentionedMembers
        : activeConversationGroup.requireMention
          ? activationTriggered
            ? groupMembers
            : []
          : groupMembers;

    chatMessages.value.push({
      id: createMessageId("user"),
      role: "user",
      text: text || "(附件)",
      status: "done",
      createdAt: startedAt,
      attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined
    });
    void dispatchChannelMessageMirror(conversationScopeKey, userContent, activeChannelChatSession.value);

    if (replyMembers.length === 0) {
      const noticeAt = Date.now();
      const activationCommand = normalizeChatConversationGroupActivationCommand(activeConversationGroup.activationCommand);
      chatMessages.value.push({
        id: createMessageId("assistant"),
        role: "assistant",
        text: `群组当前为「仅@触发」。请先 @目标成员，或输入 ${activationCommand} 触发全员响应。`,
        status: "done",
        createdAt: noticeAt
      });
      chatInput.value = "";
      chatAttachments.value = [];
      chatComposerError.value = "";
      resetChatMentionState();
      void nextTick(() => {
        resizeChatComposerInput();
      });
      setAgentMeta(activeAgent.agentId, {
        preview: "已发送（等待 @ 或激活命令）",
        timeLabel: formatTimeLabel(noticeAt),
        unread: 0
      });
      persistChatHistory(conversationScopeKey);
      agentHistories.value[conversationScopeKey] = [...chatMessages.value];
      void scrollMessagesToBottom();
      return;
    }

    const pendingRows = replyMembers.map((member) => {
      const pendingId = createMessageId("assistant");
      chatMessages.value.push({
        id: pendingId,
        role: "assistant",
        text: `${stripRoleLabel(member.displayName)} 正在思考中...`,
        status: "pending",
        createdAt: Date.now()
      });
      return {
        member,
        pendingId
      };
    });

    runtimeToolSyncContext.value = null;
    clearRuntimeToolSyncRetryTimer();

    chatInput.value = "";
    chatAttachments.value = [];
    chatComposerError.value = "";
    resetChatMentionState();
    void nextTick(() => {
      resizeChatComposerInput();
    });

    const previewText =
      text ||
      (pendingAttachments.length > 0
        ? `[附件 ${pendingAttachments.length} 个]`
        : "已发送消息");
    setAgentMeta(activeAgent.agentId, {
      preview: `你：${previewText}`,
      timeLabel: formatTimeLabel(startedAt),
      unread: 0
    });

    isSending.value = true;
    void scrollMessagesToBottom();

    let latestGroupPreview = "群聊已回复";
    let hasSuccess = false;
    try {
      for (const row of pendingRows) {
        const wasMentioned = mentionedMembers.some((member) => member.agentId === row.member.agentId);
        const sessionKey = buildGroupMemberSessionKey(activeConversationGroup, row.member.agentId, groupSourceKey);
        const promptMessages = buildGroupMemberPromptMessages(activeConversationGroup, row.member, chatMessages.value, {
          wasMentioned: wasMentioned || activationTriggered,
          sourceKey: groupSourceKey,
          sessionKey
        });
        try {
          const response = await sendOpenClawChat(promptMessages, {
            agentId: row.member.agentId,
            sessionKey
          });
          const doneAt = Date.now();
          const pendingMessage = chatMessages.value.find((item) => item.id === row.pendingId);
          const prefixedText = `【${stripRoleLabel(row.member.displayName)}】${response.text}`;
          if (pendingMessage) {
            pendingMessage.text = prefixedText;
            pendingMessage.status = "done";
            pendingMessage.createdAt = doneAt;
          }
          latestGroupPreview = prefixedText.trim() || latestGroupPreview;
          hasSuccess = true;
          setAgentMeta(row.member.agentId, {
            preview: response.text.trim() || "已在群聊回复",
            timeLabel: formatTimeLabel(doneAt),
            unread: 0
          });
        } catch (error) {
          const failedAt = Date.now();
          const pendingMessage = chatMessages.value.find((item) => item.id === row.pendingId);
          const errorText = error instanceof Error ? error.message : "群成员回复失败。";
          if (pendingMessage) {
            pendingMessage.text = `【${stripRoleLabel(row.member.displayName)}】${errorText}`;
            pendingMessage.status = "error";
            pendingMessage.createdAt = failedAt;
          }
          appendLocalRuntimeErrorLog({
            agentId: row.member.agentId,
            agentName: stripRoleLabel(row.member.displayName),
            requestText: userContent,
            errorText,
            sessionKey,
            startedAt
          });
        }
      }
      const finishedAt = Date.now();
      setAgentMeta(activeAgent.agentId, {
        preview: hasSuccess ? latestGroupPreview : "群聊消息发送失败",
        timeLabel: formatTimeLabel(finishedAt),
        unread: 0
      });
    } finally {
      isSending.value = false;
      persistChatHistory(conversationScopeKey);
      agentHistories.value[conversationScopeKey] = [...chatMessages.value];
      void scrollMessagesToBottom();
    }
    return;
  }

  const history = getOpenClawMessages(chatMessages.value);
  const pendingId = createMessageId("assistant");

  chatMessages.value.push({
    id: createMessageId("user"),
    role: "user",
    text: text || "(附件)",
    status: "done",
    createdAt: startedAt,
    attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined
  });
  void dispatchChannelMessageMirror(conversationScopeKey, userContent, activeChannelChatSession.value);

  chatMessages.value.push({
    id: pendingId,
    role: "assistant",
    text: `${stripRoleLabel(activeAgent.displayName)} 正在思考中...`,
    status: "pending",
    createdAt: Date.now()
  });
  runtimeToolSyncContext.value = {
    pendingMessageId: pendingId,
    startedAtMs: startedAt,
    runtimeAgentId: activeAgent.agentId,
    expiresAtMs: Date.now() + runtimeToolSyncWindowMs
  };
  clearRuntimeToolSyncRetryTimer();
  const initialSyncContext = runtimeToolSyncContext.value;
  if (initialSyncContext) {
    void syncRuntimeToolMessagesNow(initialSyncContext);
    scheduleRuntimeToolSyncRetry();
  }

  chatInput.value = "";
  chatAttachments.value = [];
  chatComposerError.value = "";
  resetChatMentionState();
  void nextTick(() => {
    resizeChatComposerInput();
  });
  const previewText =
    text ||
    (pendingAttachments.length > 0
      ? `[附件 ${pendingAttachments.length} 个]`
      : "已发送消息");
  setAgentMeta(activeAgent.agentId, {
    preview: `你：${previewText}`,
    timeLabel: formatTimeLabel(startedAt),
    unread: 0
  });

  isSending.value = true;
  void scrollMessagesToBottom();
  const runtimeSessionKey = resolveRuntimeSessionKeyForConversation(conversationScopeKey, activeAgent.agentId);

  try {
    const response = await sendOpenClawChat(
      [...history, { role: "user", content: userContent }],
      runtimeSessionKey
        ? { agentId: activeAgent.agentId, sessionKey: runtimeSessionKey }
        : { agentId: activeAgent.agentId }
    );
    const doneAt = Date.now();

    const pendingMessage = chatMessages.value.find((item) => item.id === pendingId);
    if (pendingMessage) {
      pendingMessage.text = response.text;
      pendingMessage.status = "done";
      pendingMessage.createdAt = doneAt;
    }

    setAgentMeta(activeAgent.agentId, {
      preview: response.text.trim() || "已回复",
      timeLabel: formatTimeLabel(doneAt),
      unread: 0
    });
  } catch (error) {
    const failedAt = Date.now();
    const pendingMessage = chatMessages.value.find((item) => item.id === pendingId);
    const errorText = error instanceof Error ? error.message : "Agent 回复失败。";
    if (pendingMessage) {
      pendingMessage.text = errorText;
      pendingMessage.status = "error";
      pendingMessage.createdAt = failedAt;
    }
    appendLocalRuntimeErrorLog({
      agentId: activeAgent.agentId,
      agentName: stripRoleLabel(activeAgent.displayName),
      requestText: userContent,
      errorText,
      sessionKey: runtimeSessionKey,
      startedAt
    });

    setAgentMeta(activeAgent.agentId, {
      preview: "消息发送失败",
      timeLabel: formatTimeLabel(failedAt),
      unread: 0
    });
  } finally {
    const syncContext = runtimeToolSyncContext.value;
    if (syncContext) {
      syncContext.expiresAtMs = Date.now() + runtimeToolSyncPostResponseWindowMs;
      await syncRuntimeToolMessagesNow(syncContext);
      const latest = runtimeToolSyncContext.value;
      if (latest && !isRuntimeToolSyncExpired(latest)) {
        scheduleRuntimeToolSyncRetry();
      } else {
        runtimeToolSyncContext.value = null;
        clearRuntimeToolSyncRetryTimer();
      }
    }
    isSending.value = false;
    persistChatHistory(conversationScopeKey);
    agentHistories.value[conversationScopeKey] = [...chatMessages.value];
    void scrollMessagesToBottom();
  }
  } finally {
    isSubmittingChat.value = false;
  }
}

async function handleWindowClose() {
  const tauriWindow = getTauriWindow();
  if (tauriWindow?.close) {
    try {
      await tauriWindow.close();
      return;
    } catch {
      // Continue fallback flow.
    }
  }

  const invoke = getTauriInvoke();
  if (invoke) {
    try {
      await invoke("quit_app");
      return;
    } catch {
      // Continue fallback flow.
    }
  }

  if (typeof window !== "undefined") {
    window.close();
  }
}

async function handleWindowMinimize() {
  const tauriWindow = getTauriWindow();
  if (!tauriWindow?.minimize) {
    return;
  }
  try {
    await tauriWindow.minimize();
  } catch {
    // Ignore runtime minimize errors.
  }
}

async function handleWindowExpand() {
  const tauriWindow = getTauriWindow();
  if (!tauriWindow) {
    return;
  }

  try {
    if (tauriWindow.toggleFullscreen) {
      await tauriWindow.toggleFullscreen();
      return;
    }

    if (tauriWindow.isFullscreen && tauriWindow.setFullscreen) {
      const isFullscreen = await tauriWindow.isFullscreen();
      await tauriWindow.setFullscreen(!isFullscreen);
      return;
    }

    if (tauriWindow.toggleMaximize) {
      await tauriWindow.toggleMaximize();
      return;
    }

    if (tauriWindow.isMaximized && tauriWindow.unmaximize && tauriWindow.maximize) {
      const isMaximized = await tauriWindow.isMaximized();
      if (isMaximized) {
        await tauriWindow.unmaximize();
      } else {
        await tauriWindow.maximize();
      }
      return;
    }

    if (tauriWindow.maximize) {
      await tauriWindow.maximize();
    }
  } catch {
    // Ignore runtime maximize errors.
  }
}

async function handleWindowMaximizeToggle() {
  const tauriWindow = getTauriWindow();
  if (tauriWindow) {
    try {
      if (tauriWindow.toggleMaximize) {
        await tauriWindow.toggleMaximize();
        return true;
      }

      if (tauriWindow.isMaximized && tauriWindow.unmaximize && tauriWindow.maximize) {
        const isMaximized = await tauriWindow.isMaximized();
        if (isMaximized) {
          await tauriWindow.unmaximize();
        } else {
          await tauriWindow.maximize();
        }
        return true;
      }

      if (tauriWindow.maximize) {
        await tauriWindow.maximize();
        return true;
      }
    } catch {
      // Keep fallback path.
    }
  }

  const invoke = getTauriInvoke();
  if (!invoke) {
    return false;
  }
  try {
    await invoke("toggle_main_window_maximize");
    return true;
  } catch {
    // Ignore runtime maximize errors.
  }
  return false;
}

async function handleWindowDragStart() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return;
  }
  try {
    await invoke("start_main_window_drag");
  } catch {
    // Ignore runtime drag errors.
  }
}

function isInteractiveDragTarget(target: EventTarget | null) {
  if (!(target instanceof Element)) {
    return false;
  }
  return Boolean(
    target.closest(
      "button, input, textarea, select, a, label, [role='button'], [data-no-window-drag], [contenteditable='true']"
    )
  );
}

const SIDEBAR_DRAG_START_DISTANCE_PX = 4;
let pendingSidebarRegionMoveListener: ((event: MouseEvent) => void) | null = null;
let pendingSidebarRegionUpListener: ((event: MouseEvent) => void) | null = null;

function clearPendingSidebarRegionDragListeners() {
  if (typeof window === "undefined") {
    pendingSidebarRegionMoveListener = null;
    pendingSidebarRegionUpListener = null;
    return;
  }
  if (pendingSidebarRegionMoveListener) {
    window.removeEventListener("mousemove", pendingSidebarRegionMoveListener);
    pendingSidebarRegionMoveListener = null;
  }
  if (pendingSidebarRegionUpListener) {
    window.removeEventListener("mouseup", pendingSidebarRegionUpListener);
    pendingSidebarRegionUpListener = null;
  }
}

function handleRegionMouseDown(event: MouseEvent) {
  if (event.button !== 0) {
    return;
  }
  if (isInteractiveDragTarget(event.target)) {
    clearPendingSidebarRegionDragListeners();
    return;
  }

  event.preventDefault();
  clearPendingSidebarRegionDragListeners();

  if (typeof window === "undefined") {
    return;
  }

  const startX = event.clientX;
  const startY = event.clientY;
  let dragStarted = false;

  pendingSidebarRegionMoveListener = (moveEvent: MouseEvent) => {
    if (dragStarted) {
      return;
    }
    const dx = Math.abs(moveEvent.clientX - startX);
    const dy = Math.abs(moveEvent.clientY - startY);
    if (dx < SIDEBAR_DRAG_START_DISTANCE_PX && dy < SIDEBAR_DRAG_START_DISTANCE_PX) {
      return;
    }
    dragStarted = true;
    clearPendingSidebarRegionDragListeners();
    void handleWindowDragStart();
  };

  pendingSidebarRegionUpListener = () => {
    clearPendingSidebarRegionDragListeners();
  };

  window.addEventListener("mousemove", pendingSidebarRegionMoveListener);
  window.addEventListener("mouseup", pendingSidebarRegionUpListener, { once: true });
}

function handleSidebarDoubleClick(event: MouseEvent) {
  if (isInteractiveDragTarget(event.target)) {
    return;
