function equalsIgnoreCase(left: string | null | undefined, right: string | null | undefined) {
  return (left ?? "").trim().toLowerCase() === (right ?? "").trim().toLowerCase();
}

function resolveUnknownErrorMessage(error: unknown, fallback: string) {
  if (error instanceof Error) {
    const message = error.message.trim();
    return message || fallback;
  }
  if (typeof error === "string") {
    const message = error.trim();
    return message || fallback;
  }
  return fallback;
}

function isProtectedStaffAgentId(agentId: string | null | undefined) {
  return PROTECTED_STAFF_AGENT_IDS.has((agentId ?? "").trim().toLowerCase());
}

function resolveAgentChannelDisplayLabel(
  agent: Pick<AgentListItem, "agentId" | "channel"> | null | undefined,
  fallback = ""
) {
  if (!agent) {
    return fallback;
  }
  const normalizedAgentId = (agent.agentId ?? "").trim().toLowerCase();
  const rawChannel = (agent.channel ?? "").trim();
  if (!rawChannel) {
    return normalizedAgentId === "main" ? "main" : "默认会话";
  }
  if (normalizedAgentId !== "main" && rawChannel.toLowerCase() === "main") {
    return "默认会话";
  }
  return rawChannel;
}

function shouldShowAgentChannelTag(agent: Pick<AgentListItem, "agentId" | "channel" | "groupKind"> | null | undefined) {
  if (!agent || agent.groupKind === "group") {
    return false;
  }
  const channelLabel = resolveAgentChannelDisplayLabel(agent, "").trim().toLowerCase();
  return Boolean(channelLabel && channelLabel !== "默认会话" && channelLabel !== "main" && channelLabel !== "群聊");
}

function normalizeChannelPaneType(value: string | null | undefined) {
  const normalized = (value ?? "").trim().toLowerCase();
  if (!normalized) {
    return "";
  }
  return chatChannelAliasMap.get(normalized) ?? normalized;
}

function resolveChannelConfigCatalog(channelId: string) {
  const normalized = normalizeChannelPaneType(channelId);
  if (!normalized) {
    return null;
  }
  return chatChannelCatalogMap.get(normalized) ?? null;
}

function resolveChannelConfigBackendType(channel: ChannelPaneCatalogItem | null) {
  if (!channel) {
    return "";
  }
  return (channel.backendChannelType ?? channel.id).trim().toLowerCase();
}

function normalizeProviderIdentifier(value: string | null | undefined) {
  return (value ?? "")
    .trim()
    .toLowerCase()
    .replace(/^\/+/, "")
    .replace(/\/+$/, "");
}

function parseAgentModelReference(value: string | null | undefined) {
  const rawModel = (value ?? "").trim().replace(/^\/+/, "");
  if (!rawModel) {
    return { rawModel: "", providerId: "", modelId: "" };
  }
  const separatorIndex = rawModel.indexOf("/");
  if (separatorIndex <= 0 || separatorIndex >= rawModel.length - 1) {
    return { rawModel, providerId: "", modelId: rawModel };
  }
  return {
    rawModel,
    providerId: rawModel.slice(0, separatorIndex),
    modelId: rawModel.slice(separatorIndex + 1)
  };
}

function normalizeModelReference(value: string | null | undefined) {
  const parsed = parseAgentModelReference(value);
  const providerId = normalizeProviderIdentifier(parsed.providerId);
  const modelId = parsed.modelId.trim().toLowerCase();
  if (providerId && modelId) {
    return `${providerId}/${modelId}`;
  }
  if (modelId) {
    return modelId;
  }
  return parsed.rawModel.trim().toLowerCase();
}

function buildProviderModelReference(providerId: string | null | undefined, modelId: string | null | undefined) {
  const normalizedProviderId = normalizeProviderIdentifier(providerId);
  const normalizedModelId = (modelId ?? "").trim();
  if (normalizedProviderId && normalizedModelId) {
    return `${normalizedProviderId}/${normalizedModelId}`;
  }
  if (normalizedModelId) {
    return normalizedModelId;
  }
  return normalizedProviderId;
}

function normalizeProviderIdToken(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "");
}

function inferProviderNameFromBaseUrl(value: string | null | undefined) {
  const raw = (value ?? "").trim();
  if (!raw) {
    return "";
  }

  const candidate = /^[a-z][a-z0-9+.-]*:\/\//i.test(raw) ? raw : `https://${raw}`;
  let hostname = "";
  try {
    hostname = new URL(candidate).hostname.trim().toLowerCase();
  } catch {
    const withoutScheme = raw.replace(/^[a-z][a-z0-9+.-]*:\/\//i, "");
    hostname = withoutScheme.split(/[/?#]/)[0]?.split(":")[0]?.trim().toLowerCase() ?? "";
  }

  if (!hostname) {
    return "";
  }

  const parts = hostname
    .split(".")
    .map((part) => part.trim())
    .filter(Boolean);
  if (parts.length === 0) {
    return "";
  }

  let index = parts.length - 2;
  if (parts.length >= 3) {
    const tld = parts[parts.length - 1];
    const secondLevel = parts[parts.length - 2];
    if (tld.length === 2 && secondLevel.length <= 3) {
      index = parts.length - 3;
    }
  }

  const token = (parts[Math.max(0, index)] ?? "").replace(/[^a-z0-9-_]/g, "");
  return token;
}

function buildRelatedModelProviderBaseId(draft: RelatedModelDraft) {
  const rawBaseUrl = draft.baseUrl.trim();
  let providerSeed = "";
  if (rawBaseUrl) {
    const urlCandidate = /^[a-z][a-z0-9+.-]*:\/\//i.test(rawBaseUrl) ? rawBaseUrl : `https://${rawBaseUrl}`;
    try {
      const parsedUrl = new URL(urlCandidate);
      const firstPath = parsedUrl.pathname.split("/").find((segment) => segment.trim().length > 0) ?? "";
      providerSeed = [parsedUrl.hostname, firstPath].filter(Boolean).join("-");
    } catch {
      providerSeed = rawBaseUrl;
    }
  }
  if (!providerSeed) {
    providerSeed = draft.model.trim();
  }
  const normalized = normalizeProviderIdToken(providerSeed);
  return normalized || "custom-provider";
}

function resolveRelatedModelNextProviderId(draft: RelatedModelDraft) {
  const existingProviderIds = new Set(
    (relatedModelSnapshot.value?.platforms ?? [])
      .map((platform) => normalizeProviderIdentifier(platform.providerId))
      .filter(Boolean)
  );
  const baseProviderId = buildRelatedModelProviderBaseId(draft);
  if (!existingProviderIds.has(baseProviderId)) {
    return baseProviderId;
  }
  let index = 2;
  let candidate = `${baseProviderId}-${index}`;
  while (existingProviderIds.has(candidate)) {
    index += 1;
    candidate = `${baseProviderId}-${index}`;
  }
  return candidate;
}

function getPlatformModelReference(platform: OpenClawPlatformSnapshotItem) {
  return buildProviderModelReference(platform.providerId || platform.pathPrefix, platform.model);
}

function normalizeProviderProtocol(protocol: string | null | undefined): OpenClawProviderProtocol {
  return equalsIgnoreCase(protocol, "anthropic") ? "anthropic" : "openai";
}

function inferProviderApiKind(protocol: OpenClawProviderProtocol, apiPath: string): OpenClawProviderApiKind {
  if (protocol === "anthropic") {
    return "anthropic-messages";
  }
  return apiPath.trim().toLowerCase().includes("responses") ? "openai-responses" : "openai-completions";
}

function normalizeProviderApiKind(
  protocol: OpenClawProviderProtocol,
  apiKind: OpenClawProviderApiKind | string | null | undefined
): OpenClawProviderApiKind {
  if (protocol === "anthropic") {
    return "anthropic-messages";
  }
  return apiKind === "openai-responses" ? "openai-responses" : "openai-completions";
}

function resolveProviderProtocolByApiKind(apiKind: OpenClawProviderApiKind | string | null | undefined): OpenClawProviderProtocol {
  return apiKind === "anthropic-messages" ? "anthropic" : "openai";
}

function getProviderApiKindLabel(apiKind: OpenClawProviderApiKind | string | null | undefined) {
  const protocol = resolveProviderProtocolByApiKind(apiKind);
  const normalizedApiKind = normalizeProviderApiKind(protocol, apiKind);
  if (normalizedApiKind === "anthropic-messages") {
    return "Anthropic Messages";
  }
  if (normalizedApiKind === "openai-responses") {
    return "OpenAI Responses";
  }
  return "OpenAI Completions";
}

function resolveRelatedModelPlatform(agent: AgentListItem | null, platforms: OpenClawPlatformSnapshotItem[]) {
  if (platforms.length === 0) {
    return null;
  }

  const parsedModel = parseAgentModelReference(agent?.model);
  const normalizedProviderId = normalizeProviderIdentifier(parsedModel.providerId);
  if (normalizedProviderId) {
    const providerMatched =
      platforms.find((platform) => normalizeProviderIdentifier(platform.providerId) === normalizedProviderId) ??
      platforms.find((platform) => normalizeProviderIdentifier(platform.pathPrefix) === normalizedProviderId);
    if (providerMatched) {
      return providerMatched;
    }
  }

  const normalizedModelId = parsedModel.modelId.trim().toLowerCase();
  if (normalizedModelId) {
    const modelMatched = platforms.find((platform) => (platform.model ?? "").trim().toLowerCase() === normalizedModelId);
    if (modelMatched) {
      return modelMatched;
    }
  }

  const normalizedRawModel = parsedModel.rawModel.trim().toLowerCase();
  if (normalizedRawModel) {
    const rawMatched = platforms.find((platform) => (platform.model ?? "").trim().toLowerCase() === normalizedRawModel);
    if (rawMatched) {
      return rawMatched;
    }
  }

  return platforms[0];
}

function formatDateTime(timestampMs: number | null | undefined) {
  if (!timestampMs || !Number.isFinite(timestampMs)) {
    return "—";
  }
  return new Date(timestampMs).toLocaleString("zh-CN", {
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  });
}

function formatTaskScheduleKind(kind: string, deleteAfterRun: boolean) {
  if (deleteAfterRun) {
    return "一次性";
  }
  if (kind === "cron") {
    return "周期";
  }
  if (kind === "at") {
    return "定时";
  }
  return "任务";
}

function formatTaskNextRunCountdown(nextRunAtMs: number | null | undefined) {
  if (!nextRunAtMs || !Number.isFinite(nextRunAtMs)) {
    return "未设置";
  }
  const delta = nextRunAtMs - Date.now();
  const absDelta = Math.abs(delta);
  if (absDelta < 60 * 60 * 1000) {
    return delta >= 0 ? "1h内" : "已逾期";
  }
  const hours = Math.round(absDelta / (60 * 60 * 1000));
  if (hours < 24) {
    return delta >= 0 ? `${hours}h后` : `${hours}h前`;
  }
  const days = Math.round(absDelta / (24 * 60 * 60 * 1000));
  return delta >= 0 ? `${days}天后` : `${days}天前`;
}

function formatCompactTime(timestampMs: number | null | undefined) {
  if (!timestampMs || !Number.isFinite(timestampMs)) {
    return "--:--:--";
  }
  return new Date(timestampMs).toLocaleTimeString("zh-CN", {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  });
}

function formatRunDurationLabel(durationMs: number | null | undefined) {
  if (!durationMs || !Number.isFinite(durationMs) || durationMs <= 0) {
    return "—";
  }
  const totalMinutes = Math.floor(durationMs / 60000);
  if (totalMinutes < 60) {
    return `${Math.max(1, totalMinutes)} 分`;
  }
  const totalHours = Math.floor(totalMinutes / 60);
  if (totalHours < 24) {
    return `${totalHours} 小时`;
  }
  const totalDays = Math.floor(totalHours / 24);
  return `${totalDays} 天`;
}

function formatInteger(value: number) {
  return Math.max(0, Math.round(value)).toLocaleString("zh-CN");
}

function getEffectiveLogTotalTokens(log: OpenClawMessageLogItem) {
  if (typeof log.totalTokens === "number" && Number.isFinite(log.totalTokens)) {
    return Math.max(0, Math.round(log.totalTokens));
  }
  const prompt = typeof log.promptTokens === "number" && Number.isFinite(log.promptTokens) ? Math.max(0, Math.round(log.promptTokens)) : 0;
  const completion =
    typeof log.completionTokens === "number" && Number.isFinite(log.completionTokens) ? Math.max(0, Math.round(log.completionTokens)) : 0;
  const cache =
    typeof log.cacheReadInputTokens === "number" && Number.isFinite(log.cacheReadInputTokens)
      ? Math.max(0, Math.round(log.cacheReadInputTokens))
      : 0;
  return prompt + completion + cache;
}

function updateDashboardHeapUsage() {
  if (typeof window === "undefined") {
    dashboardJsHeapUsageMb.value = null;
    return;
  }
  const performanceWithMemory = window.performance as Performance & {
    memory?: { usedJSHeapSize?: number };
  };
  const bytes = performanceWithMemory.memory?.usedJSHeapSize;
  if (typeof bytes !== "number" || !Number.isFinite(bytes) || bytes <= 0) {
    dashboardJsHeapUsageMb.value = null;
    return;
  }
  dashboardJsHeapUsageMb.value = Math.max(1, Math.round(bytes / (1024 * 1024)));
}

function mapGatewayStatusTone(status: string): DashboardHealthTone {
  const normalized = status.trim().toLowerCase();
  if (normalized === "online") {
    return "online";
  }
  if (normalized === "checking") {
    return "neutral";
  }
  if (normalized === "unconfigured" || normalized === "unsupported") {
    return "warn";
  }
  return "offline";
}

function mapGatewayStatusLabel(status: string) {
  const normalized = status.trim().toLowerCase();
  if (normalized === "online") {
    return "在线";
  }
  if (normalized === "checking") {
    return "检测中";
  }
  if (normalized === "unconfigured") {
    return "未配置";
  }
  if (normalized === "unsupported") {
    return "不可用";
  }
  return "离线";
}

function clearRelatedResourceSnapshots() {
  relatedMemorySnapshot.value = null;
  relatedSkillsSnapshot.value = null;
  relatedToolsSnapshot.value = null;
  relatedModelSnapshot.value = null;
  relatedModelDraft.value = buildRelatedModelCustomDraft();
  relatedModelCustomExpanded.value = false;
  relatedModelApiKeyVisible.value = false;
  relatedModelSelectedPopularPlatformId.value = null;
  relatedModelEditingProviderId.value = null;
  relatedModelPendingDeleteProviderId.value = null;
  relatedChannelSnapshot.value = null;
  relatedTaskSnapshot.value = null;
}

function getStableChatMessages(messages: AgentChatMessage[]) {
  return messages.filter((item) => item.status !== "pending" && !isLegacyWelcomeMessage(item));
}

function buildArchiveTitle(messages: AgentChatMessage[]) {
  const firstUserMessage = messages.find((item) => item.role === "user" && item.text.trim());
  const firstAssistantMessage = messages.find((item) => item.role === "assistant" && item.text.trim());
  const base = firstUserMessage?.text.trim() || firstAssistantMessage?.text.trim() || "会话归档";
  const clipped = base.replace(/\s+/g, " ").trim();
  if (clipped.length > 22) {
    return `${clipped.slice(0, 22)}...`;
  }
  return clipped || "会话归档";
}

function getArchivePreviewText(record: ChatArchiveRecord) {
  const latest = record.messages[record.messages.length - 1];
  if (!latest) {
    return "暂无内容";
  }
  const text = latest.text.replace(/\s+/g, " ").trim();
  if (!text) {
    return "暂无内容";
  }
  if (text.length > 64) {
    return `${text.slice(0, 64)}...`;
  }
  return text;
}

function normalizeStoredConversationScopeKey(rawScopeKey: string) {
  const scopeKey = rawScopeKey.trim();
  if (!scopeKey) {
    return null;
  }
  const normalized = scopeKey.toLowerCase();
  if (normalized.startsWith("agent:") || normalized.startsWith("channel:")) {
    return normalized;
  }
  return buildAgentConversationScopeKey(scopeKey);
}

function resolveOpenClawRuntimeSessionKey(conversationScopeKey: string) {
  const normalizedScopeKey = normalizeStoredConversationScopeKey(conversationScopeKey);
  if (!normalizedScopeKey || !normalizedScopeKey.startsWith("agent:")) {
    return null;
  }
  const rest = normalizedScopeKey.slice("agent:".length);
  const [rawAgentId, ...targetParts] = rest.split(":");
  const agentId = rawAgentId.trim().toLowerCase();
  if (!agentId) {
    return null;
  }
  const sessionTarget = normalizeConversationKeyPart(targetParts.join(":") || agentId);
  return `agent:${agentId}:${sessionTarget}`;
}

type ParsedConversationScope =
  | { kind: "agent"; ownerAgentId: string; sessionTarget: string | null }
  | { kind: "channel"; channelType: string; accountId: string; ownerAgentId: string };

function parseConversationScope(scopeKey: string): ParsedConversationScope | null {
  const normalizedScopeKey = normalizeStoredConversationScopeKey(scopeKey);
  if (!normalizedScopeKey) {
    return null;
  }
  if (normalizedScopeKey.startsWith("agent:")) {
    const rest = normalizedScopeKey.slice("agent:".length);
    const parts = rest.split(":");
    const ownerAgentId = parts[0] || "unknown";
    const sessionTarget = parts.slice(1).join(":").trim() || null;
    return {
      kind: "agent",
      ownerAgentId,
      sessionTarget
    };
  }
  if (!normalizedScopeKey.startsWith("channel:")) {
    return null;
  }
  const parts = normalizedScopeKey.split(":");
  if (parts.length < 4) {
    return null;
  }
  const channelType = parts[1] || "unknown";
  const ownerAgentId = parts[parts.length - 1] || "unknown";
  const accountId = parts.slice(2, -1).join(":") || "unknown";
  return {
    kind: "channel",
    channelType,
    accountId,
    ownerAgentId
  };
}

function shouldHideFeishuConversationTargetLabel(rawValue: string) {
  const normalized = rawValue.trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  if (normalized.startsWith("feishu:direct:") || normalized.startsWith("feishu:group:")) {
    return true;
  }
  if (normalized.startsWith("user:") || normalized.startsWith("chat:")) {
    return true;
  }
  return normalized.startsWith("ou_") || normalized.startsWith("oc_");
}

function resolveAgentSessionTargetLabel(sessionTargetRaw: string) {
  const sessionTarget = stripRuntimeSessionInstanceSuffix(sessionTargetRaw);
  if (!sessionTarget) {
    return "默认会话";
  }
  const firstSegment = sessionTarget.split(":")[0]?.trim() || "";
  const normalizedChannelType = normalizeChannelPaneType(firstSegment);
  if (!normalizedChannelType || !isLikelyChannelConversationTarget(sessionTarget)) {
    return sessionTarget;
  }
  if (!shouldHideFeishuConversationTargetLabel(sessionTarget)) {
    return sessionTarget;
  }
  const catalog = resolveChannelConfigCatalog(normalizedChannelType);
  const channelName = catalog?.name?.trim() || normalizedChannelType;
  return `${channelName}会话`;
}

function resolveConversationScopeLabel(scopeKey: string) {
  const parsed = parseConversationScope(scopeKey);
  if (!parsed) {
    return "默认会话";
  }
  if (parsed.kind === "agent") {
    const sessionTarget = stripRuntimeSessionInstanceSuffix(parsed.sessionTarget ?? "").toLowerCase();
    const ownerAgentId = parsed.ownerAgentId.trim().toLowerCase();
    if (sessionTarget && sessionTarget !== "main" && sessionTarget !== ownerAgentId) {
      return resolveAgentSessionTargetLabel(parsed.sessionTarget ?? "");
    }
    return "默认会话";
  }
  const catalog = resolveChannelConfigCatalog(parsed.channelType);
  const channelName = catalog?.name?.trim() || parsed.channelType || "频道";
  const normalizedChannelType = normalizeChannelPaneType(parsed.channelType);
  const accountId = parsed.accountId.trim();
  if (!accountId) {
    return channelName;
  }
  if (normalizedChannelType === FEISHU_CHANNEL_ID && shouldHideFeishuConversationTargetLabel(accountId)) {
    return `${channelName}会话`;
  }
  return `${channelName} / ${accountId}`;
}

function buildRelatedHistoryDefaultChannelId(ownerAgentId: string) {
  const normalizedOwnerAgentId = normalizeConversationKeyPart(ownerAgentId || "main");
  return `${RELATED_HISTORY_AGENT_DEFAULT_CHANNEL_PREFIX}${normalizedOwnerAgentId}`;
}

function parseRelatedHistoryDefaultChannelOwner(channelId: string) {
  const normalized = channelId.trim().toLowerCase();
  if (!normalized.startsWith(RELATED_HISTORY_AGENT_DEFAULT_CHANNEL_PREFIX)) {
    return "";
  }
  return normalized.slice(RELATED_HISTORY_AGENT_DEFAULT_CHANNEL_PREFIX.length);
}

function resolveRelatedHistoryRecordChannelId(record: ChatRelatedHistoryRecord) {
  const parsed = parseConversationScope(record.scopeKey);
  if (!parsed) {
    return "main";
  }
  if (parsed.kind === "channel") {
    return normalizeChannelPaneType(parsed.channelType) || "main";
  }
  const target = stripRuntimeSessionInstanceSuffix(parsed.sessionTarget ?? "").toLowerCase();
  const ownerAgentId = parsed.ownerAgentId.trim().toLowerCase();
  if (!target || target === "main" || target === ownerAgentId) {
    return buildRelatedHistoryDefaultChannelId(ownerAgentId || "main");
  }
  const channelCandidate = target.split(":").find((segment) => segment.trim().length > 0)?.trim() || "";
  if (!channelCandidate || channelCandidate === "main" || channelCandidate === ownerAgentId) {
    return buildRelatedHistoryDefaultChannelId(ownerAgentId || "main");
  }
  return normalizeChannelPaneType(channelCandidate) || channelCandidate;
}

function resolveRelatedHistoryChannelLabel(channelId: string) {
  const defaultOwnerAgentId = parseRelatedHistoryDefaultChannelOwner(channelId);
  if (defaultOwnerAgentId) {
    return defaultOwnerAgentId === "main" ? `${MAIN_STAFF_DISPLAY_NAME} 默认会话` : "默认会话";
  }
  const normalized = normalizeChannelPaneType(channelId) || channelId.trim().toLowerCase();
  if (!normalized || normalized === "main") {
    return "默认会话";
  }
  const catalog = resolveChannelConfigCatalog(normalized);
  return catalog?.name?.trim() || channelId;
}

function isLikelyChannelConversationTarget(value: string) {
  const normalized = value.trim().toLowerCase();
  if (!normalized || normalized === "main" || normalized === "default") {
    return false;
  }
  if (normalized.includes(":")) {
    return true;
  }
  if (normalized.startsWith("ou_") || normalized.startsWith("oc_")) {
    return true;
  }
  if (normalized.startsWith("@")) {
    return true;
  }
  if (/^[+-]?\d+$/.test(normalized)) {
    return true;
  }
  if (normalized.includes("@")) {
    return true;
  }
  return false;
}

function normalizeChannelMessageMirrorTarget(channelTypeRaw: string, rawTarget: string) {
  const channelType = normalizeChannelPaneType(channelTypeRaw);
  const target = rawTarget.trim();
  if (!target) {
    return "";
  }
  if (channelType !== FEISHU_CHANNEL_ID) {
    return target;
  }

  const normalizedTarget = target.toLowerCase();
  if (normalizedTarget.startsWith("user:") || normalizedTarget.startsWith("chat:")) {
    return target;
  }
  if (normalizedTarget.startsWith("ou_")) {
    return `user:${target}`;
  }
  if (normalizedTarget.startsWith("oc_")) {
    return `chat:${target}`;
  }

  const segments = target.split(":").map((segment) => segment.trim()).filter(Boolean);
  if (segments.length >= 2) {
    const prefix = normalizeChannelPaneType(segments[0]) || segments[0].toLowerCase();
    const kind = segments[1]?.toLowerCase() || "";
    const id = segments[segments.length - 1] || "";
    if (id && (prefix === FEISHU_CHANNEL_ID || prefix === "openclaw-lark" || prefix === "lark")) {
      if (kind === "direct" || kind === "user" || kind === "open_id" || kind === "openid") {
        return `user:${id}`;
      }
      if (kind === "group" || kind === "chat") {
        return `chat:${id}`;
      }
    }
  }

  return target;
}

function resolveChannelSnapshotGroup(channelTypeRaw: string) {
  const normalizedType = normalizeChannelPaneType(channelTypeRaw);
  const rawType = channelTypeRaw.trim().toLowerCase();
  const groups = dashboardChannelSnapshot.value?.channels ?? [];
  return (
    groups.find((group) => {
      const groupNormalizedType = normalizeChannelPaneType(group.channelType);
      const groupRawType = (group.channelType ?? "").trim().toLowerCase();
      if (normalizedType) {
        return groupNormalizedType === normalizedType;
      }
      return groupRawType === rawType;
    }) ?? null
  );
}

function resolveBoundChannelAccountId(channelTypeRaw: string, ownerAgentIdRaw: string) {
  const ownerAgentId = ownerAgentIdRaw.trim().toLowerCase();
  if (!ownerAgentId) {
    return "";
  }

  const group = resolveChannelSnapshotGroup(channelTypeRaw);
  if (!group) {
    return "";
  }

  const accounts = Array.isArray(group.accounts) ? group.accounts : [];
  if (accounts.length === 0) {
    return "";
  }
  const configuredAccounts = accounts.filter((account) => account.configured);
  const preferredAccounts = configuredAccounts.length > 0 ? configuredAccounts : accounts;
  const boundAccount = preferredAccounts.find((account) => {
    const boundAgentId = (account.agentId ?? "").trim();
    return boundAgentId.length > 0 && equalsIgnoreCase(boundAgentId, ownerAgentId);
  });
  const boundAccountId = boundAccount?.accountId?.trim() ?? "";
  if (boundAccountId) {
    return boundAccountId;
  }

  const defaultAccountId = (group.defaultAccountId ?? "").trim();
  if (defaultAccountId) {
    const defaultAccount =
      preferredAccounts.find((account) => equalsIgnoreCase(account.accountId, defaultAccountId)) ??
      accounts.find((account) => equalsIgnoreCase(account.accountId, defaultAccountId));
    const resolvedDefaultAccountId = defaultAccount?.accountId?.trim() ?? "";
    if (resolvedDefaultAccountId) {
      return resolvedDefaultAccountId;
    }
    return defaultAccountId;
  }

  return preferredAccounts[0]?.accountId?.trim() ?? accounts[0]?.accountId?.trim() ?? "";
}

function resolveChannelMirrorAccountId(
  channelTypeRaw: string,
  accountIdCandidateRaw: string | null | undefined,
  ownerAgentIdRaw: string,
  options: { preferBoundForOwner?: boolean } = {}
) {
  const candidateAccountId = (accountIdCandidateRaw ?? "").trim();
  const candidateLooksLikeConversationTarget =
    candidateAccountId.length > 0 &&
    isLikelyChannelConversationTarget(candidateAccountId) &&
    candidateAccountId.includes(":");
  const group = resolveChannelSnapshotGroup(channelTypeRaw);
  const groupAccounts = Array.isArray(group?.accounts) ? group.accounts : [];
  const candidateExistsInSnapshot =
    candidateAccountId.length > 0 &&
    groupAccounts.some((account) => equalsIgnoreCase(account.accountId, candidateAccountId));
  const boundAccountId = resolveBoundChannelAccountId(channelTypeRaw, ownerAgentIdRaw);

  if (options.preferBoundForOwner && boundAccountId) {
    return boundAccountId;
  }

  if (candidateAccountId && !candidateLooksLikeConversationTarget) {
    if (!group || candidateExistsInSnapshot) {
      return candidateAccountId;
    }
  }

  if (boundAccountId) {
    return boundAccountId;
  }

  if (candidateAccountId && !candidateLooksLikeConversationTarget) {
    return candidateAccountId;
  }

  const defaultAccountId = (group?.defaultAccountId ?? "").trim();
  if (defaultAccountId) {
    return defaultAccountId;
  }
  const firstSnapshotAccountId = groupAccounts[0]?.accountId?.trim() ?? "";
  if (firstSnapshotAccountId) {
    return firstSnapshotAccountId;
  }
  return "default";
}

function collectChannelMirrorFallbackAccountIds(channelTypeRaw: string, primaryAccountIdRaw: string) {
  const primaryAccountId = primaryAccountIdRaw.trim();
  const group = resolveChannelSnapshotGroup(channelTypeRaw);
  const accounts = Array.isArray(group?.accounts) ? group.accounts : [];
  if (accounts.length === 0) {
    return [] as string[];
  }

  const configuredAccounts = accounts.filter((account) => account.configured);
  const source = configuredAccounts.length > 0 ? configuredAccounts : accounts;
  const normalizedPrimaryAccountId = primaryAccountId.toLowerCase();
  const normalizedChannelType = normalizeChannelPaneType(channelTypeRaw);
  const ordered = [...source].sort((left, right) => {
    if (normalizedChannelType === FEISHU_CHANNEL_ID) {
      if (left.isDefault && !right.isDefault) {
        return 1;
      }
      if (!left.isDefault && right.isDefault) {
        return -1;
      }
    }
    return left.accountId.localeCompare(right.accountId, "zh-CN");
  });

  const deduped = new Set<string>();
  const results: string[] = [];
  for (const account of ordered) {
    const accountId = account.accountId.trim();
    if (!accountId) {
      continue;
    }
    const normalizedAccountId = accountId.toLowerCase();
    if (normalizedAccountId === normalizedPrimaryAccountId || deduped.has(normalizedAccountId)) {
      continue;
    }
    deduped.add(normalizedAccountId);
    results.push(accountId);
  }
  return results;
}

function resolveChannelMessageMirrorTarget(
  conversationScopeKey: string,
  channelSession: ChannelPaneChatItem | null
): ChannelMessageMirrorTarget | null {
  const parsed = parseConversationScope(conversationScopeKey);
  if (!parsed) {
    return null;
  }

  const sessionAccountId =
    channelSession?.channelType === VIRTUAL_OPENCLAW_SESSION_CHANNEL_TYPE
      ? "default"
      : channelSession?.accountId?.trim() || "default";
  const resolveWithChannel = (
    channelTypeRaw: string,
    rawTarget: string,
    accountId: string | null | undefined,
    ownerAgentIdRaw: string,
    options: { preferBoundForOwner?: boolean } = {}
  ) => {
    const channelType = normalizeChannelPaneType(channelTypeRaw);
    const target = normalizeChannelMessageMirrorTarget(channelType, rawTarget);
    const resolvedAccountId = resolveChannelMirrorAccountId(
      channelType,
      accountId ?? sessionAccountId,
      ownerAgentIdRaw,
      options
    );
    if (!channelType || !target || target.toLowerCase() === "main") {
      return null;
    }
    return {
      channelType,
      accountId: resolvedAccountId,
      target
    };
  };

  if (parsed.kind === "agent") {
    const sessionTarget = stripRuntimeSessionInstanceSuffix(parsed.sessionTarget ?? "");
    const normalizedTarget = sessionTarget.toLowerCase();
    const ownerAgentId = parsed.ownerAgentId.trim().toLowerCase();
    if (!sessionTarget || normalizedTarget === "main" || normalizedTarget === ownerAgentId) {
      return null;
    }

    const firstSegment = sessionTarget.split(":")[0]?.trim() || "";
    const inferredChannelFromTarget = normalizeChannelPaneType(firstSegment);
    if (inferredChannelFromTarget) {
      return resolveWithChannel(inferredChannelFromTarget, sessionTarget, sessionAccountId, parsed.ownerAgentId, {
        preferBoundForOwner: true
      });
    }

    const channelFromSession =
      channelSession && channelSession.channelType !== VIRTUAL_OPENCLAW_SESSION_CHANNEL_TYPE
        ? normalizeChannelPaneType(channelSession.channelType)
        : "";
    if (!channelFromSession || !isLikelyChannelConversationTarget(sessionTarget)) {
      return null;
    }
    return resolveWithChannel(channelFromSession, sessionTarget, sessionAccountId, parsed.ownerAgentId, {
      preferBoundForOwner: true
    });
  }

  const channelType = normalizeChannelPaneType(parsed.channelType);
  const accountId = parsed.accountId.trim();
  if (!channelType || !isLikelyChannelConversationTarget(accountId)) {
    return null;
  }

  let target = accountId;
  const normalizedAccount = accountId.toLowerCase();
  if (!normalizedAccount.startsWith(`${channelType}:`) && accountId.includes(":")) {
    target = `${channelType}:${accountId}`;
  } else if (!accountId.includes(":") && channelType === FEISHU_CHANNEL_ID) {
    target = `user:${accountId}`;
  }

  return resolveWithChannel(channelType, target, accountId, parsed.ownerAgentId);
}

function buildChannelMessageMirrorContent(text: string, attachments: ChatComposerAttachment[]) {
  const trimmed = text.trim();
  const attachmentSummary = formatAttachmentSummaryForPrompt(attachments);
  if (attachments.length <= 0) {
    return trimmed;
  }
  const header = trimmed || "(附件)";
  if (!attachmentSummary) {
    return header;
  }
  return `${header}\n\n${attachmentSummary}`;
}

function buildChannelMirrorFailureMessagePreview(message: string) {
  const compact = message.replace(/\s+/g, " ").trim();
  if (!compact) {
    return "(empty)";
  }
  if (compact.length > 260) {
    return `${compact.slice(0, 260)}...`;
  }
  return compact;
}

async function appendChannelMirrorFailureLog(
  invoke: TauriInvoke,
  payload: OpenClawChannelMirrorFailureLogPayload
) {
  try {
    const result = await invoke("append_openclaw_channel_mirror_failure_log", { payload });
    return typeof result === "string" && result.trim() ? result.trim() : null;
  } catch (error) {
    console.warn("[channel-mirror] append_openclaw_channel_mirror_failure_log failed", {
      payload,
      error
    });
    return null;
  }
}

async function dispatchChannelMessageMirror(
  conversationScopeKey: string,
  message: string,
  channelSession: ChannelPaneChatItem | null
) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return;
  }
  const payload = message.trim();
  if (!payload) {
    return;
  }

  const target = resolveChannelMessageMirrorTarget(conversationScopeKey, channelSession);
  if (!target) {
    return;
  }

  const commandPayload: OpenClawChannelMessageSendPayload = {
    channelType: target.channelType,
    accountId: target.accountId,
    target: target.target,
    message: payload
  };
  try {
    await invoke("send_openclaw_channel_message", {
      payload: commandPayload
    });
  } catch (error) {
    const fallbackAccountIds =
      target.channelType === FEISHU_CHANNEL_ID ? collectChannelMirrorFallbackAccountIds(target.channelType, target.accountId) : [];
    if (fallbackAccountIds.length > 0) {
      for (const fallbackAccountId of fallbackAccountIds) {
        try {
          await invoke("send_openclaw_channel_message", {
            payload: {
              ...commandPayload,
              accountId: fallbackAccountId
            }
          });
          return;
        } catch {
          // try next fallback account
        }
      }
    }

    const errorText =
      error instanceof Error
        ? error.message
        : typeof error === "string" && error.trim()
          ? error
          : "未知错误";
    const channelLabel = target.channelType === FEISHU_CHANNEL_ID ? "飞书" : target.channelType;
    const localLogPath = await appendChannelMirrorFailureLog(invoke, {
      channelType: target.channelType,
      accountId: target.accountId,
      target: target.target,
      messagePreview: buildChannelMirrorFailureMessagePreview(payload),
      errorDetail: errorText
    });
    chatComposerError.value = localLogPath
      ? `消息已发送，但转发到${channelLabel}失败。详细日志已写入本地文件。`
      : `消息已发送，但转发到${channelLabel}失败。`;
    console.warn("[channel-mirror] send_openclaw_channel_message failed", {
      payload: commandPayload,
      localLogPath,
      error
    });
  }
}

function getRelatedHistoryPreviewText(messages: AgentChatMessage[]) {
  const latest = messages[messages.length - 1];
  if (!latest) {
    return "暂无内容";
  }
  const text = latest.text.replace(/\s+/g, " ").trim();
  if (text) {
    if (text.length > 64) {
      return `${text.slice(0, 64)}...`;
    }
    return text;
  }
  const attachmentCount = latest.attachments?.length ?? 0;
  if (attachmentCount > 0) {
    return `[附件 ${attachmentCount} 个]`;
  }
  return "暂无内容";
}

function getRelatedMessageItems(messages: AgentChatMessage[]) {
  return getStableChatMessages(messages).filter(
    (item) => (item.role === "assistant" || item.role === "user") && !isRuntimeToolMessage(item)
  );
}

function shouldUseLegacyAgentStorage(scopeKey: string, agentId: string) {
  const normalizedScopeKey = normalizeStoredConversationScopeKey(scopeKey);
  if (!normalizedScopeKey) {
    return false;
  }
  return normalizedScopeKey === buildAgentConversationScopeKey(agentId);
}

function formatOpenClawSessionScopeLabel(item: OpenClawAgentSessionSnapshotItem, ownerAgentId: string) {
  const normalizedOwnerAgentId = ownerAgentId.trim().toLowerCase();
  const base = item.sessionTarget?.trim() || normalizedOwnerAgentId || "main";
  const normalizedBase = base.toLowerCase();
  const baseLabel =
    !normalizedBase || normalizedBase === "main" || normalizedBase === normalizedOwnerAgentId ? "默认会话" : base;
  const channel = item.lastChannel?.trim() || "";
  return channel ? `${baseLabel} · ${channel}` : baseLabel;
}

async function loadOpenClawRelatedHistoryRecords(agent: AgentListItem, activeScopeKey: string | null) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return [] as ChatRelatedHistoryRecord[];
  }
  try {
    const snapshot = (await invoke("load_openclaw_agent_sessions_snapshot", {
      agentId: agent.agentId
    })) as OpenClawAgentSessionsSnapshotResponse;
    const sessions = Array.isArray(snapshot.sessions) ? snapshot.sessions : [];
    return sessions
      .map((item) => ({
        id: `openclaw-session:${item.sessionKey}`,
        scopeKey: item.sessionKey,
        scopeLabel:
          activeScopeKey && normalizeStoredConversationScopeKey(item.sessionKey) === activeScopeKey
            ? `${formatOpenClawSessionScopeLabel(item, agent.agentId)}（当前）`
            : formatOpenClawSessionScopeLabel(item, agent.agentId),
        updatedAt: typeof item.updatedAtMs === "number" && Number.isFinite(item.updatedAtMs) ? item.updatedAtMs : Date.now(),
        messageCount: typeof item.messageCount === "number" && Number.isFinite(item.messageCount) ? Math.max(0, item.messageCount) : 0,
        preview: item.preview?.trim() || "暂无消息",
        isActiveScope: Boolean(activeScopeKey && normalizeStoredConversationScopeKey(item.sessionKey) === activeScopeKey),
        sessionId: item.sessionId?.trim() || undefined
      }))
      .sort((left, right) => right.updatedAt - left.updatedAt);
  } catch {
    return [] as ChatRelatedHistoryRecord[];
  }
}

async function loadOpenClawSessionHistory(agent: AgentListItem, scopeKey: string) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return [] as AgentChatMessage[];
  }
  const normalizedScopeKey = normalizeStoredConversationScopeKey(scopeKey);
  const runtimeScopeKey = normalizedScopeKey ? resolveOpenClawRuntimeSessionKey(normalizedScopeKey) ?? normalizedScopeKey : scopeKey;
  try {
    const response = (await invoke("load_openclaw_agent_session_history", {
      agentId: agent.agentId,
      sessionKey: runtimeScopeKey
    })) as OpenClawAgentSessionHistoryResponse;
    const messages = Array.isArray(response.messages) ? response.messages : [];
    return messages
      .filter((item) => item.role === "assistant" || item.role === "user")
      .map((item, index) => ({
        id: item.id?.trim() || createMessageId(`runtime-${index}`),
        role: item.role,
        text: typeof item.text === "string" ? sanitizeMessageTextForDisplay(item.text) : "",
        status: "done" as ChatStatus,
        createdAt: typeof item.createdAtMs === "number" && Number.isFinite(item.createdAtMs) ? item.createdAtMs : Date.now()
      }))
      .filter((item) => item.text.trim().length > 0);
  } catch {
    return [] as AgentChatMessage[];
  }
}

function isOpenClawAgentSessionScope(scopeKey: string, agentId: string) {
  const normalizedScopeKey = normalizeStoredConversationScopeKey(scopeKey);
  if (!normalizedScopeKey) {
    return false;
  }
  const baseScope = buildAgentConversationScopeKey(agentId);
  if (normalizedScopeKey === baseScope) {
    return true;
  }
  const agentPrefix = `${baseScope}:`;
  return normalizedScopeKey.startsWith(agentPrefix);
}

function areChatHistoriesEquivalent(left: AgentChatMessage[], right: AgentChatMessage[]) {
  if (left.length !== right.length) {
    return false;
  }
  for (let index = 0; index < left.length; index += 1) {
    const leftItem = left[index];
    const rightItem = right[index];
    if (!leftItem || !rightItem) {
      return false;
    }
    if (leftItem.role !== rightItem.role) {
      return false;
    }
    if (leftItem.text !== rightItem.text) {
      return false;
    }
    if ((leftItem.createdAt ?? 0) !== (rightItem.createdAt ?? 0)) {
      return false;
    }
  }
  return true;
}

function buildOpenClawHistoryMessageFingerprint(message: AgentChatMessage) {
  const createdAt = typeof message.createdAt === "number" && Number.isFinite(message.createdAt) ? message.createdAt : 0;
  return `${message.role}|${createdAt}|${message.text}`;
}

const OPENCLAW_ASSISTANT_NEAR_DUPLICATE_WINDOW_MS = 2 * 60 * 1000;
const OPENCLAW_USER_NEAR_DUPLICATE_WINDOW_MS = 20 * 1000;

function normalizeOpenClawHistorySemanticText(text: string) {
  return text.replace(/\s+/g, " ").trim();
}

function buildOpenClawMessageSemanticKey(message: AgentChatMessage) {
  if (message.role !== "assistant" && message.role !== "user") {
    return "";
  }
  const normalizedText = normalizeOpenClawHistorySemanticText(message.text);
  if (!normalizedText) {
    return "";
  }
  return `${message.role}|${normalizedText}`;
}

function resolveOpenClawNearDuplicateWindowMsByRole(role: ChatRole) {
  if (role === "assistant") {
    return OPENCLAW_ASSISTANT_NEAR_DUPLICATE_WINDOW_MS;
  }
  if (role === "user") {
    return OPENCLAW_USER_NEAR_DUPLICATE_WINDOW_MS;
  }
  return 0;
}

function hasNearDuplicateMessage(existingTimes: number[], candidateCreatedAt: number, windowMs: number) {
  if (windowMs <= 0) {
    return false;
  }
  if (!Number.isFinite(candidateCreatedAt) || candidateCreatedAt <= 0) {
    return existingTimes.length > 0;
  }
  return existingTimes.some(
    (existingTime) =>
      Number.isFinite(existingTime) &&
      existingTime > 0 &&
      Math.abs(existingTime - candidateCreatedAt) <= windowMs
  );
}

function mergeOpenClawHistoryWithLocal(local: AgentChatMessage[], remote: AgentChatMessage[]) {
  if (local.length === 0) {
    return remote.map((message) => ({ ...message }));
  }
  if (remote.length === 0) {
    return local.map((message) => ({ ...message }));
  }

  const merged = local.map((message) => ({ ...message }));
  const seenIds = new Set(merged.map((message) => message.id.trim()).filter(Boolean));
  const seenFingerprints = new Set(
    merged
      .filter((message) => message.role === "assistant" || message.role === "user")
      .map((message) => buildOpenClawHistoryMessageFingerprint(message))
  );
  const assistantSemanticTimes = new Map<string, number[]>();
  for (const message of merged) {
    const semanticKey = buildOpenClawMessageSemanticKey(message);
    if (!semanticKey) {
      continue;
    }
    const createdAt = typeof message.createdAt === "number" && Number.isFinite(message.createdAt) ? message.createdAt : 0;
    const existingTimes = assistantSemanticTimes.get(semanticKey) ?? [];
    existingTimes.push(createdAt);
    assistantSemanticTimes.set(semanticKey, existingTimes);
  }

  for (const message of remote) {
    const id = message.id.trim();
    const fingerprint = buildOpenClawHistoryMessageFingerprint(message);
    if ((id && seenIds.has(id)) || seenFingerprints.has(fingerprint)) {
      continue;
    }
    const semanticKey = buildOpenClawMessageSemanticKey(message);
    if (semanticKey) {
      const createdAt = typeof message.createdAt === "number" && Number.isFinite(message.createdAt) ? message.createdAt : 0;
      const windowMs = resolveOpenClawNearDuplicateWindowMsByRole(message.role);
      const existingTimes = assistantSemanticTimes.get(semanticKey) ?? [];
      if (hasNearDuplicateMessage(existingTimes, createdAt, windowMs)) {
        continue;
      }
    }
    const clonedMessage = { ...message };
    merged.push(clonedMessage);
    if (id) {
      seenIds.add(id);
    }
    seenFingerprints.add(fingerprint);
    if (semanticKey) {
      const createdAt = typeof message.createdAt === "number" && Number.isFinite(message.createdAt) ? message.createdAt : 0;
      const existingTimes = assistantSemanticTimes.get(semanticKey) ?? [];
      existingTimes.push(createdAt);
      assistantSemanticTimes.set(semanticKey, existingTimes);
    }
  }

  return merged;
}

async function syncOpenClawSessionHistoryToLocal(
  agent: AgentListItem,
  scopeKey: string,
  options: { applyToActiveConversation?: boolean; runtimeSessionKey?: string | null } = {}
) {
  const normalizedScopeKey = normalizeStoredConversationScopeKey(scopeKey);
  if (!normalizedScopeKey || !isOpenClawAgentSessionScope(normalizedScopeKey, agent.agentId)) {
    return [] as AgentChatMessage[];
  }

  const resolvedRuntimeSessionKey =
    normalizeRuntimeSessionKeyForAgent(options.runtimeSessionKey ?? "", agent.agentId) || normalizedScopeKey;
  const latestHistory = await loadOpenClawSessionHistory(agent, resolvedRuntimeSessionKey);
  if (latestHistory.length === 0) {
    return [] as AgentChatMessage[];
  }

  const localCachedHistory = agentHistories.value[normalizedScopeKey] ?? loadChatHistory(normalizedScopeKey);
  const mergedHistory = mergeOpenClawHistoryWithLocal(localCachedHistory, latestHistory);
  if (!areChatHistoriesEquivalent(localCachedHistory, mergedHistory)) {
    agentHistories.value[normalizedScopeKey] = mergedHistory.map((message) => ({ ...message }));
    safeStorageSet(chatStorageKeyFor(normalizedScopeKey), JSON.stringify(mergedHistory));
  }

  if (options.applyToActiveConversation && activeConversationScopeKey.value === normalizedScopeKey) {
    const hasPendingMessage = chatMessages.value.some((message) => message.status === "pending");
    if (!hasPendingMessage && !areChatHistoriesEquivalent(chatMessages.value, mergedHistory)) {
      chatMessages.value = mergedHistory.map((message) => ({ ...message }));
      chatAttachments.value = [];
      chatComposerError.value = "";
      refreshAgentMetaFromHistory(agent.agentId, mergedHistory, agent.currentWork);
      void scrollMessagesToBottom();
    }
  }

  return mergedHistory;
}

function stopOpenClawSessionSyncMonitor() {
  if (openclawSessionSyncPollTimer) {
    window.clearInterval(openclawSessionSyncPollTimer);
    openclawSessionSyncPollTimer = 0;
  }
}

async function pollActiveOpenClawSessionHistory() {
  if (openclawSessionSyncInFlight) {
    return;
  }
  const agent = activeAgent.value;
  const scopeKey = activeConversationScopeKey.value;
  if (!agent || !scopeKey || !isOpenClawAgentSessionScope(scopeKey, agent.agentId)) {
    return;
  }
  openclawSessionSyncInFlight = true;
  try {
    const runtimeSessionKey = resolveRuntimeSessionKeyForConversation(scopeKey, agent.agentId);
    await syncOpenClawSessionHistoryToLocal(agent, scopeKey, {
      applyToActiveConversation: true,
      runtimeSessionKey
    });
  } finally {
    openclawSessionSyncInFlight = false;
  }
}

function syncOpenClawSessionSyncMonitorState() {
  const agent = activeAgent.value;
  const scopeKey = activeConversationScopeKey.value;
  const shouldRun =
    activeSection.value === "chat" &&
    Boolean(agent && scopeKey && isOpenClawAgentSessionScope(scopeKey, agent.agentId));
  if (!shouldRun) {
    stopOpenClawSessionSyncMonitor();
    return;
  }

  if (!openclawSessionSyncPollTimer) {
    openclawSessionSyncPollTimer = window.setInterval(() => {
      void pollActiveOpenClawSessionHistory();
    }, openclawSessionSyncPollIntervalMs);
  }
  void pollActiveOpenClawSessionHistory();
}

function buildVirtualOpenClawSessionItem(scopeKey: string, scopeLabel: string, agentId: string, preview: string): ChannelPaneChatItem {
  return {
    id: `virtual-openclaw-${scopeKey}`,
    catalogId: "openclaw-session",
    channelType: VIRTUAL_OPENCLAW_SESSION_CHANNEL_TYPE,
    name: scopeLabel,
    icon: null,
    accountId: scopeKey,
    summary: preview || "历史会话",
    statusLabel: "历史会话",
    statusTone: "online",
    boundAgentId: agentId
  };
}

const activeConversationScopeKey = computed(() =>
  normalizeStoredConversationScopeKey(resolveConversationScopeKey(activeAgent.value?.agentId ?? null, activeChannelChatSession.value) ?? "")
);

function isRelatedHistoryRecordActive(record: ChatRelatedHistoryRecord) {
  const activeScopeKey = activeConversationScopeKey.value;
  const targetScopeKey = normalizeStoredConversationScopeKey(record.scopeKey);
  if (!activeScopeKey || !targetScopeKey) {
    return false;
  }
  return activeScopeKey === targetScopeKey;
}

async function handleRelatedHistoryRecordSelect(record: ChatRelatedHistoryRecord) {
  const agent = activeAgent.value;
  if (!agent) {
    return;
  }
  const normalizedScopeKey = normalizeStoredConversationScopeKey(record.scopeKey);
  if (!normalizedScopeKey) {
    return;
  }
  if (activeConversationScopeKey.value === normalizedScopeKey) {
    return;
  }

  const loadOptions: ConversationStorageReadOptions = shouldUseLegacyAgentStorage(normalizedScopeKey, agent.agentId)
    ? { legacyAgentId: agent.agentId }
    : {};
  if (isOpenClawAgentSessionScope(normalizedScopeKey, agent.agentId)) {
    await syncOpenClawSessionHistoryToLocal(agent, normalizedScopeKey);
  } else {
    const history = loadChatHistory(normalizedScopeKey, loadOptions);
    if (history.length > 0) {
      agentHistories.value[normalizedScopeKey] = [...history];
    }
  }

  const targetSession = buildVirtualOpenClawSessionItem(
    normalizedScopeKey,
    resolveConversationScopeLabel(normalizedScopeKey),
    agent.agentId,
    record.preview
  );
  switchAgent(agent.agentId, { channelSession: targetSession, force: true });
}

function collectRelatedConversationScopeKeys(agent: AgentListItem) {
  const normalizedAgentId = normalizeConversationKeyPart(agent.agentId);
  const historyKeyPrefix = `${CHAT_STORAGE_PREFIX}.`;
  const archiveKeyPrefix = `${CHAT_ARCHIVE_STORAGE_PREFIX}.`;
  const scopeSet = new Set<string>();

  const collectFromStoragePrefix = (prefix: string) => {
    const rawKeys = safeStorageKeysByPrefix(prefix);
    for (const rawKey of rawKeys) {
      const rawScopeKey = rawKey.slice(prefix.length).trim();
      if (!rawScopeKey) {
        continue;
      }
      const normalizedScopeKey = normalizeStoredConversationScopeKey(rawScopeKey);
      if (!normalizedScopeKey) {
        continue;
      }
      const parsed = parseConversationScope(normalizedScopeKey);
      if (!parsed || parsed.ownerAgentId !== normalizedAgentId) {
        continue;
      }
      scopeSet.add(normalizedScopeKey);
    }
  };

  collectFromStoragePrefix(historyKeyPrefix);
  collectFromStoragePrefix(archiveKeyPrefix);

  const activeScopeKey = resolveConversationScopeKey(agent.agentId, activeChannelChatSession.value);
  const normalizedActiveScopeKey = activeScopeKey ? normalizeStoredConversationScopeKey(activeScopeKey) : null;
  if (normalizedActiveScopeKey) {
    scopeSet.add(normalizedActiveScopeKey);
  }

  return Array.from(scopeSet.values());
}

function collectRelatedHistoryRecords(agent: AgentListItem) {
  const activeScopeKey = resolveConversationScopeKey(agent.agentId, activeChannelChatSession.value);
  const normalizedActiveScopeKey = activeScopeKey ? normalizeStoredConversationScopeKey(activeScopeKey) : null;
  const scopeKeys = collectRelatedConversationScopeKeys(agent);
  const records: ChatRelatedHistoryRecord[] = [];

  for (const scopeKey of scopeKeys) {
    const loadOptions: ConversationStorageReadOptions = shouldUseLegacyAgentStorage(scopeKey, agent.agentId)
      ? { legacyAgentId: agent.agentId }
      : {};
    const sessionId = peekSessionId(scopeKey, loadOptions);
    let messages = getRelatedMessageItems(loadChatHistory(scopeKey, loadOptions));
    if (normalizedActiveScopeKey && scopeKey === normalizedActiveScopeKey) {
      const activeMessages = getRelatedMessageItems(chatMessages.value);
      if (activeMessages.length > 0 || messages.length === 0) {
        messages = activeMessages;
      }
    }
    if (messages.length === 0) {
      if (normalizedActiveScopeKey && scopeKey === normalizedActiveScopeKey) {
        records.push({
          id: `related-history:${scopeKey}`,
          scopeKey,
          scopeLabel: `${resolveConversationScopeLabel(scopeKey)}（当前）`,
          updatedAt: Date.now(),
          messageCount: 0,
          preview: "当前会话暂无消息",
          isActiveScope: true,
          sessionId: sessionId || undefined
        });
      }
      continue;
    }
    const latest = messages[messages.length - 1];
    records.push({
      id: `related-history:${scopeKey}`,
      scopeKey,
      scopeLabel: scopeKey === normalizedActiveScopeKey ? `${resolveConversationScopeLabel(scopeKey)}（当前）` : resolveConversationScopeLabel(scopeKey),
      updatedAt: latest?.createdAt ?? Date.now(),
      messageCount: messages.length,
      preview: getRelatedHistoryPreviewText(messages),
      isActiveScope: Boolean(normalizedActiveScopeKey && scopeKey === normalizedActiveScopeKey),
      sessionId: sessionId || undefined
    });
  }

  records.sort((left, right) => {
    if (left.isActiveScope !== right.isActiveScope) {
      return left.isActiveScope ? -1 : 1;
    }
    return right.updatedAt - left.updatedAt;
  });
  return records;
}

function collectRelatedArchiveRecords(agent: AgentListItem) {
  const scopeKeys = collectRelatedConversationScopeKeys(agent);
  const records: ChatRelatedArchiveRecord[] = [];
  for (const scopeKey of scopeKeys) {
    const loadOptions: ConversationStorageReadOptions = shouldUseLegacyAgentStorage(scopeKey, agent.agentId)
      ? { legacyAgentId: agent.agentId }
      : {};
    const archives = loadChatArchives(scopeKey, loadOptions);
    for (const record of archives) {
      records.push({
        id: `${scopeKey}::${record.id}`,
        scopeKey,
        scopeLabel: resolveConversationScopeLabel(scopeKey),
        archivedAt: record.archivedAt,
        title: record.title,
        messageCount: record.messages.length,
        preview: getArchivePreviewText(record),
        record
      });
    }
  }
  records.sort((left, right) => right.archivedAt - left.archivedAt);
  return records;
}

function resolveRelatedHistoryConversationId(record: ChatRelatedHistoryRecord) {
  const extractConversationId = (rawValue: string) => {
    const target = rawValue.trim();
    if (!target) {
      return "";
    }
    const idMatch = target.match(/(?:^|:)((?:ou|oc)_[^:\s]+)/i);
    if (idMatch?.[1]) {
      return idMatch[1];
    }
    const segments = target
      .split(":")
      .map((segment) => segment.trim())
      .filter(Boolean);
    if (segments.length >= 2) {
      return segments[segments.length - 1] || target;
    }
    return target;
  };

  const explicitSessionId = (record.sessionId ?? "").trim();
  if (explicitSessionId) {
    return explicitSessionId;
  }

  const parsed = parseConversationScope(record.scopeKey);
  if (!parsed) {
    return extractConversationId(record.scopeKey) || "unknown";
  }
  if (parsed.kind === "agent") {
    const ownerAgentId = parsed.ownerAgentId.trim().toLowerCase() || "main";
    const target = stripRuntimeSessionInstanceSuffix(parsed.sessionTarget ?? "");
    const normalizedTarget = target.toLowerCase();
    if (!target || normalizedTarget === "main" || normalizedTarget === ownerAgentId) {
      return "unknown";
    }
    return extractConversationId(target) || target;
  }
  const accountId = parsed.accountId.trim();
  if (!accountId) {
    const channelType = normalizeChannelPaneType(parsed.channelType) || parsed.channelType.trim().toLowerCase();
    return channelType || "unknown";
  }
  return extractConversationId(accountId) || accountId;
}

function resolveRelatedHistoryScopeLabel(record: ChatRelatedHistoryRecord) {
  const parsed = parseConversationScope(record.scopeKey);
  if (!parsed) {
    return record.scopeLabel.trim() || "默认会话";
  }
  if (parsed.kind === "channel") {
    return normalizeChannelPaneType(parsed.channelType) || parsed.channelType.trim().toLowerCase() || "默认会话";
  }
  const target = stripRuntimeSessionInstanceSuffix(parsed.sessionTarget ?? "");
  const ownerAgentId = parsed.ownerAgentId.trim().toLowerCase();
  const normalizedTarget = target.toLowerCase();
  if (!target || normalizedTarget === "main" || normalizedTarget === ownerAgentId) {
    return "默认会话";
  }
  const channelCandidate = target.split(":")[0]?.trim() || "";
  const normalizedChannelType = normalizeChannelPaneType(channelCandidate);
  if (normalizedChannelType) {
    return normalizedChannelType;
  }
  return target;
}

const relatedHistoryChannelFilterOptions = computed(() => {
  const records = chatRelatedHistoryRecords.value;
  const channelMap = new Map<string, { count: number; firstIndex: number }>();
  records.forEach((record, index) => {
    const channelId = resolveRelatedHistoryRecordChannelId(record);
    const existing = channelMap.get(channelId);
    if (existing) {
      existing.count += 1;
      return;
    }
    channelMap.set(channelId, { count: 1, firstIndex: index });
  });
  const channelOptions = Array.from(channelMap.entries())
    .sort((left, right) => {
      const leftIsDefault = Boolean(parseRelatedHistoryDefaultChannelOwner(left[0])) || left[0] === "main";
      const rightIsDefault = Boolean(parseRelatedHistoryDefaultChannelOwner(right[0])) || right[0] === "main";
      if (leftIsDefault && !rightIsDefault) {
        return -1;
      }
      if (rightIsDefault && !leftIsDefault) {
        return 1;
      }
      return left[1].firstIndex - right[1].firstIndex;
    })
    .map(([id, meta]) => ({
      id,
      label: resolveRelatedHistoryChannelLabel(id),
      count: meta.count
    }));
  return [
    { id: RELATED_HISTORY_FILTER_ALL, label: "所有", count: records.length },
    ...channelOptions
  ];
});

const effectiveRelatedHistoryChannelFilter = computed(() => {
  const selected = relatedHistoryChannelFilter.value;
  if (selected === RELATED_HISTORY_FILTER_ALL) {
    return selected;
  }
  return relatedHistoryChannelFilterOptions.value.some((option) => option.id === selected) ? selected : RELATED_HISTORY_FILTER_ALL;
});

const filteredChatRelatedHistoryRecords = computed(() => {
  const activeFilter = effectiveRelatedHistoryChannelFilter.value;
  if (activeFilter === RELATED_HISTORY_FILTER_ALL) {
    return chatRelatedHistoryRecords.value;
  }
  return chatRelatedHistoryRecords.value.filter((record) => resolveRelatedHistoryRecordChannelId(record) === activeFilter);
});

function syncRelatedMemorySelection(preferredId: string | null = null) {
  const items = relatedMemoryItems.value;
  if (items.length === 0) {
    relatedMemorySelectedId.value = null;
    relatedMemoryDraftContent.value = "";
    return;
  }

  const nextSelectedId = preferredId || relatedMemorySelectedId.value;
  const selected =
    (nextSelectedId ? items.find((item) => item.id === nextSelectedId) : null) ??
    items[0];

  relatedMemorySelectedId.value = selected.id;
  relatedMemoryDraftContent.value = selected.content;
}

function getLogStatusTone(status: number) {
  if (status >= 500) {
    return "error";
  }
  if (status >= 400) {
    return "warn";
  }
  return "ok";
}

function formatDurationLabel(durationMs: number) {
  if (!Number.isFinite(durationMs)) {
    return "—";
  }
  if (durationMs >= 1000) {
    return `${(durationMs / 1000).toFixed(2)}s`;
  }
  return `${Math.max(0, Math.round(durationMs))}ms`;
}

function parseRuntimeLogEndpoint(errorText: string) {
  const source = errorText.trim();
  const urlMatch = source.match(/https?:\/\/[^\s)]+/i);
  return urlMatch?.[0] ?? "openclaw://runtime/client-error";
}

function resolveRuntimeLogEndpointParts(endpoint: string) {
  const normalized = endpoint.trim();
  if (!/^https?:\/\//i.test(normalized)) {
    return { baseUrl: undefined as string | undefined, path: undefined as string | undefined };
  }
  try {
    const parsed = new URL(normalized);
    return {
      baseUrl: `${parsed.protocol}//${parsed.host}`,
      path: `${parsed.pathname}${parsed.search}` || "/"
    };
  } catch {
    return { baseUrl: undefined as string | undefined, path: undefined as string | undefined };
  }
}

function appendLocalRuntimeErrorLog(payload: {
  agentId: string;
  agentName: string;
  requestText: string;
  errorText: string;
  sessionKey?: string | null;
  startedAt?: number;
}) {
  const normalizedAgentId = payload.agentId.trim();
  const normalizedError = payload.errorText.trim();
  if (!normalizedAgentId || !normalizedError) {
    return;
  }

  const createdAt = Date.now();
  const endpoint = parseRuntimeLogEndpoint(normalizedError);
  const { baseUrl, path } = resolveRuntimeLogEndpointParts(endpoint);
  const startedAt = typeof payload.startedAt === "number" ? payload.startedAt : createdAt;
  const duration = Math.max(0, Math.round(createdAt - startedAt));
  const sessionId = payload.sessionKey?.trim() || `runtime-${normalizedAgentId}-local-error`;

  const nextLog: OpenClawMessageLogItem = {
    id: createMessageId("runtime-log-error"),
    sessionId,
    platformId: `openclaw-agent-${normalizedAgentId}`,
    platformName: `OpenClaw 运行时 / ${payload.agentName.trim() || normalizedAgentId}`,
    protocol: "openai",
    method: "MESSAGE",
    endpoint,
    baseUrl,
    path,
    requestBody: payload.requestText ? JSON.stringify({ role: "user", content: payload.requestText }, null, 2) : "",
    responseStatus: 500,
    responseBody: "",
    streamSummary: "",
    duration,
    firstTokenTime: duration,
    error: normalizedError,
    createdAt
  };

  localRuntimeErrorLogs.value = [nextLog, ...localRuntimeErrorLogs.value]
    .sort((left, right) => right.createdAt - left.createdAt)
    .slice(0, localRuntimeErrorLogLimit);
}

function getLogRequestUrl(log: OpenClawMessageLogItem) {
  if (log.baseUrl || log.path) {
    return `${log.baseUrl ?? ""}${log.path ?? ""}` || log.endpoint;
  }
  return log.endpoint;
}

function getLogAgentId(log: OpenClawMessageLogItem): string | null {
  const platformId = (log.platformId ?? "").trim();
  if (platformId.startsWith("openclaw-agent-")) {
    return platformId.slice("openclaw-agent-".length);
  }
  if (platformId.startsWith("openclaw-runtime-")) {
    return platformId.slice("openclaw-runtime-".length);
  }
  const sessionId = (log.sessionId ?? "").trim();
  if (sessionId.startsWith("runtime-")) {
    return sessionId.slice("runtime-".length);
  }
  return null;
}

function resolveUtilityRuntimeRoleFilterAgentId(filterId: string, currentAgentId: string | null) {
  if (filterId === UTILITY_LOG_ROLE_FILTER_ALL) {
    return null;
  }
  if (filterId === UTILITY_LOG_ROLE_FILTER_ACTIVE) {
    return currentAgentId?.trim() || null;
  }
  return filterId.trim() || null;
}

function matchesAgentLog(log: OpenClawMessageLogItem, agentId: string | null) {
  if (!agentId) {
    return false;
  }
  const normalizedAgentId = agentId.trim().toLowerCase();
  if (!normalizedAgentId) {
    return false;
  }
  const platformId = (log.platformId ?? "").trim().toLowerCase();
  if (platformId === `openclaw-agent-${normalizedAgentId}` || platformId === `openclaw-runtime-${normalizedAgentId}`) {
    return true;
  }
  const sessionId = (log.sessionId ?? "").trim().toLowerCase();
  if (sessionId.startsWith(`runtime-${normalizedAgentId}-`)) {
    return true;
  }
  return equalsIgnoreCase(getLogAgentId(log), agentId);
}

function isScheduledRuntimeLog(log: OpenClawMessageLogItem) {
  const method = (log.method ?? "").trim().toLowerCase();
  if (method.includes("cron") || method.includes("schedule") || method.includes("timer")) {
    return true;
  }
  const toolName = normalizeRuntimeToolName(log).trim().toLowerCase();
  if (toolName.includes("cron") || toolName.includes("schedule") || toolName.includes("timer")) {
    return true;
  }
  const requestTarget = `${log.path ?? ""} ${log.endpoint ?? ""}`.toLowerCase();
  if (
    requestTarget.includes("/cron") ||
    requestTarget.includes("/schedule") ||
    requestTarget.includes("scheduled") ||
    requestTarget.includes("/timer")
  ) {
    return true;
  }
  const payloadSummary = `${log.requestBody ?? ""} ${log.streamSummary ?? ""} ${log.responseBody ?? ""}`.toLowerCase();
  return payloadSummary.includes("\"cron\"") || payloadSummary.includes("\"schedule\"") || payloadSummary.includes("定时");
}

function isToolRuntimeLog(log: OpenClawMessageLogItem) {
  const method = (log.method ?? "").trim().toUpperCase();
  if (/^TOOL(?::|\/|_|$)/.test(method)) {
    return true;
  }
  const target = `${log.path ?? ""} ${log.endpoint ?? ""}`.toLowerCase();
  return target.includes("/tools/") || target.includes("tool_call") || target.includes("tool-call");
}

function getRuntimeLogCategory(log: OpenClawMessageLogItem): Exclude<UtilityLogCategory, "all"> {
  return isToolRuntimeLog(log) ? "tool" : "message";
}

function matchesRuntimeLogCategory(log: OpenClawMessageLogItem, category: UtilityLogCategory) {
  if (category === "all") {
    return true;
  }
  return getRuntimeLogCategory(log) === category;
}

function matchesRuntimeLogSchedule(log: OpenClawMessageLogItem, filter: UtilityLogScheduleFilter) {
  if (filter === "all") {
    return true;
  }
  const isScheduled = isScheduledRuntimeLog(log);
  return filter === "scheduled" ? isScheduled : !isScheduled;
}

function getRuntimeLogCategoryLabel(log: OpenClawMessageLogItem) {
  return getRuntimeLogCategory(log) === "tool" ? "工具" : "消息";
}

function clearRuntimeToolSyncRetryTimer() {
  if (runtimeToolSyncRetryTimer) {
    window.clearTimeout(runtimeToolSyncRetryTimer);
    runtimeToolSyncRetryTimer = 0;
  }
}

function isRuntimeToolSyncExpired(context: RuntimeToolSyncContext) {
  return Date.now() > context.expiresAtMs;
}

function normalizeRuntimeToolName(log: OpenClawMessageLogItem) {
  const method = (log.method ?? "").trim();
  if (method.toUpperCase().startsWith("TOOL:")) {
    const name = method.slice("TOOL:".length).trim();
    if (name) {
      return name;
    }
  }
  const endpoint = (log.endpoint ?? "").trim();
  if (endpoint) {
    const match = endpoint.match(/\/tool\/([^/?#]+)/i);
    if (match?.[1]) {
      try {
        return decodeURIComponent(match[1]);
      } catch {
        return match[1];
      }
    }
  }
  return "tool";
}

function normalizeRuntimeToolPayloadText(value?: string) {
  const source = (value ?? "").trim();
  if (!source) {
    return "";
  }
  try {
    return JSON.stringify(JSON.parse(source), null, 2);
  } catch {
    return source;
  }
}

function buildRuntimeToolMessage(log: OpenClawMessageLogItem): AgentChatMessage {
  const toolInput = normalizeRuntimeToolPayloadText(log.requestBody);
  const toolOutput = normalizeRuntimeToolPayloadText(log.streamSummary || log.responseBody || log.error || "");
  const toolStatus: ChatToolStatus = (log.responseStatus >= 400 || Boolean((log.error ?? "").trim())) ? "error" : "done";
  return {
    id: `runtime-tool-${log.id}`,
    role: "assistant",
    text: toolOutput || toolInput || "工具执行完成。",
    status: toolStatus === "error" ? "error" : "done",
    createdAt: log.createdAt,
    kind: "runtime_tool",
    toolName: normalizeRuntimeToolName(log),
    toolStatus,
    toolInput: toolInput || undefined,
    toolOutput: toolOutput || undefined
  };
}

function insertRuntimeToolMessages(beforeMessageId: string, logs: OpenClawMessageLogItem[], afterMs: number, agentId: string) {
  const anchorIndex = chatMessages.value.findIndex((message) => message.id === beforeMessageId);
  if (anchorIndex < 0) {
    return 0;
  }
  const rows = logs
    .filter((log) => isToolRuntimeLog(log))
    .filter((log) => matchesAgentLog(log, agentId))
    .filter((log) => log.createdAt >= afterMs)
    .filter((log) => !chatMessages.value.some((message) => message.id === `runtime-tool-${log.id}`))
    .sort((left, right) => left.createdAt - right.createdAt)
    .map((log) => buildRuntimeToolMessage(log));

  if (rows.length === 0) {
    return 0;
  }

  chatMessages.value.splice(anchorIndex, 0, ...rows);
  return rows.length;
}

async function loadRuntimeToolLogs() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return [] as OpenClawMessageLogItem[];
  }
  try {
    const result = (await invoke("load_openclaw_message_logs")) as OpenClawMessageLogResponse;
    return Array.isArray(result.logs) ? result.logs : [];
  } catch {
    return [] as OpenClawMessageLogItem[];
  }
}

async function syncRuntimeToolMessagesNow(context: RuntimeToolSyncContext) {
  if (isRuntimeToolSyncExpired(context)) {
    runtimeToolSyncContext.value = null;
    clearRuntimeToolSyncRetryTimer();
    return 0;
  }
  const hasAnchor = chatMessages.value.some((message) => message.id === context.pendingMessageId);
  if (!hasAnchor) {
    runtimeToolSyncContext.value = null;
    clearRuntimeToolSyncRetryTimer();
    return 0;
  }
  const logs = await loadRuntimeToolLogs();
  const inserted = insertRuntimeToolMessages(context.pendingMessageId, logs, context.startedAtMs, context.runtimeAgentId);
  if (inserted > 0) {
    await scrollMessagesToBottom();
  }
  return inserted;
}

function scheduleRuntimeToolSyncRetry() {
  clearRuntimeToolSyncRetryTimer();
  const context = runtimeToolSyncContext.value;
  if (!context) {
    return;
  }
  runtimeToolSyncRetryTimer = window.setTimeout(() => {
    void (async () => {
      const current = runtimeToolSyncContext.value;
      if (!current) {
        clearRuntimeToolSyncRetryTimer();
        return;
      }
      await syncRuntimeToolMessagesNow(current);
      const latest = runtimeToolSyncContext.value;
      if (!latest || isRuntimeToolSyncExpired(latest)) {
        runtimeToolSyncContext.value = null;
        clearRuntimeToolSyncRetryTimer();
        return;
      }
      scheduleRuntimeToolSyncRetry();
    })();
  }, runtimeToolSyncRetryDelayMs);
}

function isRuntimeToolMessageExpanded(messageId: string) {
  return Boolean(expandedRuntimeToolMessages.value[messageId]);
}

function toggleRuntimeToolMessageExpanded(messageId: string) {
  const current = expandedRuntimeToolMessages.value[messageId];
  expandedRuntimeToolMessages.value = {
    ...expandedRuntimeToolMessages.value,
    [messageId]: !current
  };
}

function resolveRuntimeToolStatus(message: AgentChatMessage): ChatToolStatus {
  if (message.toolStatus === "running" || message.toolStatus === "done" || message.toolStatus === "error") {
    return message.toolStatus;
  }
  if (message.status === "pending") {
    return "running";
  }
  if (message.status === "error") {
    return "error";
  }
  return "done";
}

function getRuntimeToolStatusLabel(message: AgentChatMessage) {
  const status = resolveRuntimeToolStatus(message);
  if (status === "running") {
    return "加载中";
  }
  if (status === "error") {
    return "失败";
  }
  return "完成";
}

function getRuntimeToolStatusClass(message: AgentChatMessage) {
  const status = resolveRuntimeToolStatus(message);
  if (status === "running") {
    return "is-running";
  }
  if (status === "error") {
    return "is-error";
  }
  return "is-done";
}

function getRuntimeToolLabel(message: AgentChatMessage) {
  return message.toolName?.trim() || "tool";
}

function getRuntimeToolMessageDetail(message: AgentChatMessage) {
  const sections: string[] = [];
  const input = message.toolInput?.trim() ?? "";
  const output = message.toolOutput?.trim() ?? "";
  if (input) {
    sections.push(`输入\n${input}`);
  }
  if (output) {
    sections.push(`结果\n${output}`);
  }
  if (sections.length > 0) {
    return sections.join("\n\n");
  }
  return message.text.trim();
}

function formatJsonText(value?: string) {
  const source = (value ?? "").trim();
  if (!source) {
    return { text: "暂无内容", language: "text" as const };
  }
  try {
    return {
      text: JSON.stringify(JSON.parse(source), null, 2),
      language: "json" as const
    };
  } catch {
    return { text: source, language: "text" as const };
  }
}

function getDefaultLogDetailTab(log: OpenClawMessageLogItem): UtilityLogDetailTab {
  if ((log.responseBody ?? "").trim()) {
    return "response";
  }
  if ((log.streamSummary ?? "").trim()) {
    return "stream";
  }
  if ((log.requestBody ?? "").trim()) {
    return "request";
  }
  return "raw";
}

function buildLogDetailSections(log: OpenClawMessageLogItem) {
  const sections: Array<{ id: UtilityLogDetailTab; label: string; text: string; language: "json" | "text" }> = [];

  if ((log.requestBody ?? "").trim()) {
    const view = formatJsonText(log.requestBody);
    sections.push({ id: "request", label: "请求体", text: view.text, language: view.language });
  }

  if ((log.responseBody ?? "").trim()) {
    const view = formatJsonText(log.responseBody);
    sections.push({ id: "response", label: "响应体", text: view.text, language: view.language });
  }

  if ((log.streamSummary ?? "").trim()) {
    const view = formatJsonText(log.streamSummary);
    sections.push({ id: "stream", label: "流式汇总", text: view.text, language: view.language });
  }

  const rawText = [log.error, log.responseBody].filter((item) => Boolean(item && item.trim())).join("\n\n").trim();
  if (rawText) {
    const view = formatJsonText(rawText);
    sections.push({ id: "raw", label: "原始响应", text: view.text, language: view.language });
  }

  if (sections.length === 0) {
    sections.push({ id: "raw", label: "原始响应", text: "暂无可预览内容", language: "text" });
  }

  return sections;
}

function getErrorSignature(log: OpenClawMessageLogItem) {
  const errorText = (log.error ?? "").trim();
  if (errorText) {
    return errorText.split("\n")[0].slice(0, 120);
  }
  if (log.responseStatus >= 500) {
    return `HTTP ${log.responseStatus} · ${log.method}`;
  }
  if (log.responseStatus >= 400) {
    return `HTTP ${log.responseStatus} · ${log.method}`;
  }
  return "运行异常";
}

function pickLogForDetail(logId: string | null, logs: OpenClawMessageLogItem[]) {
  if (!logId) {
    return logs[0] ?? null;
  }
  return logs.find((log) => log.id === logId) ?? logs[0] ?? null;
}

function selectUtilityLog(log: OpenClawMessageLogItem | null, preferredTab?: UtilityLogDetailTab) {
  utilitySelectedLogId.value = log?.id ?? null;
  if (!log) {
    utilityLogDetailTab.value = "response";
    return;
  }
  utilityLogDetailTab.value = preferredTab ?? getDefaultLogDetailTab(log);
}

const MEMORY_FILE_NAME_EXPLANATION_MAP: Record<string, string> = {
  "AGENTS.MD": "员工工作规则",
  "MEMORY.MD": "长期记忆",
  "IDENTITY.MD": "身份定义",
  "USER.MD": "用户身份定义",
  "TOOLS.MD": "工具使用规范",
  "SOUL.MD": "性格与价值观",
  "HEARTBEAT.MD": "状态心跳记录",
  "BOOTSTRAP.MD": "启动说明"
};

function getFileNameFromPath(pathValue: string) {
  const normalized = pathValue.replace(/\\/g, "/").trim();
  if (!normalized) {
    return "";
  }
  const segments = normalized.split("/").filter(Boolean);
  return segments[segments.length - 1] ?? normalized;
}

function getMemoryDisplayName(item: SourceFileSnapshotItem) {
  const fileName = getFileNameFromPath(item.relativePath || item.sourcePath || item.title) || item.title || "记忆文件";
  const explanation = MEMORY_FILE_NAME_EXPLANATION_MAP[fileName.toUpperCase()];
  if (explanation) {
    return `${fileName} · ${explanation}`;
  }

  const fallbackTitle = item.title.trim();
  if (fallbackTitle && fallbackTitle.toUpperCase() !== fileName.toUpperCase()) {
    return `${fileName} · ${fallbackTitle}`;
  }
  return fileName;
}

function buildMemoryFallbackSnapshot(items: MemoryRecord[]): SourceFileSnapshotResponse {
  return {
    sourcePath: "localStorage:keai.desktop-pet.memory",
    detail: "当前环境未启用 runtime 记忆快照，以下为本地记忆数据。",
    items: items.map((item) => ({
      id: item.id,
      title: item.title,
      summary: item.summary,
      content: item.summary,
      sourcePath: "localStorage",
      relativePath: `${item.scope}/${item.title}`,
      facetKey: item.scope,
      facetLabel: item.scope,
      category: item.scope,
      updatedAtMs: item.updatedAt,
      exists: true
    }))
  };
}

function buildTaskFallbackSnapshot(items: TaskRecord[]): TaskSnapshotResponse {
  const jobs: TaskSnapshotItem[] = items.map((item) => ({
    // Keep fallback snapshot compatible with legacy task status chips.
    // `done` and `cancelled` are treated as disabled terminal states.
    id: item.id,
    name: item.title,
    agentId: item.owner,
    sessionTarget: item.project,
    enabled: item.status !== "done" && item.status !== "cancelled",
    deleteAfterRun: item.status === "done" || item.status === "cancelled",
    statusKind: item.status === "in_progress" ? "late" : item.status === "done" || item.status === "cancelled" ? "disabled" : "scheduled",
    statusLabel: item.status === "in_progress" ? "待执行" : item.status === "done" || item.status === "cancelled" ? "已停用" : "已启用",
    summary: item.summary,
    nextRunAtMs: item.dueAt,
    createdAtMs: item.updatedAt,
    updatedAtMs: item.updatedAt,
    scheduleKind: "manual"
  }));

  return {
    sourcePath: "localStorage:keai.desktop-pet.tasks",
    detail: "当前环境未启用 runtime 任务快照，以下为本地任务数据。",
    jobs
  };
}

async function loadRelatedMemorySnapshot() {
  const invoke = getTauriInvoke();
  if (invoke) {
    relatedMemorySnapshot.value = (await invoke("load_memory_file_snapshot")) as SourceFileSnapshotResponse;
    return;
  }
  relatedMemorySnapshot.value = buildMemoryFallbackSnapshot(loadMemories());
}

async function loadRelatedSkillsSnapshot() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    relatedSkillsSnapshot.value = {
      sourcePath: "runtime unavailable",
      builtIn: [],
      installed: []
    };
    relatedResourceModalError.value = "当前环境不支持读取 OpenClaw 技能库。";
    return;
  }
  relatedSkillsSnapshot.value = (await invoke("load_openclaw_skills_list")) as OpenClawSkillsListResponse;
}

async function loadRelatedToolsSnapshot(agentId: string) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    relatedToolsSnapshot.value = {
      profile: "default",
      profileLabel: "default",
      tools: []
    };
    relatedResourceModalError.value = "当前环境不支持读取 OpenClaw 工具权限。";
    return;
  }
  relatedToolsSnapshot.value = (await invoke("load_openclaw_tools_list", { agentId })) as OpenClawToolsListResponse;
}

async function loadRelatedModelSnapshot() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    relatedModelSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: "当前环境不支持读取模型平台配置。",
      platforms: []
    };
    relatedModelDraft.value = buildRelatedModelCustomDraft();
    relatedModelCustomExpanded.value = true;
    relatedModelApiKeyVisible.value = false;
    relatedModelSelectedPopularPlatformId.value = null;
    relatedModelEditingProviderId.value = null;
    relatedModelPendingDeleteProviderId.value = null;
    relatedResourceModalError.value = "当前环境不支持模型配置快照。";
    return;
  }

  relatedModelSnapshot.value = (await invoke("load_openclaw_platforms_snapshot")) as OpenClawPlatformSnapshotResponse;
  relatedModelCustomExpanded.value = (relatedModelSnapshot.value?.platforms ?? []).length === 0;
  relatedModelDraft.value = buildRelatedModelCustomDraft();
  relatedModelApiKeyVisible.value = false;
  relatedModelSelectedPopularPlatformId.value = null;
  relatedModelEditingProviderId.value = null;
  relatedModelPendingDeleteProviderId.value = null;
}

async function loadRelatedChannelSnapshot() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    relatedChannelSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: "当前环境不支持读取频道配置。",
      channels: []
    };
    relatedResourceModalError.value = "当前环境不支持频道配置快照。";
    return;
  }
  relatedChannelSnapshot.value = (await invoke("load_openclaw_channel_accounts_snapshot")) as OpenClawChannelAccountsSnapshotResponse;
}

async function loadRelatedTaskSnapshot() {
  const invoke = getTauriInvoke();
  if (invoke) {
    const agentId = activeAgent.value?.agentId?.trim() ?? "";
    relatedTaskSnapshot.value = (await invoke("load_task_snapshot", agentId ? { agentId } : {})) as TaskSnapshotResponse;
    return;
  }
  relatedTaskSnapshot.value = buildTaskFallbackSnapshot(taskItems.value);
}

function buildTaskReminderOccurrenceKey(job: TaskSnapshotItem) {
  const nextRunAtMs = typeof job.nextRunAtMs === "number" && Number.isFinite(job.nextRunAtMs)
    ? Math.floor(job.nextRunAtMs)
    : 0;
  return `${job.id}:${nextRunAtMs}`;
}

function isTaskReminderCandidate(job: TaskSnapshotItem, nowMs: number) {
  if (!job.enabled || job.statusKind === "disabled") {
    return false;
  }
  if (typeof job.nextRunAtMs !== "number" || !Number.isFinite(job.nextRunAtMs)) {
    return false;
  }
  return job.nextRunAtMs <= nowMs;
}

async function loadTaskSnapshotForReminder() {
  const invoke = getTauriInvoke();
  if (invoke) {
    return (await invoke("load_task_snapshot")) as TaskSnapshotResponse;
  }
  return buildTaskFallbackSnapshot(taskItems.value);
}

function clearTaskReminderAutoCloseTimer() {
  if (taskReminderAutoCloseTimer) {
    window.clearTimeout(taskReminderAutoCloseTimer);
    taskReminderAutoCloseTimer = 0;
  }
}

function buildTaskReminderSystemNotificationBody(job: TaskSnapshotItem) {
  const lines = [`${formatTaskScheduleKind(job.scheduleKind, job.deleteAfterRun)} · 到点 ${formatDateTime(job.nextRunAtMs)}`];
  const summary = job.summary.trim();
  if (summary) {
    lines.push(summary);
  }
  return lines.join("\n");
}

function buildTaskReminderSystemNotificationTitle(job: TaskSnapshotItem) {
  const title = `任务提醒：${job.name || "未命名任务"}`;
  return title;
}

async function tryShowTauriTaskReminderNotification(job: TaskSnapshotItem) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    return false;
  }

  const title = buildTaskReminderSystemNotificationTitle(job);
  const body = buildTaskReminderSystemNotificationBody(job);
  const notifyByBackendCommand = async () => {
    await invoke("show_system_notification", {
      title,
      body
    });
  };

  try {
    await notifyByBackendCommand();
    return true;
  } catch (error) {
    console.warn("Failed to show task reminder system notification via Tauri backend.", error);
    return false;
  }
}

function showWebTaskReminderNotification(job: TaskSnapshotItem) {
  if (typeof window === "undefined" || typeof Notification === "undefined") {
    return;
  }

  const title = buildTaskReminderSystemNotificationTitle(job);
  const body = buildTaskReminderSystemNotificationBody(job);
  const tag = `dragonclaw-task-reminder-${job.id}`;

  const dispatchNotification = () => {
    try {
      const notification = new Notification(title, { body, tag });
      notification.onclick = () => {
        if (typeof window.focus === "function") {
          window.focus();
        }
        activeSection.value = "tasks";
        if (typeof notification.close === "function") {
          notification.close();
        }
      };
    } catch {
      // Ignore web notification failures and keep in-app reminders available.
    }
  };

  if (Notification.permission === "granted") {
    dispatchNotification();
    return;
  }

  if (Notification.permission !== "default" || taskReminderNotificationPermissionRequesting) {
    return;
  }

  taskReminderNotificationPermissionRequesting = true;
  Notification.requestPermission()
    .then((permission) => {
      if (permission === "granted") {
        dispatchNotification();
      }
    })
    .catch(() => {
      // Ignore permission request failures.
    })
    .finally(() => {
      taskReminderNotificationPermissionRequesting = false;
    });
}

async function showSystemTaskReminderNotification(job: TaskSnapshotItem) {
  const shownByTauri = await tryShowTauriTaskReminderNotification(job);
  if (shownByTauri) {
    return;
  }
  showWebTaskReminderNotification(job);
}

function showNextTaskReminder() {
  if (taskReminderPopup.value || taskReminderQueue.value.length === 0) {
    return;
  }
  const [nextJob, ...restJobs] = taskReminderQueue.value;
  taskReminderQueue.value = restJobs;
  taskReminderPopup.value = {
    id: `task-reminder-${nextJob.id}-${nextJob.nextRunAtMs ?? Date.now()}`,
    job: nextJob,
    queuedCount: taskReminderQueue.value.length
  };
  void showSystemTaskReminderNotification(nextJob);
  clearTaskReminderAutoCloseTimer();
  taskReminderAutoCloseTimer = window.setTimeout(() => {
    closeTaskReminderPopup();
  }, taskReminderAutoCloseMs);
}

function closeTaskReminderPopup() {
  if (!taskReminderPopup.value) {
    return;
  }
  taskReminderPopup.value = null;
  clearTaskReminderAutoCloseTimer();
  if (taskReminderQueue.value.length > 0) {
    window.setTimeout(() => {
      showNextTaskReminder();
    }, 180);
  }
}

function openTaskBoardFromReminder() {
  activeSection.value = "tasks";
  closeTaskReminderPopup();
}

function triggerTemporaryTaskReminderTestPopup() {
  const nowMs = Date.now();
  const currentPopup = taskReminderPopup.value;
  if (currentPopup && !currentPopup.job.id.startsWith(TEMP_TEST_TASK_REMINDER_ID_PREFIX)) {
    taskReminderQueue.value = [currentPopup.job, ...taskReminderQueue.value];
  }

  const testJob: TaskSnapshotItem = {
    id: `${TEMP_TEST_TASK_REMINDER_ID_PREFIX}-${nowMs}`,
    name: "临时测试监控任务",
    agentId: "monitor-test-agent",
    sessionTarget: "manual-test",
    enabled: true,
    deleteAfterRun: true,
    statusKind: "enabled",
    statusLabel: "启用",
    summary: "这是测试任务消息：用于验证左侧按钮触发监控任务提醒弹窗。",
    nextRunAtMs: nowMs,
    createdAtMs: nowMs,
    updatedAtMs: nowMs,
    scheduleKind: "at"
  };

  taskReminderPopup.value = {
    id: `task-reminder-test-${nowMs}`,
    job: testJob,
    queuedCount: taskReminderQueue.value.length
  };
  void showSystemTaskReminderNotification(testJob);

  clearTaskReminderAutoCloseTimer();
  taskReminderAutoCloseTimer = window.setTimeout(() => {
    closeTaskReminderPopup();
  }, taskReminderAutoCloseMs);
}

function queueTaskReminder(job: TaskSnapshotItem) {
  const key = buildTaskReminderOccurrenceKey(job);
  const duplicateInPopup =
    taskReminderPopup.value !== null && buildTaskReminderOccurrenceKey(taskReminderPopup.value.job) === key;
  const duplicateInQueue = taskReminderQueue.value.some((item) => buildTaskReminderOccurrenceKey(item) === key);
  if (duplicateInPopup || duplicateInQueue) {
    return;
  }

  taskReminderQueue.value = [...taskReminderQueue.value, job];
  if (taskReminderPopup.value) {
    taskReminderPopup.value = {
      ...taskReminderPopup.value,
      queuedCount: taskReminderQueue.value.length
    };
    return;
  }
  showNextTaskReminder();
}

function bootstrapTaskReminderKeys(jobs: TaskSnapshotItem[]) {
  const nowMs = Date.now();
  for (const job of jobs) {
    if (isTaskReminderCandidate(job, nowMs)) {
      taskReminderSeenKeys.add(buildTaskReminderOccurrenceKey(job));
    }
  }
  taskReminderBootstrapped = true;
}

async function pollTaskReminders() {
  try {
    const snapshot = await loadTaskSnapshotForReminder();
    const jobs = Array.isArray(snapshot.jobs) ? snapshot.jobs : [];

    if (!taskReminderBootstrapped) {
      bootstrapTaskReminderKeys(jobs);
      return;
    }

    const nowMs = Date.now();
    const dueJobs = jobs
      .filter((job) => isTaskReminderCandidate(job, nowMs))
      .sort((left, right) => (left.nextRunAtMs ?? 0) - (right.nextRunAtMs ?? 0));

    for (const job of dueJobs) {
      const key = buildTaskReminderOccurrenceKey(job);
      if (taskReminderSeenKeys.has(key)) {
        continue;
      }
      taskReminderSeenKeys.add(key);
      queueTaskReminder(job);
    }

    if (taskReminderSeenKeys.size > 600) {
      taskReminderSeenKeys.clear();
      for (const job of dueJobs.slice(-120)) {
        taskReminderSeenKeys.add(buildTaskReminderOccurrenceKey(job));
      }
    }
  } catch {
    // Ignore reminder polling failures; task board can still be refreshed manually.
  }
}

function startTaskReminderMonitor() {
  taskReminderSeenKeys.clear();
  taskReminderQueue.value = [];
  taskReminderPopup.value = null;
  taskReminderBootstrapped = false;
  clearTaskReminderAutoCloseTimer();
  if (taskReminderPollTimer) {
    window.clearInterval(taskReminderPollTimer);
  }
  void pollTaskReminders();
  taskReminderPollTimer = window.setInterval(() => {
    void pollTaskReminders();
  }, taskReminderPollIntervalMs);
}

function stopTaskReminderMonitor() {
  if (taskReminderPollTimer) {
    window.clearInterval(taskReminderPollTimer);
    taskReminderPollTimer = 0;
  }
  clearTaskReminderAutoCloseTimer();
  taskReminderQueue.value = [];
  taskReminderPopup.value = null;
  taskReminderSeenKeys.clear();
  taskReminderBootstrapped = false;
}

async function refreshDashboardData() {
  if (isDashboardRefreshing.value) {
    return;
  }

  isDashboardRefreshing.value = true;
  dashboardRefreshError.value = "";
  updateDashboardHeapUsage();

  const invoke = getTauriInvoke();
  if (!invoke) {
    dashboardGatewayHealth.value = {
      status: "unsupported",
      checkedUrl: null,
      detail: "当前环境不支持网关探测。",
      latencyMs: null,
      gatewayPort: null
    };
    dashboardChannelSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: "当前环境不支持频道统计。",
      channels: []
    };
    dashboardPlatformSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: "当前环境不支持平台统计。",
      platforms: []
    };
    chatRuntimeLogs.value = {
      detail: "当前环境不支持运行日志。",
      logs: []
    };
    dashboardLastRefreshedAt.value = Date.now();
    isDashboardRefreshing.value = false;
    return;
  }

  const [gatewayResult, channelResult, platformResult, logsResult] = await Promise.allSettled([
    invoke("check_openclaw_gateway"),
    invoke("load_openclaw_channel_accounts_snapshot"),
    invoke("load_openclaw_platforms_snapshot"),
    invoke("load_openclaw_message_logs")
  ]);

  if (gatewayResult.status === "fulfilled") {
    dashboardGatewayHealth.value = gatewayResult.value as GatewayHealthSnapshotResponse;
  } else {
    dashboardGatewayHealth.value = {
      status: "offline",
      checkedUrl: null,
      detail: gatewayResult.reason instanceof Error ? gatewayResult.reason.message : "网关状态读取失败。",
      latencyMs: null,
      gatewayPort: null
    };
  }

  if (channelResult.status === "fulfilled") {
    dashboardChannelSnapshot.value = channelResult.value as OpenClawChannelAccountsSnapshotResponse;
  } else {
    dashboardChannelSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: channelResult.reason instanceof Error ? channelResult.reason.message : "频道统计读取失败。",
      channels: []
    };
  }

  if (platformResult.status === "fulfilled") {
    dashboardPlatformSnapshot.value = platformResult.value as OpenClawPlatformSnapshotResponse;
  } else {
    dashboardPlatformSnapshot.value = {
      sourcePath: "runtime unavailable",
      detail: platformResult.reason instanceof Error ? platformResult.reason.message : "平台统计读取失败。",
      platforms: []
    };
  }

  if (logsResult.status === "fulfilled") {
    chatRuntimeLogs.value = logsResult.value as OpenClawMessageLogResponse;
  } else {
    chatRuntimeLogs.value = {
      detail: logsResult.reason instanceof Error ? logsResult.reason.message : "运行日志读取失败。",
      logs: []
    };
  }

  if (
    gatewayResult.status === "rejected" ||
    channelResult.status === "rejected" ||
    platformResult.status === "rejected" ||
    logsResult.status === "rejected"
  ) {
    dashboardRefreshError.value = "部分数据读取失败，已展示可用信息。";
  }

  dashboardLastRefreshedAt.value = Date.now();
  isDashboardRefreshing.value = false;
}

async function openExternalUrl(url: string) {
  const trimmed = url.trim();
  if (!trimmed) {
    return;
  }

  const invoke = getTauriInvoke();
  if (invoke) {
    try {
      await invoke("open_external_url", { url: trimmed });
      return;
    } catch {
      // Fallback to browser open.
    }
  }

  if (typeof window !== "undefined") {
    window.open(trimmed, "_blank", "noopener,noreferrer");
  }
}

async function handleOpenDetectedFileFolder(file: ChatDetectedFile) {
  if (!isAbsoluteLocalPath(file.normalizedPath)) {
    showChatAgentDeleteNotice("当前附件不包含可打开的本地路径。");
    return;
  }
  const invoke = getTauriInvoke();
  if (!invoke) {
    showChatAgentDeleteNotice("当前环境不支持打开本地文件夹。");
    return;
  }
  try {
    await invoke("open_local_path_in_folder", { path: file.normalizedPath });
  } catch (error) {
    showChatAgentDeleteNotice(resolveUnknownErrorMessage(error, "打开文件夹失败。"));
  }
}

function canOpenDetectedFileFolder(file: ChatDetectedFile) {
  return isAbsoluteLocalPath(file.normalizedPath);
}

function stopFeishuQrCountdown() {
  if (feishuQrCountdownTimer) {
    window.clearInterval(feishuQrCountdownTimer);
    feishuQrCountdownTimer = 0;
  }
}

function startFeishuQrCountdown(expiresAtMs: number | null) {
  stopFeishuQrCountdown();
  feishuQrTickMs.value = Date.now();
  if (!expiresAtMs || expiresAtMs <= feishuQrTickMs.value) {
    return;
  }

  feishuQrCountdownTimer = window.setInterval(() => {
    feishuQrTickMs.value = Date.now();
    if (feishuQrTickMs.value >= expiresAtMs) {
      stopFeishuQrCountdown();
    }
  }, 1000);
}

function resetFeishuQrState() {
  stopFeishuQrCountdown();
  feishuQrTargetUrl.value = "";
  feishuQrDeviceCode.value = "";
  feishuQrPollIntervalSeconds.value = 5;
  feishuQrExpiresAtMs.value = null;
  feishuQrTickMs.value = Date.now();
  feishuOpenclawUserCode.value = "";
  feishuQrVisible.value = false;
}

async function requestFeishuQrContext() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    throw new Error("当前环境不支持获取飞书创建二维码。");
  }
  const response = (await invoke("request_feishu_openclaw_qr")) as FeishuOnboardingQrResponse;
  const targetUrl = typeof response.qrUrl === "string" ? response.qrUrl.trim() : "";
  const userCode = typeof response.userCode === "string" ? response.userCode.trim() : "";
  const deviceCode = typeof response.deviceCode === "string" ? response.deviceCode.trim() : "";
  if (!targetUrl || !userCode || !deviceCode) {
    throw new Error("飞书创建二维码返回为空，请稍后重试。");
  }

  feishuQrTargetUrl.value = targetUrl;
  feishuOpenclawUserCode.value = userCode;
  feishuQrDeviceCode.value = deviceCode;
  feishuQrPollIntervalSeconds.value = Number.isFinite(response.pollIntervalSeconds)
    ? Math.max(1, Math.min(30, Math.floor(response.pollIntervalSeconds)))
    : 5;
  feishuQrExpiresAtMs.value = Number.isFinite(response.expiresAtMs) ? response.expiresAtMs : null;
  startFeishuQrCountdown(feishuQrExpiresAtMs.value);
}

function getFeishuChannelGroup(snapshot: OpenClawChannelAccountsSnapshotResponse | null | undefined) {
  if (!snapshot) {
    return null;
  }
  return snapshot.channels.find((group) => normalizeChannelPaneType(group.channelType) === FEISHU_CHANNEL_ID) ?? null;
}

function syncFeishuFormValues(values: Record<string, unknown> | null | undefined) {
  const appId = values?.appId;
  const appSecret = values?.appSecret;
  feishuAppId.value = typeof appId === "string" ? appId : "";
  feishuAppSecret.value = typeof appSecret === "string" ? appSecret : "";
}

async function loadFeishuChannelFormValues(accountId: string) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    throw new Error("当前环境不支持读取飞书配置。");
  }
  const normalizedAccountId = accountId.trim() || FEISHU_DEFAULT_ACCOUNT_ID;
  const values = (await invoke("load_openclaw_channel_form_values", {
    channelType: FEISHU_CHANNEL_ID,
    accountId: normalizedAccountId
  })) as Record<string, unknown>;
  syncFeishuFormValues(values);
}

async function openFeishuConnectModal(options?: {
  accountId?: string;
  accountName?: string;
  loadExisting?: boolean;
}) {
  closeProxyConfigModal();
  closeRelatedResourceModal();
  closeChannelConfigModal();
  closeChannelBindingModal();
  closeUtilityModal();
  closeSidebarSettingsModal();
  closeSidebarLogsPanel();
  isFeishuConnectModalOpen.value = true;
  feishuConnectLoading.value = true;
  feishuConnectSaving.value = false;
  feishuConnectChecking.value = false;
  feishuConnectError.value = "";
  feishuConnectNotice.value = "";
  feishuManualExpanded.value = false;
  feishuAppSecretVisible.value = false;
  feishuQrRequesting.value = false;
  feishuTargetAccountId.value = options?.accountId?.trim() || FEISHU_DEFAULT_ACCOUNT_ID;
  feishuTargetAccountName.value = normalizeChatUserGroupName(options?.accountName ?? "");
  resetFeishuQrState();
  syncFeishuFormValues(null);
  const loadExisting = options?.loadExisting !== false;

  try {
    if (loadExisting) {
      await loadFeishuChannelFormValues(feishuTargetAccountId.value);
    }
    const group = getFeishuChannelGroup(dashboardChannelSnapshot.value);
    const targetAccount = group?.accounts.find((account) => equalsIgnoreCase(account.accountId, feishuTargetAccountId.value)) ?? null;
    const hasConfiguredFeishuAccount = Boolean(targetAccount?.configured);
    const hasRunningFeishuAccount = Boolean(
      group?.accounts.some((account) => {
        const normalizedStatus = (account.status ?? "").trim().toLowerCase();
        return account.configured && (normalizedStatus === "connected" || normalizedStatus === "online");
      })
    );
    feishuPluginPrepared = hasRunningFeishuAccount;
    if (hasConfiguredFeishuAccount) {
      const accountLabel = (targetAccount?.name ?? "").trim() || targetAccount?.accountId || feishuTargetAccountId.value;
      feishuConnectNotice.value = `已检测到账号 ${accountLabel} 的飞书配置。你可以重新扫码创建机器人，或直接更新 App ID / App Secret。`;
    } else if (feishuTargetAccountName.value) {
      feishuConnectNotice.value = `将创建新机器人：${feishuTargetAccountName.value}。`;
    } else if (group?.accounts.some((account) => account.configured)) {
      feishuConnectNotice.value = "已检测到飞书账号配置。你可以重新扫码创建新机器人，或直接更新 App ID / App Secret。";
    }
  } catch (error) {
    feishuConnectError.value = error instanceof Error ? error.message : "读取飞书配置失败。";
  } finally {
    feishuConnectLoading.value = false;
  }
}

function closeFeishuConnectModal() {
  isFeishuConnectModalOpen.value = false;
  feishuConnectLoading.value = false;
  feishuConnectSaving.value = false;
  feishuConnectChecking.value = false;
  feishuConnectError.value = "";
  feishuConnectNotice.value = "";
  feishuManualExpanded.value = false;
  feishuAppSecretVisible.value = false;
  feishuQrRequesting.value = false;
  resetFeishuQrState();
  feishuAppId.value = "";
  feishuAppSecret.value = "";
  feishuTargetAccountId.value = FEISHU_DEFAULT_ACCOUNT_ID;
  feishuTargetAccountName.value = "";
}

function notifyFeishuConfiguredAndClose() {
  if (typeof window !== "undefined") {
    window.alert("飞书已配置完成。");
  }
  closeFeishuConnectModal();
}

async function handleFeishuQrConnect() {
  if (feishuConnectChecking.value || feishuQrRequesting.value) {
    return;
  }

  feishuQrRequesting.value = true;
  feishuConnectError.value = "";
  feishuConnectNotice.value = "";
  try {
    await requestFeishuQrContext();
    feishuQrVisible.value = true;
    feishuConnectNotice.value = "创建码已更新，请尽快扫码完成机器人创建。";
  } catch (error) {
    feishuConnectError.value = error instanceof Error ? error.message : "获取飞书创建二维码失败。";
  } finally {
    feishuQrRequesting.value = false;
  }
}

async function handleFeishuOpenDocs() {
  await openExternalUrl(FEISHU_DOCS_URL);
}

async function handleFeishuOpenQrLink() {
  if (!feishuQrTargetUrl.value.trim()) {
    return;
  }
  await openExternalUrl(feishuQrTargetUrl.value);
}

async function saveFeishuCredentials(
  appId: string,
  appSecret: string,
  domain: "feishu" | "lark" = "feishu"
) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    throw new Error("当前环境不支持写入飞书配置。");
  }
  const targetAccountId = feishuTargetAccountId.value.trim() || FEISHU_DEFAULT_ACCOUNT_ID;
  const targetAccountName = feishuTargetAccountName.value.trim();

  if (!feishuPluginPrepared) {
    const pluginInstallResult = (await invoke("install_openclaw_channel_plugin", {
      channelType: FEISHU_CHANNEL_ID
    })) as OpenClawChannelPluginInstallResult;
    if (!pluginInstallResult.success) {
      throw new Error(pluginInstallResult.detail || "安装飞书插件失败。");
    }
    const restartResult = (await invoke("run_lobster_action", {
      action: "restart_gateway"
    })) as LobsterActionResult;
    if (!restartResult.success) {
      feishuPluginPrepared = false;
      throw new Error(`飞书插件已安装，但网关重启失败：${restartResult.detail}`);
    }
    feishuPluginPrepared = true;
  }

  await invoke("save_openclaw_channel_config", {
    payload: {
      channelType: FEISHU_CHANNEL_ID,
      accountId: targetAccountId,
      config: {
        appId,
        appSecret,
        domain
      }
    }
  });
  if (targetAccountName) {
    await renameChannelAccount(FEISHU_CHANNEL_ID, targetAccountId, targetAccountName);
  }

  const bindingAgentId = resolveMainStaffAgent()?.agentId?.trim() || "main";
  await invoke("save_openclaw_channel_binding", {
    payload: {
      channelType: FEISHU_CHANNEL_ID,
      accountId: targetAccountId,
      agentId: bindingAgentId
    }
  });
}

async function handleFeishuManualSave() {
  const invoke = getTauriInvoke();
  if (!invoke || feishuConnectSaving.value) {
    if (!invoke) {
      feishuConnectError.value = "当前环境不支持写入飞书配置。";
    }
    return;
  }

  const appId = feishuAppId.value.trim();
  const appSecret = feishuAppSecret.value.trim();
  if (!appId) {
    feishuConnectError.value = "请输入 App ID。";
    return;
  }
  if (!appSecret) {
    feishuConnectError.value = "请输入 App Secret。";
    return;
  }

  feishuConnectSaving.value = true;
  feishuConnectError.value = "";
  feishuConnectNotice.value = "";
  try {
    await saveFeishuCredentials(appId, appSecret, "feishu");
    feishuConnectNotice.value = "飞书凭证已保存。";
    await refreshDashboardData();
    notifyFeishuConfiguredAndClose();
  } catch (error) {
    feishuConnectError.value = error instanceof Error ? error.message : "保存飞书配置失败。";
  } finally {
    feishuConnectSaving.value = false;
  }
}

async function handleFeishuConnectionCheck() {
  const invoke = getTauriInvoke();
  if (!invoke || feishuConnectChecking.value) {
    if (!invoke) {
      feishuConnectError.value = "当前环境不支持检查飞书连接状态。";
    }
    return;
  }

  feishuConnectChecking.value = true;
  feishuConnectError.value = "";
  feishuConnectNotice.value = "";
  try {
    const deviceCode = feishuQrDeviceCode.value.trim();
    if (deviceCode) {
      const pollResult = (await invoke("poll_feishu_openclaw_qr_result", {
        deviceCode
      })) as FeishuOnboardingPollResponse;
      const normalizedStatus = (pollResult.status ?? "").trim().toLowerCase();
      const appId = typeof pollResult.appId === "string" ? pollResult.appId.trim() : "";
      const appSecret = typeof pollResult.appSecret === "string" ? pollResult.appSecret.trim() : "";
      const tenantBrand = typeof pollResult.tenantBrand === "string" ? pollResult.tenantBrand.trim().toLowerCase() : "";
      const pollMessage = typeof pollResult.message === "string" ? pollResult.message.trim() : "";

      if (normalizedStatus === "success" && appId && appSecret) {
        feishuAppId.value = appId;
        feishuAppSecret.value = appSecret;
        feishuManualExpanded.value = true;
        const domain: "feishu" | "lark" = tenantBrand === "lark" ? "lark" : "feishu";
        await saveFeishuCredentials(appId, appSecret, domain);
        feishuConnectNotice.value = "已自动获取并保存飞书凭证。";
        await refreshDashboardData();
        notifyFeishuConfiguredAndClose();
        return;
      } else if (normalizedStatus === "pending") {
        feishuConnectNotice.value =
          pollMessage || `尚未拿到飞书凭证，请先完成扫码创建后再检查（建议间隔 ${feishuQrPollIntervalSeconds.value} 秒）。`;
      } else if (normalizedStatus === "denied") {
        feishuConnectError.value = pollMessage || "你已拒绝授权，请重新获取创建码并扫码。";
        return;
      } else if (normalizedStatus === "expired") {
        feishuConnectError.value = pollMessage || "创建码已过期，请重新获取创建码。";
        return;
      } else if (normalizedStatus === "error") {
        feishuConnectError.value = pollMessage || "获取飞书凭证失败，请稍后重试。";
        return;
      }
    }

    const snapshot = (await invoke("load_openclaw_channel_accounts_snapshot")) as OpenClawChannelAccountsSnapshotResponse;
    dashboardChannelSnapshot.value = snapshot;
    if (relatedResourceModalTarget.value === "channel") {
      relatedChannelSnapshot.value = snapshot;
    }

    const group = getFeishuChannelGroup(snapshot);
    if (!group || group.accounts.length === 0) {
      if (!feishuConnectNotice.value) {
        feishuConnectNotice.value = "尚未检测到飞书账号配置，可展开“手动输入”先保存 App ID 和 App Secret。";
      }
      return;
    }

    const targetAccount = group.accounts.find((account) => equalsIgnoreCase(account.accountId, feishuTargetAccountId.value)) ?? null;
    if (!targetAccount) {
      feishuConnectNotice.value = `尚未检测到账号 ${feishuTargetAccountId.value}，请先完成扫码创建或手动保存。`;
      return;
    }
    if (!targetAccount.configured) {
      if (!feishuConnectNotice.value) {
        feishuConnectNotice.value = "已检测到飞书账号，但凭证尚未配置完整，请检查 App ID / App Secret。";
      }
      return;
    }

    const normalizedAccountStatus = targetAccount.status.trim().toLowerCase();
    const statusLabel = normalizedAccountStatus === "connected" ? "已连接" : "已配置";
    feishuConnectNotice.value = `检查完成：${targetAccount.accountId} ${statusLabel}。`;
  } catch (error) {
    feishuConnectError.value = error instanceof Error ? error.message : "检查飞书状态失败。";
  } finally {
    feishuConnectChecking.value = false;
  }
}

function resetChannelConfigSecretVisibility() {
  channelConfigSecretVisibility.value = {};
}

function isChannelConfigQrMode(catalog: ChannelPaneCatalogItem | null | undefined) {
  return catalog?.connectionMode === "qr";
}

function isChannelQrBindingTerminalStatus(status: string | null | undefined) {
  const normalizedStatus = (status ?? "").trim().toLowerCase();
  return normalizedStatus === "success" || normalizedStatus === "error";
}

function stopChannelQrBindingPolling() {
  if (channelQrBindingPollTimer) {
    window.clearInterval(channelQrBindingPollTimer);
    channelQrBindingPollTimer = 0;
  }
}

async function clearChannelQrBindingSession(sessionId: string) {
  const normalizedSessionId = sessionId.trim();
  if (!normalizedSessionId) {
    return;
  }
  const invoke = getTauriInvoke();
  if (!invoke) {
    return;
  }
  try {
    await invoke("clear_openclaw_channel_qr_binding_session", { sessionId: normalizedSessionId });
  } catch {
    // Ignore cleanup errors.
  }
}

function resetChannelQrBindingState(options?: { clearSession?: boolean }) {
  const shouldClearSession = options?.clearSession === true;
  const previousSessionId = channelQrBindingSessionId.value.trim();
  stopChannelQrBindingPolling();
  channelQrBindingStarting.value = false;
  channelQrBindingSessionId.value = "";
  channelQrBindingChannelType.value = "";
  channelQrBindingSnapshot.value = null;
  if (shouldClearSession && previousSessionId) {
    void clearChannelQrBindingSession(previousSessionId);
  }
}

function applyChannelQrBindingSnapshot(snapshot: OpenClawChannelQrBindingSessionSnapshot, fallbackChannelType = "") {
  channelQrBindingSnapshot.value = snapshot;
  channelQrBindingSessionId.value = (snapshot.sessionId ?? "").trim();
  const channelType = normalizeChannelPaneType(snapshot.channelType) || normalizeChannelPaneType(fallbackChannelType) || fallbackChannelType;
  channelQrBindingChannelType.value = channelType;
}

function countConfiguredChannelAccountsInSnapshot(
  channelTypeRaw: string,
  snapshot: OpenClawChannelAccountsSnapshotResponse | null | undefined = dashboardChannelSnapshot.value
) {
  const normalizedType = normalizeChannelPaneType(channelTypeRaw);
  if (!snapshot || !normalizedType) {
    return 0;
  }
  let configuredCount = 0;
  for (const group of snapshot.channels ?? []) {
    if (normalizeChannelPaneType(group.channelType) !== normalizedType) {
      continue;
    }
    for (const account of group.accounts ?? []) {
      if (account.configured) {
        configuredCount += 1;
      }
    }
  }
  return configuredCount;
}

async function refreshDashboardAfterQrBindingSuccess(channelTypeRaw: string) {
  const normalizedType = normalizeChannelPaneType(channelTypeRaw);
  await refreshDashboardData();
  if (!normalizedType) {
    return true;
  }
  if (countConfiguredChannelAccountsInSnapshot(normalizedType) > 0) {
    return true;
  }
  const invoke = getTauriInvoke();
  if (!invoke) {
    return false;
  }
  for (let attempt = 0; attempt < 4; attempt += 1) {
    await sleepMs(1200);
    try {
      const snapshot = (await invoke("load_openclaw_channel_accounts_snapshot")) as OpenClawChannelAccountsSnapshotResponse;
      dashboardChannelSnapshot.value = snapshot;
      if (relatedResourceModalTarget.value === "channel") {
        relatedChannelSnapshot.value = snapshot;
      }
      if (countConfiguredChannelAccountsInSnapshot(normalizedType, snapshot) > 0) {
        return true;
      }
    } catch {
      // Ignore transient polling failures after QR binding succeeds.
    }
  }
  return false;
}

async function pollChannelQrBindingSession(sessionId: string) {
  const invoke = getTauriInvoke();
  const normalizedSessionId = sessionId.trim();
  if (!invoke || !normalizedSessionId) {
    return;
  }
  try {
    const snapshot = (await invoke("poll_openclaw_channel_qr_binding", {
      sessionId: normalizedSessionId
    })) as OpenClawChannelQrBindingSessionSnapshot;
    applyChannelQrBindingSnapshot(snapshot, channelQrBindingChannelType.value);
    const normalizedStatus = (snapshot.status ?? "").trim().toLowerCase();
    if (normalizedStatus === "success") {
      stopChannelQrBindingPolling();
      channelConfigNotice.value = "二维码绑定成功。";
      channelConfigError.value = "";
      const synced = await refreshDashboardAfterQrBindingSuccess(snapshot.channelType || channelQrBindingChannelType.value);
      if (!synced) {
        channelConfigNotice.value = "二维码绑定成功，频道列表正在同步中，请稍后点击刷新。";
      }
      return;
    }
    if (normalizedStatus === "error") {
      stopChannelQrBindingPolling();
      channelConfigNotice.value = "";
      channelConfigError.value = (snapshot.detail ?? "").trim() || "二维码绑定失败，请重试。";
    }
  } catch (error) {
    stopChannelQrBindingPolling();
    const detail = error instanceof Error ? error.message : "读取二维码绑定状态失败。";
    if (detail.includes("未找到二维码会话")) {
      resetChannelQrBindingState();
      return;
    }
    channelConfigError.value = detail;
  }
}

function startChannelQrBindingPolling(sessionId: string) {
  const normalizedSessionId = sessionId.trim();
  if (!normalizedSessionId) {
    return;
  }
  stopChannelQrBindingPolling();
  void pollChannelQrBindingSession(normalizedSessionId);
  channelQrBindingPollTimer = window.setInterval(() => {
    void pollChannelQrBindingSession(normalizedSessionId);
  }, CHANNEL_QR_BINDING_POLL_INTERVAL_MS);
}

async function handleStartChannelQrBinding() {
  const invoke = getTauriInvoke();
  if (!invoke) {
    channelConfigError.value = "当前环境不支持二维码绑定。";
    return;
  }
  if (channelQrBindingStarting.value) {
    return;
  }
  const backendType = normalizeChannelPaneType(channelConfigBackendType.value);
  if (backendType !== "weixin" && backendType !== "wecom") {
    channelConfigError.value = "当前频道暂不支持二维码绑定。";
    return;
  }

  channelConfigNotice.value = "";
  channelConfigError.value = "";
  resetChannelQrBindingState({ clearSession: true });
  channelQrBindingChannelType.value = backendType;
  channelQrBindingStarting.value = true;

  try {
    const snapshot = (await invoke("start_openclaw_channel_qr_binding", {
      channelType: backendType
    })) as OpenClawChannelQrBindingSessionSnapshot;
    applyChannelQrBindingSnapshot(snapshot, backendType);
    const normalizedStatus = (snapshot.status ?? "").trim().toLowerCase();
    if (normalizedStatus === "success") {
      const synced = await refreshDashboardAfterQrBindingSuccess(snapshot.channelType || backendType);
      channelConfigNotice.value = synced ? "二维码绑定成功。" : "二维码绑定成功，频道列表正在同步中，请稍后点击刷新。";
      channelConfigError.value = "";
    } else if (normalizedStatus === "error") {
      channelConfigNotice.value = "";
      channelConfigError.value = (snapshot.detail ?? "").trim() || "二维码绑定失败，请重试。";
    } else if (!isChannelQrBindingTerminalStatus(normalizedStatus)) {
      startChannelQrBindingPolling(snapshot.sessionId ?? "");
    }
  } catch (error) {
    channelConfigError.value = error instanceof Error ? error.message : "启动二维码绑定失败。";
  } finally {
    channelQrBindingStarting.value = false;
  }
}

function isChannelConfigSecretVisible(fieldKey: string) {
  return channelConfigSecretVisibility.value[fieldKey] === true;
}

function toggleChannelConfigSecretVisibility(fieldKey: string) {
  channelConfigSecretVisibility.value = {
    ...channelConfigSecretVisibility.value,
    [fieldKey]: !channelConfigSecretVisibility.value[fieldKey]
  };
}

function getChannelConfigGroup(catalogId: string, backendType: string) {
  const groups = dashboardChannelSnapshot.value?.channels ?? [];
  for (const group of groups) {
    const groupType = (group.channelType ?? "").trim().toLowerCase();
    const normalizedGroupType = normalizeChannelPaneType(group.channelType);
    if (groupType === backendType || normalizedGroupType === catalogId) {
      return group;
    }
  }
  return null;
}

function extractChannelBotSequence(raw: string | null | undefined) {
  const value = (raw ?? "").trim();
  if (!value) {
    return 0;
  }
  const matched = value.match(/(?:机器人|bot|BOT)?\D*(\d+)\s*$/u) ?? value.match(/(\d+)\s*$/u);
  if (!matched) {
    return 0;
  }
  const index = Number.parseInt(matched[1], 10);
  if (!Number.isFinite(index) || index <= 0) {
    return 0;
  }
  return index;
}

function resolveNextChannelBotPreset(catalog: ChannelPaneCatalogItem, backendType: string) {
  const group = getChannelConfigGroup(catalog.id, backendType);
  const existingAccounts = group?.accounts ?? [];
  const existingAccountIdsLower = new Set(existingAccounts.map((account) => account.accountId.trim().toLowerCase()).filter(Boolean));
  const existingNamesLower = new Set(existingAccounts.map((account) => (account.name ?? "").trim().toLowerCase()).filter(Boolean));

  let maxIndex = 0;
  for (const account of existingAccounts) {
    maxIndex = Math.max(maxIndex, extractChannelBotSequence(account.accountId), extractChannelBotSequence(account.name));
  }
  if (maxIndex === 0 && existingAccounts.length > 0) {
    maxIndex = existingAccounts.length;
  }

  const accountPrefix = (catalog.id || backendType || "channel").trim().toLowerCase() || "channel";
  const channelName = catalog.name?.trim() || catalog.id || backendType || "频道";
  let index = Math.max(1, maxIndex + 1);
  while (index < 1000) {
    const accountId = `${accountPrefix}-bot-${index}`;
    const accountName = `${channelName}机器人${index}`;
    if (!existingAccountIdsLower.has(accountId.toLowerCase()) && !existingNamesLower.has(accountName.toLowerCase())) {
      return {
        accountId,
        accountName,
        existingAccountIds: existingAccounts.map((account) => account.accountId)
      };
    }
    index += 1;
  }

  const fallbackId = `${accountPrefix}-bot-${Date.now()}`;
  return {
    accountId: fallbackId,
    accountName: `${channelName}机器人`,
    existingAccountIds: existingAccounts.map((account) => account.accountId)
  };
}

async function renameChannelAccount(channelType: string, accountId: string, name: string) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    throw new Error("当前环境不支持修改频道账号名称。");
  }
  await invoke("rename_openclaw_channel_account", {
    payload: {
      channelType,
      accountId,
      name
    }
  });
}

async function openChannelConfigModal(
  catalogId: string,
  backendType: string,
  accountId: string,
  options?: {
    allowEditAccountId?: boolean;
    loadExisting?: boolean;
    existingAccountIds?: string[];
    draftAccountName?: string;
  }
) {
  closeProxyConfigModal();
  closeRelatedResourceModal();
  closeUtilityModal();
  closeSidebarSettingsModal();
  closeSidebarLogsPanel();
  closeFeishuConnectModal();
  closeChannelBindingModal();

  const invoke = getTauriInvoke();
  const allowEdit = options?.allowEditAccountId === true;
  const loadExisting = options?.loadExisting === true;
  const catalog = chatChannelCatalogMap.get(catalogId) ?? null;
  const isQrMode = isChannelConfigQrMode(catalog);
  channelConfigCatalogId.value = catalogId;
  channelConfigBackendType.value = backendType;
  channelConfigAccountId.value = accountId;
  channelConfigDraftAccountName.value = options?.draftAccountName?.trim() ?? "";
  channelConfigAllowEditAccountId.value = allowEdit;
  channelConfigExistingAccountIds.value = options?.existingAccountIds ?? [];
  channelConfigForm.value = {};
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  channelConfigSaving.value = false;
  channelConfigSyncing.value = false;
  resetChannelConfigSecretVisibility();

  if (!isQrMode && loadExisting && invoke) {
    try {
      const values = (await invoke("load_openclaw_channel_form_values", {
        channelType: backendType,
        accountId
      })) as Record<string, string>;
      channelConfigForm.value = values && typeof values === "object" ? values : {};
    } catch (error) {
      channelConfigForm.value = {};
      channelConfigError.value = error instanceof Error ? error.message : "读取频道配置失败。";
    }
  }

  if (isQrMode) {
    const normalizedBackendType = normalizeChannelPaneType(backendType);
    const normalizedSessionType = normalizeChannelPaneType(channelQrBindingChannelType.value);
    if (normalizedSessionType && normalizedSessionType !== normalizedBackendType) {
      resetChannelQrBindingState({ clearSession: true });
    }
    if (!channelQrBindingSessionId.value.trim()) {
      channelQrBindingChannelType.value = normalizedBackendType;
    } else if (!isChannelQrBindingTerminalStatus(channelQrBindingSnapshot.value?.status)) {
      startChannelQrBindingPolling(channelQrBindingSessionId.value);
    }
  } else {
    resetChannelQrBindingState({ clearSession: true });
  }

  isChannelConfigModalOpen.value = true;
}

function closeChannelConfigModal() {
  const shouldKeepQrSession = isChannelConfigQrMode(activeChannelConfigMeta.value);
  stopChannelQrBindingPolling();
  if (!shouldKeepQrSession) {
    resetChannelQrBindingState({ clearSession: true });
  }
  isChannelConfigModalOpen.value = false;
  channelConfigCatalogId.value = "";
  channelConfigBackendType.value = "";
  channelConfigAccountId.value = "";
  channelConfigDraftAccountName.value = "";
  channelConfigAllowEditAccountId.value = false;
  channelConfigExistingAccountIds.value = [];
  channelConfigForm.value = {};
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  channelConfigSaving.value = false;
  channelConfigSyncing.value = false;
  resetChannelConfigSecretVisibility();
}

async function handleOpenChannelConfigDocs() {
  const url = activeChannelConfigMeta.value?.docsUrl?.trim();
  if (!url) {
    return;
  }
  await openExternalUrl(url);
}

async function handleOpenChannelQrBindingLink() {
  const targetUrl = channelQrBindingRawUrl.value.trim();
  if (!targetUrl) {
    return;
  }
  await openExternalUrl(targetUrl);
}

async function loadActiveChannelConfigFormValues() {
  const invoke = getTauriInvoke();
  const backendType = channelConfigBackendType.value.trim().toLowerCase();
  const accountId = channelConfigAccountId.value.trim();
  if (!invoke || !backendType || !accountId) {
    return;
  }
  const values = (await invoke("load_openclaw_channel_form_values", {
    channelType: backendType,
    accountId
  })) as Record<string, string>;
  channelConfigForm.value = values && typeof values === "object" ? values : {};
}

async function handleInstallDingtalkPlugin() {
  if (channelConfigSaving.value || channelConfigSyncing.value) {
    return;
  }
  const invoke = getTauriInvoke();
  if (!invoke) {
    channelConfigError.value = "当前环境不支持安装频道插件。";
    return;
  }
  const backendType = channelConfigBackendType.value.trim().toLowerCase() || "dingtalk";

  channelConfigSyncing.value = true;
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  try {
    const result = (await invoke("install_openclaw_channel_plugin", {
      channelType: backendType
    })) as OpenClawChannelPluginInstallResult;
    if (!result.success) {
      throw new Error(result.detail || "安装钉钉插件失败。");
    }
    channelConfigNotice.value = result.detail || "钉钉插件安装完成。";
    await refreshDashboardData();
  } catch (error) {
    channelConfigError.value = error instanceof Error ? error.message : "安装钉钉插件失败。";
  } finally {
    channelConfigSyncing.value = false;
  }
}

async function handleRefreshChannelConfigStatus() {
  if (channelConfigSaving.value || channelConfigSyncing.value) {
    return;
  }
  channelConfigSyncing.value = true;
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  try {
    await loadActiveChannelConfigFormValues();
    await refreshDashboardData();
    channelConfigNotice.value = "状态已刷新。";
  } catch (error) {
    channelConfigError.value = error instanceof Error ? error.message : "刷新频道状态失败。";
  } finally {
    channelConfigSyncing.value = false;
  }
}

async function handleAuthorizeDiscordBot() {
  const applicationId = (channelConfigForm.value.appId ?? "").trim();
  if (!applicationId) {
    channelConfigError.value = "请先填写 Application ID，再进行机器人授权。";
    return;
  }
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  const inviteUrl = `https://discord.com/oauth2/authorize?client_id=${encodeURIComponent(applicationId)}&permissions=8&scope=bot%20applications.commands`;
  await openExternalUrl(inviteUrl);
}

async function handleOpenLegacyChannelConfigFromCatalog(channelId: string) {
  const catalog = resolveChannelConfigCatalog(channelId);
  if (!catalog) {
    return;
  }
  const backendType = resolveChannelConfigBackendType(catalog);
  if (!backendType) {
    return;
  }
  const isQrMode = isChannelConfigQrMode(catalog);
  if (isQrMode) {
    const group = getChannelConfigGroup(catalog.id, backendType);
    const target = group?.accounts.find((account) => account.isDefault) ?? group?.accounts[0] ?? null;
    await openChannelConfigModal(catalog.id, backendType, target?.accountId || FEISHU_DEFAULT_ACCOUNT_ID, {
      allowEditAccountId: false,
      loadExisting: false,
      existingAccountIds: group?.accounts.map((account) => account.accountId) ?? []
    });
    return;
  }

  const preset = resolveNextChannelBotPreset(catalog, backendType);
  if (catalog.id === FEISHU_CHANNEL_ID) {
    await openFeishuConnectModal({
      accountId: preset.accountId,
      accountName: preset.accountName,
      loadExisting: false
    });
    return;
  }

  await openChannelConfigModal(catalog.id, backendType, preset.accountId, {
    allowEditAccountId: false,
    loadExisting: false,
    existingAccountIds: preset.existingAccountIds,
    draftAccountName: preset.accountName
  });
}

async function handleSaveChannelConfig() {
  if (channelConfigSyncing.value) {
    return;
  }
  const invoke = getTauriInvoke();
  const meta = activeChannelConfigMeta.value;
  if (isChannelConfigQrMode(meta)) {
    channelConfigError.value = "该频道使用二维码绑定，无需手动保存参数。";
    return;
  }
  const backendType = channelConfigBackendType.value.trim().toLowerCase();
  const accountId = channelConfigAccountId.value.trim();
  if (!meta) {
    return;
  }
  if (!backendType) {
    channelConfigError.value = "当前频道类型无效。";
    return;
  }
  if (!accountId) {
    channelConfigError.value = "账号 ID 不能为空。";
    return;
  }
  if (
    channelConfigAllowEditAccountId.value &&
    channelConfigExistingAccountIds.value.some((item) => item.trim().toLowerCase() === accountId.toLowerCase())
  ) {
    channelConfigError.value = `账号 ID ${accountId} 已存在。`;
    return;
  }
  if (!invoke) {
    channelConfigError.value = "当前环境不支持写入频道配置。";
    return;
  }

  const payloadConfig: Record<string, string> = {};
  for (const field of meta.fields ?? []) {
    const value = (channelConfigForm.value[field.key] ?? "").trim();
    if (field.required && !value) {
      channelConfigError.value = `${field.label} 不能为空。`;
      return;
    }
    if (value) {
      payloadConfig[field.key] = value;
    }
  }

  channelConfigSaving.value = true;
  channelConfigNotice.value = "";
  channelConfigError.value = "";
  try {
    if (meta.id === "dingtalk") {
      const pluginInstallResult = (await invoke("install_openclaw_channel_plugin", {
        channelType: backendType
      })) as OpenClawChannelPluginInstallResult;
      if (!pluginInstallResult.success) {
        throw new Error(pluginInstallResult.detail || "安装钉钉插件失败。");
      }
    }

    await invoke("save_openclaw_channel_config", {
      payload: {
        channelType: backendType,
        accountId,
        config: payloadConfig
      }
    });

    const draftName = channelConfigDraftAccountName.value.trim();
    if (draftName) {
      await renameChannelAccount(backendType, accountId, draftName);
    }

    if (isChannelConfigGuidedLayout.value) {
      const restartResult = (await invoke("run_lobster_action", {
        action: "restart_gateway"
      })) as LobsterActionResult;
      if (!restartResult.success) {
        throw new Error(`配置已保存，但网关重启失败：${restartResult.detail}`);
      }
    }

    closeChannelConfigModal();
    await refreshDashboardData();
  } catch (error) {
    channelConfigError.value = error instanceof Error ? error.message : "保存频道配置失败。";
  } finally {
    channelConfigSaving.value = false;
  }
}

function handleChannelPaneCatalogCardClick(channelId: string) {
  const normalized = normalizeChannelPaneType(channelId);
  void handleOpenLegacyChannelConfigFromCatalog(normalized || channelId);
}

function resolveMainStaffAgent() {
  const staff = agents.value.filter((agent) => agent.groupKind === "staff");
  if (staff.length === 0) {
    return null;
  }
  return (
    staff.find((agent) => equalsIgnoreCase(agent.agentId, "main")) ??
    staff.find((agent) => (agent.channel ?? "").trim().toLowerCase() === "main") ??
    staff[0]
  );
}

function findChannelAccountSnapshot(channelType: string, accountId: string) {
  const normalizedType = normalizeChannelPaneType(channelType);
  const rawType = channelType.trim().toLowerCase();
  const normalizedAccountId = accountId.trim().toLowerCase();
  if (!normalizedAccountId) {
    return null;
  }

  const groups = dashboardChannelSnapshot.value?.channels ?? [];
  for (const group of groups) {
    const groupNormalizedType = normalizeChannelPaneType(group.channelType);
    const groupRawType = (group.channelType ?? "").trim().toLowerCase();
    if (normalizedType) {
      if (groupNormalizedType !== normalizedType) {
        continue;
      }
    } else if (groupRawType !== rawType) {
      continue;
    }

    const accounts = Array.isArray(group.accounts) ? group.accounts : [];
    const matched = accounts.find((account) => account.accountId.trim().toLowerCase() === normalizedAccountId);
    if (matched) {
      return matched;
    }
  }

  return null;
}

function closeChannelBindingModal() {
  isChannelBindingModalOpen.value = false;
  channelBindingModalItem.value = null;
  channelBindingTargetAgentId.value = "";
  channelBindingSaving.value = false;
  channelBindingError.value = "";
}

function handleChannelPaneChatItemConfigClick(item: ChannelPaneChatItem) {
  closeProxyConfigModal();
  closeRelatedResourceModal();
  closeChannelConfigModal();
  closeFeishuConnectModal();
  closeUtilityModal();
  closeSidebarSettingsModal();
  closeSidebarLogsPanel();

  const staff = agents.value.filter((agent) => agent.groupKind === "staff");
  const explicitBoundAgent = item.boundAgentId?.trim()
    ? staff.find((agent) => equalsIgnoreCase(agent.agentId, item.boundAgentId ?? "")) ?? null
    : null;
  const mainAgent = resolveMainStaffAgent();
  const initialTargetAgent = explicitBoundAgent ?? mainAgent ?? staff[0] ?? null;

  channelBindingModalItem.value = { ...item };
  channelBindingTargetAgentId.value = initialTargetAgent?.agentId ?? "";
  channelBindingSaving.value = false;
  channelBindingError.value = "";
  isChannelBindingModalOpen.value = true;
}

async function handleSaveChannelBinding() {
  const invoke = getTauriInvoke();
  const item = channelBindingModalItem.value;
  const targetAgentId = channelBindingTargetAgentId.value.trim();
  if (!item || channelBindingSaving.value) {
    return;
  }
  if (!targetAgentId) {
    channelBindingError.value = "请选择要绑定的数字员工。";
    return;
  }
  const targetAgent =
    agents.value.find((agent) => agent.groupKind === "staff" && equalsIgnoreCase(agent.agentId, targetAgentId)) ?? null;
  if (!targetAgent) {
    channelBindingError.value = "所选数字员工不可用，请重新选择。";
    return;
  }
  if (!invoke) {
    channelBindingError.value = "当前环境不支持保存频道绑定。";
    return;
  }

  channelBindingSaving.value = true;
  channelBindingError.value = "";
  try {
    await invoke("save_openclaw_channel_binding", {
      payload: {
        channelType: item.channelType,
        accountId: item.accountId,
        agentId: targetAgent.agentId
      }
    });
    await refreshDashboardData();

    const activeSession = activeChannelChatSession.value;
    if (activeSession && activeSession.id === item.id) {
      switchAgent(targetAgent.agentId, {
        channelSession: {
          ...activeSession,
          boundAgentId: targetAgent.agentId
        },
        force: true
      });
    }

    closeChannelBindingModal();
  } catch (error) {
    channelBindingError.value = resolveUnknownErrorMessage(error, "保存频道绑定失败。");
  } finally {
    channelBindingSaving.value = false;
  }
}

async function handleChannelPaneChatItemClick(item: ChannelPaneChatItem) {
  const account = findChannelAccountSnapshot(item.channelType, item.accountId);
  const configuredBoundAgentId = account?.agentId?.trim() ?? "";
  const configuredBoundAgent = configuredBoundAgentId
    ? agents.value.find((agent) => equalsIgnoreCase(agent.agentId, configuredBoundAgentId)) ?? null
    : null;
  const mainAgent = resolveMainStaffAgent();
  const targetAgent = configuredBoundAgent ?? mainAgent;

  if (!targetAgent) {
    return;
  }

  const shouldPersistDefaultBinding = !configuredBoundAgent;
  const invoke = getTauriInvoke();
  if (invoke && shouldPersistDefaultBinding) {
    try {
      await invoke("save_openclaw_channel_binding", {
        payload: {
          channelType: item.channelType,
          accountId: item.accountId,
          agentId: targetAgent.agentId
        }
      });
      await refreshDashboardData();
    } catch {
      // Keep UX smooth: still allow entering chat even if binding persistence fails.
    }
  }

  switchAgent(targetAgent.agentId, {
    channelSession: {
      ...item,
      boundAgentId: targetAgent.agentId
    }
  });
}

function isChannelChatItemActive(item: ChannelPaneChatItem) {
  const activeSession = activeChannelChatSession.value;
  const selectedAgent = selectedAgentId.value;
  if (!activeSession || !selectedAgent) {
    return false;
  }
  if (activeSession.id !== item.id) {
    return false;
  }
  const boundAgentId = item.boundAgentId?.trim();
  if (!boundAgentId) {
    return true;
  }
  return equalsIgnoreCase(boundAgentId, selectedAgent);
}

function getSkillMarketCacheKey(category: SkillMarketSectionCategory, sortBy: SkillMarketSortBy) {
  return `${category}:${sortBy}`;
}

function getSkillMarketGlobalCacheKey(sortBy: SkillMarketSortBy) {
  return `global:${sortBy}`;
}

async function loadSkillMarketSection(category: SkillMarketSectionCategory, force = false) {
  const cacheKey = getSkillMarketCacheKey(category, skillMarketSortBy.value);
  if (!force) {
    const cached = skillMarketCache.get(cacheKey);
    if (cached) {
      if (category === "top") {
        skillMarketTopSkills.value = cached.skills;
        skillMarketTopTotal.value = cached.total;
      } else {
        skillMarketCategorySkills.value = cached.skills;
        skillMarketCategoryTotal.value = cached.total;
      }
      return;
    }
  }

  const result =
    category === "top"
      ? await fetchSkillTop50()
      : await fetchSkillsByCategory(category, {
          page: 1,
          pageSize: 200,
          sortBy: skillMarketSortBy.value,
          order: "desc"
        });

  skillMarketCache.set(cacheKey, {
    skills: result.skills,
    total: result.total
  });

  if (category === "top") {
    skillMarketTopSkills.value = result.skills;
    skillMarketTopTotal.value = result.total;
  } else {
    skillMarketCategorySkills.value = result.skills;
    skillMarketCategoryTotal.value = result.total;
  }
}

async function refreshSkillMarket(force = false) {
  const token = ++skillMarketRequestToken;
  const keyword = skillMarketSearch.value.trim();
  skillMarketLoading.value = true;
  skillMarketError.value = "";

  try {
    if (keyword) {
      const globalCacheKey = getSkillMarketGlobalCacheKey(skillMarketSortBy.value);
      if (!force) {
        const cached = skillMarketGlobalCache.get(globalCacheKey);
        if (cached) {
          skillMarketGlobalSkills.value = cached.skills;
          skillMarketGlobalTotal.value = cached.total;
        } else {
          const result = await fetchSkillsGlobal({
            page: 1,
            pageSize: 500,
            sortBy: skillMarketSortBy.value,
            order: "desc"
          });
          if (token !== skillMarketRequestToken) {
            return;
          }
          skillMarketGlobalSkills.value = result.skills;
          skillMarketGlobalTotal.value = result.total;
          skillMarketGlobalCache.set(globalCacheKey, {
            skills: result.skills,
            total: result.total
          });
        }
      } else {
        const result = await fetchSkillsGlobal({
          page: 1,
          pageSize: 500,
          sortBy: skillMarketSortBy.value,
          order: "desc"
        });
        if (token !== skillMarketRequestToken) {
          return;
        }
        skillMarketGlobalSkills.value = result.skills;
        skillMarketGlobalTotal.value = result.total;
        skillMarketGlobalCache.set(globalCacheKey, {
          skills: result.skills,
          total: result.total
        });
      }
    } else {
      skillMarketGlobalSkills.value = [];
      skillMarketGlobalTotal.value = 0;
    }

    await loadSkillMarketSection(activeSkillMarketCategory.value, force);
    if (token !== skillMarketRequestToken) {
      return;
    }
  } catch (error) {
    if (token !== skillMarketRequestToken) {
      return;
    }
    skillMarketError.value = error instanceof Error ? error.message : "技能市场加载失败。";
  } finally {
    if (token === skillMarketRequestToken) {
      skillMarketLoading.value = false;
    }
  }
}

function handleSkillMarketCategorySwitch(category: SkillMarketSectionCategory) {
  if (activeSkillMarketCategory.value === category) {
    return;
  }
  activeSkillMarketCategory.value = category;
  skillMarketPage.value = 1;
  void refreshSkillMarket();
}

function handleSkillMarketSortChange(sortBy: SkillMarketSortBy) {
  if (skillMarketSortBy.value === sortBy) {
    return;
  }
  skillMarketSortBy.value = sortBy;
  skillMarketPage.value = 1;
  skillMarketCache.clear();
  skillMarketGlobalCache.clear();
  void refreshSkillMarket(true);
}

function handleSkillMarketSearchSubmit() {
  skillMarketPage.value = 1;
  void refreshSkillMarket(true);
}

function goToSkillMarketPage(page: number) {
  const total = skillMarketCurrentTotalPages.value;
  const nextPage = Math.min(Math.max(1, page), total);
  if (nextPage === skillMarketPage.value) {
    return;
  }
  skillMarketPage.value = nextPage;
}

function goPrevSkillMarketPage() {
  goToSkillMarketPage(skillMarketPage.value - 1);
}

function goNextSkillMarketPage() {
  goToSkillMarketPage(skillMarketPage.value + 1);
}

function getSkillMarketInitial(name: string) {
  const trimmed = name.trim();
  if (!trimmed) {
    return "技";
  }
  return trimmed.charAt(0).toUpperCase();
}

function getSkillMarketDescription(skill: SkillMarketSkill) {
  return skill.descriptionZh.trim() || skill.description.trim() || "暂无技能描述。";
}

function formatSkillMarketCount(value: number | null | undefined) {
  if (!value || !Number.isFinite(value) || value <= 0) {
    return "0";
  }
  if (value >= 10000) {
    return `${(value / 10000).toFixed(1)}w`;
  }
  return String(Math.round(value));
}

function formatSkillMarketVersion(value: string | null | undefined) {
  const trimmed = (value ?? "").trim();
  return trimmed || "v1.0.0";
}

async function openSkillHomepage(skill: SkillMarketSkill) {
  const url = skill.homepage?.trim() || SKILL_MARKET_SKILLHUB_URL;
  await openExternalUrl(url);
}

function openSkillMarketDetailModal(skill: SkillMarketSkill) {
  activeSkillMarketDetail.value = skill;
}

function closeSkillMarketDetailModal() {
  activeSkillMarketDetail.value = null;
}

function isSkillMarketSkillInstalling(skill: SkillMarketSkill | null | undefined) {
  const slug = skill?.slug?.trim();
  return Boolean(slug) && skillMarketInstallingSlug.value === slug;
}

function getSkillMarketCategoryLabel(category: string | null | undefined) {
  const normalized = (category ?? "").trim().toLowerCase();
  if (!normalized) {
    return "未分类";
  }
  const matched = skillMarketCategories.find((item) => item.id === normalized || item.apiCategory === normalized);
  return matched?.label ?? normalized;
}

function canInstallSkillMarketSkill(skill: SkillMarketSkill) {
  const slug = skill.slug?.trim();
  if (slug && getTauriInvoke()) {
    return true;
  }
  return Boolean((skill.homepage ?? "").trim() || SKILL_MARKET_SKILLHUB_URL);
}

async function installSkillMarketSkill(skill: SkillMarketSkill) {
  const slug = skill.slug?.trim() ?? "";
  const invoke = getTauriInvoke();

  if (invoke && slug) {
    if (skillMarketInstallingSlug.value === slug) {
      return;
    }
    skillMarketInstallingSlug.value = slug;
    try {
      const result = (await invoke("install_skill_market_skill", {
        skillSlug: slug
      })) as string;
      skillMarketActionNotice.value = result?.trim() || `技能「${skill.name}」安装成功。`;
      if (relatedResourceModalTarget.value === "skills") {
        await loadRelatedSkillsSnapshot();
      }
      return;
    } catch (error) {
      skillMarketActionNotice.value =
        error instanceof Error
          ? error.message
          : typeof error === "string" && error.trim()
            ? error
            : `安装 ${skill.name} 失败。`;
      return;
    } finally {
      if (skillMarketInstallingSlug.value === slug) {
        skillMarketInstallingSlug.value = "";
      }
    }
  }

  const url = skill.homepage?.trim() || SKILL_MARKET_SKILLHUB_URL;
  await openExternalUrl(url);
  skillMarketActionNotice.value = "当前环境暂不支持一键安装，已打开 SkillHub 页面。";
}

function buildInstallableRoleAgentId(sourcePath: string) {
  const base = sourcePath
    .replace(/\.md$/i, "")
    .replace(/[\\/]+/g, "-")
    .toLowerCase()
    .replace(/[^a-z0-9-]+/g, "-")
    .replace(/-{2,}/g, "-")
    .replace(/^-+|-+$/g, "");
  return base || `role-${Date.now()}`;
}

function resolveInstalledRoleWorkspaceDir(installResult: string, normalizedAgentId: string) {
  const matched = installResult.match(/工作区[:：]\s*([^)）]+)/);
  const workspaceWithFile = matched?.[1]?.trim() ?? "";
  const normalizedPath = workspaceWithFile.replace(/[\\/]AGENTS\.md$/i, "");
  if (normalizedPath) {
    return normalizedPath;
  }
  return `~/.openclaw/workspace-${normalizedAgentId}`;
}

function buildRoleWorkflowInstallPrompt(roleName: string, sourcePath: string, detailMarkdown: string) {
  const normalizedRoleName = roleName.trim() || "未命名角色";
  const normalizedSourcePath = sourcePath.trim() || "unknown";
  const normalizedDetail = detailMarkdown.trim();

  return [
    ROLE_WORKFLOW_INSTALL_PROMPT_PREFIX,
    "若已安装 openclaw-agent-factory 等角色创建 skill，请优先调用对应 skill 完成创建。",
    `角色名称：${normalizedRoleName}`,
    `来源：${normalizedSourcePath}`,
    "详情内容：",
    normalizedDetail
  ].join("\n");
}

function buildRoleWorkflowInstallNoticeText(roleName: string, workspaceDir: string, dispatchSummary = "") {
  const normalizedDispatchSummary = dispatchSummary.trim();
  return [
    `角色已安装：${roleName}。`,
    `配置文件目录：${workspaceDir}。`,
    normalizedDispatchSummary
  ]
    .filter(Boolean)
    .join("");
}

function upsertOptimisticRoleWorkflowAgent(agentId: string, roleName: string, workspaceDir: string) {
  const normalizedName = roleName.trim() || agentId;
  const existingIndex = agents.value.findIndex((agent) => equalsIgnoreCase(agent.agentId, agentId));
  const nextAgent: AgentListItem = {
    agentId,
    displayName: normalizedName,
    roleLabel: "数字员工",
    channel: "main",
    model: "llm/petclaw-1.0",
    workspace: workspaceDir,
    toolsProfile: "default",
    toolsEnabledCount: null,
    statusLabel: "在线",
    statusTone: "online",
    currentWorkLabel: "正在处理什么",
    currentWork: "刚安装完成，等待开始协作",
    recentOutput: "",
    scheduledLabel: "随时可用",
    groupKind: "staff"
  };

  if (existingIndex >= 0) {
    const existingAgent = agents.value[existingIndex];
    agents.value[existingIndex] = {
      ...existingAgent,
      ...nextAgent,
      roleLabel: existingAgent.roleLabel || nextAgent.roleLabel
    };
  } else {
    agents.value = [...agents.value, nextAgent];
  }

  setAgentMeta(agentId, {
    preview: "角色安装完成，等待开始对话",
    timeLabel: formatTimeLabel(Date.now()),
    unread: 0
  });
  syncChatUserAgentOrder();
}

async function installRoleWorkflowRole() {
  const found = activeRoleWorkflowBase.value;
  if (!found || roleWorkflowDetailLoading.value || isRoleWorkflowInstalling.value) {
    return null;
  }
  const invoke = getTauriInvoke();
  if (!invoke) {
    roleWorkflowDetailNotice.value = {
      tone: "error",
      text: "当前环境不支持安装角色（仅桌面端可用）。"
    };
    return null;
  }

  const agentId = buildInstallableRoleAgentId(found.role.sourcePath);
  if (isProtectedStaffAgentId(agentId)) {
    roleWorkflowDetailNotice.value = {
      tone: "error",
      text: "主控员工 main 受保护，不能被替换。请更换角色 ID。"
    };
    return null;
  }
  const markdown = roleWorkflowDetailDraft.value.contentZh.trim();
  if (!markdown) {
    roleWorkflowDetailNotice.value = {
      tone: "error",
      text: "详情内容为空，无法安装角色。"
    };
    return null;
  }

  const selectedNameZh = roleWorkflowNameZhDraft.value.trim() || found.role.nameZh;
  roleWorkflowDetailNotice.value = null;
  isRoleWorkflowInstalling.value = true;
  try {
    const installStartedAt = Date.now();
    const result = (await invoke("install_role_workflow_agent", {
      agentId,
      displayName: selectedNameZh || found.role.nameEn || found.role.nameZh,
      content: markdown,
      sourcePath: found.role.sourcePath
    })) as string;

    const roleName = selectedNameZh || found.role.nameZh || found.role.nameEn || agentId;
    const workspaceDir = resolveInstalledRoleWorkspaceDir(result ?? "", agentId);
    const openclawPrompt = buildRoleWorkflowInstallPrompt(roleName, found.role.sourcePath, markdown);
    const dispatchAgentId = selectedAgentId.value;
    upsertOptimisticRoleWorkflowAgent(agentId, roleName, workspaceDir);
    switchAgent(agentId, { force: true });
    roleWorkflowDetailNotice.value = {
      tone: "success",
      text: buildRoleWorkflowInstallNoticeText(roleName, workspaceDir, "正在同步角色详情到 OpenClaw...")
    };
    const installDurationMs = Date.now() - installStartedAt;
    console.info(`[role-install] install_role_workflow_agent completed in ${installDurationMs}ms`, {
      agentId,
      roleName
    });

    void (async () => {
      const dispatchStartedAt = Date.now();
      try {
        await sendOpenClawChat(
          [{ role: "user", content: openclawPrompt }],
          dispatchAgentId ? { agentId: dispatchAgentId } : {}
        );
        const dispatchDurationMs = Date.now() - dispatchStartedAt;
        console.info(`[role-install] sendOpenClawChat completed in ${dispatchDurationMs}ms`, {
          agentId,
          dispatchAgentId: dispatchAgentId ?? null
        });
        roleWorkflowDetailNotice.value = {
          tone: "success",
          text: buildRoleWorkflowInstallNoticeText(roleName, workspaceDir, "已将角色详情发送到 OpenClaw。")
        };
      } catch (dispatchError) {
        const dispatchDurationMs = Date.now() - dispatchStartedAt;
        console.warn(`[role-install] sendOpenClawChat failed after ${dispatchDurationMs}ms`, dispatchError);
        roleWorkflowDetailNotice.value = {
          tone: "success",
          text: buildRoleWorkflowInstallNoticeText(
            roleName,
            workspaceDir,
            `发送角色详情到 OpenClaw 失败：${dispatchError instanceof Error ? dispatchError.message : "未知错误"}`
          )
        };
      }
    })();

    void (async () => {
      const reloadStartedAt = Date.now();
      try {
        await loadAgents();
        const reloadDurationMs = Date.now() - reloadStartedAt;
        console.info(`[role-install] loadAgents completed in ${reloadDurationMs}ms`, {
          agentId,
          roleName
        });
        const installedAgent =
          agents.value.find((agent) => equalsIgnoreCase(agent.agentId, agentId)) ??
          agents.value.find((agent) => stripRoleLabel(agent.displayName) === roleName);
        if (installedAgent) {
          switchAgent(installedAgent.agentId, { force: true });
        } else {
          upsertOptimisticRoleWorkflowAgent(agentId, roleName, workspaceDir);
          switchAgent(agentId, { force: true });
        }
      } catch (reloadError) {
        const reloadDurationMs = Date.now() - reloadStartedAt;
        console.warn(`[role-install] loadAgents failed after ${reloadDurationMs}ms`, reloadError);
      }
    })();

    return agentId;
  } catch (error) {
    roleWorkflowDetailNotice.value = {
      tone: "error",
      text: error instanceof Error ? error.message : `安装 ${found.role.nameZh} 失败。`
    };
    return null;
  } finally {
    isRoleWorkflowInstalling.value = false;
  }
}

async function openRoleWorkflowEditor(role: AgencyRosterRole) {
  if (isRoleWorkflowInstalling.value) {
    return;
  }
  const roleId = role.id;
  const override = roleWorkflowOverrides.value[roleId];
  const requestToken = ++roleWorkflowDetailRequestToken;
  roleWorkflowDetailRoleId.value = roleId;
  roleWorkflowDetailNotice.value = null;
  roleWorkflowDetailLoading.value = true;
  roleWorkflowNameZhOriginal.value = override?.nameZh ?? role.nameZh;
  roleWorkflowNameZhDraft.value = roleWorkflowNameZhOriginal.value;
  roleWorkflowDetailOriginalContent.value = "正在加载详情内容...";
  roleWorkflowDetailDraft.value = {
    contentZh: "正在加载详情内容..."
  };

  try {
    const detailSnapshot = await loadAgentDetailMarkdownZh(role.sourcePath);
    if (requestToken !== roleWorkflowDetailRequestToken || roleWorkflowDetailRoleId.value !== roleId) {
      return;
    }
    const baseContent = detailSnapshot.contentZh;
    roleWorkflowDetailOriginalContent.value = baseContent;
    roleWorkflowDetailDraft.value = {
      contentZh: override?.detailContentZh ?? baseContent
    };
    if (!detailSnapshot.found) {
      roleWorkflowDetailNotice.value = {
        tone: "error",
        text: `未找到 ${role.sourcePath}，已加载占位详情。`
      };
    }
  } catch (error) {
    if (requestToken !== roleWorkflowDetailRequestToken || roleWorkflowDetailRoleId.value !== roleId) {
      return;
    }
    roleWorkflowDetailNotice.value = {
      tone: "error",
      text: error instanceof Error ? error.message : "角色详情加载失败。"
    };
    const fallbackText = `# 角色详情加载失败\n\n${roleWorkflowDetailNotice.value.text}`;
    roleWorkflowDetailOriginalContent.value = fallbackText;
    roleWorkflowDetailDraft.value = {
      contentZh: fallbackText
    };
  } finally {
    if (requestToken === roleWorkflowDetailRequestToken && roleWorkflowDetailRoleId.value === roleId) {
      roleWorkflowDetailLoading.value = false;
    }
  }
}

function closeRoleWorkflowDetail() {
  if (isRoleWorkflowInstalling.value) {
    return;
  }
  roleWorkflowDetailRequestToken += 1;
  roleWorkflowDetailRoleId.value = null;
  roleWorkflowDetailDraft.value = { contentZh: "" };
  roleWorkflowDetailOriginalContent.value = "";
  roleWorkflowNameZhDraft.value = "";
  roleWorkflowNameZhOriginal.value = "";
  roleWorkflowDetailLoading.value = false;
  roleWorkflowDetailNotice.value = null;
}

function createRoleWorkflowVersionId() {
  return `role-ver-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function hasRoleWorkflowOverrideContent(override: RoleWorkflowOverride) {
  if ((override.nameZh ?? "").trim()) {
    return true;
  }
  if ((override.workflowZh ?? "").trim()) {
    return true;
  }
  if ((override.detailContentZh ?? "").trim()) {
    return true;
  }
  return (override.detailVersions?.length ?? 0) > 0;
}

function saveRoleWorkflowDetail() {
  const activeId = roleWorkflowDetailRoleId.value;
  const found = activeRoleWorkflowBase.value;
  if (!activeId || !found || roleWorkflowDetailLoading.value) {
    return;
  }

  const nextContent = roleWorkflowDetailDraft.value.contentZh;
  const nextNameZh = roleWorkflowNameZhDraft.value.trim() || found.role.nameZh;
  const current = roleWorkflowOverrides.value[activeId] ?? {};
  const nextVersions = [
    {
      id: createRoleWorkflowVersionId(),
      contentZh: nextContent,
      savedAt: Date.now()
    },
    ...(current.detailVersions ?? [])
  ].slice(0, 3);

  roleWorkflowOverrides.value = {
    ...roleWorkflowOverrides.value,
    [activeId]: {
      ...current,
      nameZh: nextNameZh,
      detailContentZh: nextContent,
      detailVersions: nextVersions
    }
  };
  persistRoleWorkflowOverrides();
  roleWorkflowDetailOriginalContent.value = nextContent;
  roleWorkflowNameZhOriginal.value = nextNameZh;
  roleWorkflowNameZhDraft.value = nextNameZh;
  roleWorkflowDetailNotice.value = {
    tone: "success",
    text: `${nextNameZh} 已保存。`
  };
}

function restoreRoleWorkflowOriginalContent() {
  const found = activeRoleWorkflowBase.value;
  if (!found || roleWorkflowDetailLoading.value) {
    return;
  }
  roleWorkflowDetailDraft.value = {
    contentZh: roleWorkflowDetailOriginalContent.value
  };
  roleWorkflowNameZhDraft.value = roleWorkflowNameZhOriginal.value;
  roleWorkflowDetailNotice.value = {
    tone: "success",
    text: `${roleWorkflowNameZhOriginal.value || found.role.nameZh} 已恢复原始内容。`
  };
}

function applyRoleWorkflowSavedVersion(versionId: string) {
  const found = activeRoleWorkflowBase.value;
  const matched = roleWorkflowDetailSavedVersions.value.find((version) => version.id === versionId);
  if (!found || !matched || roleWorkflowDetailLoading.value) {
    return;
  }
  roleWorkflowDetailDraft.value = {
    contentZh: matched.contentZh
  };
  roleWorkflowDetailNotice.value = {
    tone: "success",
    text: `已载入 ${found.role.nameZh} 的历史版本（${formatDateTime(matched.savedAt)}）。`
  };
}

function deleteRoleWorkflowSavedVersion(versionId: string) {
  const activeId = roleWorkflowDetailRoleId.value;
  if (!activeId || roleWorkflowDetailLoading.value) {
    return;
  }
  const current = roleWorkflowOverrides.value[activeId];
  if (!current) {
    return;
  }
  const nextVersions = (current.detailVersions ?? []).filter((version) => version.id !== versionId);
  const nextOverride: RoleWorkflowOverride = {
    ...current
  };
  if (nextVersions.length > 0) {
    nextOverride.detailVersions = nextVersions;
  } else {
    delete nextOverride.detailVersions;
  }

  if (hasRoleWorkflowOverrideContent(nextOverride)) {
    roleWorkflowOverrides.value = {
      ...roleWorkflowOverrides.value,
      [activeId]: nextOverride
    };
  } else {
    const { [activeId]: _, ...rest } = roleWorkflowOverrides.value;
    roleWorkflowOverrides.value = rest;
  }
  persistRoleWorkflowOverrides();
}

function handleRecruitmentOpenRoleDetail(role: AgencyRosterRole) {
  void openRoleWorkflowEditor(role);
}

async function installRecruitmentRoleWithoutDialog(role: AgencyRosterRole) {
  const invoke = getTauriInvoke();
  if (!invoke) {
    throw new Error("当前环境不支持添加数字员工（仅桌面端可用）。");
  }

  const override = roleWorkflowOverrides.value[role.id];
  const roleName = override?.nameZh?.trim() || role.nameZh || role.nameEn || "未命名角色";
  const agentId = buildInstallableRoleAgentId(role.sourcePath);
  if (isProtectedStaffAgentId(agentId)) {
    throw new Error("主控员工 main 受保护，不能被替换。请更换角色 ID。");
  }

  let markdown = override?.detailContentZh?.trim() ?? "";
  if (!markdown) {
    const detailSnapshot = await loadAgentDetailMarkdownZh(role.sourcePath);
    markdown = detailSnapshot.contentZh.trim();
  }
  if (!markdown) {
    throw new Error(`角色「${roleName}」详情为空，无法添加。`);
  }

  const result = (await invoke("install_role_workflow_agent", {
    agentId,
    displayName: roleName,
    content: markdown,
    sourcePath: role.sourcePath
  })) as string;
  const workspaceDir = resolveInstalledRoleWorkspaceDir(result ?? "", agentId);
  upsertOptimisticRoleWorkflowAgent(agentId, roleName, workspaceDir);

  try {
    await loadAgents();
  } catch {
    // Keep optimistic state when snapshot reload fails.
  }

  return roleName;
}

function handleRecruitRole(role: AgencyRosterRole) {
  void (async () => {
    recruitmentActionNotice.value = "";
    if (isRoleWorkflowInstalling.value) {
      recruitmentActionNotice.value = "正在添加数字员工，请稍候...";
      return;
    }
    isRoleWorkflowInstalling.value = true;
    try {
      const roleName = await installRecruitmentRoleWithoutDialog(role);
      showChatAgentDeleteNotice(`${roleName} 数字员工已添加成功。`);
    } catch (error) {
      recruitmentActionNotice.value = error instanceof Error ? error.message : "添加数字员工失败，请稍后重试。";
    } finally {
      isRoleWorkflowInstalling.value = false;
    }
  })();
}

function selectRecruitmentDivisionFilter(divisionId: string) {
  recruitmentDivisionFilter.value = divisionId;
}

function cloneCreateEmployeeDefaultRules() {
  return CREATE_EMPLOYEE_DEFAULT_RULES.map((rule) => ({
    ...rule
  }));
}

function getCreateEmployeeFormalityLabel(value: number) {
  if (value < 30) return "非常正式";
  if (value < 45) return "比较正式";
  if (value > 70) return "非常随意";
  if (value > 55) return "比较随意";
  return "平衡";
}

function getCreateEmployeeDetailLabel(value: number) {
  if (value < 30) return "非常简洁";
  if (value < 45) return "比较简洁";
  if (value > 70) return "非常详细";
  if (value > 55) return "比较详细";
  return "平衡";
}

function resolveCreateEmployeeRoleLabel(identityIds: string[]) {
  const selectedNames = CREATE_EMPLOYEE_IDENTITY_OPTIONS.filter((identity) => identityIds.includes(identity.id)).map(
    (identity) => identity.name
  );
  if (selectedNames.length === 0) {
    return "数字员工";
  }
  if (selectedNames.length === 1) {
    return selectedNames[0];
  }
  if (selectedNames.length === 2) {
    return `${selectedNames[0]} + ${selectedNames[1]}`;
  }
  return `${selectedNames.slice(0, 2).join(" + ")} 等多功能助手`;
}

function resolveCreateEmployeeWorkspace(scope: ChatUserCustomAgentKnowledgeScope, specificDomain: string) {
  if (scope === "document") {
    return "knowledge-base";
  }
  if (scope === "specific") {
    const normalizedDomain = specificDomain
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9\u4e00-\u9fa5]+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 24);
    return normalizedDomain ? `domain-${normalizedDomain}` : "domain-lab";
  }
  return "general-lab";
}

function resolveCreateEmployeeCurrentWork(mission: string, tasks: string[]) {
  const normalizedMission = mission.trim();
  if (normalizedMission) {
    return normalizedMission.slice(0, 120);
  }
  if (tasks.length > 0) {
    return `擅长：${tasks.slice(0, 3).join("、")}${tasks.length > 3 ? "等任务" : ""}`;
  }
  return "等待分配任务";
}

function resetCreateEmployeeModalDraft() {
  createEmployeeStep.value = 1;
  createEmployeeError.value = "";
  createEmployeeNotice.value = "";
  createEmployeeNameDraft.value = "";
  createEmployeeSelectedIdentityIds.value = [];
  createEmployeeMissionDraft.value = "";
  createEmployeeTasks.value = [];
  createEmployeeTaskInput.value = "";
  createEmployeeKnowledgeScope.value = "general";
  createEmployeeSpecificDomain.value = "";
  createEmployeeFormality.value = 50;
  createEmployeeDetail.value = 50;
  createEmployeeOpeningLine.value = "";
  createEmployeeRules.value = cloneCreateEmployeeDefaultRules();
}

function openCreateEmployeeModal() {
  resetCreateEmployeeModalDraft();
  isCreateEmployeeModalOpen.value = true;
  void nextTick(() => {
    createEmployeeNameInputRef.value?.focus();
  });
}

function closeCreateEmployeeModal() {
  isCreateEmployeeModalOpen.value = false;
  resetCreateEmployeeModalDraft();
}

function selectCreateEmployeeStep(step: CreateEmployeeModalStep) {
  createEmployeeStep.value = step;
}

function validateCreateEmployeeStep(step: CreateEmployeeModalStep) {
  if (step >= 1) {
    const normalizedName = normalizeChatUserGroupName(createEmployeeNameDraft.value);
    if (!normalizedName) {
      createEmployeeError.value = "请先填写员工名称。";
      selectCreateEmployeeStep(1);
      void nextTick(() => {
        createEmployeeNameInputRef.value?.focus();
      });
      return false;
    }
    if (isProtectedStaffAgentId(normalizedName)) {
      createEmployeeError.value = "员工名称不能使用 main（系统主控员工保留）。";
      selectCreateEmployeeStep(1);
      void nextTick(() => {
        createEmployeeNameInputRef.value?.focus();
      });
      return false;
    }
    if (createEmployeeSelectedIdentityIds.value.length === 0) {
      createEmployeeError.value = "请至少选择 1 个核心身份。";
      selectCreateEmployeeStep(1);
      return false;
    }
  }
  if (step >= 2 && createEmployeeKnowledgeScope.value === "specific" && !createEmployeeSpecificDomain.value.trim()) {
    createEmployeeError.value = "请填写具体领域，或切换为通用知识范围。";
    selectCreateEmployeeStep(2);
    return false;
  }
  if (step >= 3 && createEmployeeRules.value.every((rule) => !rule.enabled)) {
    createEmployeeError.value = "请至少保留 1 条重要规则。";
    selectCreateEmployeeStep(3);
    return false;
  }
  createEmployeeError.value = "";
  return true;
}

function handleCreateEmployeeNextStep() {
  const step = createEmployeeStep.value;
  if (!validateCreateEmployeeStep(step)) {
    return;
  }
  if (step >= 3) {
    return;
  }
  createEmployeeError.value = "";
  selectCreateEmployeeStep((step + 1) as CreateEmployeeModalStep);
}

function handleCreateEmployeePrevStep() {
  const step = createEmployeeStep.value;
  if (step <= 1) {
    return;
  }
  createEmployeeError.value = "";
  selectCreateEmployeeStep((step - 1) as CreateEmployeeModalStep);
}

function handleCreateEmployeePickRandomName() {
  const randomName = CREATE_EMPLOYEE_RANDOM_NAMES[Math.floor(Math.random() * CREATE_EMPLOYEE_RANDOM_NAMES.length)];
  createEmployeeNameDraft.value = randomName;
  createEmployeeError.value = "";
}

function toggleCreateEmployeeIdentity(identityId: string) {
  const current = new Set(createEmployeeSelectedIdentityIds.value);
  if (current.has(identityId)) {
    current.delete(identityId);
  } else {
    current.add(identityId);
  }
  createEmployeeSelectedIdentityIds.value = Array.from(current);
  createEmployeeError.value = "";
}

function addCreateEmployeeTask(rawTask: string) {
  const normalizedTask = rawTask.trim();
  if (!normalizedTask) {
    return;
  }
  if (createEmployeeTasks.value.includes(normalizedTask)) {
    createEmployeeTaskInput.value = "";
    return;
  }
  if (createEmployeeTasks.value.length >= CREATE_EMPLOYEE_MAX_TASKS) {
    createEmployeeNotice.value = `最多保留 ${CREATE_EMPLOYEE_MAX_TASKS} 条任务指令。`;
    return;
  }
  createEmployeeTasks.value = [...createEmployeeTasks.value, normalizedTask];
  createEmployeeTaskInput.value = "";
  createEmployeeNotice.value = "";
}

function removeCreateEmployeeTask(task: string) {
  createEmployeeTasks.value = createEmployeeTasks.value.filter((item) => item !== task);
}

function handleCreateEmployeeTaskAdd() {
  addCreateEmployeeTask(createEmployeeTaskInput.value);
  void nextTick(() => {
    createEmployeeTaskInputRef.value?.focus();
  });
}

function handleCreateEmployeeTaskInputKeydown(event: KeyboardEvent) {
  if (event.key !== "Enter") {
    return;
  }
  event.preventDefault();
  handleCreateEmployeeTaskAdd();
}

function handleCreateEmployeeRuleToggle(ruleId: string, nextEnabled: boolean) {
  createEmployeeRules.value = createEmployeeRules.value.map((rule) =>
    rule.id === ruleId
      ? {
          ...rule,
          enabled: nextEnabled
        }
      : rule
  );
}

function handleCreateEmployeeAddCustomRule() {
  if (typeof window === "undefined") {
    return;
  }
  if (createEmployeeRules.value.length >= CREATE_EMPLOYEE_MAX_RULES) {
    createEmployeeNotice.value = `最多添加 ${CREATE_EMPLOYEE_MAX_RULES} 条规则。`;
    return;
  }
  const input = window.prompt("请输入自定义规则");
  if (input === null) {
    return;
  }
  const normalizedRule = input.trim();
  if (!normalizedRule) {
    return;
  }
  const exists = createEmployeeRules.value.some((rule) => rule.text.trim() === normalizedRule);
  if (exists) {
    createEmployeeNotice.value = "该规则已存在。";
    return;
  }
  createEmployeeRules.value = [
    ...createEmployeeRules.value,
    {
      id: `custom-rule-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      text: normalizedRule,
      enabled: true,
      custom: true
    }
  ];
  createEmployeeNotice.value = "";
}

function handleCreateEmployeeSubmit() {
  if (!validateCreateEmployeeStep(3)) {
    return;
  }
  const normalizedName = normalizeChatUserGroupName(createEmployeeNameDraft.value);
  if (!normalizedName) {
    createEmployeeError.value = "请先填写员工名称。";
    return;
  }
  if (isProtectedStaffAgentId(normalizedName)) {
    createEmployeeError.value = "员工名称不能使用 main（系统主控员工保留）。";
    selectCreateEmployeeStep(1);
    return;
  }

  const duplicateAgent =
    agents.value.find(
      (agent) =>
        agent.groupKind === "staff" &&
        !isChatConversationGroupAgentId(agent.agentId) &&
        equalsIgnoreCase(stripRoleLabel(agent.displayName), normalizedName)
    ) ?? null;
  if (duplicateAgent) {
    createEmployeeError.value = `员工名称「${normalizedName}」已存在，请更换后再创建。`;
    selectCreateEmployeeStep(1);
    return;
  }

  const roleLabel = resolveCreateEmployeeRoleLabel(createEmployeeSelectedIdentityIds.value);
  const mission = createEmployeeMissionDraft.value.trim();
  const tasks = [...createEmployeeTasks.value];
  const workspace = resolveCreateEmployeeWorkspace(createEmployeeKnowledgeScope.value, createEmployeeSpecificDomain.value);
  const currentWork = resolveCreateEmployeeCurrentWork(mission, tasks);
  const createdAgent = createOrGetChatUserCustomAgent(normalizedName, {
    kind: "staff",
    roleLabel,
    channel: "custom",
    workspace,
    currentWork,
    scheduledLabel: "随时可用",
    mission,
    tasks,
    knowledgeScope: createEmployeeKnowledgeScope.value,
    specificDomain: createEmployeeSpecificDomain.value.trim()
  });
  if (!createdAgent) {
    createEmployeeError.value = "创建员工失败，请稍后重试。";
    return;
  }

  closeCreateEmployeeModal();
  staffSourceDetail.value = `已创建自定义员工「${normalizedName}」。`;
  activeSection.value = "chat";
  activeAgentPaneTab.value = "staff";
  switchAgent(createdAgent.agentId, { force: true });
  chatInput.value = mission ? `请以「${normalizedName}」身份协助我，目标是：${mission}` : `请以「${normalizedName}」身份协助我，目标是：`;
}

function hashTextToUnsigned(value: string) {
  let hash = 0;
  for (let index = 0; index < value.length; index += 1) {
    hash = (hash * 33 + value.charCodeAt(index)) >>> 0;
  }
  return hash >>> 0;
}

function getRecruitmentRoleAvatarLabel(role: AgencyRosterRole) {
  const englishName = role.nameEn.trim();
  if (englishName) {
    const words = englishName.split(/[^A-Za-z0-9]+/).filter(Boolean);
    if (words.length >= 2) {
      return `${words[0][0]}${words[1][0]}`.toUpperCase();
    }
    if (words.length === 1) {
      return words[0].slice(0, 2).toUpperCase();
    }
  }

  const chineseName = role.nameZh.trim().replace(/\s+/g, "");
  if (!chineseName) {
    return "AI";
  }
  return chineseName.slice(0, 2);
}

function getRecruitmentRoleAvatarStyle(role: AgencyRosterRole) {
  const hue = hashTextToUnsigned(role.id || role.nameZh || role.sourcePath) % 360;
  const hueOffset = (hue + 36) % 360;
  const textHue = (hue + 228) % 360;
  return {
    background: `linear-gradient(145deg, hsl(${hue}, 70%, 91%), hsl(${hueOffset}, 76%, 84%))`,
    color: `hsl(${textHue}, 58%, 22%)`
  };
}

function handleSidebarSectionChange(section: SidebarSection) {
  closeChatQuickCreateMenu();
  closeSidebarSystemMenu();
  activeSection.value = section;
  if (section !== "chat") {
    isAgentSettingsOpen.value = false;
    closeSidebarLogsPanel();
    closeSidebarSettingsModal();
  }

  if (section === "tasks") {
    taskItems.value = loadTasks();
    taskModuleView.value = "projects";
    taskModuleError.value = "";
    taskModuleNotice.value = "";
    activeTaskProject.value = DEFAULT_TASK_PROJECT_NAME;
    syncTaskProjectNamesFromTasks();
  }
}

function formatMarketPoints(value: number) {
  return marketPointsFormatter.format(Math.max(0, Math.floor(value)));
}

function openTaskProjectsHome() {
  taskModuleView.value = "projects";
  taskModuleError.value = "";
  taskDragTaskId.value = null;
  taskDragOverStatus.value = null;
}

function openTaskProjectBoard(projectName: string) {
  if (!taskProjectNames.value.includes(projectName)) {
    return;
  }
  activeTaskProject.value = projectName;
  taskModuleView.value = "board";
  taskModuleError.value = "";
  taskModuleNotice.value = "";
  resetTaskDraftForm();
}

function handleCreateTaskProject() {
  const projectName = normalizeTaskProjectName(taskProjectInput.value);
  if (!projectName) {
    taskModuleError.value = "请输入项目名称。";
    taskModuleNotice.value = "";
    return;
  }
  if (projectName === DEFAULT_TASK_PROJECT_NAME) {
    taskModuleError.value = `「${DEFAULT_TASK_PROJECT_NAME}」是默认项目，不能重复创建。`;
    taskModuleNotice.value = "";
    return;
  }
  if (taskProjectNames.value.some((item) => item.toLowerCase() === projectName.toLowerCase())) {
    taskModuleError.value = `项目「${projectName}」已存在。`;
    taskModuleNotice.value = "";
    return;
  }

  taskProjectNames.value = buildTaskProjectList([...taskProjectNames.value, projectName]);
  saveTaskProjectsToStorage(taskProjectNames.value);
  taskProjectInput.value = "";
  taskModuleNotice.value = `项目「${projectName}」已创建。`;
  taskModuleError.value = "";
}

function handleCreateTaskInActiveProject() {
  const title = taskDraftTitle.value.trim();
  if (!title) {
    taskModuleError.value = "请先填写任务标题。";
    taskModuleNotice.value = "";
    return;
  }
  const draft = createTaskDraft();
  const projectName = activeTaskProject.value === DEFAULT_TASK_PROJECT_NAME ? "" : activeTaskProject.value;
  updateTaskRecord({
    ...draft,
    title,
    summary: taskDraftSummary.value.trim() || "暂无说明",
    owner: taskDraftOwner.value.trim() || "Commander",
    priority: taskDraftPriority.value,
    project: projectName,
    status: "todo"
  });
  taskModuleNotice.value = `任务「${title}」已添加到「${activeTaskProject.value}」。`;
  taskModuleError.value = "";
  resetTaskDraftForm();
}

function getTaskStatusText(status: TaskBoardStatus) {
  if (status === "todo") return "待办事项";
  if (status === "in_progress") return "进行中";
  if (status === "in_review") return "回顾";
  if (status === "done") return "完成";
  return "取消";
}

function getTaskPriorityText(priority: TaskRecord["priority"]) {
  if (priority === "p0") return "P0 紧急";
  if (priority === "p1") return "P1 常规";
  return "P2 低优先";
}

function getTaskPrevStatus(status: TaskBoardStatus) {
  const index = taskStatusFlow.indexOf(status);
  if (index <= 0) {
    return null;
  }
  return taskStatusFlow[index - 1] ?? null;
}

function getTaskNextStatus(status: TaskBoardStatus) {
  const index = taskStatusFlow.indexOf(status);
  if (index < 0 || index >= taskStatusFlow.length - 1) {
    return null;
  }
  return taskStatusFlow[index + 1] ?? null;
}

function updateTaskStatus(taskId: string, nextStatus: TaskBoardStatus) {
  const current = taskItems.value.find((task) => task.id === taskId);
  if (!current || current.status === nextStatus) {
    return;
  }
  updateTaskRecord({
    ...current,
    status: nextStatus
  });
  taskModuleError.value = "";
  taskModuleNotice.value = `任务「${current.title}」已移动到「${getTaskStatusText(nextStatus)}」。`;
}

function moveTaskToPrevStatus(task: TaskRecord) {
  const prev = getTaskPrevStatus(task.status);
  if (!prev) {
    return;
  }
  updateTaskStatus(task.id, prev);
}

function moveTaskToNextStatus(task: TaskRecord) {
  const next = getTaskNextStatus(task.status);
  if (!next) {
    return;
  }
  updateTaskStatus(task.id, next);
}

function handleTaskDragStart(taskId: string) {
  taskDragTaskId.value = taskId;
  taskDragOverStatus.value = null;
}

function handleTaskDragEnd() {
  taskDragTaskId.value = null;
  taskDragOverStatus.value = null;
}

function handleTaskColumnDragOver(status: TaskBoardStatus) {
  if (!taskDragTaskId.value) {
    return;
  }
  taskDragOverStatus.value = status;
}

function handleTaskColumnDrop(status: TaskBoardStatus) {
  const taskId = taskDragTaskId.value;
  if (!taskId) {
    return;
  }
  updateTaskStatus(taskId, status);
  handleTaskDragEnd();
}

async function refreshRelatedResourceData(target: RelatedResourceTarget) {
  const agent = activeAgent.value;
  if (!agent) {
    return;
  }
  relatedResourceModalLoading.value = true;
  relatedResourceModalError.value = "";
  relatedResourceModalNotice.value = "";

  try {
    if (target === "memory") {
      await loadRelatedMemorySnapshot();
      syncRelatedMemorySelection();
      return;
    }
    if (target === "skills") {
      await loadRelatedSkillsSnapshot();
      return;
    }
    if (target === "tools") {
      await loadRelatedToolsSnapshot(agent.agentId);
      return;
    }
    if (target === "model") {
      await loadRelatedModelSnapshot();
      return;
    }
    if (target === "channel") {
      await loadRelatedChannelSnapshot();
      return;
    }
    await loadRelatedTaskSnapshot();
  } catch (error) {
    relatedResourceModalError.value = error instanceof Error ? error.message : "加载关联资源失败。";
  } finally {
    relatedResourceModalLoading.value = false;
  }
}

async function openRelatedResource(target: RelatedResourceTarget) {
  if (!activeAgent.value) {
    return;
  }
  closeProxyConfigModal();
  closeFeishuConnectModal();
  closeChannelConfigModal();
  closeChannelBindingModal();
  relatedResourceModalTarget.value = target;
  relatedSkillSearch.value = "";
  relatedMemorySearch.value = "";
  relatedToolsFilter.value = RELATED_TOOLS_FILTER_ALL;
  relatedScheduleFilter.value = "all";
  relatedResourceModalError.value = "";
  relatedResourceModalNotice.value = "";
  if (target === "skills") {
    relatedSkillCategory.value = "builtIn";
  }
  if (target === "memory") {
    relatedMemorySelectedId.value = null;
    relatedMemoryDraftContent.value = "";
  }
  clearRelatedResourceSnapshots();
  await refreshRelatedResourceData(target);
}

function closeRelatedResourceModal() {
  relatedResourceModalTarget.value = null;
  relatedResourceModalError.value = "";
  relatedResourceModalNotice.value = "";
  relatedMemorySearch.value = "";
  relatedMemorySelectedId.value = null;
  relatedMemoryDraftContent.value = "";
  relatedSkillSearch.value = "";
  relatedToolsFilter.value = RELATED_TOOLS_FILTER_ALL;
  relatedScheduleFilter.value = "all";
  relatedModelDraft.value = buildRelatedModelCustomDraft();
  relatedModelCustomExpanded.value = false;
  relatedModelApiKeyVisible.value = false;
  relatedModelSelectedPopularPlatformId.value = null;
  relatedModelEditingProviderId.value = null;
  relatedModelPendingDeleteProviderId.value = null;
}

async function handleRelatedResourceRefresh() {
  if (!relatedResourceModalTarget.value) {
    return;
  }
  await refreshRelatedResourceData(relatedResourceModalTarget.value);
}

function handleRelatedMemorySelect(item: SourceFileSnapshotItem) {
  relatedMemorySelectedId.value = item.id;
  relatedMemoryDraftContent.value = item.content;
  relatedResourceModalNotice.value = "";
  relatedResourceModalError.value = "";
}

async function handleRelatedMemorySave() {
  const invoke = getTauriInvoke();
  const selected = relatedMemorySelectedItem.value;
  if (!selected || relatedResourceModalSaving.value) {
    return;
  }
  if (!invoke) {
    relatedResourceModalError.value = "当前环境不支持保存记忆文件。";
    return;
  }

  relatedResourceModalSaving.value = true;
  relatedResourceModalError.value = "";
  try {
    await invoke("save_source_file", {
      kind: "memory",
      sourcePath: selected.sourcePath,
      content: relatedMemoryDraftContent.value
    });
    relatedResourceModalNotice.value = `记忆文件「${getMemoryDisplayName(selected)}」已保存。`;
    await loadRelatedMemorySnapshot();
    syncRelatedMemorySelection(selected.id);
  } catch (error) {
    relatedResourceModalError.value = error instanceof Error ? error.message : "记忆文件保存失败。";
  } finally {
    relatedResourceModalSaving.value = false;
  }
}

function resetUtilityLogViewState() {
  utilityLogTab.value = "runtime";
  utilityLogDetailTab.value = "response";
  utilityRuntimeCategory.value = "all";
  utilityRuntimeRoleFilter.value = UTILITY_LOG_ROLE_FILTER_ACTIVE;
  utilityRuntimeScheduleFilter.value = "all";
  utilitySelectedLogId.value = null;
  isSidebarLogDetailModalOpen.value = false;
}

function clearUtilityViewStatus() {
  utilityModalError.value = "";
  utilityModalNotice.value = "";
}

function closeSidebarLogsPanel() {
  const closeSidebarUtilityView = chatSettingsPanelMode.value === "logs" || chatSettingsPanelMode.value === "history";
  if (!isSidebarLogsOpen.value && !closeSidebarUtilityView) {
    return;
  }
  isSidebarLogDetailModalOpen.value = false;
  isSidebarLogsOpen.value = false;
  if (closeSidebarUtilityView) {
    isAgentSettingsOpen.value = false;
    chatSettingsPanelMode.value = "agent";
  }
  utilityModalLoading.value = false;
  clearUtilityViewStatus();
  resetUtilityLogViewState();
}

function closeUtilityModal() {
  utilityModalType.value = null;
  utilityModalLoading.value = false;
  clearUtilityViewStatus();
  resetUtilityLogViewState();
}

async function refreshUtilityModalData(type: UtilityModalType, options: RefreshUtilityModalOptions = {}) {
  const agent = activeAgent.value;
  const refreshToken = ++utilityModalRefreshToken;
  const keepHistoryVisible =
    type === "history" &&
    Boolean(options.keepContentVisible) &&
    chatRelatedHistoryRecords.value.length > 0 &&
    Boolean(agent);
  if (!keepHistoryVisible) {
    utilityModalLoading.value = true;
  }
  utilityModalError.value = "";

  try {
    if (type === "history") {
      const conversationScopeKey = resolveConversationScopeKey(agent?.agentId ?? null, activeChannelChatSession.value);
      if (!agent || !conversationScopeKey) {
        if (refreshToken !== utilityModalRefreshToken) {
          return;
        }
        chatHistoryArchives.value = [];
        chatRelatedHistoryRecords.value = [];
        chatRelatedArchiveRecords.value = [];
        return;
      }
      const normalizedConversationScopeKey = normalizeStoredConversationScopeKey(conversationScopeKey);
      if (normalizedConversationScopeKey && isOpenClawAgentSessionScope(normalizedConversationScopeKey, agent.agentId)) {
        const runtimeSessionKey = resolveRuntimeSessionKeyForConversation(normalizedConversationScopeKey, agent.agentId);
        await syncOpenClawSessionHistoryToLocal(agent, normalizedConversationScopeKey, {
          applyToActiveConversation: true,
          runtimeSessionKey
        });
      }
      if (refreshToken !== utilityModalRefreshToken) {
        return;
      }
      const readOptions: ConversationStorageReadOptions = activeChannelChatSession.value ? {} : { legacyAgentId: agent.agentId };
      const nextHistoryArchives = loadChatArchives(conversationScopeKey, readOptions);
      const localRelatedRecords = collectRelatedHistoryRecords(agent);
      const openclawRelatedRecords = await loadOpenClawRelatedHistoryRecords(
        agent,
        normalizeStoredConversationScopeKey(conversationScopeKey)
      );
      if (refreshToken !== utilityModalRefreshToken) {
        return;
      }
      let nextRelatedRecords = localRelatedRecords;
      if (openclawRelatedRecords.length > 0) {
        const mergedMap = new Map<string, ChatRelatedHistoryRecord>();
        for (const record of openclawRelatedRecords) {
          mergedMap.set(record.scopeKey, record);
        }
        for (const record of localRelatedRecords) {
          if (!mergedMap.has(record.scopeKey)) {
            mergedMap.set(record.scopeKey, record);
          }
        }
        nextRelatedRecords = Array.from(mergedMap.values()).sort((left, right) => right.updatedAt - left.updatedAt);
      }
      const nextRelatedArchiveRecords = collectRelatedArchiveRecords(agent);
      chatHistoryArchives.value = nextHistoryArchives;
      chatRelatedHistoryRecords.value = nextRelatedRecords;
      chatRelatedArchiveRecords.value = nextRelatedArchiveRecords;
      return;
    }

    const invoke = getTauriInvoke();
    if (!invoke) {
      if (refreshToken !== utilityModalRefreshToken) {
        return;
      }
      chatRuntimeLogs.value = {
        detail: "当前环境不支持读取运行日志。",
        logs: []
      };
      utilitySelectedLogId.value = null;
      return;
    }
    const nextRuntimeLogs = (await invoke("load_openclaw_message_logs")) as OpenClawMessageLogResponse;
    if (refreshToken !== utilityModalRefreshToken) {
      return;
    }
    chatRuntimeLogs.value = nextRuntimeLogs;
    const filteredLogs = runtimeLogItems.value;
    const categorizedLogs = runtimeCategoryLogItems.value;
    const selected = pickLogForDetail(utilitySelectedLogId.value, categorizedLogs);
    if (utilityLogTab.value === "errorAnalysis") {
      const errorLog =
        filteredLogs.find((log) => log.responseStatus >= 400 || Boolean((log.error ?? "").trim())) ??
        pickLogForDetail(utilitySelectedLogId.value, filteredLogs);
      selectUtilityLog(errorLog, "raw");
    } else {
      selectUtilityLog(selected);
    }
  } catch (error) {
    if (refreshToken !== utilityModalRefreshToken) {
      return;
    }
    utilityModalError.value = error instanceof Error ? error.message : "加载数据失败。";
  } finally {
    if (refreshToken === utilityModalRefreshToken) {
      utilityModalLoading.value = false;
    }
  }
}

async function handleUtilityModalRefresh() {
  if (utilityModalType.value) {
    await refreshUtilityModalData(utilityModalType.value);
    return;
  }
  if (isHistoryPanelActive.value) {
    await refreshUtilityModalData("history");
    return;
  }
  if (isLogsPanelActive.value || isSidebarLogsOpen.value) {
    await refreshUtilityModalData("logs");
  }
}

async function handleArchiveCurrentChat() {
  const agent = activeAgent.value;
  const conversationScopeKey = resolveConversationScopeKey(agent?.agentId ?? null, activeChannelChatSession.value);
  if (!agent || !conversationScopeKey) {
    return;
  }

  const stableMessages = getStableChatMessages(chatMessages.value);
  const meaningfulMessages = stableMessages.filter(
    (item) => (item.role === "assistant" || item.role === "user") && !isRuntimeToolMessage(item)
  );
  if (meaningfulMessages.length === 0) {
    utilityModalNotice.value = "当前会话暂无可归档的消息。";
    return;
  }

  const readOptions: ConversationStorageReadOptions = activeChannelChatSession.value ? {} : { legacyAgentId: agent.agentId };
  const archives = loadChatArchives(conversationScopeKey, readOptions);
  const archiveRecord: ChatArchiveRecord = {
    id: createMessageId("archive"),
    archivedAt: Date.now(),
    title: buildArchiveTitle(meaningfulMessages),
    messages: meaningfulMessages.map((item) => ({ ...item }))
  };
  const nextArchives = [archiveRecord, ...archives].slice(0, 60);
  persistChatArchives(conversationScopeKey, nextArchives);
  chatHistoryArchives.value = nextArchives;

  chatMessages.value = createWelcomeMessages(agent);
  chatAttachments.value = [];
  chatComposerError.value = "";
  runtimeToolSyncContext.value = null;
  expandedRuntimeToolMessages.value = {};
  clearRuntimeToolSyncRetryTimer();
  currentSessionId.value =
    parseConversationScope(conversationScopeKey)?.kind === "agent"
      ? buildScopedRuntimeSessionKey(conversationScopeKey, agent.agentId)
      : createSessionId();
  persistChatHistory(conversationScopeKey);
  agentHistories.value[conversationScopeKey] = [...chatMessages.value];
  refreshAgentMetaFromHistory(agent.agentId, chatMessages.value, agent.currentWork);

  utilityModalNotice.value = "当前会话已归档，可在聊天记录中查看。";
  if (utilityModalType.value === "history" || isHistoryPanelActive.value) {
    await refreshUtilityModalData("history");
  }
  void scrollMessagesToBottom();
}

function handleRestoreArchive(record: ChatArchiveRecord) {
  const agent = activeAgent.value;
  const conversationScopeKey = resolveConversationScopeKey(agent?.agentId ?? null, activeChannelChatSession.value);
  if (!agent || !conversationScopeKey) {
    return;
  }
  const restoredMessages = record.messages.map((message) => ({ ...message }));
  chatMessages.value = restoredMessages.length > 0 ? restoredMessages : createWelcomeMessages(agent);
  chatAttachments.value = [];
  chatComposerError.value = "";
  runtimeToolSyncContext.value = null;
  expandedRuntimeToolMessages.value = {};
  clearRuntimeToolSyncRetryTimer();
  persistChatHistory(conversationScopeKey);
  agentHistories.value[conversationScopeKey] = [...chatMessages.value];
  refreshAgentMetaFromHistory(agent.agentId, chatMessages.value, agent.currentWork);
  utilityModalNotice.value = `已恢复归档会话「${record.title}」。`;
  if (utilityModalType.value === "history") {
    closeUtilityModal();
  }
  void scrollMessagesToBottom();
}

