    closeChatAgentContextMenu();
    closeChannelPaneItemContextMenu();
    closeChatMessageContextMenu();
    if (section === "dashboard") {
      void refreshDashboardData();
      return;
    }
    if (section === "skills" && !skillMarketLoading.value && skillMarketTopSkills.value.length === 0 && skillMarketCategorySkills.value.length === 0) {
      void refreshSkillMarket();
    }
  }
);

watch(
  () => selectedAgentId.value,
  () => {
    sidebarAvatarUploadError.value = "";
    sidebarProfileNotice.value = "";
    sidebarAvatarPresetCategory.value = "pixel";
    resetChatMentionState();
  }
);

watch(
  () => isChatMentionDropdownVisible.value,
  (visible) => {
    if (!visible) {
      resetChatMentionState();
    }
  }
);

watch(
  () => chatMentionCandidates.value.length,
  (length) => {
    if (length <= 0) {
      chatMentionActiveIndex.value = 0;
      return;
    }
    if (chatMentionActiveIndex.value >= length) {
      chatMentionActiveIndex.value = length - 1;
    }
  }
);

watch(
  [skillMarketCurrentTotalPages, () => skillMarketSearch.value],
  ([totalPages]) => {
    if (skillMarketPage.value > totalPages) {
      skillMarketPage.value = totalPages;
    }
  }
);
</script>

