              @mousedown.left="handleRegionMouseDown"
              @dblclick="handleSidebarDoubleClick"
            >
              <div>
                <h2>运行日志</h2>
                <p>{{ utilityModalSubtitle }}</p>
              </div>
              <div class="utility-modal__actions" data-no-window-drag>
                <button class="utility-modal__refresh" type="button" :disabled="utilityModalLoading" @click="handleUtilityModalRefresh">刷新</button>
                <button class="utility-modal__close" type="button" aria-label="关闭日志" @click="closeSidebarLogsPanel">×</button>
              </div>
            </header>

            <div class="utility-modal__body utility-modal__body--logs utility-panel-body">
              <p v-if="utilityModalNotice" class="utility-modal__notice">{{ utilityModalNotice }}</p>
              <p v-if="utilityModalError" class="utility-modal__error">{{ utilityModalError }}</p>
              <div v-if="utilityModalLoading" class="utility-modal__empty">正在加载数据...</div>

              <template v-else>
                <p class="utility-modal__detail">
                  {{ chatRuntimeLogs?.detail || "展示 OpenClaw 运行日志。" }} · 当前筛选
                  {{ utilityLogTab === "runtime" ? runtimeCategoryLogItems.length : runtimeLogItems.length }} / {{ runtimeLogItems.length }} 条
                </p>

                <div class="utility-log-tabs" role="tablist" aria-label="日志视图切换">
                  <button
                    type="button"
                    class="utility-log-tab"
                    :class="{ 'is-active': utilityLogTab === 'runtime' }"
                    @click="handleUtilityLogTabChange('runtime')"
                  >
                    运行日志
                  </button>
                  <button
                    type="button"
                    class="utility-log-tab"
                    :class="{ 'is-active': utilityLogTab === 'errorAnalysis' }"
                    @click="handleUtilityLogTabChange('errorAnalysis')"
                  >
                    错误日志分析
                  </button>
                </div>

                <template v-if="utilityLogTab === 'runtime'">
                  <div class="utility-log-categories-wrap">
                    <div class="utility-log-categories" role="tablist" aria-label="运行日志分类">
                      <button
                        v-for="category in utilityRuntimeCategories"
                        :key="category.id"
                        type="button"
                        class="utility-log-category"
                        :class="{ 'is-active': utilityRuntimeCategory === category.id }"
                        @click="handleUtilityRuntimeCategoryChange(category.id)"
                      >
                        {{ category.label }}
                      </button>
                    </div>
                    <div class="utility-log-filters">
                      <label class="utility-log-filter">
                        <span>角色</span>
                        <select
                          v-model="utilityRuntimeRoleFilter"
                          class="utility-log-filter__select"
                          @change="handleUtilityRuntimeRoleFilterChange"
                        >
                          <option v-for="option in utilityRuntimeRoleFilterOptions" :key="option.id" :value="option.id">
                            {{ option.label }}（{{ option.count }}）
                          </option>
                        </select>
                      </label>
                      <label class="utility-log-filter">
                        <span>定时任务</span>
                        <select
                          v-model="utilityRuntimeScheduleFilter"
                          class="utility-log-filter__select"
                          @change="handleUtilityRuntimeScheduleFilterChange"
                        >
                          <option v-for="option in utilityRuntimeScheduleFilterOptions" :key="option.id" :value="option.id">
                            {{ option.label }}（{{ option.count }}）
                          </option>
                        </select>
                      </label>
                    </div>
                  </div>

                  <div v-if="runtimeCategoryLogItems.length === 0" class="utility-modal__empty">当前分类暂无运行日志。</div>
                  <div v-else class="utility-log-layout">
                    <div class="utility-log-list">
                      <button
                        v-for="log in runtimeCategoryLogItems"
                        :key="log.id"
                        type="button"
                        class="utility-log-item"
                        :class="{ 'is-active': selectedRuntimeLog?.id === log.id }"
                        @click="handleUtilityLogSelect(log)"
                      >
                        <div class="utility-log-item__head">
                          <div class="utility-log-item__meta">
                            <strong>{{ log.method }}</strong>
                            <span class="utility-log-kind" :data-kind="getRuntimeLogCategory(log)">{{ getRuntimeLogCategoryLabel(log) }}</span>
                          </div>
                          <span class="utility-log-status" :data-tone="getLogStatusTone(log.responseStatus)">{{ log.responseStatus }}</span>
                        </div>
                        <p>{{ getLogRequestUrl(log) }}</p>
                        <small>{{ formatDateTime(log.createdAt) }} · 耗时 {{ formatDurationLabel(log.duration) }}</small>
                      </button>
                    </div>

                    <section v-if="selectedRuntimeLog && activeRuntimeLogDetailSection" class="utility-log-detail">
                      <div class="utility-log-detail__head">
                        <header class="utility-log-detail__header">
                          <div class="utility-log-detail__title-wrap">
                            <div class="utility-log-detail__route">
                              <span class="utility-log-detail__method">{{ selectedRuntimeLog.method }}</span>
                              <strong>{{ selectedRuntimeLog.path || selectedRuntimeLog.endpoint || "/" }}</strong>
                            </div>
                            <p>{{ getLogRequestUrl(selectedRuntimeLog) }}</p>
                            <div class="utility-log-detail__meta">
                              <span class="utility-log-detail__meta-item">{{ selectedRuntimeLog.platformName }}</span>
                              <span class="utility-log-detail__meta-item">{{ formatDateTime(selectedRuntimeLog.createdAt) }}</span>
                              <span class="utility-log-kind" :data-kind="getRuntimeLogCategory(selectedRuntimeLog)">
                                {{ getRuntimeLogCategoryLabel(selectedRuntimeLog) }}
                              </span>
                            </div>
                          </div>
                          <div class="utility-log-detail__header-side">
                            <span class="utility-log-status" :data-tone="getLogStatusTone(selectedRuntimeLog.responseStatus)">{{
                              selectedRuntimeLog.responseStatus
                            }}</span>
                          </div>
                        </header>
                        <div class="utility-log-detail__stats">
                          <span class="utility-log-detail__stat">
                            <small>耗时</small>
                            <strong>{{ formatDurationLabel(selectedRuntimeLog.duration) }}</strong>
                          </span>
                          <span v-if="typeof selectedRuntimeLog.firstTokenTime === 'number'" class="utility-log-detail__stat">
                            <small>首 Token</small>
                            <strong>{{ formatDurationLabel(selectedRuntimeLog.firstTokenTime) }}</strong>
                          </span>
                          <span
                            v-if="
                              typeof selectedRuntimeLog.totalTokens === 'number' ||
                              typeof selectedRuntimeLog.promptTokens === 'number' ||
                              typeof selectedRuntimeLog.completionTokens === 'number' ||
                              typeof selectedRuntimeLog.cacheReadInputTokens === 'number'
                            "
                            class="utility-log-detail__stat"
                          >
                            <small>总 Token</small>
                            <strong>{{ getEffectiveLogTotalTokens(selectedRuntimeLog) }}</strong>
                          </span>
                        </div>
                        <div class="utility-log-detail-tabs" role="tablist" aria-label="日志详情分栏">
                          <button
                            v-for="section in runtimeLogDetailSections"
                            :key="section.id"
                            type="button"
                            class="utility-log-detail-tab"
                            :class="{ 'is-active': activeRuntimeLogDetailSection.id === section.id }"
                            @click="handleUtilityLogDetailTabSelect(section.id)"
                          >
                            {{ section.label }}
                          </button>
                        </div>
                      </div>
                      <div class="utility-log-detail__content-wrap">
                        <button
                          type="button"
                          class="utility-log-copy"
                          title="复制当前内容"
                          aria-label="复制当前内容"
                          @click="handleCopyRuntimeLogContent"
                        >
                          <ControlIcon name="copy" />
                        </button>
                        <pre class="utility-log-detail__content" tabindex="0">{{ activeRuntimeLogDetailSection.text }}</pre>
                      </div>
                    </section>
                  </div>
                </template>

                <template v-else>
                  <div v-if="errorAnalysisSummaries.length === 0" class="utility-modal__empty">当前筛选暂无错误日志。</div>
                  <div v-else class="utility-log-layout">
                    <div class="utility-error-list">
                      <button
                        v-for="summary in errorAnalysisSummaries"
                        :key="summary.key"
                        type="button"
                        class="utility-error-item"
                        :class="{ 'is-active': selectedErrorSummary?.key === summary.key }"
                        @click="handleUtilityErrorSummarySelect(summary.key)"
                      >
                        <div class="utility-error-item__head">
                          <strong>{{ summary.title }}</strong>
                          <span>{{ summary.count }} 次</span>
                        </div>
                        <p>{{ summary.latestLog.method }} {{ summary.latestLog.path || summary.latestLog.endpoint || "/" }}</p>
                        <small>最近 {{ formatDateTime(summary.latestAt) }}</small>
                      </button>
                    </div>

                    <section v-if="selectedRuntimeLog && activeRuntimeLogDetailSection" class="utility-log-detail">
                      <div class="utility-log-detail__head">
                        <header class="utility-log-detail__header">
                          <div>
                            <strong>错误详情</strong>
                            <p>{{ selectedRuntimeLog.method }} {{ selectedRuntimeLog.path || selectedRuntimeLog.endpoint || "/" }}</p>
                          </div>
                          <span class="utility-log-status" :data-tone="getLogStatusTone(selectedRuntimeLog.responseStatus)">{{
                            selectedRuntimeLog.responseStatus
                          }}</span>
                        </header>
                        <div class="utility-log-detail-tabs" role="tablist" aria-label="错误详情分栏">
                          <button
                            v-for="section in runtimeLogDetailSections"
                            :key="section.id"
                            type="button"
                            class="utility-log-detail-tab"
                            :class="{ 'is-active': activeRuntimeLogDetailSection.id === section.id }"
                            @click="handleUtilityLogDetailTabSelect(section.id)"
                          >
                            {{ section.label }}
                          </button>
                        </div>
                      </div>
                      <div class="utility-log-detail__content-wrap">
                        <button
                          type="button"
                          class="utility-log-copy"
                          title="复制当前内容"
                          aria-label="复制当前内容"
                          @click="handleCopyRuntimeLogContent"
                        >
                          <ControlIcon name="copy" />
                        </button>
                        <pre class="utility-log-detail__content" tabindex="0">{{ activeRuntimeLogDetailSection.text }}</pre>
                      </div>
                    </section>
                  </div>
                </template>
              </template>
            </div>
          </main>

          <template v-else>
            <section class="chat-list">
            <header class="chat-list__header" @mousedown.left="handleRegionMouseDown" @dblclick="handleSidebarDoubleClick">
              <div class="search-row">
                <label class="search-box" aria-label="搜索 Agent">
                  <ControlIcon name="search" />
                  <input v-model="searchQuery" type="text" placeholder="搜索 Agent" />
                </label>
                <div ref="chatQuickCreateMenuRef" class="search-create-menu" data-no-window-drag>
                  <button
                    class="search-add"
                    type="button"
                    title="快捷新建"
                    aria-label="快捷新建"
                    aria-haspopup="menu"
                    :aria-expanded="isChatQuickCreateMenuOpen"
                    @click.stop="toggleChatQuickCreateMenu"
                  >
                    <ControlIcon name="plus" />
                  </button>
                  <div v-if="isChatQuickCreateMenuOpen" class="search-create-menu__popover" role="menu" aria-label="快捷新建菜单">
                    <button type="button" class="search-create-menu__item" role="menuitem" @click="handleChatQuickCreateAction('role')">
                      新建角色
                    </button>
                    <button type="button" class="search-create-menu__item" role="menuitem" @click="handleChatQuickCreateAction('group')">
                      新建群聊
                    </button>
                    <button type="button" class="search-create-menu__item" role="menuitem" @click="handleChatQuickCreateAction('friend')">
                      添加虾友
                    </button>
                  </div>
                </div>
              </div>
              <div class="agent-pane-tabs" role="tablist" aria-label="Agent 分组">
                <button
                  v-for="tab in agentPaneTabs"
                  :key="tab.id"
                  class="agent-pane-tab"
                  :class="{ active: activeAgentPaneTab === tab.id }"
                  type="button"
                  @click="activeAgentPaneTab = tab.id"
                >
                  {{ tab.label }}
                </button>
              </div>
            </header>

            <div class="chat-list__body">
              <template v-if="isChannelPaneActive">
                <div class="chat-channel-pane">
                  <section v-if="configuredChannelChatItems.length > 0" class="chat-channel-pane__chat-list">
                    <article
                      v-for="item in configuredChannelChatItems"
                      :key="`channel-chat-${item.id}`"
                      class="chat-channel-pane__chat-item"
                      :class="{ 'is-active': isChannelChatItemActive(item) }"
                      role="button"
                      tabindex="0"
                      @click="handleChannelPaneChatItemClick(item)"
                      @keydown.enter.prevent="handleChannelPaneChatItemClick(item)"
                      @keydown.space.prevent="handleChannelPaneChatItemClick(item)"
                      @contextmenu.prevent="handleChannelPaneChatItemContextMenu(item, $event)"
                    >
                      <div class="chat-channel-pane__chat-item-main">
                        <span class="chat-channel-pane__icon-shell">
                          <img v-if="item.icon" :src="item.icon" :alt="item.name" />
                          <span v-else>{{ item.name.charAt(0).toUpperCase() }}</span>
                        </span>
                        <div class="chat-channel-pane__chat-item-copy">
                          <strong>{{ item.name }}</strong>
                          <small>{{ item.summary }}</small>
                        </div>
                      </div>
                      <div class="chat-channel-pane__chat-item-actions">
                        <button
                          class="chat-channel-pane__chat-item-config"
                          type="button"
                          title="配置频道绑定"
                          aria-label="配置频道绑定"
                          @click.stop="handleChannelPaneChatItemConfigClick(item)"
                        >
                          <ControlIcon name="settings" />
                        </button>
                        <i class="chat-channel-pane__chat-item-dot" :data-tone="item.statusTone" :title="item.statusLabel" />
                      </div>
                    </article>
                  </section>
                  <section v-else class="chat-channel-pane__placeholder">
                    <p>{{ normalizedQuery ? "没有匹配的频道聊天项" : "暂无已配置频道" }}</p>
                    <small>{{
                      normalizedQuery
                        ? "尝试清空搜索条件，或先在下方频道列表完成配置。"
                        : "点击下方频道卡片开始配置，配置成功后会在这里加载对应频道聊天项。"
                    }}</small>
                  </section>
                  <div class="chat-channel-pane__bottom">
                    <section class="chat-channel-pane__section">
                      <header class="chat-channel-pane__head">
                        <h4>频道列表</h4>
                        <small>{{ visibleChannelPaneCatalog.length }} 个</small>
                      </header>
                      <div v-if="visibleChannelPaneCatalog.length > 0" class="chat-channel-pane__catalog-grid">
                        <article
                          v-for="channel in visibleChannelPaneCatalog"
                          :key="`channel-pane-${channel.id}`"
                          class="chat-channel-pane__catalog-card"
                          :class="{ 'chat-channel-pane__catalog-card--interactive': true }"
                          @click="handleChannelPaneCatalogCardClick(channel.id)"
                        >
                          <div class="chat-channel-pane__identity">
                            <span class="chat-channel-pane__icon-shell">
                              <img :src="channel.icon" :alt="channel.name" />
                            </span>
                            <strong>{{ channel.name }}</strong>
                          </div>
                          <span
                            class="chat-channel-pane__status-dot"
                            :class="{ 'is-configured': channel.configured }"
                            :title="channel.configured ? '已配置' : '未配置'"
                            :aria-label="channel.configured ? '已配置' : '未配置'"
                          />
                        </article>
                      </div>
                      <p v-else class="list-empty list-empty--compact">没有匹配的频道。</p>
                    </section>
                  </div>
                </div>
              </template>
              <template v-else>
                <div
                  v-if="currentPaneAgentSections.length > 0"
                  class="agent-group-list"
                  :class="{ 'agent-group-list--flat': isConversationGroupPaneActive }"
                >
                  <div v-if="isConversationGroupPaneActive" class="agent-flat-head">
                    <small>{{ currentPaneAgentSections[0]?.agents.length ?? 0 }} 个群聊</small>
                    <button
                      class="agent-group-add"
                      type="button"
                      title="新建群聊"
                      aria-label="新建群聊"
                      @click="handleCreateChatUserGroup"
                    >
                      <ControlIcon name="plus" />
                    </button>
                  </div>
                  <section
                    v-for="(section, sectionIndex) in currentPaneAgentSections"
                    :key="`agent-group-${activeAgentPaneTab}-${section.id}`"
                    class="agent-group-section"
                    :class="{
                      'agent-group-section--default': section.isDefault,
                      'agent-group-section--collapsed': !isConversationGroupPaneActive && isChatUserSectionCollapsed(section.id),
                      'agent-group-section--flat': isConversationGroupPaneActive
                    }"
                  >
                    <header v-if="!isConversationGroupPaneActive" class="agent-group-head">
                      <strong>{{ section.title }}</strong>
                      <div class="agent-group-head__actions">
                        <small>{{ section.agents.length }}</small>
                        <button
                          class="agent-group-collapse"
                          :class="{ 'is-collapsed': isChatUserSectionCollapsed(section.id) }"
                          type="button"
                          :title="isChatUserSectionCollapsed(section.id) ? `展开 ${section.title}` : `折叠 ${section.title}`"
                          :aria-label="isChatUserSectionCollapsed(section.id) ? `展开 ${section.title}` : `折叠 ${section.title}`"
                          @click="toggleChatUserSectionCollapsed(section.id)"
                        >
                          <ControlIcon name="chevron-down" />
                        </button>
                        <button
                          v-if="section.id !== CHAT_USER_PINNED_GROUP_ID && !section.isDefault"
                          class="agent-group-delete"
                          type="button"
                          :title="`删除 ${section.title}`"
                          :aria-label="`删除 ${section.title}`"
                          @click="handleDeleteChatUserGroup(section.id)"
                        >
                          <ControlIcon name="trash" />
                        </button>
                        <button
                          v-if="sectionIndex === 0"
                          class="agent-group-add"
                          type="button"
                          title="新建群聊"
                          aria-label="新建群聊"
                          @click="handleCreateChatUserGroup"
                        >
                          <ControlIcon name="plus" />
                        </button>
                      </div>
                    </header>

                    <template v-if="isConversationGroupPaneActive || !isChatUserSectionCollapsed(section.id)">
                      <p v-if="section.agents.length === 0" class="list-empty list-empty--compact">该分组暂无成员。</p>
                      <button
                        v-for="agent in section.agents"
                        :key="`${section.id}-${agent.agentId}`"
                        class="agent-item"
                        :class="{
                          active: selectedAgentId === agent.agentId,
                          'agent-item--dragging': !isConversationGroupPaneActive && chatUserDragAgentId === agent.agentId,
                          'agent-item--drag-over':
                            !isConversationGroupPaneActive &&
                            chatUserDragSectionId === section.id &&
                            chatUserDragOverAgentId === agent.agentId &&
                            chatUserDragAgentId !== agent.agentId
                        }"
                        type="button"
                        @click="switchAgent(agent.agentId)"
                        :draggable="!isConversationGroupPaneActive"
                        @dragstart="!isConversationGroupPaneActive && handleChatUserAgentDragStart(section.id, agent.agentId, $event)"
                        @dragover.prevent="!isConversationGroupPaneActive && handleChatUserAgentDragOver(section.id, agent.agentId, $event)"
                        @drop.prevent="!isConversationGroupPaneActive && handleChatUserAgentDrop(section.id, agent.agentId)"
                        @dragend="!isConversationGroupPaneActive && handleChatUserAgentDragEnd()"
                        @contextmenu.prevent="handleChatAgentItemContextMenu(agent, $event)"
                      >
                        <div class="agent-avatar" :class="{ 'agent-avatar--group': agent.groupKind === 'group' }">
                          <span
                            v-if="isChatConversationGroupAgentId(agent.agentId) && getConversationGroupPreviewMembers(agent.agentId).length > 0"
                            class="group-avatar-stack group-avatar-stack--md"
                            aria-hidden="true"
                          >
                            <span
                              v-for="member in getConversationGroupPreviewMembers(agent.agentId)"
                              :key="`chat-list-group-avatar-${agent.agentId}-${member.agentId}`"
                              class="group-avatar-stack__item"
                            >
                              <img
                                v-if="getAgentAvatarUrl(member)"
                                class="group-avatar-stack__image"
                                :src="getAgentAvatarUrl(member) ?? undefined"
                                :alt="`${stripRoleLabel(member.displayName)} 头像`"
                                loading="lazy"
                                decoding="async"
                              />
                              <span v-else>{{ getAgentInitial(member) }}</span>
                            </span>
                          </span>
                          <img
                            v-else-if="getAgentAvatarUrl(agent)"
                            class="agent-avatar__image"
                            :src="getAgentAvatarUrl(agent) ?? undefined"
                            :alt="`${stripRoleLabel(agent.displayName)} 头像`"
                            loading="lazy"
                            decoding="async"
                          />
                          <span v-else>{{ getAgentInitial(agent) }}</span>
                          <i class="status-dot" :data-tone="agent.statusTone" />
                        </div>
                        <div class="agent-content">
                          <div class="agent-top-line">
                            <strong>{{ stripRoleLabel(agent.displayName) }}</strong>
                            <span v-if="shouldShowAgentChannelTag(agent)" class="agent-channel">{{ resolveAgentChannelDisplayLabel(agent) }}</span>
                          </div>
                          <p class="agent-preview">{{ getAgentMeta(agent.agentId).preview }}</p>
                          <small class="agent-status">{{ getAgentStatusLabel(agent) }}</small>
                        </div>
                      </button>
                    </template>
                  </section>
                </div>
                <p v-else class="list-empty">
                  {{ normalizedQuery ? "没有匹配的 Agent" : currentPaneEmptyText }}
                </p>
              </template>
            </div>
          </section>

          <div
            v-if="isChannelPaneItemContextMenuOpen && channelPaneItemContextMenuTarget"
            ref="channelPaneItemContextMenuRef"
            class="agent-context-menu"
            role="menu"
            aria-label="频道操作菜单"
            data-no-window-drag
            :style="{
              left: `${channelPaneItemContextMenuPosition.x}px`,
              top: `${channelPaneItemContextMenuPosition.y}px`
            }"
            @mousedown.stop
          >
            <button
              type="button"
              class="agent-context-menu__item"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChannelPaneItemContextMenuRename"
              @keydown.enter.stop.prevent="handleChannelPaneItemContextMenuRename"
              @keydown.space.stop.prevent="handleChannelPaneItemContextMenuRename"
            >
              修改名称
            </button>
            <button
              type="button"
              class="agent-context-menu__item agent-context-menu__item--danger"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChannelPaneItemContextMenuDelete"
              @keydown.enter.stop.prevent="handleChannelPaneItemContextMenuDelete"
              @keydown.space.stop.prevent="handleChannelPaneItemContextMenuDelete"
            >
              删除
            </button>
          </div>

          <div
            v-if="isChannelPaneDeleteConfirmModalOpen && channelPaneDeleteConfirmTarget"
            class="related-resource-modal-backdrop"
            @click.self="closeChannelPaneDeleteConfirmModal"
          >
            <section class="related-resource-modal chat-agent-delete-modal" role="dialog" aria-modal="true" aria-label="确认删除频道账号">
              <header class="related-resource-modal__header chat-agent-delete-modal__header">
                <div class="chat-agent-delete-modal__title">
                  <span class="chat-agent-delete-modal__icon" aria-hidden="true">
                    <ControlIcon name="trash" />
                  </span>
                  <div>
                    <strong>确认删除</strong>
                    <p>该操作不可撤销，请确认后继续。</p>
                  </div>
                </div>
              </header>
              <div class="related-resource-modal__body chat-agent-delete-modal__body">
                <div class="chat-agent-delete-modal__risk">
                  <p>
                    即将删除频道账号
                    <strong>「{{ channelPaneDeleteConfirmTarget.name }} · {{ channelPaneDeleteConfirmTarget.accountId }}」</strong>。
                  </p>
                  <small>删除后该频道会从列表移除，并解除与员工的绑定关系。</small>
                </div>
                <div class="chat-agent-delete-modal__actions">
                  <button
                    class="related-resource-modal__refresh"
                    type="button"
                    :disabled="isChannelPaneDeleteConfirming"
                    @click="closeChannelPaneDeleteConfirmModal"
                  >
                    取消
                  </button>
                  <button
                    class="related-resource-modal__refresh chat-agent-delete-modal__confirm"
                    type="button"
                    :disabled="isChannelPaneDeleteConfirming"
                    @click="handleChannelPaneDeleteConfirmSubmit"
                  >
                    {{ isChannelPaneDeleteConfirming ? "删除中..." : "确认删除" }}
                  </button>
                </div>
              </div>
            </section>
          </div>

          <div
            v-if="isChatAgentContextMenuOpen"
            ref="chatAgentContextMenuRef"
            class="agent-context-menu"
            role="menu"
            :aria-label="isChatAgentContextMenuGroupTarget ? '群聊操作菜单' : '数字员工操作菜单'"
            data-no-window-drag
            :style="{
              left: `${chatAgentContextMenuPosition.x}px`,
              top: `${chatAgentContextMenuPosition.y}px`
            }"
            @mousedown.stop
          >
            <button
              type="button"
              class="agent-context-menu__item"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChatAgentContextMenuInfo"
              @keydown.enter.stop.prevent="handleChatAgentContextMenuInfo"
              @keydown.space.stop.prevent="handleChatAgentContextMenuInfo"
            >
              信息
            </button>
            <button
              v-if="!isChatAgentContextMenuGroupTarget"
              type="button"
              class="agent-context-menu__item"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChatAgentContextMenuPin"
              @keydown.enter.stop.prevent="handleChatAgentContextMenuPin"
              @keydown.space.stop.prevent="handleChatAgentContextMenuPin"
            >
              置顶
            </button>
            <button
              type="button"
              class="agent-context-menu__item agent-context-menu__item--danger"
              role="menuitem"
              :disabled="Boolean(chatAgentContextMenuTarget && isProtectedStaffAgentId(chatAgentContextMenuTarget.agentId))"
              @mousedown.left.stop.prevent="handleChatAgentContextMenuDelete"
              @keydown.enter.stop.prevent="handleChatAgentContextMenuDelete"
              @keydown.space.stop.prevent="handleChatAgentContextMenuDelete"
            >
              删除
            </button>
          </div>

          <div
            v-if="isChatMessageContextMenuOpen"
            ref="chatMessageContextMenuRef"
            class="agent-context-menu chat-message-context-menu"
            role="menu"
            aria-label="消息操作菜单"
            data-no-window-drag
            :style="{
              left: `${chatMessageContextMenuPosition.x}px`,
              top: `${chatMessageContextMenuPosition.y}px`
            }"
            @mousedown.stop
          >
            <button
              v-if="chatMessageContextMenuHasSelection"
              type="button"
              class="agent-context-menu__item"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChatMessageContextMenuCopySelection"
              @keydown.enter.stop.prevent="handleChatMessageContextMenuCopySelection"
              @keydown.space.stop.prevent="handleChatMessageContextMenuCopySelection"
            >
              复制选中文本
            </button>
            <button
              type="button"
              class="agent-context-menu__item"
              role="menuitem"
              @mousedown.left.stop.prevent="handleChatMessageContextMenuCopyRecord"
              @keydown.enter.stop.prevent="handleChatMessageContextMenuCopyRecord"
              @keydown.space.stop.prevent="handleChatMessageContextMenuCopyRecord"
            >
              复制整条记录
            </button>
          </div>

          <div
            v-if="isChatAgentDeleteConfirmModalOpen && chatAgentDeleteConfirmTarget"
            class="related-resource-modal-backdrop"
            @click.self="closeChatAgentDeleteConfirmModal"
          >
            <section
              class="related-resource-modal chat-agent-delete-modal"
              role="dialog"
              aria-modal="true"
              :aria-label="isChatAgentDeleteConfirmGroupTarget ? '确认删除群聊' : '确认删除员工'"
            >
              <header class="related-resource-modal__header chat-agent-delete-modal__header">
                <div class="chat-agent-delete-modal__title">
                  <span class="chat-agent-delete-modal__icon" aria-hidden="true">
                    <ControlIcon name="trash" />
                  </span>
                  <div>
                    <strong>确认删除</strong>
                    <p>该操作不可撤销，请确认后继续。</p>
                  </div>
                </div>
              </header>
              <div class="related-resource-modal__body chat-agent-delete-modal__body">
                <div class="chat-agent-delete-modal__risk">
                  <p>
                    即将删除{{ isChatAgentDeleteConfirmGroupTarget ? "群聊" : "员工" }}
                    <strong>「{{ stripRoleLabel(chatAgentDeleteConfirmTarget.displayName) || chatAgentDeleteConfirmTarget.agentId }}」</strong>。
                  </p>
                  <small>{{
                    isChatAgentDeleteConfirmGroupTarget
                      ? "删除后该群聊将从团队列表移除。"
                      : "删除后该员工将从列表移除，且可能同时删除本地配置文件。"
                  }}</small>
                </div>
                <div class="chat-agent-delete-modal__actions">
                  <button
                    class="related-resource-modal__refresh"
                    type="button"
                    :disabled="isChatAgentDeleteConfirming"
                    @click="closeChatAgentDeleteConfirmModal"
                  >
                    取消
                  </button>
                  <button
                    class="related-resource-modal__refresh chat-agent-delete-modal__confirm"
                    type="button"
                    :disabled="isChatAgentDeleteConfirming"
                    @click="handleChatAgentDeleteConfirmSubmit"
                  >
                    {{ isChatAgentDeleteConfirming ? "删除中..." : "确认删除" }}
                  </button>
                </div>
              </div>
            </section>
          </div>

          <section class="chat-window" :class="{ 'chat-window--settings-open': isAgentSettingsOpen }">
            <header class="chat-window__header" @mousedown.left="handleRegionMouseDown" @dblclick="handleSidebarDoubleClick">
              <div class="chat-agent-header">
                <div
                  class="chat-agent-header__avatar"
                  :class="{ 'is-group': activeAgentIsConversationGroup, 'is-clickable': activeAgentIsConversationGroup }"
                  :role="activeAgentIsConversationGroup ? 'button' : undefined"
                  :tabindex="activeAgentIsConversationGroup ? 0 : undefined"
                  @click="activeAgentIsConversationGroup && openGroupInfoPanel()"
                  @keydown.enter.prevent="activeAgentIsConversationGroup && openGroupInfoPanel()"
                  @keydown.space.prevent="activeAgentIsConversationGroup && openGroupInfoPanel()"
                >
                  <span
                    v-if="activeAgentIsConversationGroup && activeConversationGroupPreviewMembers.length > 0"
                    class="group-avatar-stack group-avatar-stack--lg"
                    aria-hidden="true"
                  >
                    <span
                      v-for="member in activeConversationGroupPreviewMembers"
                      :key="`chat-header-group-avatar-${member.agentId}`"
                      class="group-avatar-stack__item"
                    >
                      <img
                        v-if="getAgentAvatarUrl(member)"
                        class="group-avatar-stack__image"
                        :src="getAgentAvatarUrl(member) ?? undefined"
                        :alt="`${stripRoleLabel(member.displayName)} 头像`"
                        loading="lazy"
                        decoding="async"
                      />
                      <span v-else>{{ getAgentInitial(member) }}</span>
                    </span>
                  </span>
                  <img
                    v-else-if="activeAgentAvatarUrl"
                    class="chat-agent-header__avatar-image"
                    :src="activeAgentAvatarUrl"
                    :alt="`${activeAgent ? stripRoleLabel(activeAgent.displayName) : '当前角色'} 头像`"
                    loading="lazy"
                    decoding="async"
                  />
                  <span v-else>{{ activeAgent ? getAgentInitial(activeAgent) : "?" }}</span>
                </div>
                <div>
                  <strong>{{ activeAgent ? stripRoleLabel(activeAgent.displayName) : "请选择 Agent" }}</strong>
                  <p>
                    {{ activeAgent ? getAgentStatusLabel(activeAgent) : "未选择" }}
                    <span v-if="activeAgent && activeConversationChannelLabel">· {{ activeConversationChannelLabel }}</span>
                  </p>
                </div>
              </div>
              <div class="chat-window__header-right">
                <button
                  v-if="activeAgentIsConversationGroup && activeConversationGroupMemberCount > 0"
                  type="button"
                  class="chat-window__group-summary chat-window__group-summary--trigger"
                  :class="{ 'is-active': isGroupInfoPanelActive }"
                  :aria-label="`查看群聊 ${activeConversationGroup?.name ?? ''} 成员信息`"
                  @click="openGroupInfoPanel"
                >
                  <span class="group-avatar-stack group-avatar-stack--xs" aria-hidden="true">
                    <span
                      v-for="member in activeConversationGroupPreviewMembers"
                      :key="`chat-header-group-summary-${member.agentId}`"
                      class="group-avatar-stack__item"
                    >
                      <img
                        v-if="getAgentAvatarUrl(member)"
                        class="group-avatar-stack__image"
                        :src="getAgentAvatarUrl(member) ?? undefined"
                        :alt="`${stripRoleLabel(member.displayName)} 头像`"
                        loading="lazy"
                        decoding="async"
                      />
                      <span v-else>{{ getAgentInitial(member) }}</span>
                    </span>
                  </span>
                  <span class="chat-window__group-summary-text">等{{ activeConversationGroupMemberCount }}个朋友</span>
                </button>
                <div class="chat-window__actions">
                <button
                  type="button"
                  class="header-btn"
                  :class="{ 'is-active': isHistoryPanelActive }"
                  title="聊天记录"
                  aria-label="打开聊天记录"
                  @click="openSidebarHistory"
                >
                  <ControlIcon name="history" />
                </button>
                <button
                  type="button"
                  class="header-btn"
                  :class="{ 'is-active': isLogsPanelActive }"
                  title="运行日志"
                  aria-label="打开运行日志"
                  @click="openSidebarLogs"
                >
                  <ControlIcon name="runtime" />
                </button>
                <button
                  type="button"
                  class="header-btn"
                  :class="{ 'is-active': isAgentProfilePanelActive }"
                  title="设置"
                  aria-label="打开会话设置"
                  @click="toggleAgentSettingsPanel"
                >
                  <ControlIcon name="settings" />
                </button>
                </div>
              </div>
            </header>

            <div
              class="chat-window__content"
              :class="{
                'chat-window__content--settings-open': isAgentSettingsOpen
              }"
            >
              <div
                ref="messageScroller"
                class="chat-window__messages"
                :class="{ 'chat-window__messages--empty': isConversationEmpty }"
                @mousedown.left="handleChatWindowMessagesMouseDown"
              >
                <div v-if="isConversationEmpty" class="chat-empty-state">
                  <div class="chat-empty-state__logo" aria-hidden="true">
                    <img :src="appLogoUrl" alt="DragonClaw logo" />
                  </div>
                  <h3>DragonClaw</h3>
                  <p>描述你的目标，DragonClaw 会分解任务并执行反馈。</p>
                  <div v-if="!activeAgentIsConversationGroup" class="chat-empty-state__actions">
                    <button class="chat-empty-action" type="button" :disabled="!activeAgent" @click="openRelatedResource('memory')">
                      <span class="chat-empty-action__icon" aria-hidden="true">
                        <ControlIcon name="settings" />
                      </span>
                      <span class="chat-empty-action__content">
                        <strong>快速配置</strong>
                        <small>定制角色身份，为你服务</small>
                      </span>
                    </button>
                    <button class="chat-empty-action" type="button" :disabled="!activeAgent" @click="openRelatedResource('channel')">
                      <span class="chat-empty-action__icon" aria-hidden="true">
                        <ControlIcon name="chat" />
                      </span>
                      <span class="chat-empty-action__content">
                        <strong>聊天渠道设置</strong>
                        <small>快速配置不同平台的聊天机器人</small>
                      </span>
                    </button>
                  </div>
                </div>

                <template v-else>
                  <article
                    v-for="message in chatMessagesForDisplay"
                    :key="message.id"
                    class="message-row"
                    :class="[
                      `message-row--${message.role}`,
                      `message-row--${message.status}`,
                      { 'message-row--tool': isRuntimeToolMessage(message) }
                    ]"
                    @contextmenu="handleChatMessageContextMenu(message, $event)"
                  >
                    <template v-if="isRuntimeToolMessage(message)">
                      <div class="chat-tool-call__avatar" aria-hidden="true">
                        <ControlIcon name="tool" />
                      </div>
                      <div class="chat-tool-call__body">
                        <button class="chat-tool-call__pill" type="button" @click="toggleRuntimeToolMessageExpanded(message.id)">
                          <span class="chat-tool-call__pill-main">
                            <ControlIcon class="chat-tool-call__icon" name="bolt" />
                            <span class="chat-tool-call__name">{{ getRuntimeToolLabel(message) }}</span>
                            <span class="chat-tool-call__status" :class="getRuntimeToolStatusClass(message)">
                              {{ getRuntimeToolStatusLabel(message) }}
                            </span>
                          </span>
                          <ControlIcon class="chat-tool-call__caret" :class="{ 'is-open': isRuntimeToolMessageExpanded(message.id) }" name="chevron-down" />
                        </button>
                        <pre
                          v-if="isRuntimeToolMessageExpanded(message.id) && getRuntimeToolMessageDetail(message)"
                          class="chat-tool-call__detail"
                        >{{ getRuntimeToolMessageDetail(message) }}</pre>
                      </div>
                    </template>
                    <div
                      v-else-if="message.status === 'pending'"
                      class="message-bubble message-bubble--typing"
                      role="status"
                      aria-live="polite"
                      aria-label="正在思考中"
                    >
                      <span class="typing-indicator" aria-hidden="true">
                        <span class="typing-indicator__dot" />
                        <span class="typing-indicator__dot" />
                        <span class="typing-indicator__dot" />
                      </span>
                    </div>
                    <div v-else class="message-bubble" @click="handleMessageBubbleActionClick">
                      <div v-if="message.attachments && message.attachments.length > 0" class="message-bubble__attachments">
                        <span v-for="attachment in message.attachments" :key="`${message.id}-${attachment.id}`" class="message-bubble__attachment">
                          {{ attachment.name }} · {{ formatAttachmentSize(attachment.size) }}
                        </span>
                      </div>
                      <div
                        v-if="getMessageDisplayHtml(message)"
                        class="message-bubble__markdown"
                        v-html="getMessageDisplayHtml(message)"
                      />
                      <section v-if="getMessageDetectedFiles(message).length > 0" class="message-file-output-list" aria-label="消息中的文件输出">
                        <article
                          v-for="file in getMessageDetectedFiles(message)"
                          :key="`${message.id}-${file.id}`"
                          class="message-file-output"
                        >
                          <header v-if="shouldShowDetectedFileHeader(file)" class="message-file-output__head">
                            <p class="message-file-output__path" :title="file.normalizedPath">{{ file.normalizedPath }}</p>
                            <button
                              v-if="canOpenDetectedFileFolder(file)"
                              class="message-file-output__open-btn"
                              type="button"
                              title="打开所在文件夹"
                              aria-label="打开所在文件夹"
                              @click="handleOpenDetectedFileFolder(file)"
                            >
                              <ControlIcon name="folder-open" />
                            </button>
                          </header>
                          <div
                            v-if="supportsDetectedFilePreviewKind(file)"
                            class="message-file-output__preview"
                            :class="{
                              'is-image': isImageDetectedFile(file),
                              'is-video': isVideoDetectedFile(file),
                              'is-standalone': !shouldShowDetectedFileHeader(file)
                            }"
                            @mouseenter="setDetectedVideoPreviewHover(file, true)"
                            @mouseleave="setDetectedVideoPreviewHover(file, false)"
                          >
                            <img
                              v-if="isImageDetectedFile(file) && getDetectedFilePreviewUrl(file)"
                              class="message-file-output__image"
                              :src="getDetectedFilePreviewUrl(file) ?? undefined"
                              :alt="`图片预览：${file.normalizedPath}`"
                              loading="lazy"
                              decoding="async"
                              @error="markDetectedFilePreviewError(file)"
                            />
                            <audio
                              v-else-if="isAudioDetectedFile(file) && getDetectedFilePreviewUrl(file)"
                              class="message-file-output__audio"
                              controls
                              preload="metadata"
                              :src="getDetectedFilePreviewUrl(file) ?? undefined"
                              @error="markDetectedFilePreviewError(file)"
                            />
                            <video
                              v-else-if="isVideoDetectedFile(file) && getDetectedFilePreviewUrl(file)"
                              class="message-file-output__video"
                              :controls="isDetectedVideoPreviewControlsVisible(file)"
                              preload="auto"
                              playsinline
                              :src="getDetectedFilePreviewUrl(file) ?? undefined"
                              @loadeddata="handleDetectedVideoLoadedData"
                              @error="markDetectedFilePreviewError(file)"
                            />
                            <iframe
                              v-else-if="isHtmlDetectedFile(file) && getDetectedFilePreviewUrl(file)"
                              class="message-file-output__iframe"
                              :src="getDetectedFilePreviewUrl(file) ?? undefined"
                              sandbox="allow-same-origin allow-scripts"
                              loading="lazy"
                              @error="markDetectedFilePreviewError(file)"
                            />
                            <p
                              v-if="!canPreviewDetectedFile(file) && !isVideoDetectedFile(file)"
                              class="message-file-output__empty message-file-output__empty--inline"
                            >
                              {{ getDetectedFilePreviewHint(file) }}
                            </p>
                          </div>
                        </article>
                      </section>
                    </div>
                    <span v-if="!isRuntimeToolMessage(message)" class="message-time">{{ getMessageTimeLabel(message) }}</span>
                  </article>
                </template>
              </div>

              <transition name="chat-settings-sidebar-slide">
                <aside v-if="isAgentSettingsOpen" class="chat-settings-sidebar" data-no-window-drag @mousedown.left.stop>
                <div v-if="isLogsPanelActive" class="chat-settings-sidebar__body chat-settings-sidebar__body--logs">
                  <div class="chat-settings-logs-head">
                    <strong>运行日志</strong>
                    <button class="utility-modal__refresh" type="button" :disabled="utilityModalLoading" @click="handleUtilityModalRefresh">
                      刷新
                    </button>
                  </div>
                  <p class="utility-modal__detail">
                    仅展示当前角色日志 · 当前筛选
                    {{ utilityLogTab === "runtime" ? runtimeCategoryLogItems.length : runtimeLogItems.length }} / {{ runtimeLogItems.length }} 条
                  </p>
                  <p v-if="utilityModalNotice" class="utility-modal__notice">{{ utilityModalNotice }}</p>
                  <p v-if="utilityModalError" class="utility-modal__error">{{ utilityModalError }}</p>

                  <div v-if="utilityModalLoading" class="utility-modal__empty">正在加载数据...</div>
                  <div v-else-if="!activeAgent" class="utility-modal__empty">请选择员工后查看日志。</div>

                  <template v-else>
                    <div class="utility-log-tabs" role="tablist" aria-label="日志视图切换">
                      <button
                        type="button"
                        class="utility-log-tab"
                        :class="{ 'is-active': utilityLogTab === 'runtime' }"
                        @click="handleUtilityLogTabChange('runtime')"
                      >
                        运行日志
                      </button>
                      <button
                        type="button"
                        class="utility-log-tab"
                        :class="{ 'is-active': utilityLogTab === 'errorAnalysis' }"
                        @click="handleUtilityLogTabChange('errorAnalysis')"
                      >
                        错误日志分析
                      </button>
                    </div>

                    <template v-if="utilityLogTab === 'runtime'">
                      <div class="utility-log-categories-wrap">
                        <div class="utility-log-categories" role="tablist" aria-label="运行日志分类">
                          <button
                            v-for="category in utilityRuntimeCategories"
                            :key="category.id"
                            type="button"
                            class="utility-log-category"
                            :class="{ 'is-active': utilityRuntimeCategory === category.id }"
                            @click="handleUtilityRuntimeCategoryChange(category.id)"
                          >
                            {{ category.label }}
                          </button>
                        </div>
                        <div class="utility-log-filters">
                          <label class="utility-log-filter">
                            <span>定时任务</span>
                            <select
                              v-model="utilityRuntimeScheduleFilter"
                              class="utility-log-filter__select"
                              @change="handleUtilityRuntimeScheduleFilterChange"
                            >
                              <option v-for="option in utilityRuntimeScheduleFilterOptions" :key="option.id" :value="option.id">
                                {{ option.label }}（{{ option.count }}）
                              </option>
                            </select>
                          </label>
                        </div>
                      </div>

                      <div v-if="runtimeCategoryLogItems.length === 0" class="utility-modal__empty">当前角色暂无运行日志。</div>
                      <div v-else class="utility-log-layout">
                        <div class="utility-log-list">
                          <button
                            v-for="log in runtimeCategoryLogItems"
                            :key="log.id"
                            type="button"
                            class="utility-log-item"
                            :class="{ 'is-active': selectedRuntimeLog?.id === log.id }"
                            @click="handleUtilityLogSelect(log)"
                          >
                            <div class="utility-log-item__head">
                              <div class="utility-log-item__meta">
                                <strong>{{ log.method }}</strong>
                                <span class="utility-log-kind" :data-kind="getRuntimeLogCategory(log)">{{ getRuntimeLogCategoryLabel(log) }}</span>
                              </div>
                              <span class="utility-log-status" :data-tone="getLogStatusTone(log.responseStatus)">{{ log.responseStatus }}</span>
                            </div>
                            <p>{{ getLogRequestUrl(log) }}</p>
                            <small>{{ formatDateTime(log.createdAt) }} · 耗时 {{ formatDurationLabel(log.duration) }}</small>
                          </button>
                        </div>
                      </div>
                    </template>

                    <template v-else>
                      <div v-if="errorAnalysisSummaries.length === 0" class="utility-modal__empty">当前角色暂无错误日志。</div>
                      <div v-else class="utility-log-layout">
                        <div class="utility-error-list">
                          <button
                            v-for="summary in errorAnalysisSummaries"
                            :key="summary.key"
                            type="button"
                            class="utility-error-item"
                            :class="{ 'is-active': selectedErrorSummary?.key === summary.key }"
                            @click="handleUtilityErrorSummarySelect(summary.key)"
                          >
                            <div class="utility-error-item__head">
                              <strong>{{ summary.title }}</strong>
                              <span>{{ summary.count }} 次</span>
                            </div>
                            <p>{{ summary.latestLog.method }} {{ summary.latestLog.path || summary.latestLog.endpoint || "/" }}</p>
                            <small>最近 {{ formatDateTime(summary.latestAt) }}</small>
                          </button>
                        </div>
                      </div>
                    </template>
                  </template>
                </div>

                <div v-else-if="isHistoryPanelActive" class="chat-settings-sidebar__body chat-settings-sidebar__body--history">
                  <p v-if="utilityModalNotice" class="utility-modal__notice">{{ utilityModalNotice }}</p>
                  <p v-if="utilityModalError" class="utility-modal__error">{{ utilityModalError }}</p>

                  <div v-if="utilityModalLoading" class="utility-modal__empty">正在加载数据...</div>
                  <div v-else-if="!activeAgent" class="utility-modal__empty">请选择用户后查看聊天记录。</div>
                  <template v-else>
                    <p class="chat-settings-history-section-title">对话记录</p>
                    <div v-if="chatRelatedHistoryRecords.length === 0" class="utility-modal__empty">当前 Agent 暂无关联会话记录。</div>
                    <div v-else>
                      <div class="utility-history-filter related-schedule-filter" role="tablist" aria-label="对话记录渠道筛选">
                        <button
                          v-for="option in relatedHistoryChannelFilterOptions"
                          :key="`related-history-channel-filter-${option.id}`"
                          class="related-schedule-filter__button"
                          :class="{ 'is-active': effectiveRelatedHistoryChannelFilter === option.id }"
                          type="button"
                          @click="relatedHistoryChannelFilter = option.id"
                        >
                          {{ option.label }}
                          <em>{{ option.count }}</em>
                        </button>
                      </div>
                      <div v-if="filteredChatRelatedHistoryRecords.length === 0" class="utility-modal__empty">当前筛选暂无关联会话记录。</div>
                      <div v-else class="utility-history-list">
                        <article
                          v-for="record in filteredChatRelatedHistoryRecords"
                          :key="record.id"
                          class="utility-history-card utility-history-card--clickable"
                          :class="{ 'is-active': isRelatedHistoryRecordActive(record) }"
                          role="button"
                          tabindex="0"
                          @click="handleRelatedHistoryRecordSelect(record)"
                          @keydown.enter.prevent="handleRelatedHistoryRecordSelect(record)"
                          @keydown.space.prevent="handleRelatedHistoryRecordSelect(record)"
                        >
                          <div class="utility-history-card__head">
                            <strong>{{ resolveRelatedHistoryScopeLabel(record) }}{{ isRelatedHistoryRecordActive(record) ? "（当前）" : "" }}</strong>
                            <small>{{ formatDateTime(record.updatedAt) }}</small>
                          </div>
                          <p>{{ record.preview }}</p>
                          <div class="utility-history-card__foot utility-history-card__foot--related">
                            <span class="utility-history-card__conversation-id" :title="resolveRelatedHistoryConversationId(record)">
                              对话ID {{ resolveRelatedHistoryConversationId(record) }}
                            </span>
                            <span class="utility-history-card__message-count">{{ record.messageCount }} 条消息</span>
                          </div>
                        </article>
                      </div>
                    </div>
                  </template>
                </div>

                <div v-else-if="activeAgent && isGroupInfoPanelActive" class="chat-settings-sidebar__body chat-settings-sidebar__body--group">
                  <section class="chat-group-info-card">
                    <header class="chat-group-info-card__header">
                      <div class="chat-group-info-card__header-main">
                        <strong>{{ activeConversationGroup?.name || stripRoleLabel(activeAgent.displayName) }}</strong>
                        <small>{{ activeConversationGroupMemberCount }} 位成员</small>
                      </div>
                      <button class="chat-group-info-card__close" type="button" aria-label="关闭群聊信息" @click="closeAgentSettingsPanel">
                        ×
                      </button>
                    </header>

                    <section class="chat-group-info-card__section">
                      <div class="chat-group-info-card__section-head">
                        <h5>群聊名称</h5>
                        <button class="chat-group-info-card__edit" type="button" aria-label="修改群聊名称" @click="openConversationGroupRenameModal">
                          <ControlIcon name="edit" />
                        </button>
                      </div>
                      <p class="chat-group-info-card__value">{{ activeConversationGroup?.name || "未命名群聊" }}</p>
                    </section>

                    <section class="chat-group-info-card__section">
                      <h5>负责人</h5>
                      <p class="chat-group-info-card__value chat-group-info-card__value--owner">
                        <span class="chat-group-info-card__owner-dot" aria-hidden="true"></span>
                        <span>{{ activeConversationGroupOwner ? stripRoleLabel(activeConversationGroupOwner.displayName) : "未设置" }}</span>
                      </p>
                    </section>

                    <section v-if="activeConversationGroup" class="chat-group-info-card__section">
                      <h5>群组策略</h5>
                      <div class="chat-group-policy-grid">
                        <label class="chat-group-policy-field">
                          <span>groupPolicy</span>
                          <select
                            :value="activeConversationGroup.groupPolicy"
                            @change="handleActiveConversationGroupPolicyChange(($event.target as HTMLSelectElement).value)"
                          >
                            <option value="allowlist">allowlist（按 allowFrom 放行）</option>
                            <option value="open">open（全部来源可触发）</option>
                          </select>
                        </label>

                        <label class="chat-group-policy-check">
                          <input
                            type="checkbox"
                            :checked="activeConversationGroup.requireMention"
                            @change="handleActiveConversationGroupRequireMentionChange(($event.target as HTMLInputElement).checked)"
                          />
                          <span>requireMention：仅 @成员 或 activation 命令触发回复</span>
                        </label>

                        <label class="chat-group-policy-field">
                          <span>allowFrom（逗号分隔，支持 `*` 与前缀 `*`）</span>
                          <input
                            type="text"
                            :value="activeConversationGroupAllowFromText"
                            placeholder="例如：*, channel:feishu:*"
                            @change="handleActiveConversationGroupAllowFromChange(($event.target as HTMLInputElement).value)"
                          />
                        </label>

                        <div class="chat-group-policy-inline">
                          <label class="chat-group-policy-field">
                            <span>activation 命令</span>
                            <input
                              type="text"
                              maxlength="32"
                              :value="activeConversationGroup.activationCommand"
                              placeholder="/activation"
                              @change="handleActiveConversationGroupActivationCommandChange(($event.target as HTMLInputElement).value)"
                            />
                          </label>
                          <label class="chat-group-policy-field">
                            <span>historyLimit（条）</span>
                            <input
                              type="number"
                              :min="CHAT_CONVERSATION_GROUP_MIN_HISTORY_LIMIT"
                              :max="CHAT_CONVERSATION_GROUP_MAX_HISTORY_LIMIT"
                              :value="activeConversationGroup.historyLimit"
                              @change="handleActiveConversationGroupHistoryLimitChange(($event.target as HTMLInputElement).value)"
                            />
                          </label>
                        </div>
                      </div>
                    </section>

                    <section class="chat-group-info-card__section">
                      <h5>群成员</h5>
                      <div v-if="activeConversationGroupMembers.length > 0" class="chat-group-info-member-grid">
                        <article
                          v-for="member in activeConversationGroupMembers"
                          :key="`group-info-member-${member.agentId}`"
                          class="chat-group-info-member"
                        >
                          <div class="chat-group-info-member__avatar">
                            <img
                              v-if="getAgentAvatarUrl(member)"
                              :src="getAgentAvatarUrl(member) ?? undefined"
                              :alt="`${stripRoleLabel(member.displayName)} 头像`"
                              loading="lazy"
                              decoding="async"
                            />
                            <span v-else>{{ getAgentInitial(member) }}</span>
                            <span v-if="isActiveConversationGroupOwner(member.agentId)" class="chat-group-info-member__owner-badge" title="负责人">
                              <ControlIcon name="bolt" />
                            </span>
                          </div>
                          <strong :title="stripRoleLabel(member.displayName)">{{ stripRoleLabel(member.displayName) }}</strong>
                          <small>{{ resolveAgentChannelDisplayLabel(member) }}</small>
                        </article>
                      </div>
                      <p v-else class="chat-group-info-card__empty">该群聊暂无成员。</p>
                    </section>
                  </section>
                </div>

                <div v-else-if="activeAgent" class="chat-settings-sidebar__body">
                  <div class="chat-settings-agent-card">
                    <div class="chat-settings-agent-card__head">
                      <div class="chat-settings-agent-card__avatar">{{ getAgentInitial(activeAgent) }}</div>
                      <div class="chat-settings-agent-card__identity">
                        <strong>{{ stripRoleLabel(activeAgent.displayName) }}</strong>
                        <div class="chat-settings-chip-row">
                          <span class="chat-settings-status-chip" :data-tone="activeAgent.statusTone">{{ getAgentStatusLabel(activeAgent) }}</span>
                          <span class="chat-settings-soft-chip">{{ getAgentScheduledLabel(activeAgent) }}</span>
                        </div>
                      </div>
                      <button class="chat-settings-agent-card__close" type="button" aria-label="关闭设置" @click="closeAgentSettingsPanel">×</button>
                    </div>

                    <section class="chat-settings-resource-quick">
                      <div class="chat-settings-resource-grid">
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('model')">
                          <span class="chat-settings-resource-action__icon">模</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">模型 {{ activeAgent.model || "未配置" }}</span>
                            <span class="chat-settings-resource-action__sub">编辑基础 URL、模型 ID、协议与 API 密钥</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('memory')">
                          <span class="chat-settings-resource-action__icon">记</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">记忆</span>
                            <span class="chat-settings-resource-action__sub">查看与编辑记忆文件</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('skills')">
                          <span class="chat-settings-resource-action__icon">技</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">技能库</span>
                            <span class="chat-settings-resource-action__sub">启用或禁用技能能力</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('tools')">
                          <span class="chat-settings-resource-action__icon">工</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">工具权限 {{ getAgentToolsEnabledLabel(activeAgent) }}</span>
                            <span class="chat-settings-resource-action__sub">配置可用工具权限</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('channel')">
                          <span class="chat-settings-resource-action__icon">频</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">频道 {{ resolveAgentChannelDisplayLabel(activeAgent) }}</span>
                            <span class="chat-settings-resource-action__sub">管理渠道账号绑定</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                        <button class="chat-settings-resource-action" type="button" @click="openRelatedResource('schedule')">
                          <span class="chat-settings-resource-action__icon">排</span>
                          <span class="chat-settings-resource-action__content">
                            <span class="chat-settings-resource-action__main">定时任务</span>
                            <span class="chat-settings-resource-action__sub">查看与调整定时任务</span>
                          </span>
                          <span class="chat-settings-resource-action__arrow">›</span>
                        </button>
                      </div>
                    </section>

                    <dl class="chat-settings-list">
                      <div class="chat-settings-list__row chat-settings-list__row--model">
                        <dt>模型</dt>
                        <dd>
                          <button class="chat-settings-model-trigger" type="button" @click="openRelatedResource('model')">
                            <span class="chat-settings-model-trigger__value">{{ activeAgent.model || "—" }}</span>
                            <span class="chat-settings-model-trigger__hint">修改配置 ›</span>
                          </button>
                        </dd>
                      </div>
                      <div class="chat-settings-list__row">
                        <dt>员工 Id</dt>
                        <dd>
                          <div class="chat-settings-copy-field">
                            <span class="chat-settings-copy-field__value">{{ activeAgent.agentId || "—" }}</span>
                            <button
                              class="chat-settings-copy-field__button"
                              type="button"
                              title="复制员工 Id"
                              aria-label="复制员工 Id"
                              @click="handleCopyActiveAgentId"
                            >
                              <ControlIcon name="copy" />
                            </button>
                          </div>
                        </dd>
                      </div>
                      <div class="chat-settings-list__row">
                        <dt>工具权限</dt>
                        <dd>{{ activeAgent.toolsProfile || "—" }}</dd>
                      </div>
                      <div class="chat-settings-list__row">
                        <dt>工作目录</dt>
                        <dd>{{ activeAgent.workspace || "—" }}</dd>
                      </div>
                      <div class="chat-settings-list__row">
                        <dt>所属渠道</dt>
                        <dd>{{ resolveAgentChannelDisplayLabel(activeAgent, "—") }}</dd>
                      </div>
                      <div class="chat-settings-list__row">
                        <dt>{{ getAgentCurrentWorkLabel(activeAgent) }}</dt>
                        <dd>
                          <div class="chat-settings-preview">
                            <p class="chat-settings-preview__text">{{ getAgentCurrentWork(activeAgent) }}</p>
                            <button
                              class="chat-settings-preview__expand"
                              type="button"
                              :title="`展开${getAgentCurrentWorkLabel(activeAgent)}`"
                              :aria-label="`展开${getAgentCurrentWorkLabel(activeAgent)}`"
                              @click="openChatSettingsTextPreviewModal(getAgentCurrentWorkLabel(activeAgent), getAgentCurrentWork(activeAgent))"
                            >
                              <ControlIcon name="expand" />
                            </button>
                          </div>
                        </dd>
                      </div>
                    </dl>

                    <section class="chat-settings-output">
                      <h5>最近产出</h5>
                      <div class="chat-settings-recent-output">
                        <div class="chat-settings-preview chat-settings-preview--boxed">
                          <p class="chat-settings-preview__text">{{ getAgentRecentOutput(activeAgent) }}</p>
                          <button
                            class="chat-settings-preview__expand"
                            type="button"
                            title="展开最近产出"
                            aria-label="展开最近产出"
                            @click="openChatSettingsTextPreviewModal('最近产出', getAgentRecentOutput(activeAgent))"
                          >
                            <ControlIcon name="expand" />
                          </button>
                        </div>
                      </div>
                    </section>
                  </div>
                </div>

                  <div v-else class="chat-settings-sidebar__empty">请选择员工后打开设置。</div>
                </aside>
              </transition>

            </div>

            <footer class="chat-window__composer">
              <div
                class="composer-panel"
                :class="{ 'is-drag-over': isChatComposerDragOver }"
                @dragenter="handleChatComposerDragEnter"
                @dragover.prevent="handleChatComposerDragOver"
                @dragleave="handleChatComposerDragLeave"
                @drop.prevent="handleChatComposerDrop"
              >
                <div v-if="chatAttachments.length > 0" class="composer-attachments">
                  <span v-for="attachment in chatAttachments" :key="attachment.id" class="composer-attachment-chip" :title="attachment.name">
                    <span class="composer-attachment-chip__name">{{ attachment.name }}</span>
                    <small>{{ formatAttachmentSize(attachment.size) }}</small>
                    <button type="button" aria-label="移除附件" @click="removeChatAttachment(attachment.id)">
                      ×
                    </button>
                  </span>
                </div>
                <div class="composer-input-shell">
                  <textarea
                    ref="chatComposerInputRef"
                    v-model="chatInput"
                    rows="3"
                    :placeholder="chatComposerPlaceholder"
                    :disabled="!activeAgent || isVoiceRecording || isVoiceRecordingProcessing"
                    @input="handleChatComposerInput"
                    @click="handleChatComposerCursorActivity"
                    @keyup="handleChatComposerCursorActivity"
                    @blur="handleChatComposerBlur"
                    @keydown="handleChatComposerKeydown"
                    @paste="handleChatComposerPaste"
                  />
                  <div v-if="isChatMentionDropdownVisible" class="composer-mention-panel" data-no-window-drag>
                    <div v-if="chatMentionCandidates.length === 0" class="composer-mention-empty">没有匹配成员</div>
                    <button
                      v-for="(candidate, index) in chatMentionCandidates"
                      :key="`composer-mention-${candidate.agentId}`"
                      class="composer-mention-item"
                      :class="{ 'is-active': index === chatMentionActiveIndex }"
                    type="button"
                    @mouseenter="chatMentionActiveIndex = index"
                    @mousedown.prevent="applyChatMentionCandidate(candidate)"
                  >
                    <span class="composer-mention-item__avatar" :class="{ 'is-all': candidate.isAll }">
                      <img
                        v-if="candidate.avatarUrl"
                        :src="candidate.avatarUrl"
                        :alt="`${candidate.displayName} 头像`"
                        loading="lazy"
                        decoding="async"
                      />
                      <span v-else>{{ candidate.isAll ? "全" : candidate.displayName.slice(0, 1).toUpperCase() }}</span>
                    </span>
                    <span class="composer-mention-item__main">
                      <strong>{{ candidate.displayName }}</strong>
                    </span>
                  </button>
                </div>
                </div>
                <p v-if="chatComposerError" class="composer-error">{{ chatComposerError }}</p>
                <div class="composer-meta">
                  <div class="composer-meta__left">
                    <button
                      class="composer-input-action"
                      type="button"
                      title="附件"
                      aria-label="添加附件"
                      :disabled="!activeAgent || isSending || isVoiceRecording || isVoiceRecordingProcessing"
                      @click="triggerChatAttachmentPicker"
                    >
                      <ControlIcon name="plus" />
                    </button>
                    <button
                      class="composer-model-chip composer-model-chip--trigger"
                      type="button"
                      :disabled="!activeAgent"
                      @click="openRelatedResource('model')"
                    >
                      <span class="composer-model-chip__label">{{ activeAgent?.model || "DragonClaw" }}</span>
                      <ControlIcon name="chevron-down" />
                    </button>
                  </div>
                  <div class="composer-meta__right">
                    <button
                      class="composer-new-chat"
                      type="button"
                      title="新建聊天"
                      aria-label="新建聊天"
                      :disabled="!activeAgent || isSending || isVoiceRecording || isVoiceRecordingProcessing"
                      @click="handleNewChat"
                    >
                      <ControlIcon name="chat-plus" />
                      <span>新建聊天</span>
                    </button>
                    <button
                      class="composer-input-action composer-voice-action"
                      :class="{ 'is-recording': isVoiceRecording, 'is-processing': isVoiceRecordingProcessing }"
                      type="button"
                      :title="voiceActionButtonLabel"
                      :aria-label="voiceActionButtonLabel"
                      :disabled="!activeAgent || isSending || isSubmittingChat || isVoiceRecordingProcessing"
                      @click="handleVoiceSendClick"
                    >
                      <ControlIcon name="mic" />
                    </button>
                    <button
                      class="composer-send"
                      type="button"
                      :disabled="!activeAgent || isSending || isVoiceRecording || isVoiceRecordingProcessing || (!chatInput.trim() && chatAttachments.length === 0)"
                      @click="submitChat"
                    >
                      <ControlIcon name="send" />
                    </button>
                  </div>
                </div>
                <input
                  ref="chatAttachmentInputRef"
                  class="composer-file-input"
                  type="file"
                  multiple
                  :accept="CHAT_COMPOSER_FILE_ACCEPT"
                  @change="handleChatAttachmentInputChange"
                />
              </div>
            </footer>
          </section>
        </template>
        </template>

        <main v-else class="module-board" :class="{ 'module-board--dashboard': activeSection === 'dashboard' }">
          <template v-if="activeSection === 'dashboard'">
            <header
              class="module-board__header module-board__header--dashboard"
              @mousedown.left="handleRegionMouseDown"
              @dblclick="handleSidebarDoubleClick"
            >
              <div>
                <h2>仪表盘</h2>
                <p>OpenClaw 运行状态总览 · 最近刷新 {{ formatDateTime(dashboardLastRefreshedAt) }}</p>
              </div>
              <div class="dashboard-toolbar" data-no-window-drag>
                <span class="dashboard-health-badge" :data-tone="dashboardHealthBadge.tone">{{ dashboardHealthBadge.label }}</span>
                <button class="dashboard-toolbar__refresh" type="button" :disabled="isDashboardRefreshing" @click="refreshDashboardData()">
                  {{ isDashboardRefreshing ? "刷新中..." : "刷新状态" }}
                </button>
              </div>
            </header>

            <section class="dashboard-section">
              <header class="dashboard-section__header">
                <div>
                  <strong>统计信息</strong>
                  <p>保留原控制台核心指标，集中展示平台、调用、网关和 Token 情况。</p>
                </div>
              </header>

              <div class="dashboard-stats-grid">
                <article v-for="card in dashboardLegacyStatCards" :key="card.id" class="dashboard-metric-card dashboard-metric-card--compact" :data-tone="card.tone">
                  <span class="dashboard-metric-card__label">{{ card.label }}</span>
                  <strong>{{ card.value }}</strong>
                </article>
              </div>
            </section>

            <section class="dashboard-section">
              <header class="dashboard-section__header">
                <div>
                  <strong>当前状态</strong>
                  <p>聚焦今天最常看的运行状态，避免在多个页签之间来回切换。</p>
                </div>
              </header>

              <div class="dashboard-status-grid">
                <article v-for="card in dashboardStatusCards" :key="card.id" class="dashboard-status-card" :data-tone="card.tone">
                  <span class="dashboard-metric-card__label">{{ card.label }}</span>
                  <strong>{{ card.value }}</strong>
                  <p>{{ card.detail }}</p>
                </article>
              </div>
            </section>

            <section class="dashboard-activity-panel">
              <header class="dashboard-activity-panel__header">
                <div>
                  <strong>最近活动</strong>
                  <p>实时日志 {{ dashboardRecentActivities.length }} 条</p>
                </div>
              </header>

              <div v-if="dashboardRecentActivities.length === 0" class="dashboard-activity-panel__empty">暂无活动记录。</div>
              <div v-else class="dashboard-activity-list">
                <article v-for="activity in dashboardRecentActivities" :key="activity.id" class="dashboard-activity-item">
                  <span class="dashboard-activity-item__time">{{ activity.timeLabel }}</span>
                  <span class="dashboard-activity-item__tag" :data-tone="activity.tone">{{ activity.tag }}</span>
                  <p>{{ activity.summary }}</p>
                </article>
              </div>
            </section>

            <p v-if="dashboardRefreshError" class="module-board__error">{{ dashboardRefreshError }}</p>
            <p class="module-board__detail">{{ dashboardDetailText }}</p>
          </template>

          <template v-else>
            <header class="module-board__header" @mousedown.left="handleRegionMouseDown" @dblclick="handleSidebarDoubleClick">
              <h2>{{ getModuleTitle(activeSection) }}</h2>
              <p>{{ missionStatement }}</p>
            </header>

            <div v-if="activeSection === 'tasks'" class="module-board__metrics">
              <article>
                <span>任务总数</span>
                <strong>{{ taskSummary.total }}</strong>
              </article>
              <article>
                <span>待办</span>
                <strong>{{ taskSummary.todo }}</strong>
              </article>
              <article>
                <span>进行中</span>
                <strong>{{ taskSummary.doing }}</strong>
              </article>
              <article>
                <span>回顾</span>
                <strong>{{ taskSummary.review }}</strong>
              </article>
              <article>
                <span>已完成</span>
                <strong>{{ taskSummary.done }}</strong>
              </article>
              <article>
                <span>已取消</span>
                <strong>{{ taskSummary.cancelled }}</strong>
              </article>
            </div>

            <template v-if="activeSection === 'recruitment'">
              <section class="module-surface recruitment-surface">
                <section class="recruitment-surface__top" aria-label="角色筛选区">
                  <div class="recruitment-division-filter" role="tablist" aria-label="角色分类筛选">
                    <button
                      v-for="option in recruitmentDivisionFilterOptions"
                      :key="option.id"
                      class="recruitment-division-filter__item"
                      :class="{ active: recruitmentDivisionFilter === option.id }"
                      :title="`${option.visibleCount} / ${option.totalCount} 个角色`"
                      role="tab"
                      :aria-selected="recruitmentDivisionFilter === option.id"
                      type="button"
                      @click="selectRecruitmentDivisionFilter(option.id)"
                    >
                      {{ option.label }}
                    </button>
                    <input
                      v-model="recruitmentKeyword"
                      class="module-surface__search recruitment-division-filter__search"
                      type="search"
                      placeholder="搜索角色 / 分组 / 领域"
                    />
                  </div>
                </section>
                <p v-if="recruitmentActionNotice" class="module-surface__hint module-surface__hint--notice">{{ recruitmentActionNotice }}</p>
                <section class="recruitment-linked-strip" aria-label="已加入聊天列表">
                  <header class="recruitment-linked-strip__header">
                    <strong>已加入聊天列表</strong>
                    <div class="recruitment-linked-strip__meta">
                      <small v-if="recruitmentLinkedRoleAgents.length > 0">{{ recruitmentLinkedRoleAgents.length }} 个</small>
                      <small v-else>点击角色卡片「+ 对话」后会自动出现在这里</small>
                    </div>
                  </header>
                  <p v-if="recruitmentLinkedRoleAgents.length === 0" class="recruitment-linked-strip__empty">
                    还没有从角色库添加数字员工。点击任意角色卡片的「+ 对话」后，会自动加入左侧聊天列表，并在这里展示。
                  </p>
                  <div v-else class="recruitment-linked-strip__list">
                    <article
                      v-for="item in recruitmentLinkedRoleAgents"
                      :key="`recruitment-linked-${item.agentId}`"
                      class="recruitment-linked-chip"
                    >
                      <span class="recruitment-linked-chip__avatar" :style="getRecruitmentRoleAvatarStyle(item.role)">
                        {{ getRecruitmentRoleAvatarLabel(item.role) }}
                      </span>
                      <span class="recruitment-linked-chip__text">
                        <strong>{{ stripRoleLabel(item.displayName) }}</strong>
                        <small>{{ item.groupTitleZh || item.divisionTitleZh }}</small>
                      </span>
                    </article>
                  </div>
                </section>
                <section class="recruitment-create-division" aria-label="新增员工入口">
                  <header class="recruitment-create-division__header">
                    <strong>新增员工</strong>
                  </header>
                  <div class="recruitment-role-grid recruitment-role-grid--create">
                    <article class="recruitment-agent-card recruitment-agent-card--new recruitment-agent-card--new-standalone">
                      <button class="recruitment-agent-card__new-button" type="button" @click="openCreateEmployeeModal">
                        <span class="recruitment-agent-card__new-plus">+</span>
                        <strong class="recruitment-agent-card__new-title">新增员工</strong>
                        <p class="recruitment-agent-card__new-hint">创建一个新的员工角色卡片</p>
                      </button>
                    </article>
                  </div>
                </section>
                <div v-if="filteredRecruitmentDivisions.length === 0" class="module-empty">未找到匹配角色，请调整搜索词。</div>
                <div v-else class="recruitment-division-list">
                  <section v-for="division in filteredRecruitmentDivisions" :key="division.id" class="recruitment-division">
                    <header class="recruitment-division__header">
                      <strong>{{ division.titleZh }}</strong>
                      <small>{{ division.count }} 个</small>
                    </header>
                    <div class="recruitment-role-grid">
                      <article
                        v-for="item in division.groups.flatMap((group) => group.roles.map((role) => ({ role, groupTitleZh: group.titleZh })))"
                        :key="item.role.id"
                        class="recruitment-agent-card recruitment-agent-card--clickable"
                        role="button"
                        tabindex="0"
                        @click="handleRecruitmentOpenRoleDetail(item.role)"
                        @keydown.enter.prevent="handleRecruitmentOpenRoleDetail(item.role)"
                        @keydown.space.prevent="handleRecruitmentOpenRoleDetail(item.role)"
                      >
                        <header class="recruitment-agent-card__header">
                          <div class="recruitment-agent-card__avatar" :style="getRecruitmentRoleAvatarStyle(item.role)">
                            {{ getRecruitmentRoleAvatarLabel(item.role) }}
                          </div>
                          <span class="recruitment-agent-card__division">{{ item.groupTitleZh || division.titleZh }}</span>
                        </header>
                        <strong class="recruitment-agent-card__title">{{ item.role.nameZh }}</strong>
                        <p class="recruitment-agent-card__desc">{{ item.role.workflowZh }}</p>
                        <div class="recruitment-agent-card__actions">
                          <button class="recruitment-agent-card__chat" type="button" @click.stop="handleRecruitRole(item.role)">+ 对话</button>
                          <button class="recruitment-agent-card__link" type="button" @click.stop="handleRecruitmentCreateTeam(item.role)">
                            创建团队
                          </button>
                        </div>
                      </article>
                    </div>
                  </section>
                </div>
              </section>
              <p class="module-board__detail">角色库来源：`src/agent-data/zh/README.md`。</p>
            </template>

            <template v-else-if="activeSection === 'skills'">
              <section class="module-surface skill-market-surface">
                <div class="module-surface__toolbar module-surface__toolbar--skills-top">
                  <input
                    v-model="skillMarketSearch"
                    class="module-surface__search"
                    type="search"
                    placeholder="搜索技能名称、描述或标签"
                    @keydown.enter.prevent="handleSkillMarketSearchSubmit"
                  />
                  <span class="module-surface__meta">显示 {{ skillMarketMetaVisible }} / {{ skillMarketMetaTotal }} 个技能</span>
                </div>
                <div class="skill-market-category-row" role="tablist" aria-label="技能分类">
                  <button
                    v-for="category in skillMarketCategories"
                    :key="`skill-market-${category.id}`"
                    class="skill-market-category-chip"
                    :class="{ active: activeSkillMarketCategory === category.id }"
                    :title="category.hint"
                    type="button"
                    @click="handleSkillMarketCategorySwitch(category.id)"
                  >
                    {{ category.label }}
                  </button>
                </div>
                <div class="module-surface__toolbar module-surface__toolbar--skills-actions">
                  <select
                    class="module-surface__select"
                    :value="skillMarketSortBy"
                    @change="handleSkillMarketSortChange(($event.target as HTMLSelectElement).value as SkillMarketSortBy)"
                  >
                    <option value="score">综合评分</option>
                    <option value="downloads">下载量</option>
                    <option value="stars">收藏数</option>
                  </select>
                  <button class="module-surface__button" type="button" :disabled="skillMarketLoading" @click="handleSkillMarketSearchSubmit">
                    {{ skillMarketLoading ? "加载中..." : "搜索" }}
                  </button>
                </div>
                <p class="module-surface__hint">{{ skillMarketSummaryText }}</p>
                <p v-if="skillMarketActionNotice" class="module-surface__hint module-surface__hint--notice">{{ skillMarketActionNotice }}</p>

                <div v-if="skillMarketLoading" class="module-empty">正在加载技能市场数据...</div>
                <div v-else-if="skillMarketError" class="module-empty">{{ skillMarketError }}</div>
                <div v-else-if="pagedSkillMarketSkills.length === 0" class="module-empty">没有匹配的技能，请调整关键词或分类。</div>
                <div v-else class="skill-market-grid">
                  <article v-for="skill in pagedSkillMarketSkills" :key="skill.slug || skill.name" class="skill-market-card-v2">
                    <div class="skill-market-card-v2__header">
                      <div class="skill-market-card-v2__avatar">{{ getSkillMarketInitial(skill.name) }}</div>
                      <div class="skill-market-card-v2__title">
                        <strong>{{ skill.name }}</strong>
                        <p>{{ getSkillMarketDescription(skill) }}</p>
                      </div>
                    </div>
                    <div class="skill-market-card-v2__meta">
                      <span>↓ {{ formatSkillMarketCount(skill.downloads) }}</span>
                      <span>☆ {{ formatSkillMarketCount(skill.stars) }}</span>
                      <span>{{ formatSkillMarketVersion(skill.version) }}</span>
                    </div>
                    <div class="skill-market-card-v2__tags">
                      <span>{{ getSkillMarketCategoryLabel(skill.category) }}</span>
                      <span v-if="skill.ownerName">@{{ skill.ownerName }}</span>
                    </div>
                    <div class="skill-market-card-v2__actions">
                      <button class="skill-market-card-v2__action skill-market-card-v2__action--ghost" type="button" @click="openSkillMarketDetailModal(skill)">
                        查看详情
                      </button>
                      <button
                        class="skill-market-card-v2__action"
                        type="button"
                        :disabled="!canInstallSkillMarketSkill(skill) || isSkillMarketSkillInstalling(skill)"
                        @click="installSkillMarketSkill(skill)"
                      >
                        {{ isSkillMarketSkillInstalling(skill) ? "安装中..." : "安装技能" }}
                      </button>
                    </div>
                  </article>
                </div>

                <div v-if="!skillMarketLoading && !skillMarketError && skillMarketCurrentTotalPages > 1" class="skill-market-pagination">
                  <button class="skill-market-pagination__button" type="button" :disabled="!skillMarketCanPrevPage" @click="goPrevSkillMarketPage">
                    上一页
                  </button>
                  <button
                    v-for="page in skillMarketPageNumbers"
                    :key="`skill-page-${page}`"
                    class="skill-market-pagination__page"
                    :class="{ active: page === skillMarketPage }"
                    type="button"
                    @click="goToSkillMarketPage(page)"
                  >
                    {{ page }}
                  </button>
                  <button class="skill-market-pagination__button" type="button" :disabled="!skillMarketCanNextPage" @click="goNextSkillMarketPage">
                    下一页
                  </button>
                </div>
              </section>
              <p class="module-board__detail">数据来源：技能市场 API（可通过 Runtime fallback）。</p>
            </template>

            <template v-else-if="activeSection === 'market'">
              <section class="module-surface marketplace-surface">
                <div class="marketplace-toggle" role="tablist" aria-label="商城类型">
                  <button
                    v-for="tab in marketTabs"
                    :key="tab.id"
                    class="marketplace-toggle__button"
                    :class="{ active: activeMarketTab === tab.id }"
                    type="button"
                    role="tab"
                    :aria-selected="activeMarketTab === tab.id"
                    @click="activeMarketTab = tab.id"
                  >
                    {{ tab.label }}
                  </button>
                </div>

                <div class="marketplan-grid">
                  <article v-for="plan in activeMarketPlans" :key="`${activeMarketTab}-${plan.id}`" class="marketplan-card">
                    <strong class="marketplan-card__title">{{ plan.title }}</strong>
                    <p class="marketplan-card__price">
                      <span class="marketplan-card__price-currency">¥</span>
                      <span class="marketplan-card__price-value">{{ plan.price }}</span>
                    </p>
                    <p class="marketplan-card__description">{{ plan.description }}</p>
                    <p class="marketplan-card__points">{{ formatMarketPoints(plan.points) }} {{ plan.pointsLabel }}</p>
                    <button class="marketplan-card__action" type="button">{{ plan.actionLabel }}</button>
                  </article>
                </div>
              </section>
              <p class="module-board__detail">商城模块提供会员套餐与智慧流程。</p>
            </template>

            <template v-else-if="activeSection === 'tasks'">
              <section class="module-surface task-module-surface">
                <p v-if="taskModuleNotice" class="module-surface__hint module-surface__hint--notice">{{ taskModuleNotice }}</p>
                <p v-if="taskModuleError" class="module-surface__hint module-surface__hint--error">{{ taskModuleError }}</p>

                <template v-if="taskModuleView === 'projects'">
                  <div class="task-project-toolbar">
                    <input
                      v-model="taskProjectInput"
                      class="module-surface__search"
                      type="text"
                      placeholder="输入项目名称，例如：发布计划"
                      @keydown.enter.prevent="handleCreateTaskProject"
                    />
                    <button class="module-surface__button" type="button" @click="handleCreateTaskProject">添加项目</button>
                  </div>

                  <div class="task-project-grid">
                    <button
                      v-for="project in taskProjectCards"
                      :key="project.name"
                      type="button"
                      class="task-project-card"
                      :class="{ 'task-project-card--default': project.isDefault }"
                      @click="openTaskProjectBoard(project.name)"
                    >
                      <div class="task-project-card__head">
                        <strong>{{ project.name }}</strong>
                        <span>{{ project.count }} 项</span>
                      </div>
                      <p>
                        进行中 {{ project.activeCount }} · 回顾 {{ project.reviewCount }} · 完成 {{ project.doneCount }}
                      </p>
                      <small>
                        {{ project.updatedAt ? `最近更新 ${formatDateTime(project.updatedAt)}` : "暂无任务，点击进入看板开始创建。" }}
                      </small>
                    </button>
                  </div>
                </template>

                <template v-else>
                  <div class="task-board-topbar">
                    <button class="task-board-back" type="button" @click="openTaskProjectsHome">← 返回项目</button>
                    <div>
                      <strong>{{ activeTaskProjectName }}</strong>
                      <p>{{ activeProjectTaskItems.length }} 项任务 · 参照 vibe-kanban 五列流转</p>
                    </div>
                  </div>

                  <div class="task-board-creator">
                    <input
                      v-model="taskDraftTitle"
                      type="text"
                      class="task-board-creator__input task-board-creator__input--title"
                      placeholder="新增任务标题"
                      @keydown.enter.prevent="handleCreateTaskInActiveProject"
                    />
                    <input v-model="taskDraftSummary" type="text" class="task-board-creator__input" placeholder="任务摘要（可选）" />
                    <input v-model="taskDraftOwner" type="text" class="task-board-creator__input" placeholder="负责人（默认 Commander）" />
                    <select v-model="taskDraftPriority" class="task-board-creator__select">
                      <option value="p0">P0 紧急</option>
                      <option value="p1">P1 常规</option>
                      <option value="p2">P2 低优先</option>
                    </select>
                    <button class="task-board-creator__button" type="button" @click="handleCreateTaskInActiveProject">添加任务</button>
                  </div>

                  <div class="task-board-columns">
                    <section
                      v-for="column in activeProjectTaskColumns"
                      :key="column.id"
                      class="task-board-column"
                      :class="{ 'is-drag-over': taskDragOverStatus === column.id }"
                      @dragover.prevent="handleTaskColumnDragOver(column.id)"
                      @drop.prevent="handleTaskColumnDrop(column.id)"
                    >
                      <header class="task-board-column__header">
                        <div>
                          <strong>{{ column.label }}</strong>
                          <span>{{ column.subtitle }}</span>
                        </div>
                        <em>{{ column.tasks.length }}</em>
                      </header>

                      <div v-if="column.tasks.length === 0" class="task-board-column__empty">{{ column.emptyText }}</div>
                      <div v-else class="task-board-column__list">
                        <article
                          v-for="task in column.tasks"
                          :key="task.id"
                          class="task-board-card"
                          :data-status="task.status"
                          :data-priority="task.priority"
                          draggable="true"
                          @dragstart="handleTaskDragStart(task.id)"
                          @dragend="handleTaskDragEnd"
                        >
                          <div class="task-board-card__head">
                            <strong>{{ task.title }}</strong>
                            <span>{{ getTaskPriorityText(task.priority) }}</span>
                          </div>
                          <p>{{ task.summary }}</p>
                          <small>{{ task.owner }} · 截止 {{ formatDateTime(task.dueAt) }} · 更新 {{ formatDateTime(task.updatedAt) }}</small>
                          <div class="task-board-card__actions">
                            <button type="button" :disabled="!getTaskPrevStatus(task.status)" @click="moveTaskToPrevStatus(task)">上一步</button>
                            <button type="button" :disabled="!getTaskNextStatus(task.status)" @click="moveTaskToNextStatus(task)">下一步</button>
                          </div>
                        </article>
                      </div>
                    </section>
                  </div>
                </template>
              </section>
              <p class="module-board__detail">任务来源：localStorage（默认项目 {{ DEFAULT_TASK_PROJECT_NAME }} 收纳未归属项目任务）。</p>
            </template>

            <template v-else>
              <p class="module-board__note">该模块将在下一步接入完整业务面板。当前优先完成聊天壳层与 Agent 会话接入。</p>
              <p class="module-board__detail">{{ staffSourceDetail }}</p>
            </template>
          </template>
        </main>
      </div>
    </div>

    <div v-if="isCreateEmployeeModalOpen" class="create-employee-modal-backdrop" @click.self="closeCreateEmployeeModal">
      <section class="create-employee-modal" role="dialog" aria-modal="true" aria-label="新增员工">
        <header class="create-employee-modal__header">
          <div>
            <strong>新增员工</strong>
            <p>只需三步，创建一个可立即开始对话的数字员工。</p>
          </div>
          <button class="create-employee-modal__close" type="button" aria-label="关闭" @click="closeCreateEmployeeModal">×</button>
        </header>

        <div class="create-employee-modal__content">
          <div class="create-employee-modal__flow">
            <div class="create-employee-stepper">
              <span class="create-employee-stepper__track" />
              <span class="create-employee-stepper__track create-employee-stepper__track--active" :style="{ width: `${createEmployeeProgressPercent}%` }" />
              <div
                v-for="step in CREATE_EMPLOYEE_STEPS"
                :key="`create-employee-step-${step.id}`"
                class="create-employee-stepper__item"
                :class="{
                  'is-active': createEmployeeStep === step.id,
                  'is-completed': createEmployeeStep > step.id
                }"
              >
                <span class="create-employee-stepper__circle">{{ step.id }}</span>
                <span class="create-employee-stepper__label">{{ step.label }}</span>
              </div>
            </div>

            <p v-if="createEmployeeError" class="create-employee-modal__status create-employee-modal__status--error">{{ createEmployeeError }}</p>
            <p v-else-if="createEmployeeNotice" class="create-employee-modal__status create-employee-modal__status--notice">{{ createEmployeeNotice }}</p>

            <div class="create-employee-modal__summary">
              <span class="create-employee-modal__summary-avatar">{{ createEmployeeAvatarLabel }}</span>
              <div class="create-employee-modal__summary-copy">
                <strong>{{ createEmployeeResolvedName }}</strong>
                <p>{{ createEmployeeRoleLabel }} · 任务 {{ createEmployeeTasks.length }} 条 · 规则 {{ createEmployeeEnabledRules.length }} 条</p>
              </div>
              <span class="create-employee-modal__summary-badge">步骤 {{ createEmployeeStep }} / 3</span>
            </div>

            <section v-if="createEmployeeStep === 1" class="create-employee-modal__step">
              <h4>为你的员工赋予身份</h4>
              <label class="create-employee-modal__field">
                <span>1. 取个好名字</span>
                <input ref="createEmployeeNameInputRef" v-model="createEmployeeNameDraft" type="text" maxlength="24" placeholder="例如：财税小专家、灵感火花" />
              </label>
              <button class="create-employee-modal__ghost" type="button" @click="handleCreateEmployeePickRandomName">随机起名</button>

              <div class="create-employee-modal__field">
                <span>2. 选择核心身份（可多选）</span>
                <div class="create-employee-identity-grid">
                  <button
                    v-for="identity in CREATE_EMPLOYEE_IDENTITY_OPTIONS"
                    :key="identity.id"
                    class="create-employee-identity-card"
                    :class="{ 'is-selected': createEmployeeSelectedIdentityIds.includes(identity.id) }"
                    type="button"
                    @click="toggleCreateEmployeeIdentity(identity.id)"
                  >
                    <span class="create-employee-identity-card__icon">{{ identity.icon }}</span>
                    <strong>{{ identity.name }}</strong>
                    <small>{{ identity.desc }}</small>
                  </button>
                </div>
              </div>

              <footer class="create-employee-modal__actions">
                <span />
                <button type="button" @click="handleCreateEmployeeNextStep">下一步：设定能力</button>
              </footer>
            </section>

            <section v-else-if="createEmployeeStep === 2" class="create-employee-modal__step">
              <h4>明确它的使命和特长</h4>
              <label class="create-employee-modal__field">
                <span>1. 一句话描述它的工作</span>
                <textarea v-model="createEmployeeMissionDraft" rows="3" placeholder="例如：帮我快速阅读长文章并提取摘要" />
              </label>

              <div class="create-employee-modal__field">
                <span>2. 添加具体任务指令</span>
                <div class="create-employee-task-examples">
                  <button
                    v-for="task in CREATE_EMPLOYEE_TASK_EXAMPLES"
                    :key="`create-employee-example-${task}`"
                    type="button"
                    @click="addCreateEmployeeTask(task)"
                  >
                    {{ task }}
                  </button>
                </div>
                <div class="create-employee-task-input-row">
                  <input
                    ref="createEmployeeTaskInputRef"
                    v-model="createEmployeeTaskInput"
                    type="text"
                    maxlength="80"
                    placeholder="输入自定义任务..."
                    @keydown="handleCreateEmployeeTaskInputKeydown"
                  />
                  <button type="button" @click="handleCreateEmployeeTaskAdd">添加</button>
                </div>
                <div class="create-employee-task-list">
                  <div v-if="createEmployeeTasks.length === 0" class="create-employee-task-list__empty">尚未添加任务指令。</div>
                  <div v-for="task in createEmployeeTasks" :key="`create-employee-task-${task}`" class="create-employee-task-chip">
                    <span>{{ task }}</span>
                    <button type="button" aria-label="移除任务" @click="removeCreateEmployeeTask(task)">×</button>
                  </div>
                </div>
              </div>

              <label class="create-employee-modal__field">
                <span>3. 设定知识范围</span>
                <select v-model="createEmployeeKnowledgeScope">
                  <option value="general">通用知识与信息</option>
                  <option value="specific">聚焦特定领域</option>
                  <option value="document">主要基于您上传的文档/数据</option>
                </select>
                <textarea
                  v-if="createEmployeeKnowledgeScope === 'specific'"
                  v-model="createEmployeeSpecificDomain"
                  rows="2"
                  maxlength="240"
                  placeholder="请说明具体领域，例如：机器学习与人工智能"
                />
              </label>

              <footer class="create-employee-modal__actions">
                <button type="button" class="is-secondary" @click="handleCreateEmployeePrevStep">上一步</button>
                <button type="button" @click="handleCreateEmployeeNextStep">下一步：调整性格</button>
              </footer>
            </section>

            <section v-else class="create-employee-modal__step">
              <h4>塑造它的沟通方式和原则</h4>
              <div class="create-employee-modal__field">
                <span>1. 沟通风格</span>
                <div class="create-employee-slider-row">
                  <label>
                    <div>
                      <small>正式</small>
                      <strong>{{ createEmployeeFormalityLabel }}</strong>
                      <small>随意</small>
                    </div>
                    <input v-model.number="createEmployeeFormality" type="range" min="0" max="100" />
                  </label>
                  <label>
                    <div>
                      <small>简洁直接</small>
                      <strong>{{ createEmployeeDetailLabel }}</strong>
                      <small>详细生动</small>
                    </div>
                    <input v-model.number="createEmployeeDetail" type="range" min="0" max="100" />
                  </label>
                </div>
                <p class="create-employee-style-preview">{{ createEmployeeStylePreviewText }}</p>
              </div>

              <label class="create-employee-modal__field">
                <span>2. 开场白（可选）</span>
                <textarea v-model="createEmployeeOpeningLine" rows="3" maxlength="240" placeholder="自定义员工第一句话，不填则使用默认开场白" />
              </label>

              <div class="create-employee-modal__field">
                <span>3. 重要规则</span>
                <div class="create-employee-rule-list">
                  <label v-for="rule in createEmployeeRules" :key="rule.id">
                    <input
                      :checked="rule.enabled"
                      type="checkbox"
                      @change="handleCreateEmployeeRuleToggle(rule.id, ($event.target as HTMLInputElement).checked)"
                    />
                    <span>{{ rule.text }}</span>
                  </label>
                </div>
                <button class="create-employee-modal__ghost" type="button" @click="handleCreateEmployeeAddCustomRule">添加自定义规则</button>
              </div>

              <footer class="create-employee-modal__actions">
                <button type="button" class="is-secondary" @click="handleCreateEmployeePrevStep">上一步</button>
                <button type="button" class="is-primary" @click="handleCreateEmployeeSubmit">创建并开始对话</button>
              </footer>
            </section>
          </div>
        </div>
      </section>
    </div>

    <div v-if="isCreateChatUserGroupModalOpen" class="related-resource-modal-backdrop" @click.self="closeCreateChatUserGroupModal">
      <section class="chat-user-group-modal" role="dialog" aria-modal="true" aria-label="创建团队">
        <header class="chat-user-group-modal__header">
          <div>
            <strong>创建团队</strong>
            <p>设置团队名称并添加成员，创建后会自动拉入团队会话。</p>
          </div>
          <button class="chat-user-group-modal__close" type="button" aria-label="关闭" @click="closeCreateChatUserGroupModal">×</button>
        </header>
        <form class="chat-user-group-modal__body" @submit.prevent="handleCreateChatUserGroupSubmit">
          <div class="chat-user-group-modal__panes">
            <section class="chat-user-group-modal__pane">
              <label class="chat-user-group-modal__search">
                <ControlIcon name="search" />
                <input v-model="createChatUserGroupSearch" type="text" placeholder="搜索成员" />
              </label>
              <header class="chat-user-group-modal__members-head">
                <span>所有成员 ({{ createChatUserGroupFilteredAgents.length }})</span>
                <div>
                  <button type="button" @click="handleCreateChatUserGroupSelectAllMembers">全选</button>
                  <button type="button" @click="handleCreateChatUserGroupClearMembers">清空</button>
                </div>
              </header>
              <div v-if="createChatUserGroupFilteredAgents.length === 0" class="chat-user-group-modal__members-empty">当前筛选暂无成员。</div>
              <button
                v-for="agent in createChatUserGroupFilteredAgents"
                :key="`create-group-member-${agent.agentId}`"
                class="chat-user-group-modal__member-row"
                :class="{ 'is-selected': isCreateChatUserGroupMemberSelected(agent.agentId) }"
                type="button"
                @click="handleCreateChatUserGroupMemberToggle(agent.agentId, !isCreateChatUserGroupMemberSelected(agent.agentId))"
              >
                <span class="chat-user-group-modal__member-avatar">
                  <img v-if="getAgentAvatarUrl(agent)" :src="getAgentAvatarUrl(agent) ?? undefined" :alt="`${stripRoleLabel(agent.displayName)} 头像`" />
                  <span v-else>{{ getAgentInitial(agent) }}</span>
                </span>
                <span class="chat-user-group-modal__member-copy">
                  <strong>{{ stripRoleLabel(agent.displayName) }}</strong>
                  <small>{{ agent.roleLabel || agent.channel }}</small>
                </span>
                <span class="chat-user-group-modal__member-action">{{ isCreateChatUserGroupMemberSelected(agent.agentId) ? "✓" : "+" }}</span>
              </button>
            </section>

            <section class="chat-user-group-modal__pane">
              <header class="chat-user-group-modal__selected-head">
                <span>已选成员 ({{ createChatUserGroupSelectedMembers.length }} / {{ CREATE_CHAT_USER_GROUP_MAX_MEMBERS }})</span>
              </header>
              <div class="chat-user-group-modal__selected-list">
                <div v-if="createChatUserGroupSelectedMembers.length === 0" class="chat-user-group-modal__members-empty">请先选择至少 1 位成员。</div>
                <article
                  v-for="agent in createChatUserGroupSelectedMembers"
                  :key="`create-group-selected-${agent.agentId}`"
                  class="chat-user-group-modal__selected-row"
                >
                  <span class="chat-user-group-modal__member-avatar">
                    <img v-if="getAgentAvatarUrl(agent)" :src="getAgentAvatarUrl(agent) ?? undefined" :alt="`${stripRoleLabel(agent.displayName)} 头像`" />
                    <span v-else>{{ getAgentInitial(agent) }}</span>
                  </span>
                  <div class="chat-user-group-modal__member-copy">
                    <strong>{{ stripRoleLabel(agent.displayName) }}</strong>
                    <small>{{ agent.roleLabel || agent.channel }}</small>
                  </div>
                  <div class="chat-user-group-modal__selected-actions">
                    <button
                      class="chat-user-group-modal__selected-owner"
                      :class="{ 'is-active': isCreateChatUserGroupOwner(agent.agentId) }"
                      type="button"
                      @click="handleCreateChatUserGroupOwnerSelect(agent.agentId)"
                    >
                      {{ isCreateChatUserGroupOwner(agent.agentId) ? "负责人" : "设为负责人" }}
                    </button>
                    <button
                      class="chat-user-group-modal__selected-remove"
                      type="button"
                      aria-label="移除成员"
                      @click="handleCreateChatUserGroupMemberToggle(agent.agentId, false)"
                    >
                      ×
                    </button>
                  </div>
                </article>
              </div>
              <label class="chat-user-group-modal__field">
                <span>团队名称 *</span>
                <input
                  ref="createChatUserGroupInputRef"
                  v-model="createChatUserGroupDraft"
                  type="text"
                  maxlength="24"
                  placeholder="例如 dev-team"
                />
              </label>
            </section>
          </div>

          <p v-if="createChatUserGroupError" class="chat-user-group-modal__error">{{ createChatUserGroupError }}</p>
          <div class="chat-user-group-modal__actions">
            <button type="button" @click="closeCreateChatUserGroupModal">取消</button>
            <button type="submit">创建团队</button>
          </div>
        </form>
      </section>
    </div>

    <div v-if="isConversationGroupRenameModalOpen" class="related-resource-modal-backdrop" @click.self="closeConversationGroupRenameModal">
      <section class="related-resource-modal conversation-group-rename-modal" role="dialog" aria-modal="true" aria-label="修改群聊名称">
        <header class="related-resource-modal__header">
          <div>
            <strong>修改群聊名称</strong>
            <p>修改后会同步更新群聊列表与会话标题。</p>
          </div>
          <div class="related-resource-modal__actions">
            <button class="related-resource-modal__close" type="button" aria-label="关闭" @click="closeConversationGroupRenameModal">×</button>
          </div>
        </header>
        <form class="related-resource-modal__body conversation-group-rename-modal__form" @submit.prevent="handleConversationGroupRenameSubmit">
          <label class="conversation-group-rename-modal__field">
            <span>群聊名称 *</span>
            <input v-model="conversationGroupRenameDraft" type="text" maxlength="24" placeholder="请输入群聊名称" />
          </label>
          <p v-if="conversationGroupRenameError" class="related-resource-modal__error">{{ conversationGroupRenameError }}</p>
          <div class="conversation-group-rename-modal__actions">
            <button class="related-resource-modal__refresh" type="button" @click="closeConversationGroupRenameModal">取消</button>
            <button class="related-resource-modal__refresh conversation-group-rename-modal__submit" type="submit">保存</button>
          </div>
        </form>
      </section>
    </div>

    <div v-if="chatSettingsTextPreviewModal" class="related-resource-modal-backdrop" @click.self="closeChatSettingsTextPreviewModal">
      <section class="related-resource-modal chat-settings-text-detail-modal" role="dialog" aria-modal="true" :aria-label="chatSettingsTextPreviewModal.title">
        <header class="related-resource-modal__header">
          <div>
            <strong>{{ chatSettingsTextPreviewModal.title }}</strong>
            <p>完整内容</p>
          </div>
          <div class="related-resource-modal__actions">
            <button class="related-resource-modal__close" type="button" aria-label="关闭" @click="closeChatSettingsTextPreviewModal">×</button>
          </div>
        </header>
        <div class="related-resource-modal__body chat-settings-text-detail-modal__body">
          <pre class="chat-settings-text-detail-modal__content">{{ chatSettingsTextPreviewModal.content }}</pre>
        </div>
      </section>
    </div>

    <div v-if="activeRoleWorkflowBase" class="role-workflow-detail-backdrop" @click.self="closeRoleWorkflowDetail">
      <section class="role-workflow-detail-modal" role="dialog" aria-modal="true" aria-label="角色详情">
        <header class="role-workflow-detail-modal__header">
          <div>
            <strong>角色详情</strong>
            <p>
              {{ activeRoleWorkflowBase.divisionTitleZh }}
              <span v-if="activeRoleWorkflowBase.groupTitleZh"> / {{ activeRoleWorkflowBase.groupTitleZh }}</span>
            </p>
          </div>
          <button
            class="role-workflow-detail-modal__close"
            type="button"
            aria-label="关闭"
            :disabled="isRoleWorkflowInstalling"
            @click="closeRoleWorkflowDetail"
          >
            ×
          </button>
        </header>

        <div class="role-workflow-detail-modal__body">
          <p
            v-if="roleWorkflowDetailNotice"
            class="role-workflow-detail-modal__notice"
            :class="`role-workflow-detail-modal__notice--${roleWorkflowDetailNotice.tone}`"
          >
            {{ roleWorkflowDetailNotice.text }}
          </p>

          <label class="role-workflow-detail-modal__field role-workflow-detail-modal__field--name">
            <span>角色中文名称</span>
            <input
              v-model="roleWorkflowNameZhDraft"
              class="role-workflow-detail-modal__name-input"
              type="text"
              placeholder="请输入角色中文名称"
              :disabled="roleWorkflowDetailLoading || isRoleWorkflowInstalling"
            />
          </label>

          <label class="role-workflow-detail-modal__field">
            <span>详情内容（Markdown，可编辑）</span>
            <textarea
              v-model="roleWorkflowDetailDraft.contentZh"
              class="role-workflow-detail-modal__editor"
              rows="18"
              placeholder="在这里编辑角色详情 Markdown"
              :disabled="roleWorkflowDetailLoading || isRoleWorkflowInstalling"
            />
          </label>

          <section class="role-workflow-detail-modal__versions">
            <header class="role-workflow-detail-modal__versions-header">
              <strong>已保存版本（最多 3 个）</strong>
            </header>
            <p v-if="roleWorkflowDetailSavedVersions.length === 0" class="role-workflow-detail-modal__versions-empty">
              暂无已保存版本，点击“保存”后会自动保留历史。
            </p>
            <ul v-else class="role-workflow-detail-modal__versions-list">
              <li v-for="version in roleWorkflowDetailSavedVersions" :key="version.id" class="role-workflow-detail-modal__version-item">
                <span class="role-workflow-detail-modal__version-time">{{ formatDateTime(version.savedAt) }}</span>
                <div class="role-workflow-detail-modal__version-actions">
                  <button type="button" :disabled="roleWorkflowDetailLoading || isRoleWorkflowInstalling" @click="applyRoleWorkflowSavedVersion(version.id)">
                    载入
                  </button>
                  <button type="button" :disabled="roleWorkflowDetailLoading || isRoleWorkflowInstalling" @click="deleteRoleWorkflowSavedVersion(version.id)">
                    删除
                  </button>
                </div>
              </li>
            </ul>
          </section>
        </div>

        <footer class="role-workflow-detail-modal__actions">
          <button type="button" :disabled="!isRoleWorkflowDraftChanged || roleWorkflowDetailLoading || isRoleWorkflowInstalling" @click="restoreRoleWorkflowOriginalContent">
            恢复原始内容
          </button>
          <button type="button" :disabled="!canSaveRoleWorkflowDraft || isRoleWorkflowInstalling" @click="saveRoleWorkflowDetail">
            {{ roleWorkflowDetailLoading ? "加载中..." : "保存" }}
          </button>
          <button type="button" :disabled="roleWorkflowDetailLoading || isRoleWorkflowInstalling" @click="installRoleWorkflowRole">
            {{ isRoleWorkflowInstalling ? "安装中..." : "安装角色" }}
          </button>
        </footer>
      </section>
    </div>

    <div v-if="activeSkillMarketDetail" class="skill-market-detail-backdrop" @click.self="closeSkillMarketDetailModal">
