  .task-reminder-pop-leave-active {
    transition: opacity 120ms linear !important;
    transform: none !important;
  }

  .chat-action-toast-pop-enter-active,
  .chat-action-toast-pop-leave-active {
    transition: opacity 120ms linear !important;
  }

  .composer-voice-action.is-recording {
