  outline: none;
  box-shadow: var(--cp-focus-ring);
}

.sidebar-profile {
  width: 100%;
  display: grid;
  grid-template-columns: 48px minmax(0, 1fr);
  align-items: center;
  gap: 10px;
  border: 0;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.68);
  padding: 8px;
  cursor: pointer;
  position: relative;
  transition: box-shadow 180ms ease, transform 180ms ease;
}

.sidebar-profile:hover {
  transform: translateY(-1px);
  box-shadow: 0 8px 16px rgba(82, 103, 149, 0.12);
}

.sidebar-profile:focus-visible {
  outline: none;
  box-shadow: var(--cp-focus-ring);
}

.sidebar-profile.is-open {
  box-shadow: 0 10px 22px rgba(82, 103, 149, 0.17);
}

.sidebar-profile--system-menu {
  grid-template-columns: 34px minmax(0, 1fr) 14px;
  gap: 6px;
  border: 1px solid var(--cp-border-200);
  background: var(--cp-surface-elevated);
  padding: 5px 8px;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);
}

.sidebar-profile--system-menu:hover {
  border-color: var(--cp-border-300);
}

.sidebar-profile--system-menu .sidebar-profile__meta strong {
  margin-top: 0;
  font-size: 13px;
  line-height: 1.05;
}

.sidebar-profile--system-menu .sidebar-profile__avatar {
  width: 30px;
  height: 30px;
  font-size: 14px;
  box-shadow: 0 2px 8px rgba(79, 111, 255, 0.22);
}

.sidebar-profile__toggle {
  width: 12px;
  height: 12px;
  display: grid;
  place-items: center;
  color: var(--cp-text-muted);
  transition: transform 180ms ease;
}

.sidebar-profile__toggle svg {
  width: 12px;
  height: 12px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2.2;
}

.sidebar-profile--system-menu.is-open .sidebar-profile__toggle {
  transform: rotate(180deg);
}

.sidebar-profile__avatar {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-weight: 700;
  color: #ffffff;
  background: linear-gradient(135deg, #5e7dff, #3f66ea);
  box-shadow: 0 2px 10px rgba(79, 111, 255, 0.26);
}

.sidebar-profile__avatar.is-group {
  background: #eaf0fb;
  box-shadow: inset 0 0 0 1px rgba(141, 165, 211, 0.32);
  color: #5a6b8a;
  overflow: hidden;
}

.sidebar-profile__avatar-image {
  width: 100%;
  height: 100%;
  border-radius: inherit;
  object-fit: cover;
  display: block;
}

.sidebar-profile__status {
  position: absolute;
  left: 40px;
  top: 10px;
  width: 9px;
  height: 9px;
  border-radius: 50%;
  border: 2px solid #ffffff;
  background: #35cc7a;
}

.sidebar-profile__meta {
  min-width: 0;
}

.sidebar-profile__meta small {
  display: block;
  font-size: 11px;
  color: #95a2bb;
}

.sidebar-profile__meta strong {
  display: block;
  margin-top: 1px;
  font-size: 18px;
  line-height: 1.1;
  color: #293145;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-page.is-sidebar-profile-panel-open .window-shell {
  pointer-events: none;
  user-select: none;
}

.sidebar-profile-panel-layer {
  --spp-overlay-base: rgba(219, 229, 246, 0.32);
  --spp-overlay-accent-a: rgba(107, 147, 219, 0.2);
  --spp-overlay-accent-b: rgba(111, 158, 236, 0.14);
  --spp-panel-border: rgba(163, 186, 224, 0.56);
  --spp-panel-bg: linear-gradient(165deg, #f8fbff 0%, #edf3ff 48%, #f6f9ff 100%);
  --spp-panel-shadow: 0 28px 56px rgba(40, 74, 133, 0.24), inset 0 1px 0 rgba(255, 255, 255, 0.88);
  --spp-text-strong: #1f3152;
  --spp-text-muted: #4a638d;
  --spp-handle-bg: rgba(103, 128, 169, 0.4);
  --spp-close-bg: rgba(71, 106, 168, 0.12);
  --spp-close-bg-hover: rgba(71, 106, 168, 0.22);
  --spp-close-color: #4a628d;
  --spp-avatar-bg: rgba(96, 138, 206, 0.18);
  --spp-avatar-color: #1f365f;
  --spp-avatar-shadow: 0 12px 24px rgba(65, 101, 163, 0.2), inset 0 1px 0 rgba(255, 255, 255, 0.85);
  --spp-lobster-border: rgba(149, 177, 222, 0.72);
  --spp-lobster-bg: rgba(255, 255, 255, 0.8);
  --spp-lobster-bg-hover: rgba(255, 255, 255, 0.95);
  --spp-lobster-color: #3a547f;
  --spp-tabs-bg: rgba(170, 192, 227, 0.16);
  --spp-tabs-border: rgba(166, 189, 225, 0.4);
  --spp-tab-border: rgba(172, 193, 228, 0.68);
  --spp-tab-bg: rgba(255, 255, 255, 0.78);
  --spp-tab-color: #47608a;
  --spp-tab-hover-border: rgba(130, 161, 214, 0.86);
  --spp-tab-active-border: #719adf;
  --spp-tab-active-bg: linear-gradient(145deg, #dfeaff, #d1e1ff);
  --spp-tab-active-color: #254274;
  --spp-avatar-row-bg: rgba(170, 192, 227, 0.16);
  --spp-avatar-row-border: rgba(166, 189, 225, 0.4);
  --spp-avatar-option-border: rgba(168, 193, 232, 0.86);
  --spp-avatar-option-bg: rgba(255, 255, 255, 0.9);
  --spp-avatar-option-active-border: #6f99e4;
  --spp-avatar-option-active-shadow: 0 9px 18px rgba(64, 129, 231, 0.28);
  --spp-primary-bg: linear-gradient(140deg, #5f88e9, #4a72d4);
  --spp-primary-text: #ffffff;
  --spp-secondary-bg: rgba(255, 255, 255, 0.82);
  --spp-secondary-border: rgba(150, 175, 218, 0.58);
  --spp-secondary-text: #2f4670;
  --spp-hint: #536c93;
  --spp-notice: #1e7c4d;
  --spp-error: #bb3758;
  position: fixed;
  inset: 0;
  z-index: 5200;
  display: grid;
  place-items: center;
  padding: 18px;
  background:
    radial-gradient(circle at 22% 16%, var(--spp-overlay-accent-a), transparent 42%),
    radial-gradient(circle at 84% 86%, var(--spp-overlay-accent-b), transparent 42%),
    var(--spp-overlay-base);
  pointer-events: auto;
  isolation: isolate;
}

.sidebar-profile-panel {
  position: relative;
  width: min(420px, calc(100vw - 30px));
  max-height: min(760px, calc(100vh - 34px));
  overflow-y: auto;
  border-radius: 28px;
  border: 1px solid var(--spp-panel-border);
  background: var(--spp-panel-bg);
  box-shadow: var(--spp-panel-shadow);
  padding: 16px 18px 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  color: var(--spp-text-strong);
  scrollbar-width: thin;
  scrollbar-color: rgba(123, 146, 189, 0.68) rgba(136, 158, 194, 0.16);
}

.sidebar-profile-panel__drag-handle {
  width: 46px;
  height: 4px;
  border-radius: 999px;
  background: var(--spp-handle-bg);
  margin-top: 1px;
}

.sidebar-profile-panel__close {
  position: absolute;
  top: 11px;
  right: 11px;
  width: 36px;
  height: 36px;
  border: 0;
  border-radius: 50%;
  background: var(--spp-close-bg);
  color: var(--spp-close-color);
  display: grid;
  place-items: center;
  cursor: pointer;
  transition: background 140ms ease, transform 140ms ease;
}

.sidebar-profile-panel__close svg {
  width: 16px;
  height: 16px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
}

.sidebar-profile-panel__close:hover {
  background: var(--spp-close-bg-hover);
  transform: scale(1.04);
}

.sidebar-profile-panel__avatar {
  width: 84px;
  height: 84px;
  border-radius: 50%;
  overflow: hidden;
  display: grid;
  place-items: center;
  background: var(--spp-avatar-bg);
  color: var(--spp-avatar-color);
  font-size: 28px;
  font-weight: 700;
  box-shadow: var(--spp-avatar-shadow);
}

.sidebar-profile-panel__avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.sidebar-profile-panel__name {
  margin-top: 1px;
  text-align: center;
  font-size: clamp(24px, 5.6vw, 32px);
  line-height: 1.1;
  color: var(--spp-text-strong);
  font-weight: 700;
  max-width: 100%;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-profile-panel__lobster-wrap {
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  margin-top: -1px;
}

.sidebar-profile-panel__lobster-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--spp-text-muted);
  letter-spacing: 0.06em;
}

.sidebar-profile-panel__lobster {
  max-width: 100%;
  min-height: 38px;
  border: 1px solid var(--spp-lobster-border);
  background: linear-gradient(165deg, rgba(255, 255, 255, 0.95), var(--spp-lobster-bg));
  color: var(--spp-lobster-color);
  display: inline-flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  font-size: 15px;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.08em;
  border-radius: 999px;
  padding: 4px 7px 4px 14px;
  cursor: pointer;
  transition: background 140ms ease, border-color 140ms ease, box-shadow 140ms ease, transform 140ms ease;
}

.sidebar-profile-panel__lobster-value {
  white-space: nowrap;
}

.sidebar-profile-panel__lobster-copy {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  background: rgba(93, 131, 201, 0.14);
  border: 1px solid rgba(120, 154, 218, 0.38);
}

.sidebar-profile-panel__lobster svg {
  width: 13px;
  height: 13px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
}

.sidebar-profile-panel__lobster:hover {
  background: var(--spp-lobster-bg-hover);
  border-color: rgba(132, 163, 219, 0.9);
  box-shadow: 0 6px 12px rgba(65, 98, 153, 0.14);
  transform: translateY(-1px);
}

.sidebar-profile-panel__lobster:focus-visible {
  outline: 2px solid rgba(87, 126, 204, 0.5);
  outline-offset: 2px;
}

.sidebar-profile-panel__tabs {
  width: 100%;
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;
  margin-top: 6px;
  padding: 6px;
  border-radius: 14px;
  background: var(--spp-tabs-bg);
  border: 1px solid var(--spp-tabs-border);
}

.sidebar-profile-panel__tab {
  height: 38px;
  border: 1px solid var(--spp-tab-border);
  border-radius: 11px;
  background: var(--spp-tab-bg);
  color: var(--spp-tab-color);
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  transition: background 140ms ease, border-color 140ms ease, color 140ms ease;
}

.sidebar-profile-panel__tab:hover {
  border-color: var(--spp-tab-hover-border);
  color: var(--spp-tab-active-color);
}

.sidebar-profile-panel__tab.is-active {
  border-color: var(--spp-tab-active-border);
  background: var(--spp-tab-active-bg);
  color: var(--spp-tab-active-color);
}

.sidebar-profile-panel__avatar-row {
  width: 100%;
  display: grid;
  grid-template-columns: repeat(7, minmax(0, 1fr));
  gap: 8px;
  margin-top: 0;
  padding: 10px;
  border-radius: 16px;
  background: var(--spp-avatar-row-bg);
  border: 1px solid var(--spp-avatar-row-border);
}

.sidebar-profile-panel__avatar-option {
  width: 100%;
  aspect-ratio: 1 / 1;
  border: 2px solid var(--spp-avatar-option-border);
  border-radius: 50%;
  background: var(--spp-avatar-option-bg);
  overflow: hidden;
  padding: 0;
  cursor: pointer;
  transition: border-color 140ms ease, transform 140ms ease, box-shadow 140ms ease;
}

.sidebar-profile-panel__avatar-option img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.sidebar-profile-panel__avatar-option.is-active {
  border-color: var(--spp-avatar-option-active-border);
  box-shadow: var(--spp-avatar-option-active-shadow);
  transform: translateY(-1px);
}

.sidebar-profile-panel__avatar-option.is-disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.sidebar-profile-panel__actions {
  width: 100%;
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 10px;
}

.sidebar-profile-panel__primary,
.sidebar-profile-panel__secondary {
  width: 100%;
  min-width: 0;
  height: 44px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-size: 13px;
  font-weight: 700;
  padding: 0 16px;
  cursor: pointer;
  transition: transform 140ms ease, filter 140ms ease, border-color 140ms ease, background 140ms ease;
}

.sidebar-profile-panel__primary {
  color: var(--spp-primary-text);
  background: var(--spp-primary-bg);
}

.sidebar-profile-panel__primary:hover:enabled,
.sidebar-profile-panel__secondary:hover {
  transform: translateY(-1px);
  filter: brightness(1.03);
}

.sidebar-profile-panel__secondary {
  color: var(--spp-secondary-text);
  background: var(--spp-secondary-bg);
  border-color: var(--spp-secondary-border);
}

.sidebar-profile-panel__primary:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.sidebar-profile-panel__hint,
.sidebar-profile-panel__notice,
.sidebar-profile-panel__error {
  margin: 0;
  text-align: center;
  font-size: 12px;
  line-height: 1.4;
}

.sidebar-profile-panel__hint {
  color: var(--spp-hint);
}

.sidebar-profile-panel__notice {
  color: var(--spp-notice);
}

.sidebar-profile-panel__error {
  color: var(--spp-error);
}

html[data-app-theme-resolved="dark"] .sidebar-profile-panel-layer {
  --spp-overlay-base: rgba(5, 8, 14, 0.92);
  --spp-overlay-accent-a: rgba(55, 104, 198, 0.18);
  --spp-overlay-accent-b: rgba(255, 173, 92, 0.12);
  --spp-panel-border: rgba(193, 213, 250, 0.3);
  --spp-panel-bg: linear-gradient(165deg, #131a2d 0%, #1b2540 48%, #141a2e 100%);
  --spp-panel-shadow: 0 32px 66px rgba(1, 4, 10, 0.72), inset 0 1px 0 rgba(255, 255, 255, 0.12);
  --spp-text-strong: #f7faff;
  --spp-text-muted: #d7e4ff;
  --spp-handle-bg: rgba(237, 244, 255, 0.3);
  --spp-close-bg: rgba(255, 255, 255, 0.12);
  --spp-close-bg-hover: rgba(255, 255, 255, 0.22);
  --spp-close-color: rgba(244, 248, 255, 0.94);
  --spp-avatar-bg: rgba(255, 255, 255, 0.18);
  --spp-avatar-color: #f7fbff;
  --spp-avatar-shadow: 0 14px 26px rgba(8, 13, 24, 0.54), inset 0 1px 0 rgba(255, 255, 255, 0.38);
  --spp-lobster-border: rgba(192, 213, 251, 0.32);
  --spp-lobster-bg: rgba(255, 255, 255, 0.08);
  --spp-lobster-bg-hover: rgba(255, 255, 255, 0.14);
  --spp-lobster-color: rgba(229, 236, 251, 0.9);
  --spp-tabs-bg: rgba(255, 255, 255, 0.06);
  --spp-tabs-border: rgba(197, 216, 251, 0.16);
  --spp-tab-border: rgba(198, 216, 255, 0.24);
  --spp-tab-bg: rgba(255, 255, 255, 0.08);
  --spp-tab-color: rgba(230, 238, 255, 0.86);
  --spp-tab-hover-border: rgba(186, 211, 255, 0.62);
  --spp-tab-active-border: rgba(140, 187, 255, 0.95);
  --spp-tab-active-bg: linear-gradient(145deg, rgba(95, 155, 255, 0.32), rgba(69, 126, 236, 0.32));
  --spp-tab-active-color: #ffffff;
  --spp-avatar-row-bg: rgba(255, 255, 255, 0.06);
  --spp-avatar-row-border: rgba(201, 219, 252, 0.16);
  --spp-avatar-option-border: rgba(255, 255, 255, 0.22);
  --spp-avatar-option-bg: rgba(255, 255, 255, 0.12);
  --spp-avatar-option-active-border: #b7d6ff;
  --spp-avatar-option-active-shadow: 0 10px 20px rgba(64, 129, 231, 0.48);
  --spp-primary-bg: linear-gradient(140deg, #f8fcff, #deebff);
  --spp-primary-text: #13223e;
  --spp-secondary-bg: rgba(255, 255, 255, 0.12);
  --spp-secondary-border: rgba(215, 228, 255, 0.34);
  --spp-secondary-text: rgba(233, 241, 255, 0.92);
  --spp-hint: rgba(226, 234, 252, 0.75);
  --spp-notice: #b9e8cb;
  --spp-error: #ffc8d9;
}

.sidebar-profile-panel__upload-input {
  display: none;
}

.sidebar-profile-panel-fade-enter-active,
.sidebar-profile-panel-fade-leave-active {
  transition: opacity 180ms ease;
}

.sidebar-profile-panel-fade-enter-active .sidebar-profile-panel,
.sidebar-profile-panel-fade-leave-active .sidebar-profile-panel {
  transition: transform 200ms ease, opacity 200ms ease;
}

.sidebar-profile-panel-fade-enter-from,
.sidebar-profile-panel-fade-leave-to {
  opacity: 0;
}

.sidebar-profile-panel-fade-enter-from .sidebar-profile-panel,
.sidebar-profile-panel-fade-leave-to .sidebar-profile-panel {
  opacity: 0;
  transform: translateY(8px) scale(0.985);
}

.sidebar-nav {
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 8px;
  margin-top: 10px;
}

.window-controls-row {
  width: 100%;
  min-height: 20px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.window-controls {
  flex-shrink: 0;
  width: auto;
  padding: 4px 0 0 2px;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  gap: 8px;
}

.window-control {
  width: 12px;
  height: 12px;
  border: 0;
  border-radius: 50%;
  padding: 0;
  cursor: pointer;
  transition: transform 120ms ease, filter 120ms ease;
}

.window-control:hover {
  transform: scale(1.06);
  filter: brightness(0.95);
}

.window-control--close {
  background: #ff5f57;
}

.window-control--minimize {
  background: #febc2e;
}

.window-control--expand {
  background: #28c840;
}

.window-version-chip {
  margin-top: 1px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  min-height: 18px;
  padding: 2px 8px;
  border-radius: 999px;
  border: 1px solid rgba(186, 202, 229, 0.86);
  background: rgba(255, 255, 255, 0.72);
  color: #61718b;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.9);
  white-space: nowrap;
}

.window-version-chip__version {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.01em;
  line-height: 1;
}

.window-version-chip__beta {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  line-height: 1;
  color: #2f62d0;
  border-radius: 999px;
  background: rgba(85, 128, 237, 0.16);
  padding: 2px 5px;
}

html[data-app-theme-resolved="dark"] .window-version-chip {
  border-color: rgba(116, 133, 171, 0.7);
  background: rgba(38, 47, 66, 0.72);
  color: #d4dff3;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

html[data-app-theme-resolved="dark"] .window-version-chip__beta {
  color: #dce7ff;
  background: rgba(96, 132, 224, 0.38);
}

.nav-item {
  position: relative;
  width: 100%;
  min-height: 40px;
  border: 0;
  border-radius: 10px;
  display: grid;
  grid-template-columns: 22px minmax(0, 1fr) auto;
  align-items: center;
  gap: 10px;
  text-align: left;
  padding: 9px 10px;
  color: #6b788f;
  background: transparent;
  cursor: pointer;
  transition: transform 140ms ease, color 180ms ease, background 180ms ease, box-shadow 180ms ease;
}

.nav-item__icon {
  width: 22px;
  height: 22px;
  display: grid;
  place-items: center;
  border-radius: 7px;
  color: #8a96ad;
  transition: background 180ms ease, color 180ms ease;
}

.nav-item svg {
  width: 17px;
  height: 17px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.nav-item__label {
  font-size: 15px;
  font-weight: 600;
  line-height: 1.1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nav-item__badge {
  min-width: 28px;
  height: 20px;
  border-radius: 999px;
  padding: 0 8px;
  display: grid;
  place-items: center;
  font-size: 11px;
  font-weight: 700;
  background: rgba(132, 145, 173, 0.26);
  color: #6a7898;
}

.nav-item:hover {
  color: #5f6f8c;
  background: rgba(243, 247, 253, 0.96);
  transform: translateY(-1px);
}

.nav-item.active {
  color: #2f3b57;
  background: rgba(255, 255, 255, 0.9);
  box-shadow:
    0 6px 16px rgba(115, 133, 168, 0.2),
    inset 0 1px 0 rgba(255, 255, 255, 0.9);
}

.nav-item.active .nav-item__icon {
  color: #ffffff;
  background: linear-gradient(135deg, #5d82ff, #4c70ef);
}

.nav-item.active .nav-item__badge {
  background: rgba(117, 132, 164, 0.2);
  color: #66738e;
}

.sidebar-spacer {
  flex: 1;
}

.sidebar-system-menu {
  width: 100%;
  position: relative;
  display: block;
  padding: 2px 0 4px;
}

.sidebar-system-menu__panel {
  position: absolute;
  left: 0;
  right: 0;
  bottom: calc(100% + 8px);
  z-index: 20;
  border: 1px solid var(--cp-border-200);
  border-radius: 12px;
  background: var(--cp-surface-elevated);
  box-shadow:
    0 10px 24px var(--cp-shadow),
    inset 0 1px 0 rgba(255, 255, 255, 0.62);
  padding: 8px;
}

.sidebar-system-menu-pop-enter-active,
.sidebar-system-menu-pop-leave-active {
  transition: opacity 170ms ease, transform 220ms cubic-bezier(0.2, 0.72, 0.24, 1);
  transform-origin: bottom center;
}

.sidebar-system-menu-pop-enter-from,
.sidebar-system-menu-pop-leave-to {
  opacity: 0;
  transform: translateY(8px) scale(0.98);
}

.sidebar-quick-actions {
  width: 100%;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(78px, 1fr));
  gap: 7px;
  align-items: center;
  padding: 0;
}

.sidebar-quick-action-wrap {
  position: relative;
  min-width: 0;
}

.sidebar-quick-action {
  width: 100%;
  min-height: 34px;
  border: 1px solid var(--cp-border-200);
  border-radius: 10px;
  background: var(--cp-surface-elevated);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.46);
  padding: 0 6px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  cursor: pointer;
  transition: transform 160ms ease, border-color 180ms ease, background-color 180ms ease, box-shadow 180ms ease;
}

.sidebar-quick-action:hover {
  transform: translateY(-1px);
  border-color: var(--cp-border-300);
  background: var(--cp-hover-bg);
}

.sidebar-quick-action:focus-visible {
  outline: none;
  box-shadow: var(--cp-focus-ring);
}

.sidebar-quick-action__bubble {
  --quick-icon: #485672;
  --quick-bg-start: #ecf4ff;
  --quick-bg-end: #b9cff9;
  position: relative;
  width: 22px;
  height: 22px;
  border-radius: 7px;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  color: var(--quick-icon);
  background: linear-gradient(145deg, var(--quick-bg-start), var(--quick-bg-end));
  border: 1px solid rgba(255, 255, 255, 0.76);
  box-shadow:
    0 3px 8px rgba(66, 86, 124, 0.18),
    inset 0 1px 0 rgba(255, 255, 255, 0.66);
  transition: transform 180ms ease, box-shadow 180ms ease, filter 180ms ease;
}

.sidebar-quick-action__bubble svg {
  position: relative;
  z-index: 1;
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.sidebar-quick-action__label {
  min-width: 0;
  color: var(--cp-soft-accent-text-strong);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.01em;
  line-height: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-quick-action--web-bar {
  grid-column: 1 / -1;
  justify-content: flex-start;
  padding: 0 10px;
}

.sidebar-quick-action--web-bar .sidebar-quick-action__label {
  font-size: 10.5px;
  letter-spacing: 0;
}

.sidebar-icon-browser__dot {
  fill: currentColor;
  stroke: none;
}

.sidebar-icon-file__stroke {
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
}

.sidebar-icon-file__card {
  fill: #f8dfbf;
  stroke: none;
}

.sidebar-icon-file__line1 {
  stroke: #f29a12;
  stroke-width: 1.6;
  stroke-linecap: round;
}

.sidebar-icon-file__line2 {
  stroke: #2f2f2f;
  stroke-width: 1.6;
  stroke-linecap: round;
}

.sidebar-icon-tee__stroke {
  fill: #ffffff;
  stroke: currentColor;
  stroke-width: 1.8;
  stroke-linejoin: round;
}

.sidebar-icon-tee__tag {
  fill: #f4c72e;
  stroke: none;
}

.sidebar-quick-action.is-active {
  border-color: var(--cp-border-strong);
  background: var(--cp-active-bg);
  box-shadow:
    0 7px 14px var(--cp-shadow),
    inset 0 1px 0 rgba(255, 255, 255, 0.58);
}

.sidebar-quick-action.is-active .sidebar-quick-action__bubble {
  transform: translateY(-1px) scale(1.05);
  box-shadow:
    0 7px 14px rgba(61, 83, 127, 0.22),
    inset 0 1px 0 rgba(255, 255, 255, 0.72);
  filter: saturate(1.08);
}

.sidebar-quick-action__bubble--theme {
  --quick-icon: #4a3e75;
  --quick-bg-start: #f3ebff;
  --quick-bg-end: #c8b4ff;
}

.sidebar-quick-action__bubble--proxy {
  --quick-icon: #2f597e;
  --quick-bg-start: #e8f6ff;
  --quick-bg-end: #b6ddff;
}

.sidebar-quick-action__bubble--logs {
  --quick-icon: #4f477b;
  --quick-bg-start: #f0eaff;
  --quick-bg-end: #d4c7ff;
}

.sidebar-quick-action__bubble--test {
  --quick-icon: #7f4e1e;
  --quick-bg-start: #fff3d8;
  --quick-bg-end: #ffd698;
}

.sidebar-quick-action__bubble--settings {
  --quick-icon: #2f6b55;
  --quick-bg-start: #e8fff3;
  --quick-bg-end: #b5efd4;
}

.sidebar-quick-action__bubble--web {
  --quick-icon: #7a5424;
  --quick-bg-start: #fff4d9;
  --quick-bg-end: #ffd08b;
}

.sidebar-theme-popover {
  position: absolute;
  left: 0;
  bottom: calc(100% + 10px);
  z-index: 28;
  width: 184px;
  border-radius: 14px;
  border: 1px solid var(--cp-border-200);
  background: var(--cp-surface-elevated);
  box-shadow:
    0 16px 32px var(--cp-shadow),
    inset 0 1px 0 rgba(255, 255, 255, 0.58);
}

.sidebar-theme-pop-enter-active,
.sidebar-theme-pop-leave-active {
  transition: opacity 180ms ease, transform 220ms cubic-bezier(0.2, 0.72, 0.24, 1);
}

.sidebar-theme-pop-enter-from,
.sidebar-theme-pop-leave-to {
  opacity: 0;
  transform: translateY(6px) scale(0.96);
}

.sidebar-theme-switcher {
  width: 100%;
  margin-bottom: 0;
  padding: 8px;
  border-radius: 12px;
  border: 0;
  background: transparent;
  box-shadow: none;
  display: grid;
  gap: 8px;
}

.sidebar-theme-switcher__mode-row,
.sidebar-theme-switcher__preset-row {
  --switch-count: 2;
  --switch-index: 0;
  position: relative;
  display: grid;
  grid-template-columns: repeat(var(--switch-count), minmax(0, 1fr));
  align-items: stretch;
  padding: 3px;
  border-radius: 10px;
  border: 1px solid var(--cp-border-200);
  background: var(--cp-hover-bg);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.42);
  isolation: isolate;
  overflow: hidden;
}

.sidebar-theme-switcher__preset-row {
  --switch-count: 3;
}

.sidebar-theme-switcher__mode-row::before,
.sidebar-theme-switcher__preset-row::before {
  content: "";
  position: absolute;
  top: 3px;
  left: 3px;
  z-index: 0;
  width: calc((100% - 6px) / var(--switch-count));
  height: calc(100% - 6px);
  border-radius: 8px;
  background: var(--cp-surface-elevated);
  box-shadow:
    0 4px 10px var(--cp-shadow),
    inset 0 1px 0 rgba(255, 255, 255, 0.48);
  transform: translateX(calc(var(--switch-index) * 100%));
  transition: transform 220ms cubic-bezier(0.22, 1, 0.36, 1);
  pointer-events: none;
}

.sidebar-theme-switcher__mode,
.sidebar-theme-switcher__preset {
  position: relative;
  z-index: 1;
  height: 30px;
  border-radius: 8px;
  border: 0;
  background: transparent;
  color: var(--cp-text-muted);
  font-size: 12px;
  font-weight: 600;
  padding: 0 4px;
  white-space: nowrap;
  cursor: pointer;
  transition: color 160ms ease;
}

.sidebar-theme-switcher__mode:hover,
.sidebar-theme-switcher__preset:hover {
  color: var(--cp-text);
}

.sidebar-theme-switcher__mode:focus-visible,
.sidebar-theme-switcher__preset:focus-visible {
  outline: none;
  box-shadow: var(--cp-focus-ring);
}

.sidebar-theme-switcher__mode-row:hover,
.sidebar-theme-switcher__preset-row:hover {
  border-color: var(--cp-border-strong);
}

.sidebar-theme-switcher__mode.is-active,
.sidebar-theme-switcher__preset.is-active {
  color: var(--cp-accent-dark);
}

.chat-list {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  border-right: 1px solid #dde2ea;
  background: #fdfdfd;
}

.chat-list__header {
  padding: 16px 14px 10px;
  border-bottom: 1px solid #e8ebf1;
  background: #fdfdfd;
  cursor: default;
}

html[data-app-theme-preset="frosted"] .window-shell {
  position: relative;
  isolation: isolate;
  border-color: rgba(237, 228, 255, 0.74);
  background: linear-gradient(145deg, rgba(255, 255, 255, 0.44), rgba(255, 255, 255, 0.18));
  box-shadow:
    0 20px 48px rgba(123, 99, 162, 0.2),
    inset 0 1px 0 rgba(255, 255, 255, 0.72);
  backdrop-filter: blur(28px) saturate(1.24);
}

html[data-app-theme-preset="frosted"] .window-shell::before {
  content: "";
  position: absolute;
  inset: -18% -12%;
  pointer-events: none;
  z-index: 0;
  background:
    radial-gradient(circle at 44% 40%, rgba(240, 130, 201, 0.34), transparent 34%),
    radial-gradient(circle at 58% 80%, rgba(255, 193, 148, 0.24), transparent 30%),
    radial-gradient(circle at 18% 22%, rgba(194, 171, 255, 0.24), transparent 36%);
  filter: blur(32px) saturate(1.1);
}

html[data-app-theme-preset="frosted"] .window-shell::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background: linear-gradient(120deg, rgba(255, 255, 255, 0.3), rgba(255, 255, 255, 0.08) 45%, rgba(255, 255, 255, 0.24));
  mix-blend-mode: screen;
}

html[data-app-theme-preset="frosted"] .chat-app {
  position: relative;
  z-index: 1;
  background:
    radial-gradient(circle at 8% 8%, rgba(255, 255, 255, 0.24), transparent 36%),
    radial-gradient(circle at 92% 12%, rgba(255, 255, 255, 0.18), transparent 34%),
    rgba(245, 240, 252, 0.44);
}

html[data-app-theme-preset="frosted"] .sidebar-icons {
  border-right-color: rgba(223, 210, 246, 0.8);
  background: rgba(245, 240, 252, 0.52);
  backdrop-filter: blur(18px) saturate(1.16);
}

html[data-app-theme-preset="frosted"] .chat-list,
html[data-app-theme-preset="frosted"] .chat-list__header {
  background: rgba(255, 255, 255, 0.54);
}

html[data-app-theme-preset="frosted"] .sidebar-brand,
html[data-app-theme-preset="frosted"] .sidebar-top__new-chat,
html[data-app-theme-preset="frosted"] .sidebar-theme-switcher,
html[data-app-theme-preset="frosted"] .chat-window__header,
html[data-app-theme-preset="frosted"] .chat-window__composer,
html[data-app-theme-preset="frosted"] .module-board,
html[data-app-theme-preset="frosted"] .search-box,
html[data-app-theme-preset="frosted"] .search-add,
html[data-app-theme-preset="frosted"] .agent-pane-tabs,
html[data-app-theme-preset="frosted"] .composer-panel {
  backdrop-filter: blur(16px) saturate(1.16);
  -webkit-backdrop-filter: blur(16px) saturate(1.16);
}

html[data-app-theme-preset="pure-white"] .window-shell {
  border-color: #dce2e8;
  background: #f1f3f5;
  box-shadow:
    0 16px 34px rgba(18, 24, 32, 0.11),
    inset 0 1px 0 rgba(255, 255, 255, 0.88);
  backdrop-filter: none;
}

html[data-app-theme-preset="pure-white"] .chat-app {
  background: #fcfcfd;
}

html[data-app-theme-preset="pure-white"] .sidebar-icons {
  border-right-color: #e5e9ee;
  background: #f4f5f7;
}

html[data-app-theme-preset="pure-white"] .chat-list,
html[data-app-theme-preset="pure-white"] .chat-list__header {
  background: #f8fafc;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .window-shell {
  border-color: rgba(115, 105, 152, 0.72);
  background: linear-gradient(145deg, rgba(46, 40, 65, 0.58), rgba(28, 24, 43, 0.48));
  box-shadow:
    0 20px 48px rgba(8, 7, 15, 0.34),
    inset 0 1px 0 rgba(188, 163, 236, 0.14);
  backdrop-filter: blur(28px) saturate(1.18);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .window-shell::before {
  background:
    radial-gradient(circle at 42% 38%, rgba(170, 99, 169, 0.34), transparent 36%),
    radial-gradient(circle at 58% 82%, rgba(166, 116, 70, 0.28), transparent 30%),
    radial-gradient(circle at 16% 18%, rgba(129, 110, 184, 0.3), transparent 34%);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .window-shell::after {
  background: linear-gradient(120deg, rgba(255, 255, 255, 0.06), rgba(255, 255, 255, 0.02) 45%, rgba(255, 255, 255, 0.08));
  mix-blend-mode: lighten;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-app {
  background:
    radial-gradient(circle at 14% 10%, rgba(108, 93, 161, 0.26), transparent 40%),
    radial-gradient(circle at 84% 8%, rgba(103, 88, 152, 0.22), transparent 42%),
    rgba(27, 23, 40, 0.66);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .sidebar-icons {
  border-right-color: rgba(123, 112, 164, 0.72);
  background: rgba(30, 25, 45, 0.72);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-list,
html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-list__header {
  background: rgba(37, 31, 55, 0.74);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-window__header {
  background: linear-gradient(180deg, rgba(46, 39, 67, 0.82), rgba(36, 31, 54, 0.78));
  border-bottom-color: rgba(155, 141, 196, 0.4);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-agent-header__avatar {
  color: #f4ecff;
  background: linear-gradient(135deg, rgba(227, 171, 255, 0.78), rgba(183, 132, 232, 0.66));
  box-shadow:
    0 8px 18px rgba(168, 106, 224, 0.32),
    inset 0 1px 0 rgba(255, 255, 255, 0.28);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-window__composer {
  background: linear-gradient(180deg, rgba(42, 35, 60, 0.82), rgba(34, 29, 52, 0.86));
  border-top-color: rgba(154, 139, 196, 0.42);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .composer-panel {
  border-color: rgba(166, 146, 206, 0.44);
  background: linear-gradient(180deg, rgba(77, 66, 104, 0.62), rgba(49, 41, 73, 0.74));
  box-shadow:
    0 10px 22px rgba(11, 9, 20, 0.38),
    inset 0 1px 0 rgba(241, 226, 255, 0.14);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .composer-panel:focus-within {
  border-color: rgba(197, 168, 239, 0.62);
  background: linear-gradient(180deg, rgba(89, 76, 118, 0.68), rgba(56, 47, 82, 0.8));
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .window-shell {
  border-color: rgba(51, 56, 64, 0.94);
  background: #0e1116;
  box-shadow:
    0 22px 46px rgba(0, 0, 0, 0.5),
    inset 0 1px 0 rgba(255, 255, 255, 0.02);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-app {
  background: #141920;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .sidebar-icons {
  border-right-color: rgba(63, 69, 79, 0.9);
  background: #101317;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-list,
html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-list__header {
  background: #1a1f27;
}

html[data-app-theme-preset="pure-white"] .chat-window__header {
  background: #fdfefe;
  border-bottom-color: #e5e9ee;
}

html[data-app-theme-preset="pure-white"] .chat-window__composer {
  background: #f8fafb;
  border-top-color: #e5e9ee;
}

html[data-app-theme-preset="pure-white"] .composer-panel {
  border-color: #d7dde5;
  background: linear-gradient(180deg, #f7f9fb, #f1f4f6);
}

html[data-app-theme-preset="pure-white"] .composer-panel:focus-within {
  border-color: #b7c0cb;
  background: linear-gradient(180deg, #fbfcfd, #f4f7fa);
}

html[data-app-theme-preset="pure-white"] .chat-window__composer textarea::placeholder {
  color: #929aa8;
}

html[data-app-theme-preset="pure-white"] .chat-agent-header__avatar {
  color: #188e48;
  background: linear-gradient(135deg, #e7f8ee, #ceeedc);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-window__header {
  background: linear-gradient(180deg, #1d2229, #181d24);
  border-bottom-color: rgba(74, 81, 92, 0.68);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-window__composer {
  background: linear-gradient(180deg, #191e25, #151a21);
  border-top-color: rgba(76, 83, 95, 0.72);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .composer-panel {
  border-color: rgba(87, 95, 108, 0.76);
  background: linear-gradient(180deg, rgba(58, 65, 76, 0.86), rgba(41, 48, 58, 0.92));
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .composer-panel:focus-within {
  border-color: rgba(112, 123, 139, 0.84);
  background: linear-gradient(180deg, rgba(65, 73, 86, 0.9), rgba(46, 54, 66, 0.96));
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-window__composer textarea {
  color: #e6ebf2;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-window__composer textarea:focus {
  color: #f4f7fc;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-window__composer textarea::placeholder {
  color: rgba(163, 171, 183, 0.74);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="pure-white"] .chat-agent-header__avatar {
  color: #d6f9e5;
  background: linear-gradient(135deg, rgba(72, 146, 103, 0.72), rgba(50, 104, 77, 0.72));
}

.search-row {
  margin-top: 0;
  display: grid;
  grid-template-columns: minmax(0, 1fr) 38px;
  gap: 8px;
}

.search-box {
  height: 38px;
  display: flex;
  align-items: center;
  gap: 8px;
  border-radius: 8px;
  border: 1px solid #d9dee7;
  background: #ffffff;
  color: #90a0ba;
  padding: 0 10px;
}

.search-box svg,
.search-add svg,
.header-btn svg,
.composer-input-action svg,
.composer-send svg {
  width: 16px;
  height: 16px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.search-box input {
  flex: 1;
  min-width: 0;
  border: 0;
  outline: 0;
  background: transparent;
  color: #3f4a63;
  font-size: 14px;
}

.search-box input::placeholder {
  color: #a5afc2;
}

.search-add {
  width: 38px;
  height: 38px;
  border: 1px solid #d9dee7;
  border-radius: 8px;
  background: #ffffff;
  color: #8290a8;
  display: grid;
  place-items: center;
  cursor: pointer;
}

.search-add svg {
  width: 18px;
  height: 18px;
  stroke-width: 2.2;
}

.search-add:hover {
  color: #3f6fd6;
  border-color: #bdcfee;
  background: #edf3ff;
}

.search-create-menu {
  position: relative;
}

.search-create-menu__popover {
  position: absolute;
  top: calc(100% + 8px);
  right: 0;
  z-index: 24;
  min-width: 132px;
  border: 1px solid #d9dee7;
  border-radius: 10px;
  background: #ffffff;
  box-shadow: 0 12px 26px rgba(42, 62, 96, 0.16);
  overflow: hidden;
}

.search-create-menu__item {
  width: 100%;
  border: 0;
  border-top: 1px solid #edf1f7;
  background: transparent;
  color: #4b5973;
  font-size: 13px;
  line-height: 1.2;
  text-align: left;
  padding: 10px 12px;
  cursor: pointer;
}

.search-create-menu__item:first-child {
  border-top: 0;
}

.search-create-menu__item:hover {
  background: #eef4ff;
  color: #2f5fd2;
}

.agent-pane-tabs {
  margin-top: 12px;
  padding: 4px;
  border-radius: 999px;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 4px;
  border: 1px solid #d9e0ea;
  background: #e9edf3;
}

.agent-pane-tab {
  height: 32px;
  border: 0;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 700;
  color: #7f8ba3;
  background: transparent;
  cursor: pointer;
  transition: color 160ms ease, background 160ms ease, box-shadow 160ms ease;
}

.agent-pane-tab.active {
  color: #33445f;
  background: #ffffff;
  box-shadow: 0 2px 6px rgba(85, 104, 136, 0.18);
}

.chat-list__body {
  min-height: 0;
  overflow: auto;
  padding: 6px 10px 10px;
  background: transparent;
}

.agent-group-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 2px 0 4px;
}

.agent-group-list--flat {
  gap: 6px;
}

.agent-flat-head {
  min-height: 24px;
  padding: 0 4px 2px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  color: #7f8ea8;
}

.agent-flat-head small {
  font-size: 11px;
  color: #95a4be;
}

.agent-group-section {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.agent-group-section--flat {
  gap: 0;
}

.agent-group-head {
  min-height: 24px;
  padding: 0 4px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  color: #7987a1;
}

.agent-group-head strong {
  margin: 0;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.02em;
}

.agent-group-head__actions {
  display: flex;
  align-items: center;
  gap: 6px;
}

.agent-group-head__actions small {
  font-size: 11px;
  color: #95a4be;
}

.agent-group-collapse {
  width: 24px;
  height: 24px;
  border: 1px solid #d7deea;
  border-radius: 7px;
  background: #ffffff;
  color: #8594ad;
  display: grid;
  place-items: center;
  padding: 0;
  cursor: pointer;
  transition: color 160ms ease, border-color 160ms ease, background-color 160ms ease;
}

.agent-group-collapse svg {
  width: 12px;
  height: 12px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
  transition: transform 160ms ease;
}

.agent-group-collapse:hover {
  color: #3f6fd6;
  border-color: #bdcfee;
  background: #edf3ff;
}

.agent-group-collapse.is-collapsed svg {
  transform: rotate(-90deg);
}

.agent-group-delete {
  width: 24px;
  height: 24px;
  border: 1px solid #d7deea;
  border-radius: 7px;
  background: #ffffff;
  color: #8594ad;
  display: grid;
  place-items: center;
  padding: 0;
  cursor: pointer;
  transition: color 160ms ease, border-color 160ms ease, background-color 160ms ease;
}

.agent-group-delete svg {
  width: 13px;
  height: 13px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.7;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.agent-group-delete:hover {
  color: #bd3a3a;
  border-color: #e8b8b8;
  background: #fff0f0;
}

.agent-group-add {
  width: 24px;
  height: 24px;
  border: 1px solid #d7deea;
  border-radius: 7px;
  background: #ffffff;
  color: #8594ad;
  display: grid;
  place-items: center;
  padding: 0;
  cursor: pointer;
  transition: color 160ms ease, border-color 160ms ease, background-color 160ms ease;
}

.agent-group-add svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.agent-group-add:hover {
  color: #3f6fd6;
  border-color: #bdcfee;
  background: #edf3ff;
}

.agent-context-menu {
  position: fixed;
  z-index: 140;
  min-width: 152px;
  border: 1px solid #d8e3f1;
  border-radius: 10px;
  background: #ffffff;
  box-shadow: 0 14px 28px rgba(47, 74, 118, 0.2);
  overflow: hidden;
  padding: 4px 0;
}

.chat-message-context-menu {
  min-width: 170px;
}

.agent-context-menu__item {
  width: 100%;
  border: 0;
  border-top: 1px solid #ebf0f7;
  background: transparent;
  text-align: left;
  padding: 8px 12px;
  font-size: 13px;
  color: #324866;
  cursor: pointer;
  transition: background-color 140ms ease, color 140ms ease;
}

.agent-context-menu__item:first-child {
  border-top: 0;
}

.agent-context-menu__item:hover {
  background: #f3f7ff;
  color: #2f62b4;
}

.agent-context-menu__item:focus-visible {
  outline: 2px solid #89b1f3;
  outline-offset: -2px;
}

.agent-context-menu__item--danger {
  color: #c04747;
}

.agent-context-menu__item--danger:hover {
  background: #fff1f1;
  color: #ad3232;
}

.agent-item {
  width: 100%;
  border: 1px solid transparent;
  border-radius: 8px;
  background: transparent;
  text-align: left;
  padding: 8px;
  display: grid;
  grid-template-columns: 46px minmax(0, 1fr);
  gap: 8px;
  align-items: center;
  cursor: pointer;
  transition: background 180ms ease, border-color 180ms ease;
}

.agent-item[draggable="true"] {
  cursor: grab;
}

.agent-item + .agent-item {
  margin-top: 4px;
}

.agent-item:hover {
  border-color: #d7dde7;
  background: #ffffff;
}

.agent-item.active {
  border-color: #9eb3f7;
  background: #e9efff;
  color: #2f446f;
}

.agent-item--dragging {
  opacity: 0.58;
  cursor: grabbing;
}

.agent-item--drag-over {
  border-color: #95b3eb;
  background: #eef4ff;
}

.agent-avatar {
  position: relative;
  width: 42px;
  height: 42px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-weight: 800;
  color: #5a6b8a;
  background: #eaf0fb;
}

.group-avatar-stack {
  --group-avatar-size: 22px;
  --group-avatar-overlap: 7px;
  --group-avatar-border-width: 1.5px;
  position: relative;
  width: fit-content;
  max-width: 100%;
  height: var(--group-avatar-size);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.group-avatar-stack__item {
  width: var(--group-avatar-size);
  height: var(--group-avatar-size);
  border-radius: 50%;
  border: var(--group-avatar-border-width) solid #ffffff;
  background: #dfe7f6;
  overflow: hidden;
  display: grid;
  place-items: center;
  font-size: 10px;
  line-height: 1;
  color: #4b5f85;
  box-shadow: 0 1px 4px rgba(52, 71, 104, 0.16);
}

.group-avatar-stack__item + .group-avatar-stack__item {
  margin-left: calc(var(--group-avatar-overlap) * -1);
}

.group-avatar-stack--md {
  --group-avatar-size: 15px;
  --group-avatar-overlap: 3px;
  --group-avatar-border-width: 1.2px;
}

.group-avatar-stack__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.group-avatar-stack--lg {
  --group-avatar-size: 16px;
  --group-avatar-overlap: 3px;
  --group-avatar-border-width: 1.25px;
}

.group-avatar-stack--xs {
  --group-avatar-size: 14px;
  --group-avatar-overlap: 4px;
  --group-avatar-border-width: 1px;
}

.group-avatar-stack--xs .group-avatar-stack__item {
  font-size: 9px;
}

.agent-avatar__image {
  width: 100%;
  height: 100%;
  border-radius: inherit;
  object-fit: cover;
  display: block;
}

.agent-avatar--group {
  border-radius: 50%;
  overflow: hidden;
}

.status-dot {
  position: absolute;
  right: 1px;
  bottom: 1px;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  border: 2px solid #fff;
  background: #26c45d;
}

.status-dot[data-tone="busy"] {
  background: #ffb62e;
}

.status-dot[data-tone="offline"] {
  background: #94a3b8;
}

.agent-content {
  min-width: 0;
}

.agent-top-line {
  display: flex;
  align-items: center;
  gap: 6px;
}

.agent-top-line strong {
  display: block;
  font-size: 14px;
  font-weight: 700;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.agent-channel {
  flex-shrink: 0;
  font-size: 10px;
  border-radius: 999px;
  padding: 1px 6px;
  background: #edf1f8;
  color: #6a7898;
  text-transform: lowercase;
}

.agent-item.active .agent-channel {
  background: #d9e4ff;
  color: #50658f;
}

.agent-preview {
  margin: 2px 0 1px;
  font-size: 12px;
  color: #6f7f9d;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.agent-status {
  font-size: 11px;
  color: #8996b0;
}

.agent-item.active .agent-preview,
.agent-item.active .agent-status {
  color: #647ba6;
}

.agent-meta {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 4px;
  color: #8a97b0;
  font-size: 11px;
}

.agent-group-chip {
  max-width: 98px;
  border: 1px solid #dae4f4;
  border-radius: 999px;
  background: #f5f8ff;
  color: #62779b;
  font-size: 10px;
  line-height: 1.2;
  padding: 2px 7px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  cursor: pointer;
}

.agent-group-chip:hover {
  border-color: #b8c9ea;
  background: #eaf1ff;
  color: #3f5f96;
}

.agent-item.active .agent-meta {
  color: #7388b3;
}

.agent-item.active .agent-group-chip {
  border-color: #9fb7ea;
  background: #dce8ff;
  color: #4a618d;
}

.agent-unread {
  min-width: 18px;
  height: 18px;
  border-radius: 999px;
  display: grid;
  place-items: center;
  font-size: 10px;
  color: #fff;
  background: #2f79ed;
}

.agent-item.active .agent-unread {
  background: #7f98ea;
}

.list-empty {
  margin: 16px 8px;
  color: #8193ad;
  font-size: 13px;
}

.list-empty--compact {
  margin: 0;
  border: 1px dashed #d5dfec;
  border-radius: 9px;
  background: #ffffff;
  padding: 10px;
  text-align: center;
  font-size: 12px;
}

.chat-channel-pane {
  display: flex;
  flex-direction: column;
  min-height: 100%;
}

.chat-channel-pane__bottom {
  margin-top: auto;
}

.chat-channel-pane__chat-list {
  margin: 12px 0;
  flex: 1;
  min-height: 180px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.chat-channel-pane__chat-item {
  width: 100%;
  border: 1px solid #dce6f5;
  border-radius: 10px;
  background: #ffffff;
  padding: 9px 10px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  text-align: left;
  cursor: pointer;
  transition:
    border-color 160ms ease,
    background-color 160ms ease,
    transform 160ms ease,
    box-shadow 160ms ease;
}

.chat-channel-pane__chat-item:focus-visible {
  outline: 2px solid rgba(232, 129, 74, 0.46);
  outline-offset: 2px;
}

.chat-channel-pane__chat-item:hover {
  border-color: #f7b28b;
  background: #fff8f2;
  box-shadow: 0 8px 18px rgba(232, 108, 32, 0.12);
  transform: translateY(-1px);
}

.chat-channel-pane__chat-item.is-active {
  border-color: #e9814a;
  background: #fff3ea;
  box-shadow: 0 10px 22px rgba(232, 108, 32, 0.14);
}

.chat-channel-pane__chat-item-main {
  min-width: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

.chat-channel-pane__chat-item-copy {
  min-width: 0;
}

.chat-channel-pane__chat-item-copy strong {
  display: block;
  color: #2f3f5b;
  font-size: 13px;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-channel-pane__chat-item-copy small {
  display: block;
  margin-top: 2px;
  color: #7286a7;
  font-size: 11px;
  line-height: 1.35;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-channel-pane__chat-item-actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

.chat-channel-pane__chat-item-config {
  width: 24px;
  height: 24px;
  flex-shrink: 0;
  border: 1px solid #d8e2f1;
  border-radius: 7px;
  background: #f7faff;
  color: #6880a2;
  cursor: pointer;
  display: grid;
  place-items: center;
  padding: 0;
  opacity: 0;
  pointer-events: none;
  transform: translateY(2px);
  transition:
    opacity 150ms ease,
    transform 150ms ease,
    border-color 150ms ease,
    background-color 150ms ease,
    color 150ms ease;
}

.chat-channel-pane__chat-item-config svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-channel-pane__chat-item-config:hover {
  border-color: #f2b18c;
  background: #fff3ea;
  color: #d66c35;
}

.chat-channel-pane__chat-item:hover .chat-channel-pane__chat-item-config,
.chat-channel-pane__chat-item:focus-within .chat-channel-pane__chat-item-config,
.chat-channel-pane__chat-item.is-active .chat-channel-pane__chat-item-config {
  opacity: 1;
  pointer-events: auto;
  transform: translateY(0);
}

.chat-channel-pane__chat-item-dot {
  flex-shrink: 0;
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: #b8c6db;
}

.chat-channel-pane__chat-item-dot[data-tone="online"] {
  background: #2f9e67;
}

.chat-channel-pane__chat-item-dot[data-tone="busy"] {
  background: #f2a93b;
}

.chat-channel-pane__placeholder {
  margin: 12px 0;
  flex: 1;
  min-height: 180px;
  border: 1px dashed #d7e2f2;
  border-radius: 12px;
  background: rgba(244, 248, 255, 0.75);
  display: grid;
  place-content: center;
  gap: 6px;
  text-align: center;
  padding: 16px;
}

.chat-channel-pane__placeholder p {
  margin: 0;
  color: #3f5577;
  font-size: 14px;
  font-weight: 700;
}

.chat-channel-pane__placeholder small {
  margin: 0;
  color: #7287a7;
  font-size: 12px;
  line-height: 1.45;
}

.chat-channel-pane__section {
  border: 1px solid #dfe8f6;
  border-radius: 10px;
  background: #f9fbff;
  padding: 10px;
}

.chat-channel-pane__head {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 6px;
}

.chat-channel-pane__head h4 {
  margin: 0;
  color: #2f4463;
  font-size: 13px;
}

.chat-channel-pane__head small {
  color: #7b8fae;
  font-size: 11px;
}

.chat-channel-pane__catalog-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.chat-channel-pane__catalog-card--interactive {
  border: 1px solid #dce6f5;
  border-radius: 10px;
  background: #ffffff;
  padding: 8px 9px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  cursor: pointer;
  transition:
    border-color 160ms ease,
    background-color 160ms ease,
    transform 160ms ease,
    box-shadow 160ms ease;
}

.chat-channel-pane__catalog-card--interactive:hover {
  border-color: #f7b28b;
  background: #fff8f2;
  box-shadow: 0 8px 18px rgba(232, 108, 32, 0.12);
  transform: translateY(-1px);
}

.chat-channel-pane__identity {
  min-width: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

.chat-channel-pane__icon-shell {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  background: #f1f5fd;
  color: #496288;
  font-size: 12px;
  font-weight: 700;
  overflow: hidden;
}

.chat-channel-pane__icon-shell img {
  width: 18px;
  height: 18px;
  object-fit: contain;
}

.chat-channel-pane__identity strong {
  display: block;
  color: #2f3f5b;
  font-size: 13px;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-channel-pane__status-dot {
  flex-shrink: 0;
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: #b8c6db;
}

.chat-channel-pane__status-dot.is-configured {
  background: #2f9e67;
}

.chat-window {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr) auto;
  min-height: 0;
  background: #ffffff;
}

.chat-window__header {
  padding: 14px 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  border-bottom: 1px solid #eceff4;
  background: #ffffff;
  cursor: default;
}

.chat-agent-header {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}

.chat-agent-header__avatar {
  width: 42px;
  height: 42px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  font-weight: 800;
  color: #2e5ca3;
  background: linear-gradient(135deg, #d8ecff, #b5d6ff);
}

.chat-agent-header__avatar.is-group {
  color: #5a6b8a;
  background: #eaf0fb;
  box-shadow: inset 0 0 0 1px rgba(141, 165, 211, 0.34);
  overflow: hidden;
}

.chat-agent-header__avatar.is-clickable {
  cursor: pointer;
  transition: box-shadow 150ms ease, transform 150ms ease;
}

.chat-agent-header__avatar.is-clickable:hover {
  box-shadow: inset 0 0 0 1px rgba(74, 119, 196, 0.45);
  transform: translateY(-1px);
}

.chat-agent-header__avatar.is-clickable:focus-visible {
  outline: 2px solid #89b1f3;
  outline-offset: 2px;
}

.chat-agent-header__avatar-image {
  width: 100%;
  height: 100%;
  border-radius: inherit;
  object-fit: cover;
  display: block;
}

.chat-agent-header strong {
  display: block;
  font-size: 18px;
  line-height: 1.1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-agent-header p {
  margin: 3px 0 0;
  color: #8094b4;
  font-size: 12px;
}

.chat-window__header-right {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
  min-width: 0;
}

.chat-window__group-summary {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
  max-width: 180px;
  overflow: hidden;
}

.chat-window__group-summary--trigger {
  border: 0;
  background: transparent;
  padding: 4px 6px;
  margin: -4px -6px;
  border-radius: 10px;
  cursor: pointer;
  transition: background 150ms ease;
}

.chat-window__group-summary--trigger:hover,
.chat-window__group-summary--trigger.is-active {
  background: #edf4ff;
}

.chat-window__group-summary--trigger:focus-visible {
  outline: 2px solid #89b1f3;
  outline-offset: 1px;
}

.chat-window__group-summary-text {
  color: #7b8da9;
  font-size: 12px;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-window__actions {
  display: flex;
  gap: 4px;
  flex-shrink: 0;
}

.header-btn {
  width: 34px;
  height: 34px;
  border: 0;
  border-radius: 10px;
  display: grid;
  place-items: center;
  color: #7c91b0;
  background: transparent;
  cursor: pointer;
  transition: background 150ms ease, color 150ms ease, opacity 150ms ease;
}

.header-btn:hover {
  color: #2c6de0;
  background: #e9f1ff;
}

.header-btn.is-active {
  color: #2c6de0;
  background: #e9f1ff;
}

.header-btn:disabled {
  cursor: not-allowed;
  opacity: 0.45;
}

.chat-window__content {
  min-height: 0;
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  position: relative;
  background: #ffffff;
  overflow: hidden;
}

.chat-window__content--settings-open {
  grid-template-columns: minmax(0, 1fr);
}

.chat-settings-sidebar {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  width: 360px;
  max-width: min(100%, 360px);
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  border-left: 1px solid #e7edf7;
  background: linear-gradient(180deg, #fbfdff 0%, #f7fbff 100%);
  display: flex;
  flex-direction: column;
  z-index: 4;
}

.chat-settings-sidebar-slide-enter-active,
.chat-settings-sidebar-slide-leave-active {
  transition: opacity 200ms ease, transform 200ms ease;
}

.chat-settings-sidebar-slide-enter-from,
.chat-settings-sidebar-slide-leave-to {
  opacity: 0;
  transform: translateX(14px);
}

.chat-settings-sidebar__header {
  padding: 14px 14px 10px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid #eef2f8;
}

.chat-settings-sidebar__header--plain {
  padding: 10px 12px 8px;
  justify-content: flex-end;
}

.chat-settings-sidebar__close {
  width: 30px;
  height: 30px;
  border: 0;
  border-radius: 8px;
  color: #6f82a3;
  background: transparent;
  font-size: 22px;
  line-height: 1;
  display: grid;
  place-items: center;
  cursor: pointer;
}

.chat-settings-sidebar__close:hover {
  color: #2a6be0;
  background: #e9f1ff;
}

.chat-settings-sidebar__body {
  padding: 8px 12px 12px;
  flex: 1;
  min-height: 0;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.chat-settings-sidebar__body--group {
  padding-top: 10px;
}

.chat-settings-sidebar__body--logs {
  padding: 8px 12px 12px;
  gap: 8px;
  min-height: 0;
  overflow: hidden;
}

.chat-settings-sidebar__body--history {
  padding: 8px 12px 12px;
  gap: 8px;
}

.chat-settings-sidebar__body--history .utility-modal__detail {
  margin-bottom: 6px;
}

.chat-settings-history-section-title {
  margin: 2px 0 0;
  color: #4f6589;
  font-size: 12px;
  font-weight: 700;
}

.utility-history-filter {
  margin-bottom: 8px;
}

.chat-settings-logs-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.chat-settings-logs-head strong {
  color: #253450;
  font-size: 16px;
}

.chat-settings-sidebar__body--logs .utility-modal__detail {
  margin-bottom: 8px;
}

.chat-settings-sidebar__body--logs .utility-log-categories-wrap {
  flex-direction: column;
  align-items: stretch;
  gap: 8px;
}

.chat-settings-sidebar__body--logs .utility-log-categories {
  margin-bottom: 0;
}

.chat-settings-sidebar__body--logs .utility-log-filters {
  margin-left: 0;
}

.chat-settings-sidebar__body--logs .utility-log-filter {
  width: 100%;
  justify-content: space-between;
}

.chat-settings-sidebar__body--logs .utility-log-filter__select {
  min-width: 0;
  width: 100%;
}

.chat-settings-sidebar__body--logs .utility-log-layout {
  grid-template-columns: minmax(0, 1fr);
  gap: 8px;
  min-height: 0;
  flex: 1;
}

.chat-settings-sidebar__body--logs .utility-log-list,
.chat-settings-sidebar__body--logs .utility-error-list {
  max-height: none;
  height: 100%;
  flex: 1;
}

.chat-group-info-card {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.chat-group-info-card__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
}

.chat-group-info-card__header-main {
  min-width: 0;
  display: grid;
  gap: 4px;
}

.chat-group-info-card__header strong {
  font-size: 20px;
  line-height: 1.15;
  color: #243954;
  word-break: break-word;
}

.chat-group-info-card__header small {
  font-size: 12px;
  color: #7b8ea9;
  white-space: nowrap;
}

.chat-group-info-card__close {
  width: 30px;
  height: 30px;
  border: 1px solid #d3e0f4;
  border-radius: 8px;
  color: #6f82a3;
  background: #ffffff;
  font-size: 20px;
  line-height: 1;
  display: grid;
  place-items: center;
  cursor: pointer;
  flex-shrink: 0;
  transition: border-color 140ms ease, color 140ms ease, background 140ms ease;
}

.chat-group-info-card__close:hover {
  color: #2a6be0;
  border-color: #b4c8e6;
  background: #e9f1ff;
}

.chat-group-info-card__section {
  border-top: 1px solid #e7eef9;
  padding-top: 10px;
}

.chat-group-info-card__section h5 {
  margin: 0 0 8px;
  font-size: 12px;
  font-weight: 700;
  color: #7a8ca8;
}

.chat-group-info-card__section-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 8px;
}

.chat-group-info-card__section-head h5 {
  margin: 0;
}

.chat-group-info-card__edit {
  width: 28px;
  height: 28px;
  border: 1px solid #d3e0f4;
  border-radius: 8px;
  background: #ffffff;
  color: #6f84a4;
  display: inline-grid;
  place-items: center;
  cursor: pointer;
  transition: border-color 140ms ease, background 140ms ease, color 140ms ease;
}

.chat-group-info-card__edit:hover {
  border-color: #b4c8e6;
  background: #f2f7ff;
  color: #4f678c;
}

.chat-group-info-card__edit svg {
  width: 14px;
  height: 14px;
}

.chat-group-info-card__value {
  margin: 0;
  color: #2b3f5c;
  font-size: 14px;
  line-height: 1.4;
  word-break: break-word;
}

.chat-group-info-card__value--owner {
  display: inline-flex;
  align-items: center;
  gap: 7px;
}

.chat-group-info-card__owner-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #36b474;
  box-shadow: 0 0 0 3px rgba(54, 180, 116, 0.18);
}

.chat-group-info-member-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px 8px;
}

.chat-group-info-member {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  min-width: 0;
}

.chat-group-info-member__avatar {
  position: relative;
  width: 48px;
  height: 48px;
  border-radius: 14px;
  overflow: hidden;
  background: #e9f1ff;
  color: #3b5d95;
  display: grid;
  place-items: center;
  font-size: 17px;
  font-weight: 700;
}

.chat-group-info-member__owner-badge {
  position: absolute;
  right: -4px;
  top: -4px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 1px solid #ffffff;
  background: #31a56a;
  color: #f3fff9;
  display: inline-grid;
  place-items: center;
}

.chat-group-info-member__owner-badge svg {
  width: 10px;
  height: 10px;
}

.chat-group-info-member__avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.chat-group-info-member strong {
  width: 100%;
  text-align: center;
  font-size: 12px;
  line-height: 1.2;
  color: #2a3e5a;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-group-info-member small {
  font-size: 11px;
  color: #7d90ad;
  white-space: nowrap;
}

.chat-group-info-card__empty {
  margin: 0;
  border: 1px dashed #d5deec;
  border-radius: 10px;
  padding: 12px;
  color: #7d8fa8;
  font-size: 13px;
}

.chat-group-policy-grid {
  display: grid;
  gap: 10px;
}

.chat-group-policy-inline {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.chat-group-policy-field {
  display: grid;
  gap: 6px;
}

.chat-group-policy-field span {
  font-size: 12px;
  color: #7a8ca8;
}

.chat-group-policy-field input,
.chat-group-policy-field select {
  width: 100%;
  min-height: 34px;
  border: 1px solid #d5deec;
  border-radius: 10px;
  background: #ffffff;
  color: #2a3e5a;
  font-size: 12px;
  line-height: 1.35;
  padding: 7px 10px;
}

.chat-group-policy-field input:focus,
.chat-group-policy-field select:focus {
  outline: none;
  border-color: #9ab7e9;
  box-shadow: 0 0 0 2px rgba(77, 126, 203, 0.18);
}

.chat-group-policy-check {
  display: inline-flex;
  align-items: flex-start;
  gap: 8px;
  font-size: 12px;
  line-height: 1.4;
  color: #425f83;
}

.chat-group-policy-check input {
  margin-top: 2px;
}

@media (max-width: 760px) {
  .chat-group-policy-inline {
    grid-template-columns: minmax(0, 1fr);
  }
}

.conversation-group-rename-modal {
  width: min(440px, calc(100vw - 32px));
}

.conversation-group-rename-modal__form {
  display: grid;
  gap: 12px;
}

.conversation-group-rename-modal__field {
  display: grid;
  gap: 7px;
}

.conversation-group-rename-modal__field span {
  font-size: 12px;
  font-weight: 700;
  color: #6f84a4;
}

.conversation-group-rename-modal__field input {
  width: 100%;
  height: 40px;
  border: 1px solid #cad8ec;
  border-radius: 10px;
  padding: 0 12px;
  background: #ffffff;
  color: #2d4260;
  font-size: 13px;
  outline: 0;
}

.conversation-group-rename-modal__field input:focus {
  border-color: #89a9d8;
  box-shadow: 0 0 0 3px rgba(114, 150, 208, 0.2);
}

.conversation-group-rename-modal__actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

.conversation-group-rename-modal__submit {
  border-color: #2f8e69;
  background: linear-gradient(180deg, #2da977, #21855d);
  color: #ebfff6;
}

.related-resource-modal.chat-agent-delete-modal {
  width: min(360px, calc(100vw - 24px));
}

.chat-agent-delete-modal__title {
  display: flex;
  align-items: flex-start;
  gap: 10px;
}

.chat-agent-delete-modal__icon {
  width: 34px;
  height: 34px;
  border-radius: 10px;
  border: 1px solid #f2cad3;
  background: #fff3f6;
  color: #cf5573;
  font-size: 16px;
  display: inline-grid;
  place-items: center;
  flex-shrink: 0;
}

.chat-agent-delete-modal__header p {
  margin-top: 3px;
  color: #7b8eaa;
}

.chat-agent-delete-modal__body {
  display: grid;
  gap: 12px;
}

.chat-agent-delete-modal__risk {
  border: 1px solid #f2d4dc;
  border-radius: 10px;
  background: #fff8fa;
  padding: 11px 12px;
  display: grid;
  gap: 6px;
}

.chat-agent-delete-modal__risk p {
  margin: 0;
  color: #6f83a3;
  font-size: 13px;
  line-height: 1.55;
}

.chat-agent-delete-modal__risk strong {
  color: #2d4260;
}

.chat-agent-delete-modal__risk small {
  color: #8598b2;
  font-size: 12px;
  line-height: 1.45;
}

.chat-agent-delete-modal__actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

.chat-agent-delete-modal__actions .related-resource-modal__refresh {
  min-width: 92px;
}

.chat-agent-delete-modal__confirm {
  border-color: #d95e7d;
  background: #d95e7d;
  color: #ffffff;
}

.chat-agent-delete-modal__confirm:hover:not(:disabled) {
  border-color: #ca5270;
  background: #ca5270;
}

.chat-settings-agent-card {
  border: 0;
  border-radius: 0;
  background: transparent;
  padding: 4px 2px 10px;
  box-shadow: none;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.chat-settings-agent-card__head {
  display: grid;
  grid-template-columns: 54px minmax(0, 1fr) auto;
  gap: 10px;
  align-items: flex-start;
}

.chat-settings-agent-card__avatar {
  width: 54px;
  height: 54px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  font-size: 20px;
  font-weight: 800;
  color: #ffffff;
  background: linear-gradient(135deg, #7f5bff, #4e75ee);
}

.chat-settings-agent-card__identity strong {
  display: block;
  font-size: 21px;
  line-height: 1.1;
  color: #222f48;
}

.chat-settings-agent-card__identity p {
  margin: 4px 0 0;
  color: #7a8ba7;
  font-size: 12px;
}

.chat-settings-agent-card__close {
  width: 30px;
  height: 30px;
  border: 1px solid #d3e0f4;
  border-radius: 8px;
  color: #6f82a3;
  background: #ffffff;
  font-size: 20px;
  line-height: 1;
  display: grid;
  place-items: center;
  cursor: pointer;
  transition: border-color 140ms ease, color 140ms ease, background 140ms ease;
}

.chat-settings-agent-card__close:hover {
  color: #2a6be0;
  border-color: #b4c8e6;
  background: #e9f1ff;
}

.chat-settings-chip-row {
  margin-top: 8px;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.chat-settings-status-chip,
.chat-settings-soft-chip {
  padding: 2px 9px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
}

.chat-settings-status-chip {
  color: #1a8250;
  background: #dcfce8;
}

.chat-settings-status-chip[data-tone="busy"] {
  color: #956607;
  background: #fff3d2;
}

.chat-settings-status-chip[data-tone="offline"] {
  color: #576780;
  background: #e8edf4;
}

.chat-settings-soft-chip {
  color: #6c7990;
  background: #eceff5;
}

.chat-settings-list {
  margin: 0;
  border-top: 1px solid #e8eef9;
  padding-top: 2px;
}

.chat-settings-list__row {
  display: grid;
  grid-template-columns: 70px minmax(0, 1fr);
  gap: 8px;
  align-items: start;
  padding: 6px 0;
  border-top: 1px solid #e9eff9;
}

.chat-settings-list__row:first-of-type {
  border-top: 0;
}

.chat-settings-list__row dt {
  margin: 0;
  color: #8a98ae;
  font-size: 11px;
}

.chat-settings-list__row dd {
  margin: 0;
  color: #2c3a54;
  font-size: 12px;
  line-height: 1.42;
  word-break: break-word;
}

.chat-settings-list__row--model dd {
  min-width: 0;
}

.chat-settings-model-trigger {
  width: 100%;
  border: 0;
  background: transparent;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  text-align: left;
  color: inherit;
  cursor: pointer;
  font: inherit;
}

.chat-settings-model-trigger__value {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.chat-settings-model-trigger__hint {
  flex-shrink: 0;
  color: #6f86a9;
  font-size: 11px;
  font-weight: 600;
}

.chat-settings-model-trigger:hover .chat-settings-model-trigger__hint {
  color: #2f6fd6;
}

.chat-settings-copy-field {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.chat-settings-copy-field__value {
  min-width: 0;
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.chat-settings-copy-field__button {
  width: 22px;
  height: 22px;
  border: 0;
  border-radius: 7px;
  padding: 0;
  display: inline-grid;
  place-items: center;
  background: transparent;
  color: #6f86a9;
  cursor: pointer;
  flex-shrink: 0;
  transition: color 120ms ease, background-color 120ms ease;
}

.chat-settings-copy-field__button svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-settings-copy-field__button:hover {
  color: #2f6fd6;
  background: #eaf2ff;
}

.chat-settings-copy-field__button:focus-visible {
  outline: 2px solid #86b5f3;
  outline-offset: 1px;
}

.chat-settings-resource-quick {
  margin-top: 2px;
}

.chat-settings-resource-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
}

.chat-settings-resource-action {
  width: 100%;
  border: 1px solid #bfd7f8;
  border-radius: 11px;
  background: #ffffff;
  min-height: 50px;
  padding: 7px 8px;
  display: grid;
  grid-template-columns: 24px minmax(0, 1fr) 12px;
  align-items: center;
  gap: 0 7px;
  text-align: left;
  cursor: pointer;
  transition: border-color 140ms ease, background 140ms ease, transform 140ms ease, box-shadow 140ms ease;
}

.chat-settings-resource-action:hover {
  border-color: #79abea;
  background: #edf5ff;
  box-shadow: 0 2px 6px rgba(95, 131, 190, 0.14);
  transform: translateY(-1px);
}

.chat-settings-resource-action__icon {
  width: 24px;
  height: 24px;
  border-radius: 7px;
  display: grid;
  place-items: center;
  color: #2f5d97;
  background: #e9f3ff;
  font-size: 11px;
  font-weight: 700;
}

.chat-settings-resource-action__content {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.chat-settings-resource-action__main {
  color: #24497b;
  font-size: 12px;
  font-weight: 700;
  line-height: 1.22;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-settings-resource-action__sub {
  color: #6d83a5;
  font-size: 10px;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-settings-resource-action__arrow {
  color: #6489bd;
  font-size: 14px;
  font-weight: 700;
  justify-self: end;
}

.chat-settings-output {
  border-top: 1px solid #e8eef9;
  padding-top: 8px;
}

.chat-settings-output h5 {
  margin: 0 0 6px;
  color: #7184a3;
  font-size: 11px;
  font-weight: 600;
}

.chat-settings-preview {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 24px;
  align-items: start;
  gap: 8px;
}

.chat-settings-preview--boxed {
  padding: 8px 9px;
  border-radius: 10px;
  background: #edf3fc;
}

.chat-settings-preview__text {
  margin: 0;
  color: inherit;
  font-size: inherit;
  line-height: 1.45;
  white-space: pre-wrap;
  word-break: break-word;
  display: -webkit-box;
  overflow: hidden;
  max-height: calc(1.45em * 7);
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 7;
}

.chat-settings-preview__expand {
  width: 24px;
  height: 24px;
  border: 0;
  border-radius: 7px;
  padding: 0;
  display: inline-grid;
  place-items: center;
  background: transparent;
  color: #6f86a9;
  cursor: pointer;
  flex-shrink: 0;
  transition: color 120ms ease, background-color 120ms ease;
}

.chat-settings-preview__expand:hover {
  color: #2f6fd6;
  background: #eaf2ff;
}

.chat-settings-preview__expand:focus-visible {
  outline: 2px solid #86b5f3;
  outline-offset: 1px;
}

.chat-settings-preview__expand svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-settings-recent-output {
  color: #2c3a54;
  font-size: 12px;
}

.chat-settings-text-detail-modal {
  width: min(760px, calc(100vw - 32px));
}

.chat-settings-text-detail-modal__body {
  padding-top: 12px;
}

.chat-settings-text-detail-modal__content {
  margin: 0;
  color: #2c3a54;
  font-family: inherit;
  font-size: 13px;
  line-height: 1.55;
  white-space: pre-wrap;
  word-break: break-word;
}

.chat-settings-sidebar__empty {
  margin: 14px;
  border: 1px dashed #d5deec;
  border-radius: 12px;
  padding: 14px;
  color: #7d8fa8;
  font-size: 13px;
}

.message-row {
  max-width: min(76%, 640px);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.message-row--tool {
  max-width: min(88%, 700px);
  flex-direction: row;
  align-items: flex-start;
  gap: 8px;
}

.message-row--user {
  align-self: flex-end;
}

.message-row--assistant,
.message-row--system {
  align-self: flex-start;
}

.message-bubble {
  border-radius: 18px;
  padding: 12px 14px;
  font-size: 13px;
  line-height: 1.58;
  color: #1f2a44;
  background: #ffffff;
  border: 1px solid #e6edf8;
  box-shadow: 0 8px 16px rgba(61, 89, 130, 0.06);
  white-space: normal;
  word-break: break-word;
  overflow-wrap: anywhere;
  user-select: text;
  -webkit-user-select: text;
}

.message-bubble__markdown {
  color: inherit;
}

.message-bubble__markdown :deep(*) {
  margin: 0;
  max-width: 100%;
  box-sizing: border-box;
  overflow-wrap: anywhere;
}

.message-bubble__markdown :deep(p) {
  line-height: 1.62;
}

.message-bubble__markdown :deep(p + p) {
  margin-top: 8px;
}

.message-bubble__markdown :deep(ul),
.message-bubble__markdown :deep(ol) {
  margin: 8px 0 0;
  padding-left: 20px;
}

.message-bubble__markdown :deep(li + li) {
  margin-top: 4px;
}

.message-bubble__markdown :deep(h1),
.message-bubble__markdown :deep(h2),
.message-bubble__markdown :deep(h3),
.message-bubble__markdown :deep(h4),
.message-bubble__markdown :deep(h5),
.message-bubble__markdown :deep(h6) {
  margin: 0 0 8px;
  color: inherit;
  line-height: 1.35;
  font-weight: 650;
}

.message-bubble__markdown :deep(h1) {
  font-size: 1.15em;
}

.message-bubble__markdown :deep(h2) {
  font-size: 1.08em;
}

.message-bubble__markdown :deep(h3) {
  font-size: 1.03em;
}

.message-bubble__markdown :deep(h4),
.message-bubble__markdown :deep(h5),
.message-bubble__markdown :deep(h6) {
  font-size: 1em;
}

.message-bubble__markdown :deep(blockquote) {
  margin: 8px 0 0;
  padding-left: 10px;
  border-left: 3px solid rgba(118, 145, 188, 0.45);
  color: #3a5176;
}

.message-bubble__markdown :deep(.message-md-codeblock) {
  position: relative;
  margin-top: 8px;
}

.message-bubble__markdown :deep(.message-md-copy) {
  border: 1px solid #c6d3e6;
  background: rgba(255, 255, 255, 0.92);
  color: #3f5d89;
  font-size: 11px;
  font-weight: 600;
  line-height: 1;
  cursor: pointer;
  transition: border-color 120ms ease, background-color 120ms ease, color 120ms ease;
}

.message-bubble__markdown :deep(.message-md-copy:hover) {
  border-color: #8aa8d3;
  color: #1f4f93;
}

.message-bubble__markdown :deep(.message-md-copy.is-copied) {
  border-color: #67b58b;
  color: #177245;
}

.message-bubble__markdown :deep(.message-md-codeblock__copy) {
  position: absolute;
  top: 6px;
  right: 6px;
  z-index: 1;
  height: 24px;
  min-width: 44px;
  border-radius: 999px;
  padding: 0 10px;
}

.message-bubble__markdown :deep(.message-md-inline-code) {
  display: inline-grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
  gap: 4px;
  max-width: 100%;
  vertical-align: middle;
}

.message-bubble__markdown :deep(.message-md-inline-code__copy) {
  height: 18px;
  min-width: 34px;
  border-radius: 6px;
  padding: 0 6px;
  font-size: 10px;
}

.message-bubble__markdown :deep(pre) {
  margin: 0;
  max-width: 100%;
  padding: 34px 12px 10px;
  border-radius: 10px;
  border: 1px solid #d9e4f5;
  background: #f5f8ff;
  color: #2d3b55;
  font-size: 11.5px;
  line-height: 1.6;
  overflow: auto;
}

.message-bubble__markdown :deep(code) {
  border-radius: 6px;
  padding: 1px 5px;
  background: rgba(59, 96, 153, 0.12);
  font-size: 11.5px;
  word-break: break-all;
}

.message-bubble__markdown :deep(pre code) {
  padding: 0;
  background: transparent;
  word-break: normal;
}

.message-bubble__markdown :deep(a) {
  color: #2563eb;
  text-decoration: underline;
  text-underline-offset: 2px;
  word-break: break-all;
}

.message-bubble__markdown :deep(hr) {
  margin: 10px 0;
  border: 0;
  border-top: 1px dashed #c8d7ef;
}

.message-bubble__attachments {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 8px;
}

.message-bubble__attachment {
  display: inline-flex;
  align-items: center;
  max-width: 100%;
  border-radius: 999px;
  border: 1px solid #d5e3f6;
  background: #f2f7ff;
  color: #47648f;
  padding: 2px 9px;
  font-size: 11px;
  font-weight: 600;
  line-height: 1.5;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.message-row--user .message-bubble {
  color: #fff;
  border-color: transparent;
  background: linear-gradient(135deg, #5a9dff, #2f78e4);
}

.message-row--user .message-bubble__attachment {
  border-color: rgba(255, 255, 255, 0.42);
  background: rgba(255, 255, 255, 0.18);
  color: rgba(255, 255, 255, 0.95);
}

.message-row--user .message-bubble__markdown :deep(a) {
  color: #eef4ff;
}

.message-row--user .message-bubble__markdown :deep(blockquote) {
  border-left-color: rgba(255, 255, 255, 0.55);
  color: rgba(236, 244, 255, 0.94);
}

.message-row--user .message-bubble__markdown :deep(pre) {
  border-color: rgba(255, 255, 255, 0.36);
  background: rgba(5, 35, 89, 0.36);
  color: rgba(244, 248, 255, 0.97);
}

.message-row--user .message-bubble__markdown :deep(code) {
  background: rgba(255, 255, 255, 0.16);
}

.message-row--user .message-bubble__markdown :deep(.message-md-copy) {
  border-color: rgba(255, 255, 255, 0.45);
  background: rgba(255, 255, 255, 0.15);
  color: rgba(244, 249, 255, 0.96);
}

.message-row--user .message-bubble__markdown :deep(.message-md-copy:hover) {
  background: rgba(255, 255, 255, 0.25);
}

.message-row--user .message-bubble__markdown :deep(.message-md-copy.is-copied) {
  border-color: rgba(109, 219, 165, 0.75);
  color: #d8ffe9;
}

.message-file-output-list {
  margin-top: 10px;
  display: grid;
  gap: 8px;
}

.message-file-output {
  border-radius: 12px;
  border: 1px solid #d7e3f6;
  background: #f8fbff;
  padding: 8px;
}

.message-file-output__head {
  display: flex;
  align-items: center;
  gap: 8px;
}

.message-file-output__path {
  margin: 0;
  flex: 1;
  min-width: 0;
  font-size: 12px;
  line-height: 1.4;
  color: #2c4365;
  word-break: break-all;
}

.message-file-output__open-btn {
  width: 28px;
  height: 28px;
  flex-shrink: 0;
  border-radius: 8px;
  border: 1px solid #c8daef;
  background: #ffffff;
  color: #365f97;
  display: inline-grid;
  place-items: center;
  cursor: pointer;
  transition: border-color 120ms ease, background-color 120ms ease, color 120ms ease;
}

.message-file-output__open-btn:hover {
  border-color: #88afe3;
  background: #edf5ff;
  color: #1d4f93;
}

.message-file-output__open-btn svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.message-file-output__preview {
  margin-top: 8px;
  width: 100%;
  border-radius: 12px;
  display: grid;
  place-items: center;
  gap: 0;
}

.message-file-output__preview.is-standalone {
  margin-top: 0;
}

.message-file-output__preview.is-image,
.message-file-output__preview.is-video {
  padding: 0;
  border: 1px solid #d9e5f6;
  background: #0c1118;
  overflow: hidden;
}

.message-file-output__image,
.message-file-output__video {
  width: auto;
  max-width: 100%;
  height: auto;
  max-height: min(56vh, 460px);
  border-radius: 0;
  border: 0;
  background: transparent;
  display: block;
  object-fit: contain;
}

.message-file-output__audio {
  width: 100%;
}

.message-file-output__iframe {
  width: 100%;
  min-height: clamp(220px, 40vh, 420px);
  max-height: min(62vh, 620px);
  border-radius: 10px;
  border: 1px solid #d9e5f6;
  background: #ffffff;
  display: block;
}

.message-file-output__empty {
  margin: 8px 0 0;
  color: #5f7596;
  font-size: 12px;
}

.message-file-output__empty--inline {
  margin: 0;
  min-height: 40px;
  display: flex;
  align-items: center;
}

.message-row--user .message-file-output {
  border-color: rgba(255, 255, 255, 0.35);
  background: rgba(5, 35, 89, 0.24);
}

.message-row--user .message-file-output__path {
  color: rgba(241, 247, 255, 0.96);
}

.message-row--user .message-file-output__open-btn {
  border-color: rgba(255, 255, 255, 0.42);
  background: rgba(255, 255, 255, 0.12);
  color: rgba(247, 250, 255, 0.98);
}

.message-row--user .message-file-output__open-btn:hover {
  background: rgba(255, 255, 255, 0.2);
}

.message-row--user .message-file-output__image,
.message-row--user .message-file-output__video {
  background: transparent;
}

.message-row--user .message-file-output__preview.is-image,
.message-row--user .message-file-output__preview.is-video,
.message-row--user .message-file-output__iframe {
  border-color: rgba(255, 255, 255, 0.3);
  background: rgba(255, 255, 255, 0.08);
}

.message-row--user .message-file-output__empty {
  color: rgba(240, 246, 255, 0.9);
}

.message-row--pending .message-bubble {
  color: #55698a;
  border-color: #dce7f8;
  background: #eef4ff;
}

.message-bubble--typing {
  width: fit-content;
  min-width: 62px;
  padding: 10px 16px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: #9ca9be;
  border-color: #e5eaf3;
  background: #ffffff;
  box-shadow: 0 6px 14px rgba(61, 89, 130, 0.08);
}

.typing-indicator {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.typing-indicator__dot {
  width: 6px;
  height: 6px;
  border-radius: 999px;
  background: #bcc6d7;
  animation: typing-dot-pulse 1.15s ease-in-out infinite;
}

.typing-indicator__dot:nth-child(2) {
  animation-delay: 0.15s;
}

.typing-indicator__dot:nth-child(3) {
  animation-delay: 0.3s;
}

.message-row--pending .message-time {
  display: none;
}

.message-row--error .message-bubble {
  color: #b42318;
  background: #fff1f1;
  border: 1px solid #f4b4b4;
}

.message-time {
  align-self: flex-end;
  font-size: 11px;
  color: #8ea1bc;
}

.message-row--tool .message-time {
  align-self: center;
  margin-left: 2px;
}

.chat-window__messages {
  grid-column: 1;
  grid-row: 1;
  min-height: 0;
  overflow: auto;
  padding: 18px 20px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.chat-window__messages--empty {
  justify-content: center;
}

.chat-empty-state {
  margin: auto;
  width: min(560px, 100%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  text-align: center;
  color: #354965;
}

.chat-empty-state__logo {
  width: 66px;
  height: 66px;
  border-radius: 20px;
  border: 1px solid #dbe7f8;
  background: #ffffff;
  color: #2d3f58;
  display: grid;
  place-items: center;
  box-shadow: 0 10px 18px rgba(61, 89, 130, 0.08);
}

.chat-empty-state__logo svg {
  width: 38px;
  height: 38px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-empty-state__logo img {
  width: 40px;
  height: 40px;
  object-fit: contain;
  display: block;
}

.chat-empty-state h3 {
  margin: 6px 0 0;
  font-size: 40px;
  line-height: 1;
  letter-spacing: -0.03em;
  color: #202f45;
}

.chat-empty-state p {
  margin: 0;
  font-size: 13px;
  color: #7b8da9;
}

.chat-empty-state__actions {
  margin-top: 8px;
  width: 100%;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 10px;
}

@media (max-width: 760px) {
  .message-row {
    max-width: min(92%, 560px);
  }

  .message-bubble {
    padding: 10px 12px;
    font-size: 12.5px;
    line-height: 1.6;
  }

  .message-bubble__markdown :deep(pre) {
    padding: 32px 10px 9px;
    font-size: 11px;
  }

  .message-bubble__markdown :deep(.message-md-codeblock__copy) {
    top: 5px;
    right: 5px;
    min-width: 40px;
    height: 22px;
    padding: 0 8px;
  }

  .message-file-output__path {
    font-size: 11px;
  }

  .message-file-output__image,
  .message-file-output__video {
    max-height: min(42vh, 320px);
  }

  .message-file-output__iframe {
    min-height: clamp(190px, 34vh, 280px);
    max-height: min(50vh, 360px);
  }
}

@keyframes typing-dot-pulse {
  0%,
  80%,
  100% {
    transform: translateY(0);
    opacity: 0.38;
  }
  40% {
    transform: translateY(-3px);
    opacity: 1;
  }
}

.chat-empty-action {
  width: 100%;
  min-height: 84px;
  border: 1px solid #dbe7f8;
  border-radius: 14px;
  background: #ffffff;
  padding: 12px;
  display: grid;
  grid-template-columns: 38px minmax(0, 1fr);
  gap: 0 10px;
  align-items: center;
  text-align: left;
  cursor: pointer;
  transition: border-color 140ms ease, background 140ms ease, transform 140ms ease, box-shadow 140ms ease;
}

.chat-empty-action:hover {
  border-color: #8db5f3;
  background: #f5f9ff;
  box-shadow: 0 8px 16px rgba(61, 89, 130, 0.09);
  transform: translateY(-1px);
}

.chat-empty-action:disabled {
  cursor: not-allowed;
  opacity: 0.56;
}

.chat-empty-action__icon {
  width: 36px;
  height: 36px;
  border-radius: 11px;
  background: #e9f2ff;
  color: #3d6ca7;
  display: grid;
  place-items: center;
}

.chat-empty-action__icon svg {
  width: 18px;
  height: 18px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-empty-action__content {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.chat-empty-action__content strong {
  color: #253a57;
  font-size: 15px;
  line-height: 1.18;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-empty-action__content small {
  color: #7389aa;
  font-size: 11px;
  line-height: 1.3;
}

.chat-window__composer {
  padding: 12px 16px 16px;
  border-top: 1px solid #ededed;
  background: #ffffff;
}

.composer-panel {
  position: relative;
  border: 1px solid #d2d4d8;
  border-radius: 20px;
  background: linear-gradient(180deg, #f0f1f3, #eceef0);
  padding: 10px 12px 8px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  transition: border-color 140ms ease, background-color 140ms ease, box-shadow 140ms ease;
}

.composer-panel:focus-within {
  border-color: #bdc3cb;
  background: linear-gradient(180deg, #f4f5f7, #eff1f4);
  box-shadow: 0 5px 14px rgba(87, 103, 126, 0.12);
}

.composer-panel.is-drag-over {
  border-color: #8ca7d4;
  background: linear-gradient(180deg, #f3f7ff, #edf3ff);
  box-shadow: 0 0 0 1px rgba(120, 151, 206, 0.25), 0 8px 18px rgba(92, 120, 172, 0.12);
}

.composer-input-shell {
  position: relative;
  min-width: 0;
}

.chat-window__composer textarea {
  display: block;
  min-height: calc(1.55em * 3 + 2px);
  max-height: calc(1.55em * 8 + 2px);
  border: 0;
  border-radius: 10px;
  outline: 0;
  background: transparent;
  color: #2d2d2d;
  padding: 2px 0 4px;
  font-size: 14px;
  line-height: 1.55;
  width: 100%;
  resize: none;
  overflow-y: hidden;
  transition: color 120ms ease;
}

.chat-window__composer textarea:focus {
  color: #1f1f1f;
}

.chat-window__composer textarea:disabled {
  color: #9a9a9a;
}

.chat-window__composer textarea::placeholder {
  color: #9c9c9c;
}

.composer-mention-panel {
  position: absolute;
  left: 0;
  bottom: calc(100% + 8px);
  z-index: 32;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 4px;
  max-height: 180px;
  width: fit-content;
  max-width: min(100%, 320px);
  overflow-y: auto;
  border: 1px solid #d7dee9;
  border-radius: 12px;
  background: #fafcff;
  padding: 6px;
}

.composer-mention-empty {
  color: #7b8ea9;
  font-size: 12px;
  line-height: 1.4;
  padding: 4px 6px;
}

.composer-mention-item {
  border: 0;
  border-radius: 10px;
  background: transparent;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  gap: 8px;
  width: auto;
  max-width: 100%;
  text-align: left;
  padding: 7px 8px;
  cursor: pointer;
  color: #324a6a;
  transition: background-color 120ms ease, color 120ms ease;
}

.composer-mention-item:hover,
.composer-mention-item.is-active {
  background: #e9f1ff;
  color: #254267;
}

.composer-mention-item__avatar {
  width: 22px;
  height: 22px;
  border-radius: 999px;
  overflow: hidden;
  flex-shrink: 0;
  display: grid;
  place-items: center;
  background: #dfe9fb;
  color: #426a99;
  font-size: 11px;
  font-weight: 700;
}

.composer-mention-item__avatar.is-all {
  background: #dff6ea;
  color: #23724d;
}

.composer-mention-item__avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.composer-mention-item__main {
  display: flex;
  align-items: center;
  min-width: 0;
}

.composer-mention-item__main strong {
  font-size: 13px;
  line-height: 1.35;
  font-weight: 600;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 280px;
}

.composer-attachments {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.composer-attachment-chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  max-width: 100%;
  height: 24px;
  border-radius: 999px;
  border: 1px solid #c8d3e2;
  background: #f6f9ff;
  color: #4d6489;
  padding: 0 8px;
}

.composer-attachment-chip__name {
  max-width: 160px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: 11px;
  line-height: 1.4;
  font-weight: 600;
}

.composer-attachment-chip small {
  color: #6d84a7;
  font-size: 10px;
  line-height: 1.2;
}

.composer-attachment-chip button {
  width: 16px;
  height: 16px;
  border: 0;
  border-radius: 999px;
  background: transparent;
  color: #6f86a8;
  font-size: 12px;
  line-height: 1;
  cursor: pointer;
  display: grid;
  place-items: center;
  padding: 0;
}

.composer-attachment-chip button:hover {
  background: #e4edf9;
  color: #4c6385;
}

.composer-error {
  margin: 0;
  color: #c43f2f;
  font-size: 11px;
  line-height: 1.3;
}

.composer-input-action {
  position: static;
  width: 28px;
  height: 28px;
  border: 0;
  border-radius: 8px;
  background: transparent;
  color: #6f8bb4;
  display: grid;
  place-items: center;
  cursor: pointer;
  flex-shrink: 0;
  transition: background-color 140ms ease, color 140ms ease;
}

.composer-input-action:hover {
  color: #4f6f9f;
  background: #dfe6f0;
}

.composer-input-action:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.composer-send {
  width: 30px;
  height: 30px;
  border: 0;
  border-radius: 999px;
  display: grid;
  place-items: center;
  cursor: pointer;
  position: static;
  color: #fff;
  background: #8d9299;
  flex-shrink: 0;
  transition: background-color 140ms ease, opacity 140ms ease;
}

.composer-send:hover:not(:disabled) {
  background: #747b84;
}

.composer-send:disabled {
  cursor: not-allowed;
  background: #c8c8c8;
  color: #f4f4f4;
  opacity: 0.8;
}

.composer-new-chat {
  height: 28px;
  border: 1px solid #c8d4e8;
  border-radius: 8px;
  background: linear-gradient(145deg, #eef4ff, #e2ecff);
  color: #2a57bb;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 0 9px;
  font-size: 12px;
  font-weight: 700;
  line-height: 1;
  cursor: pointer;
  flex-shrink: 0;
  transition: border-color 140ms ease, background-color 140ms ease, color 140ms ease, box-shadow 140ms ease;
}

.composer-new-chat svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 2.1;
  stroke-linecap: round;
  stroke-linejoin: round;
  --control-icon-accent: #3e7dff;
}

.composer-new-chat:hover:not(:disabled) {
  border-color: #b5c8ea;
  background: linear-gradient(145deg, #e8f0ff, #dce8ff);
  color: #214ca8;
  box-shadow: 0 6px 14px rgba(83, 113, 173, 0.16);
}

.composer-new-chat:disabled {
  opacity: 0.58;
  cursor: not-allowed;
}

.composer-new-chat:focus-visible {
  outline: none;
  box-shadow: var(--cp-focus-ring);
}

.composer-voice-action {
  border: 1px solid #d4dbe7;
  border-radius: 999px;
  background: #f4f6fa;
}

.composer-voice-action.is-recording {
  border-color: #e28b9f;
  background: #ffe9ee;
  color: #c53b58;
  box-shadow: 0 0 0 3px rgba(229, 109, 139, 0.14);
  animation: composer-voice-pulse 1.2s ease-in-out infinite;
}

.composer-voice-action.is-processing {
  opacity: 0.7;
}

.composer-voice-action svg,
.composer-send svg {
  width: 14px;
  height: 14px;
}

.composer-voice-action svg {
  stroke-width: 2.1;
}

.composer-send svg {
  stroke-width: 2.2;
}

@keyframes composer-voice-pulse {
  0%,
  100% {
    box-shadow: 0 0 0 1px rgba(229, 109, 139, 0.16);
  }
  50% {
    box-shadow: 0 0 0 5px rgba(229, 109, 139, 0.08);
  }
}

.composer-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  min-height: 30px;
}

.composer-meta__left,
.composer-meta__right {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  min-width: 0;
}

.composer-meta__right {
  flex-shrink: 0;
}

.composer-model-chip {
  height: 28px;
  border-radius: 8px;
  border: 0;
  background: transparent;
  color: #656565;
  padding: 0 7px;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 14px;
  font-weight: 500;
  max-width: 220px;
  overflow: hidden;
}

.composer-model-chip__label {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.composer-model-chip--trigger {
  cursor: pointer;
  appearance: none;
  transition: background-color 140ms ease, color 140ms ease;
}

.composer-model-chip--trigger:hover:not(:disabled) {
  background: #dfe2e7;
  color: #3d3d3d;
}

.composer-model-chip--trigger:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

.composer-model-chip svg {
  width: 14px;
  height: 14px;
  flex-shrink: 0;
}

.composer-file-input {
  position: absolute;
  width: 0;
  height: 0;
  opacity: 0;
  pointer-events: none;
}

.module-board {
  grid-column: 2 / 4;
  padding: 22px;
  overflow: auto;
  background: #ffffff;
  color: #24344f;
}

.module-board--utility-logs {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  gap: 10px;
}

.module-board__header--utility-logs {
  margin-bottom: 0;
  padding-bottom: 10px;
  border-bottom: 1px solid #e8eef8;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.utility-panel-body {
  padding: 0;
  min-height: 0;
}

.module-board--dashboard {
  --dashboard-surface: #ffffff;
  --dashboard-border: #d4e1f2;
  --dashboard-text: #1f3553;
  --dashboard-muted: #617da4;
  --dashboard-shadow: 0 16px 32px rgba(47, 74, 116, 0.09);
  background:
    radial-gradient(120% 72% at 0% -10%, rgba(69, 139, 233, 0.13) 0%, rgba(69, 139, 233, 0) 62%),
    radial-gradient(90% 58% at 100% -4%, rgba(41, 182, 126, 0.15) 0%, rgba(41, 182, 126, 0) 64%),
    linear-gradient(180deg, #f7faff 0%, #edf4ff 48%, #edf3ff 100%);
  color: var(--dashboard-text);
}

.module-board__header h2 {
  margin: 0;
  font-size: 26px;
  line-height: 1;
  letter-spacing: -0.01em;
}

.module-board__header {
  cursor: default;
}

.module-board__header--dashboard {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 15px;
  padding: 18px 20px;
  border: 1px solid rgba(195, 211, 233, 0.9);
  border-radius: 18px;
  background: linear-gradient(155deg, rgba(255, 255, 255, 0.98), rgba(245, 251, 255, 0.95));
  box-shadow: var(--dashboard-shadow);
}

.module-board--dashboard .module-board__header h2 {
  font-size: 31px;
  font-weight: 800;
  line-height: 1.08;
  letter-spacing: -0.02em;
}

.module-board__header p {
  margin: 8px 0 0;
  color: #7084a4;
  font-size: 14px;
}

.module-board--dashboard .module-board__header p {
  margin-top: 10px;
  color: var(--dashboard-muted);
  font-size: 13px;
}

.module-board__metrics {
  margin-top: 16px;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 10px;
}

.module-board__metrics article {
  padding: 12px;
  border: 1px solid #d5e1f0;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.88);
}

.module-board__metrics span {
  color: #7990b0;
  font-size: 12px;
}

.module-board__metrics strong {
  display: block;
  margin-top: 6px;
  font-size: 22px;
}

.module-board__note {
  margin-top: 14px;
  color: #4b5f7f;
}

.module-board__detail {
  margin-top: 10px;
  color: #7b8faa;
  font-size: 13px;
}

.module-board--dashboard .module-board__detail {
  margin-top: 12px;
  border-radius: 12px;
  border: 1px solid rgba(194, 212, 236, 0.84);
  background: rgba(255, 255, 255, 0.82);
  color: #5f7da2;
  padding: 10px 12px;
}

.module-board__error {
  margin-top: 12px;
  color: #b54708;
  font-size: 13px;
}

.module-board--dashboard .module-board__error {
  margin-top: 12px;
  border-radius: 12px;
  border: 1px solid #f0d3a4;
  background: #fff8ec;
  color: #a6640f;
  padding: 10px 12px;
}

.dashboard-toolbar {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 12px;
  flex-wrap: wrap;
}

.dashboard-health-badge {
  height: 34px;
  border-radius: 999px;
  padding: 0 13px;
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.015em;
  border: 1px solid #d3dfef;
  color: #4e617f;
  background: #f4f8ff;
}

.dashboard-health-badge::before {
  content: "";
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: currentColor;
  box-shadow: 0 0 0 5px rgba(92, 120, 154, 0.2);
}

.dashboard-health-badge[data-tone="online"] {
  border-color: #b8e8cb;
  color: #0f6a3f;
  background: #ebfbf1;
}

.dashboard-health-badge[data-tone="online"]::before {
  box-shadow: 0 0 0 5px rgba(15, 106, 63, 0.16);
}

.dashboard-health-badge[data-tone="warn"] {
  border-color: #ffdca3;
  color: #8f5b00;
  background: #fff7e2;
}

.dashboard-health-badge[data-tone="warn"]::before {
  box-shadow: 0 0 0 5px rgba(143, 91, 0, 0.16);
}

.dashboard-health-badge[data-tone="offline"] {
  border-color: #f4c3c3;
  color: #a41f1f;
  background: #fff2f2;
}

.dashboard-health-badge[data-tone="offline"]::before {
  box-shadow: 0 0 0 5px rgba(164, 31, 31, 0.15);
}

.dashboard-toolbar__refresh {
  height: 34px;
  border: 1px solid #c4d8f1;
  border-radius: 10px;
  background: linear-gradient(180deg, #ffffff 0%, #f4f8ff 100%);
  color: #2f5f9b;
  padding: 0 14px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  transition: border-color 160ms ease, background 160ms ease, color 160ms ease, box-shadow 160ms ease;
}

.dashboard-toolbar__refresh:hover {
  border-color: #9bbce7;
  background: linear-gradient(180deg, #fefeff 0%, #eaf2ff 100%);
  color: #294f83;
  box-shadow: 0 8px 16px rgba(58, 96, 151, 0.15);
}

.dashboard-toolbar__refresh:disabled {
  cursor: default;
  opacity: 0.65;
}

.dashboard-section {
  margin-top: 14px;
  border: 1px solid var(--dashboard-border);
  border-radius: 18px;
  background: linear-gradient(160deg, rgba(255, 255, 255, 0.98), rgba(246, 251, 255, 0.95));
  box-shadow: var(--dashboard-shadow), inset 0 1px 0 rgba(255, 255, 255, 0.78);
  overflow: hidden;
}

.dashboard-section__header {
  padding: 15px 16px;
  border-bottom: 1px solid #e0ebf9;
  background: linear-gradient(180deg, rgba(242, 248, 255, 0.74), rgba(246, 251, 255, 0.42));
}

.dashboard-section__header strong {
  display: block;
  font-size: 19px;
  letter-spacing: -0.012em;
  color: #203756;
}

.dashboard-section__header p {
  margin: 5px 0 0;
  font-size: 12px;
  color: #6785ad;
  line-height: 1.45;
}

.dashboard-stats-grid,
.dashboard-status-grid {
  display: grid;
  gap: 12px;
  padding: 14px;
}

.dashboard-stats-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.dashboard-status-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.dashboard-metric-card,
.dashboard-status-card {
  border: 1px solid #d3e0f3;
  border-radius: 15px;
  background: linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
  padding: 13px 14px;
  min-height: 102px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 7px;
  transition: transform 150ms ease, box-shadow 150ms ease, border-color 150ms ease;
}

.dashboard-metric-card:hover,
.dashboard-status-card:hover {
  transform: translateY(-1px);
  border-color: #b8cfea;
  box-shadow: 0 10px 20px rgba(57, 88, 132, 0.12);
}

.dashboard-metric-card--compact {
  min-height: 84px;
}

.dashboard-metric-card__label {
  color: #6f89ad;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.01em;
}

.dashboard-metric-card strong {
  color: #1f3552;
  font-size: 20px;
  line-height: 1.1;
  margin: 0;
  font-weight: 800;
  letter-spacing: -0.01em;
  overflow-wrap: anywhere;
}

.dashboard-metric-card--compact strong {
  font-size: 21px;
}

.dashboard-metric-card[data-tone="online"],
.dashboard-status-card[data-tone="online"] {
  border-color: #bce7cd;
  background: linear-gradient(162deg, #f2fcf7, #f8fefb);
}

.dashboard-metric-card[data-tone="warn"],
.dashboard-status-card[data-tone="warn"] {
  border-color: #f2dcad;
  background: linear-gradient(162deg, #fff9ee, #fffdf6);
}

.dashboard-metric-card[data-tone="offline"],
.dashboard-status-card[data-tone="offline"] {
  border-color: #efc7c7;
  background: linear-gradient(162deg, #fff6f6, #fffafa);
}

.dashboard-status-card {
  min-height: 122px;
}

.dashboard-status-card strong {
  color: #1c3555;
  font-size: 28px;
  line-height: 1.1;
  letter-spacing: -0.018em;
  margin: 1px 0;
  overflow-wrap: anywhere;
}

.dashboard-status-card p {
  margin: 0;
  color: #5d7ca3;
  font-size: 12px;
  line-height: 1.42;
  overflow-wrap: anywhere;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 3;
  overflow: hidden;
}

.dashboard-activity-panel {
  margin-top: 15px;
  border: 1px solid var(--dashboard-border);
  border-radius: 18px;
  background: linear-gradient(165deg, rgba(255, 255, 255, 0.98), rgba(246, 251, 255, 0.95));
  box-shadow: var(--dashboard-shadow);
  overflow: hidden;
}

.dashboard-activity-panel__header {
  padding: 14px 16px 12px;
  border-bottom: 1px solid #e3ecf8;
  background: linear-gradient(180deg, rgba(241, 248, 255, 0.78), rgba(248, 252, 255, 0.5));
}

.dashboard-activity-panel__header strong {
  display: block;
  color: #203654;
  font-size: 18px;
}

.dashboard-activity-panel__header p {
  margin: 5px 0 0;
  color: #5f7ea5;
  font-size: 12px;
}

.dashboard-activity-panel__empty {
  padding: 18px 16px;
  color: #6f86a7;
  font-size: 13px;
}

.dashboard-activity-list {
  max-height: 320px;
  overflow: auto;
}

.dashboard-activity-item {
  padding: 11px 16px 10px;
  display: grid;
  grid-template-columns: 86px 58px minmax(0, 1fr);
  align-items: center;
  gap: 10px;
  border-top: 1px solid #e6eef9;
  transition: background 140ms ease;
}

.dashboard-activity-item:hover {
  background: rgba(237, 245, 255, 0.48);
}

.dashboard-activity-item:first-child {
  border-top: 0;
}

.dashboard-activity-item__time {
  color: #607da3;
  font-size: 12px;
  font-variant-numeric: tabular-nums;
}

.dashboard-activity-item__tag {
  justify-self: start;
  height: 23px;
  min-width: 49px;
  border-radius: 999px;
  padding: 0 8px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  border: 1px solid #d6dfef;
  color: #516a8e;
  background: #f2f7ff;
}

.dashboard-activity-item__tag[data-tone="online"] {
  border-color: #c2eace;
  color: #186a44;
  background: #ecfbf1;
}

.dashboard-activity-item__tag[data-tone="warn"] {
  border-color: #ffdfa6;
  color: #935f00;
  background: #fff6df;
}

.dashboard-activity-item__tag[data-tone="offline"] {
  border-color: #f4c8c8;
  color: #a22b2b;
  background: #fff2f2;
}

.dashboard-activity-item p {
  margin: 0;
  color: #2f486a;
  font-size: 12px;
  line-height: 1.5;
  overflow-wrap: anywhere;
}

.module-surface {
  margin-top: 14px;
  border: 1px solid #d5e4f7;
  border-radius: 16px;
  background: linear-gradient(165deg, rgba(252, 254, 255, 0.98), rgba(243, 249, 255, 0.95));
  box-shadow: 0 14px 30px rgba(46, 77, 125, 0.08), inset 0 1px 0 rgba(255, 255, 255, 0.72);
  padding: 14px;
}

.recruitment-surface {
  border-color: #e1e4ea;
  background:
    radial-gradient(120% 120% at 100% 0%, rgba(255, 255, 255, 0.76) 0%, rgba(255, 255, 255, 0) 58%),
    linear-gradient(180deg, #f5f6f8, #eceef3);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.86), 0 16px 30px rgba(39, 44, 56, 0.08);
}

.recruitment-surface__top {
  border: 1px solid #dde2ea;
  border-radius: 14px;
  padding: 10px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.72), rgba(247, 249, 252, 0.68));
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.88);
}

.skill-market-surface {
  background:
    radial-gradient(110% 62% at 100% 0%, rgba(43, 179, 134, 0.12) 0%, rgba(43, 179, 134, 0) 64%),
    linear-gradient(162deg, rgba(252, 254, 255, 0.98), rgba(243, 249, 255, 0.95));
}

.marketplace-surface {
  display: flex;
  flex-direction: column;
  gap: 14px;
  padding: 14px;
  border-color: #e5e6e9;
  background: #f4f4f5;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.76);
}

.marketplace-toggle {
  width: fit-content;
  margin: 0 auto;
  border-radius: 12px;
  border: 1px solid #dddddf;
  background: #ebebed;
  padding: 2px;
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.marketplace-toggle__button {
  height: 34px;
  min-width: 112px;
  border: 0;
  border-radius: 10px;
  background: transparent;
  color: #9a9ba0;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: color 160ms ease, background 160ms ease, box-shadow 160ms ease;
}

.marketplace-toggle__button.active {
  background: #ffffff;
  color: #26272b;
  box-shadow: 0 1px 2px rgba(33, 35, 40, 0.12);
}

.marketplan-grid {
  margin-top: 2px;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(232px, 1fr));
  gap: 12px;
}

.marketplan-card {
  border: 1px solid #ececee;
  border-radius: 16px;
  background: #ffffff;
  color: #1f2228;
  min-height: 280px;
  padding: 15px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  box-shadow: 0 8px 24px rgba(41, 42, 46, 0.05);
}

.marketplan-card__title {
  color: #2c2e33;
  font-size: 24px;
  font-weight: 600;
  line-height: 1.3;
}

.marketplan-card__price {
  margin: 0;
  display: flex;
  align-items: baseline;
  gap: 8px;
}

.marketplan-card__price-currency {
  color: #1f2228;
  font-size: 30px;
  line-height: 1;
  font-weight: 600;
}

.marketplan-card__price-value {
  color: #1f2228;
  font-size: 48px;
  line-height: 1;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.marketplan-card__description {
  margin: 0;
  color: #8f9094;
  font-size: 16px;
  line-height: 1.5;
  min-height: 96px;
}

.marketplan-card__points {
  margin: 0;
  color: #2f3034;
  font-size: 19px;
  font-weight: 600;
  letter-spacing: 0.01em;
}

.marketplan-card__action {
  margin-top: auto;
  width: 100%;
  height: 46px;
  border: 0;
  border-radius: 12px;
  background: linear-gradient(135deg, #2e3036, #202228);
  color: #f7f7f8;
  font-size: 18px;
  font-weight: 600;
  cursor: pointer;
  transition: filter 160ms ease, transform 160ms ease;
}

.marketplan-card__action:hover {
  filter: brightness(1.06);
  transform: translateY(-1px);
}

.module-surface__toolbar {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.module-surface__toolbar--skills-top {
  margin-top: 0;
}

.module-surface__toolbar--skills-actions {
  margin-top: 10px;
  justify-content: flex-end;
}

.module-surface__search {
  flex: 1;
  min-width: 0;
  height: 38px;
  border: 1px solid #cadcf3;
  border-radius: 11px;
  background: linear-gradient(180deg, #ffffff, #f8fbff);
  color: #273754;
  padding: 0 12px;
  font-size: 13px;
  outline: 0;
  transition: border-color 150ms ease, box-shadow 150ms ease, background 150ms ease;
}

.module-surface__search:focus {
  border-color: #8eb6f0;
  box-shadow: 0 0 0 3px rgba(76, 126, 201, 0.14);
  background: #ffffff;
}

.module-surface__meta {
  height: 34px;
  border-radius: 999px;
  border: 1px solid #d1e1f4;
  background: rgba(255, 255, 255, 0.9);
  color: #5f7fa8;
  font-size: 12px;
  display: inline-flex;
  align-items: center;
  padding: 0 11px;
  font-weight: 600;
  letter-spacing: 0.01em;
  white-space: nowrap;
}

.module-surface__select {
  height: 38px;
  border: 1px solid #cadcf3;
  border-radius: 11px;
  background:
    linear-gradient(45deg, transparent 50%, #6283ad 50%) calc(100% - 14px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(135deg, #6283ad 50%, transparent 50%) calc(100% - 9px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(180deg, #ffffff 0%, #f7fbff 100%);
  padding: 0 24px 0 11px;
  color: #2f476b;
  font-size: 12px;
  font-weight: 600;
  outline: 0;
  appearance: none;
  transition: border-color 150ms ease, box-shadow 150ms ease;
}

.module-surface__select:focus {
  border-color: #8eb6f0;
  box-shadow: 0 0 0 3px rgba(76, 126, 201, 0.14);
}

.module-surface__button {
  height: 38px;
  border: 1px solid #7fa9e7;
  border-radius: 11px;
  background: linear-gradient(135deg, #4f88de, #366ec8);
  color: #ffffff;
  padding: 0 14px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.01em;
  cursor: pointer;
  box-shadow: 0 8px 16px rgba(58, 98, 165, 0.25);
  transition: transform 150ms ease, box-shadow 150ms ease, filter 150ms ease;
}

.module-surface__button:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 12px 20px rgba(58, 98, 165, 0.28);
  filter: brightness(1.03);
}

.module-surface__button:active:not(:disabled) {
  transform: translateY(0);
}

.module-surface__button:disabled {
  cursor: not-allowed;
  opacity: 0.6;
  box-shadow: none;
}

.module-surface__hint {
  margin: 10px 0 0;
  border: 1px solid #dce8f7;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.82);
  color: #617c9f;
  font-size: 12px;
  line-height: 1.5;
  padding: 8px 10px;
}

.module-surface__hint--notice {
  border-color: #cdddf4;
  background: rgba(237, 245, 255, 0.72);
  color: #3e5f8d;
}

.module-surface__hint--error {
  border-color: #f1d1d1;
  background: #fff4f4;
  color: #a83b3b;
}

.module-empty {
  margin-top: 10px;
  border: 1px dashed #c8d9ef;
  border-radius: 12px;
  padding: 16px;
  color: #6682a7;
  font-size: 13px;
  text-align: center;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.88), rgba(245, 250, 255, 0.92));
}

.recruitment-division-filter {
