  border: 1px solid #dde2ea;
  border-radius: 14px;
  padding: 8px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.68), rgba(248, 250, 253, 0.56));
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.88);
}

.recruitment-linked-strip__header {
