  grid-template-columns: auto minmax(0, 1fr);
  align-items: center;
  gap: 8px;
  padding: 6px 8px;
  text-align: left;
  transition: border-color 150ms ease, box-shadow 150ms ease;
}

.recruitment-linked-chip__avatar {
  width: 30px;
  height: 30px;
  border-radius: 10px;
  border: 1px solid rgba(255, 255, 255, 0.8);
