  font-size: 15px;
  font-weight: 700;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex: 0 0 auto;
}

.create-employee-modal__summary-copy {
  min-width: 0;
  flex: 1 1 auto;
}

.create-employee-modal__summary-copy strong {
  display: block;
  color: #2c4263;
  font-size: 14px;
}

.create-employee-modal__summary-copy p {
  margin: 2px 0 0;
  color: #7288a8;
