  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.create-employee-modal__summary-badge {
  height: 24px;
  border: 1px solid #d2ddf0;
  border-radius: 999px;
  background: #f7fbff;
  color: #587296;
  font-size: 11px;
  font-weight: 600;
  padding: 0 10px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  white-space: nowrap;
}

.create-employee-modal__step {
  border: 1px solid #dbe5f4;
  border-radius: 14px;
  background: #ffffff;
  box-shadow: 0 8px 20px rgba(56, 87, 135, 0.08);
  padding: 14px;
  min-height: 0;
  display: grid;
  align-content: start;
  gap: 12px;
}

.create-employee-modal__step h4 {
  margin: 0;
  color: #293958;
  font-size: 18px;
}

.create-employee-modal__field {
  display: grid;
  gap: 7px;
}

.create-employee-modal__field > span {
  color: #607491;
  font-size: 12px;
  font-weight: 600;
}

.create-employee-modal__field input,
.create-employee-modal__field textarea,
.create-employee-modal__field select,
.create-employee-task-input-row input {
  width: 100%;
  border: 1px solid #cedbf0;
  border-radius: 10px;
  background: #ffffff;
  color: #304766;
  font-size: 13px;
  padding: 0 10px;
  outline: none;
}

.create-employee-modal__field input,
.create-employee-modal__field select {
  height: 36px;
}

.create-employee-modal__field textarea {
  min-height: 76px;
