  background: #fbfcff;
  padding: 10px;
  display: grid;
  gap: 8px;
}

.create-employee-rule-list label {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  align-items: start;
  gap: 8px;
}

.create-employee-rule-list input {
