  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.create-employee-modal__actions button {
  min-width: 120px;
  height: 34px;
  border: 1px solid #8cb1ea;
  border-radius: 10px;
  background: linear-gradient(135deg, #4f89de, #376fc9);
  color: #ffffff;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
}

.create-employee-modal__actions button.is-secondary {
