.skill-market-category-row {
  margin-top: 10px;
  padding: 10px;
  border: 1px solid #c8d9ef;
  border-radius: 14px;
  background: linear-gradient(180deg, #e8f0fb, #dde8f8);
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: 8px;
}

.skill-market-category-chip {
  min-height: 32px;
  padding: 6px 14px;
  border: 1px solid transparent;
  border-radius: 999px;
  background: transparent;
  color: #4c6894;
  font-size: 13px;
  font-weight: 700;
  white-space: nowrap;
  cursor: pointer;
  transition: background 150ms ease, border-color 150ms ease, color 150ms ease, box-shadow 150ms ease;
}

.skill-market-category-chip:hover {
  background: rgba(255, 255, 255, 0.62);
  color: #36537f;
}

.skill-market-category-chip.active {
  border-color: #bfd3ef;
  background: rgba(255, 255, 255, 0.98);
  color: #2f4a73;
  box-shadow: 0 6px 14px rgba(84, 118, 176, 0.2);
}

.skill-market-grid {
  margin-top: 12px;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(255px, 1fr));
  gap: 12px;
}

.skill-market-card-v2 {
  border: 1px solid #d4e3f7;
  border-radius: 14px;
  background: linear-gradient(160deg, rgba(255, 255, 255, 0.98), rgba(246, 251, 255, 0.95));
  box-shadow: 0 10px 22px rgba(52, 84, 132, 0.1);
  padding: 12px;
  display: grid;
  gap: 9px;
  position: relative;
  overflow: hidden;
  transition: transform 160ms ease, box-shadow 160ms ease, border-color 160ms ease;
}

.skill-market-card-v2:hover {
  transform: translateY(-2px);
  border-color: #bdd7ef;
  box-shadow: 0 14px 24px rgba(52, 84, 132, 0.16);
}

.skill-market-card-v2__header {
  display: grid;
  grid-template-columns: 42px minmax(0, 1fr);
  gap: 10px;
  align-items: start;
}

.skill-market-card-v2__avatar {
  width: 42px;
  height: 42px;
  border-radius: 11px;
  display: grid;
  place-items: center;
  font-size: 16px;
  font-weight: 700;
  color: #ffffff;
  background: linear-gradient(145deg, #4d87dc, #376ec6);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.32), 0 8px 16px rgba(58, 99, 164, 0.24);
}

.skill-market-card-v2__title strong {
  display: block;
  color: #243f61;
  font-size: 14px;
  line-height: 1.35;
}

.skill-market-card-v2__title p {
  margin: 4px 0 0;
  color: #5f7ca1;
  font-size: 12px;
  line-height: 1.45;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 3;
  overflow: hidden;
}

.skill-market-card-v2__meta,
.skill-market-card-v2__tags {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.skill-market-card-v2__meta span {
  border: 1px solid #d7e4f7;
  background: #f1f7ff;
  color: #4e6f98;
  font-variant-numeric: tabular-nums;
}

.skill-market-card-v2__tags span {
  border: 1px solid #d5e7dd;
  background: #eefaf3;
  color: #2f6f56;
}

.skill-market-card-v2__meta span,
.skill-market-card-v2__tags span {
  border-radius: 999px;
  padding: 2px 8px;
  font-size: 11px;
  font-weight: 600;
}

.skill-market-card-v2__tags span:last-child {
  border-color: #d8e0f2;
  background: #f6f9ff;
  color: #5c7193;
}

.skill-market-card-v2__action {
  height: 32px;
  border: 1px solid #84ace8;
  border-radius: 10px;
  background: linear-gradient(135deg, #4f88de, #376fc8);
  color: #ffffff;
  padding: 0 12px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.01em;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  box-shadow: 0 8px 14px rgba(57, 95, 157, 0.24);
  transition: transform 140ms ease, box-shadow 140ms ease, filter 140ms ease;
}

.skill-market-card-v2__action:disabled {
  cursor: not-allowed;
  opacity: 0.6;
  box-shadow: none;
}

.skill-market-card-v2__actions {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: auto;
  padding-top: 9px;
  border-top: 1px solid #e5edf8;
}

.skill-market-card-v2__action--ghost {
  border-color: #d0ddee;
  background: #ffffff;
  color: #4f668a;
  box-shadow: none;
}

.skill-market-card-v2__action:hover:not(:disabled) {
  transform: translateY(-1px);
  box-shadow: 0 10px 16px rgba(57, 95, 157, 0.28);
  filter: brightness(1.03);
}

.skill-market-card-v2__action--ghost:hover:not(:disabled) {
  box-shadow: 0 8px 14px rgba(64, 93, 136, 0.12);
}

.skill-market-card-v2__action:active:not(:disabled) {
  transform: translateY(0);
}

.skill-market-detail-backdrop {
