  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: 10px;
}

.task-project-card {
  border: 1px solid #d9e4f5;
  border-radius: 12px;
  background: #ffffff;
  padding: 11px;
  text-align: left;
