}

.task-board-topbar p {
  margin: 3px 0 0;
  color: #6d83a4;
  font-size: 12px;
}

.task-board-back {
  height: 32px;
  border: 1px solid #c9daf6;
  border-radius: 8px;
  background: #eaf3ff;
  color: #315f95;
  padding: 0 11px;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  flex-shrink: 0;
}

.task-board-creator {
  display: grid;
  grid-template-columns: minmax(200px, 1.5fr) minmax(160px, 1.5fr) minmax(120px, 1fr) auto auto;
  gap: 8px;
}

.task-board-creator__input,
.task-board-creator__select,
.task-board-creator__button {
  height: 34px;
  border-radius: 8px;
