}

.task-board-column__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.task-board-column__header strong {
  display: block;
  color: #2d3f5d;
  font-size: 14px;
}

.task-board-column__header span {
  color: #6f84a5;
  font-size: 11px;
}

.task-board-column__header em {
  font-style: normal;
  border-radius: 999px;
  border: 1px solid #cfe0f7;
  padding: 1px 8px;
  background: #edf4ff;
  color: #486894;
  font-size: 11px;
  font-weight: 700;
}

.task-board-column__empty {
  border: 1px dashed #d2ddec;
  border-radius: 10px;
  padding: 14px 10px;
  text-align: center;
  color: #7f90aa;
  font-size: 12px;
  align-self: start;
}

.task-board-column__list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  min-height: 0;
}

.task-board-card {
  border: 1px solid #d8e4f5;
  border-radius: 10px;
  background: #ffffff;
  padding: 9px;
  display: grid;
  gap: 6px;
  cursor: grab;
}

.task-board-card[data-priority="p0"] {
  border-color: #f1c9c9;
  background: #fff9f9;
}

.task-board-card[data-priority="p1"] {
  border-color: #d8e4f5;
}

.task-board-card[data-priority="p2"] {
  border-color: #dce6ef;
  background: #fafcff;
}

.task-board-card[data-status="in_progress"] {
  border-color: #bfe4cc;
  background: #f2fdf6;
}

.task-board-card[data-status="in_review"] {
  border-color: #f4deb0;
  background: #fff9ee;
}

.task-board-card[data-status="done"] {
  border-color: #cbead5;
  background: #eefbf3;
}

.task-board-card[data-status="cancelled"] {
  border-color: #e4e7ed;
  background: #f7f8fb;
}

.task-board-card__head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.task-board-card__head strong {
  color: #2f3f5b;
  font-size: 13px;
  line-height: 1.35;
}

.task-board-card__head span {
  flex-shrink: 0;
  border: 1px solid #d3dff0;
  border-radius: 999px;
  padding: 1px 7px;
  font-size: 10px;
  font-weight: 700;
  color: #60728f;
  background: #f8fbff;
}

.task-board-card p {
  margin: 0;
  color: #6f83a3;
  font-size: 12px;
  line-height: 1.4;
}

.task-board-card small {
  color: #8596b1;
  font-size: 11px;
}

.task-board-card__actions {
  display: flex;
  align-items: center;
  gap: 6px;
}

.task-board-card__actions button {
  flex: 1;
  height: 27px;
  border: 1px solid #d1ddef;
  border-radius: 7px;
  background: #f8fbff;
  color: #587297;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
}

.task-board-card__actions button:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.chat-user-group-modal {
  width: min(980px, calc(100vw - 40px));
  max-height: calc(100vh - 42px);
  border-radius: 18px;
  border: 1px solid #2e3442;
  background: #141923;
  box-shadow: 0 30px 66px rgba(5, 8, 14, 0.58);
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  overflow: hidden;
}

.chat-user-group-modal__header {
  padding: 18px 20px 14px;
  border-bottom: 1px solid #242b39;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.chat-user-group-modal__header strong {
  display: block;
  color: #f1f5ff;
  font-size: 28px;
  font-weight: 600;
  line-height: 1.2;
}

.chat-user-group-modal__header p {
  margin: 8px 0 0;
  color: #8692ab;
  font-size: 14px;
  line-height: 1.5;
}

.chat-user-group-modal__close {
  width: 32px;
  height: 32px;
  border: 1px solid #343d4f;
  border-radius: 8px;
  background: #1c2331;
  color: #95a2bb;
  font-size: 22px;
  line-height: 1;
  cursor: pointer;
  transition: border-color 140ms ease, color 140ms ease, background 140ms ease;
}

.chat-user-group-modal__close:hover {
  border-color: #46526a;
  background: #242c3c;
  color: #c1ccde;
}

.chat-user-group-modal__body {
  min-height: 0;
  padding: 14px 16px 16px;
  display: grid;
  grid-template-rows: minmax(0, 1fr) auto auto;
  gap: 12px;
}

.chat-user-group-modal__panes {
  min-height: 0;
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 12px;
}

.chat-user-group-modal__pane {
  min-height: 0;
  border: 1px solid #252d3b;
  border-radius: 14px;
  background: #181f2d;
  padding: 12px;
  display: grid;
  grid-template-rows: auto auto minmax(0, 1fr) auto;
  gap: 10px;
}

.chat-user-group-modal__search {
  display: grid;
  grid-template-columns: 18px minmax(0, 1fr);
  align-items: center;
  gap: 9px;
  height: 38px;
  border: 1px solid #343d4c;
  border-radius: 11px;
  background: #1a2231;
  padding: 0 10px;
}

.chat-user-group-modal__search svg {
  width: 15px;
  height: 15px;
  fill: none;
  stroke: #6f7d95;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chat-user-group-modal__search input {
  width: 100%;
  border: 0;
  background: transparent;
  color: #dde5f5;
  font-size: 13px;
  outline: none;
}

.chat-user-group-modal__search input::placeholder {
  color: #6f7d95;
}

.chat-user-group-modal__field span {
  color: #a6b4cc;
  font-size: 12px;
  font-weight: 700;
}

.chat-user-group-modal__field input,
.chat-user-group-modal__field select {
  width: 100%;
  height: 40px;
  border: 1px solid #353f4e;
  border-radius: 10px;
  background: #1a2231;
  color: #e5ecfb;
  font-size: 13px;
  padding: 0 12px;
  outline: 0;
}

.chat-user-group-modal__field input:focus,
.chat-user-group-modal__field select:focus {
  border-color: #4b5c79;
  box-shadow: 0 0 0 3px rgba(77, 118, 190, 0.2);
}

.chat-user-group-modal__owner-select {
  appearance: none;
  -webkit-appearance: none;
  -moz-appearance: none;
  cursor: pointer;
  padding-right: 32px;
  background:
    linear-gradient(45deg, transparent 50%, #8ba0c3 50%) calc(100% - 15px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(135deg, #8ba0c3 50%, transparent 50%) calc(100% - 10px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(180deg, #1f293a 0%, #1a2231 100%);
}

.chat-user-group-modal__owner-select:hover {
  border-color: #52637f;
}

.chat-user-group-modal__owner-select option {
  background: #1a2231;
  color: #e5ecfb;
}

.chat-user-group-modal__members-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.chat-user-group-modal__members-head > span {
  color: #9aa8c0;
  font-size: 12px;
  font-weight: 700;
}

.chat-user-group-modal__members-head > div {
  display: flex;
  align-items: center;
  gap: 6px;
}

.chat-user-group-modal__members-head button {
  height: 25px;
  border: 1px solid #354050;
  border-radius: 7px;
  background: #202939;
  color: #97a5bd;
  font-size: 11px;
  padding: 0 8px;
  cursor: pointer;
}

.chat-user-group-modal__members-empty {
  border: 1px dashed #3a4558;
  border-radius: 8px;
  background: #151d2a;
  color: #7987a0;
  font-size: 12px;
  text-align: center;
  padding: 13px 10px;
}

.chat-user-group-modal__selected-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.chat-user-group-modal__selected-head span {
  color: #9aa8c0;
  font-size: 12px;
  font-weight: 700;
}

.chat-user-group-modal__selected-list {
  min-height: 0;
  overflow: auto;
  display: grid;
  align-content: flex-start;
  gap: 8px;
}

.chat-user-group-modal__member-row {
  width: 100%;
  border: 1px solid #30394a;
  border-radius: 10px;
  background: #1a2231;
  padding: 9px;
  display: grid;
  grid-template-columns: 30px minmax(0, 1fr) 24px;
  align-items: center;
  gap: 9px;
  cursor: pointer;
  text-align: left;
  transition: border-color 140ms ease, background 140ms ease, box-shadow 140ms ease;
}

.chat-user-group-modal__member-row:hover {
  border-color: #41506a;
  background: #20293a;
}

.chat-user-group-modal__member-row.is-selected {
  border-color: #2f8e69;
  background: rgba(31, 59, 49, 0.68);
  box-shadow: inset 0 0 0 1px rgba(70, 176, 132, 0.22);
}

.chat-user-group-modal__member-avatar {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  border: 1px solid #3b4659;
  background: #233046;
  color: #d5deef;
  font-size: 12px;
  font-weight: 700;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.chat-user-group-modal__member-avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.chat-user-group-modal__member-copy {
  min-width: 0;
  display: grid;
  gap: 3px;
}

.chat-user-group-modal__member-row strong {
  display: block;
  color: #e5ecfb;
  font-size: 12px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-user-group-modal__member-row small {
  display: block;
  color: #7f8da5;
  font-size: 11px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-user-group-modal__member-action {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  border: 1px solid #3f4b61;
  color: #9aa8c2;
  font-size: 15px;
  line-height: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.chat-user-group-modal__member-row.is-selected .chat-user-group-modal__member-action {
  border-color: #2f8e69;
  background: #1b6d4e;
  color: #dcfff0;
}

.chat-user-group-modal__selected-row {
  border: 1px solid #30394a;
  border-radius: 10px;
  background: #1a2231;
  padding: 9px;
  display: grid;
  grid-template-columns: 30px minmax(0, 1fr) auto;
  align-items: center;
  gap: 9px;
}

.chat-user-group-modal__selected-actions {
  display: inline-flex;
  align-items: center;
  gap: 7px;
}

.chat-user-group-modal__selected-owner {
  border: 1px solid #3d475a;
  border-radius: 999px;
  background: #202939;
  color: #8d9ab1;
  font-size: 11px;
  line-height: 1;
  height: 23px;
  padding: 0 10px;
  cursor: pointer;
}

.chat-user-group-modal__selected-owner:hover {
  border-color: #4f5d75;
  color: #c0cade;
}

.chat-user-group-modal__selected-owner.is-active {
  border-color: #2f8e69;
  background: #1b6d4e;
  color: #dcfff0;
}

.chat-user-group-modal__selected-remove {
  width: 23px;
  height: 23px;
  border: 1px solid #3d475a;
  border-radius: 50%;
  background: #202939;
  color: #8d9ab1;
  font-size: 15px;
  line-height: 1;
  cursor: pointer;
}

.chat-user-group-modal__selected-remove:hover {
  border-color: #4f5d75;
  color: #c0cade;
}

.chat-user-group-modal__error {
  margin: 0;
  border-radius: 10px;
  border: 1px solid #6b3e4d;
  background: rgba(117, 54, 74, 0.24);
  color: #f4b7c9;
  font-size: 12px;
  padding: 9px 10px;
}

.chat-user-group-modal__actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

.chat-user-group-modal__actions button {
  min-width: 90px;
  height: 34px;
  border: 1px solid #3a4457;
  border-radius: 9px;
  background: #212a3a;
  color: #9aa7bf;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}

.chat-user-group-modal__actions button:last-child {
  border-color: #2f8e69;
  background: linear-gradient(180deg, #2da977, #21855d);
  color: #ebfff6;
}

@media (max-width: 980px) {
  .chat-user-group-modal {
    width: calc(100vw - 20px);
    max-height: calc(100vh - 20px);
  }

  .chat-user-group-modal__header {
    padding: 14px 14px 10px;
  }

  .chat-user-group-modal__header strong {
    font-size: 22px;
  }

  .chat-user-group-modal__header p {
    font-size: 12px;
  }

  .chat-user-group-modal__body {
    padding: 10px;
    grid-template-rows: minmax(0, 1fr) auto auto;
  }

  .chat-user-group-modal__panes {
    grid-template-columns: minmax(0, 1fr);
  }

  .chat-user-group-modal__pane {
    min-height: 260px;
  }

  .chat-user-group-modal__actions {
    justify-content: stretch;
  }

  .chat-user-group-modal__actions button {
    flex: 1 1 auto;
  }
}

.related-resource-modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(17, 28, 48, 0.42);
  display: grid;
  place-items: center;
  z-index: 1200;
}

.feishu-connect-modal {
  width: min(500px, calc(100vw - 32px));
  max-height: calc(100vh - 32px);
  border-radius: 16px;
  border: 1px solid #e6e9f1;
  background: #ffffff;
  box-shadow: 0 22px 52px rgba(20, 27, 42, 0.3);
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  overflow: hidden;
}

.feishu-connect-modal__header {
  padding: 20px 26px 12px;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.feishu-connect-modal__header strong {
  display: block;
  color: #1f2937;
  font-size: 21px;
  font-weight: 700;
  line-height: 1.22;
}

.feishu-connect-modal__header p {
  margin: 10px 0 0;
  color: #7b7f8a;
  font-size: 13px;
  line-height: 1.55;
}

.feishu-connect-modal__header small {
  display: block;
  margin-top: 12px;
  color: #9aa0ab;
  font-size: 12px;
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
}

.feishu-connect-modal__close {
  width: 32px;
  height: 32px;
  border: 0;
  border-radius: 8px;
  background: transparent;
  color: #3c3f46;
  font-size: 25px;
  line-height: 1;
  cursor: pointer;
}

.feishu-connect-modal__close:hover {
  background: #f4f6fa;
}

.feishu-connect-modal__body {
  min-height: 0;
  overflow: auto;
  padding: 0 26px 20px;
}

.feishu-connect-modal__notice,
.feishu-connect-modal__error {
  margin: 0 0 10px;
  border-radius: 9px;
  padding: 8px 10px;
  font-size: 12px;
}

.feishu-connect-modal__notice {
  border: 1px solid #bde0c8;
  background: #edfff2;
  color: #2d7c4d;
}

.feishu-connect-modal__error {
  border: 1px solid #f1c2c2;
  background: #fff3f3;
  color: #a83b3b;
}

.feishu-connect-modal__scan-button {
  width: 100%;
  height: 52px;
  border: 0;
  border-radius: 10px;
  background: #f85a1b;
  color: #ffffff;
  font-size: 19px;
  font-weight: 700;
  cursor: pointer;
}

.feishu-connect-modal__scan-button:hover:not(:disabled) {
  background: #ea4e12;
}

.feishu-connect-modal__scan-button:disabled {
  cursor: not-allowed;
  opacity: 0.65;
}

.feishu-connect-qr {
  margin-top: 12px;
  display: grid;
  gap: 10px;
}

.feishu-connect-qr__tip {
  border: 1px solid #e5e9f1;
  border-radius: 8px;
  background: #f2f5fa;
  color: #7f8797;
  font-size: 12px;
  line-height: 1.4;
  padding: 9px 12px;
}

.feishu-connect-qr__panel {
  border: 1px solid #dde2eb;
  border-radius: 12px;
  background: #f8f9fb;
  padding: 14px;
}

.feishu-connect-qr__head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
}

.feishu-connect-qr__head strong {
  display: block;
  color: #2b2f38;
  font-size: 17px;
}

.feishu-connect-qr__head p {
  margin: 6px 0 0;
  color: #8b92a1;
  font-size: 11px;
}

.feishu-connect-qr__head button {
  height: 30px;
  border: 1px solid #d7dbe3;
  border-radius: 8px;
  background: #f1f3f6;
  color: #747d8e;
  font-size: 12px;
  padding: 0 14px;
  cursor: pointer;
}

.feishu-connect-qr__head button:disabled {
  cursor: not-allowed;
  opacity: 0.62;
}

.feishu-connect-qr__code-shell {
  margin: 14px auto 0;
  width: 228px;
  height: 228px;
  border-radius: 14px;
  background: #ffffff;
  border: 1px solid #eceff4;
  display: grid;
  place-items: center;
  padding: 8px;
}

.feishu-connect-qr__code-shell img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  display: block;
}

.feishu-connect-qr__fallback {
  margin: 0;
  color: #8f97a6;
  font-size: 12px;
}

.feishu-connect-qr__code-label {
  margin: 10px 0 0;
  color: #7e8796;
  font-size: 12px;
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  text-align: center;
}

.feishu-connect-qr__desc {
  margin: 12px 0 0;
  color: #9aa0ad;
  font-size: 12px;
  line-height: 1.5;
}

.feishu-connect-qr__expiry {
  margin: 6px 0 0;
  color: #6f7990;
  font-size: 12px;
  text-align: center;
}

.feishu-connect-qr__expiry.is-expired {
  color: #b14444;
}

.feishu-connect-qr__help {
  margin-top: 10px;
  border: 0;
  background: transparent;
  color: #8b93a2;
  font-size: 12px;
  padding: 0;
  cursor: pointer;
  text-align: left;
}

.feishu-connect-qr__help:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.feishu-connect-manual {
  margin-top: 14px;
  border-top: 1px solid #eaedf4;
  padding-top: 12px;
}

.feishu-connect-manual__toggle {
  border: 0;
  background: transparent;
  color: #7e838d;
  font-size: 13px;
  padding: 0;
  display: inline-flex;
  align-items: center;
  gap: 5px;
  cursor: pointer;
}

.feishu-connect-manual__form {
  margin-top: 14px;
  display: grid;
  gap: 12px;
}

.feishu-connect-manual__field {
  display: grid;
  gap: 8px;
}

.feishu-connect-manual__field span {
  color: #666d7a;
  font-size: 13px;
}

.feishu-connect-manual__field input {
  width: 100%;
  height: 42px;
  border: 1px solid #d9dee7;
  border-radius: 12px;
  background: #ffffff;
  color: #2b2f38;
  padding: 0 14px;
  font-size: 13px;
  outline: 0;
}

.feishu-connect-manual__field input::placeholder {
  color: #a1a8b5;
}

.feishu-connect-manual__field input:focus {
  border-color: #f3a77d;
  box-shadow: 0 0 0 3px rgba(248, 90, 27, 0.15);
}

.feishu-connect-manual__secret-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.feishu-connect-manual__secret-row input {
  flex: 1;
  min-width: 0;
}

.feishu-connect-manual__secret-row button {
  height: 36px;
  min-width: 48px;
  border: 1px solid #d9dee7;
  border-radius: 10px;
  background: #ffffff;
  color: #8790a0;
  font-size: 12px;
  cursor: pointer;
}

.feishu-connect-manual__actions {
  display: flex;
  justify-content: flex-end;
}

.feishu-connect-manual__actions button {
  min-width: 64px;
  height: 34px;
  border: 0;
  border-radius: 8px;
  background: #f85a1b;
  color: #ffffff;
  font-size: 13px;
  font-weight: 700;
  padding: 0 16px;
  cursor: pointer;
}

.feishu-connect-manual__actions button:hover:not(:disabled) {
  background: #ea4e12;
}

.feishu-connect-manual__actions button:disabled {
  cursor: not-allowed;
  opacity: 0.62;
}

.related-resource-modal {
  width: min(900px, calc(100vw - 40px));
  max-height: calc(100vh - 56px);
  border-radius: 14px;
  border: 1px solid #dbe4f3;
  background: #ffffff;
  box-shadow: 0 18px 48px rgba(26, 44, 78, 0.26);
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
