.utility-log-category.is-active {
  border-color: #9dbdea;
  background: #eaf3ff;
  color: #345986;
}

.utility-log-layout {
  display: grid;
  grid-template-columns: 320px minmax(0, 1fr);
  gap: 10px;
  min-height: 0;
  flex: 1;
}

.utility-log-list,
.utility-error-list {
  border: 1px solid #e2eaf6;
  border-radius: 10px;
  background: #fbfdff;
  padding: 8px;
  min-height: 0;
  height: 100%;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.utility-log-item,
.utility-error-item {
  width: 100%;
  border: 1px solid #dbe6f7;
  border-radius: 9px;
  background: #ffffff;
  padding: 8px 9px;
  text-align: left;
  cursor: pointer;
  transition:
    border-color 0.18s ease,
    background-color 0.18s ease,
    box-shadow 0.18s ease;
}

.utility-log-item.is-active,
.utility-error-item.is-active {
  border-color: #93b8ed;
  background: #edf5ff;
  box-shadow: 0 6px 16px rgba(57, 88, 138, 0.12);
}

.utility-log-item:hover,
.utility-error-item:hover {
  border-color: #b8cdee;
}

.utility-log-item__head,
.utility-error-item__head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.utility-log-item__head strong,
.utility-error-item__head strong {
  color: #2f3f5b;
  font-size: 12px;
}

.utility-log-item__meta {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.utility-log-kind {
  border-radius: 999px;
  padding: 1px 7px;
  font-size: 10px;
  font-weight: 700;
  color: #315f95;
  background: #eaf3ff;
}

.utility-log-kind[data-kind="tool"] {
  color: #8a4c07;
  background: #ffeecf;
}

.utility-error-item__head span {
  color: #6f84a5;
  font-size: 11px;
  font-weight: 700;
}

.utility-log-status {
  min-width: 54px;
  text-align: center;
  border-radius: 999px;
  padding: 2px 8px;
  font-size: 11px;
  font-weight: 700;
  color: #2f5f95;
  background: #e8f2ff;
}

.utility-log-status[data-tone="warn"] {
  color: #9a6206;
  background: #fff2d5;
}

.utility-log-status[data-tone="error"] {
  color: #b42318;
  background: #fde8e8;
}

.utility-log-item p,
.utility-error-item p {
  margin: 5px 0 0;
  color: #2f3f5b;
  font-size: 12px;
  line-height: 1.35;
  word-break: break-all;
}

.utility-log-item p {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
}

.utility-log-item small,
.utility-error-item small {
  display: block;
  margin-top: 4px;
  color: #7f90aa;
  font-size: 11px;
}

.utility-log-detail {
  border: 1px solid #d9e4f6;
  border-radius: 12px;
  background: #ffffff;
  padding: 11px;
  min-height: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  gap: 10px;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.65);
}

.utility-log-detail__head {
  position: sticky;
  top: 0;
  z-index: 1;
  border: 1px solid #e2eaf7;
  border-radius: 10px;
  background: linear-gradient(180deg, #f7faff 0%, #ffffff 100%);
  padding: 10px;
}

.utility-log-detail__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.utility-log-detail__title-wrap {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.utility-log-detail__route {
  min-width: 0;
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.utility-log-detail__method {
  flex-shrink: 0;
  border-radius: 999px;
  padding: 2px 8px;
  background: #e8f2ff;
  color: #275287;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.utility-log-detail__header strong {
  color: #2f3f5b;
  font-size: 13px;
  line-height: 1.35;
  word-break: break-word;
}

.utility-log-detail__header p {
  margin: 0;
  border: 1px solid #e4ebf8;
  border-radius: 8px;
  background: #f8fbff;
  padding: 5px 8px;
  color: #657c9f;
  font-size: 11px;
  line-height: 1.35;
  word-break: break-all;
  font-family:
    ui-monospace,
    SFMono-Regular,
    Menlo,
    Monaco,
    Consolas,
    "Liberation Mono",
    "Courier New",
    monospace;
}

.utility-log-detail__meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.utility-log-detail__meta-item {
  border-radius: 999px;
  background: #edf3fc;
  color: #546d92;
  font-size: 11px;
  font-weight: 600;
  padding: 2px 8px;
}

.utility-log-detail__header-side {
  flex-shrink: 0;
  display: flex;
  align-items: flex-start;
}

.utility-log-detail__header .utility-log-status {
  min-width: 58px;
  padding: 3px 9px;
}

.utility-log-detail__stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(96px, max-content));
  gap: 7px;
  margin-top: 8px;
}

.utility-log-detail__stat {
  min-width: 0;
  border: 1px solid #dbe7f8;
  border-radius: 8px;
  background: #f7faff;
  padding: 5px 8px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.utility-log-detail__stat small {
  color: #6f84a6;
  font-size: 10px;
  font-weight: 600;
  line-height: 1.1;
}

.utility-log-detail__stat strong {
  color: #2f405d;
  font-size: 12px;
  font-weight: 700;
  line-height: 1.25;
}

.utility-log-detail-tabs {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 8px;
  border: 1px solid #e2eaf7;
  border-radius: 9px;
  background: #f7faff;
  padding: 4px;
}

.utility-log-detail-tab {
  height: 28px;
  border: 1px solid transparent;
  border-radius: 7px;
  padding: 0 11px;
  background: transparent;
  color: #6a7d9c;
  font-size: 11px;
  font-weight: 700;
  cursor: pointer;
}

.utility-log-detail-tab.is-active {
  border-color: #c6d8f2;
  background: #ffffff;
  color: #305581;
  box-shadow: 0 1px 3px rgba(84, 109, 146, 0.18);
}

.utility-log-detail__content-wrap {
  position: relative;
  margin: 0;
  border: 1px solid #dde7f7;
  border-radius: 10px;
  background: #f7faff;
  min-height: 0;
  flex: 1;
  overflow: hidden;
}

.utility-log-copy {
  position: absolute;
  top: 8px;
  right: 8px;
  width: 24px;
  height: 24px;
  border: 1px solid #d8e3f4;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.9);
  color: #5e7598;
  display: grid;
  place-items: center;
  cursor: pointer;
  z-index: 2;
}

.utility-log-copy svg {
  width: 14px;
  height: 14px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.9;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.utility-log-copy:hover {
  border-color: #b3caec;
  background: #edf5ff;
  color: #345986;
}

.utility-log-detail__content {
  margin: 0;
  border: 0;
  border-radius: 0;
  background: transparent;
  padding: 10px 38px 10px 10px;
  min-height: 0;
  height: 100%;
  overflow: auto;
  font-size: 12px;
  line-height: 1.45;
  white-space: pre-wrap;
  word-break: break-word;
  user-select: text;
  -webkit-user-select: text;
}

/* Sidebar-derived palette harmonization */
.window-shell {
  border-color: var(--cp-border-200);
  background: var(--cp-shell-bg);
}

.chat-app {
  background: var(--cp-shell-bg-soft);
}

.sidebar-icons {
  border-right-color: var(--cp-border-200);
  background: var(--cp-sidebar-bg);
}

.sidebar-brand {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.sidebar-brand__name {
  color: var(--cp-text-strong);
}

.sidebar-brand__beta {
  color: var(--cp-soft-accent-text-strong);
  border-color: var(--cp-border);
  background: var(--cp-soft-accent-bg);
}

.sidebar-top__new-chat {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text);
}

.sidebar-top__new-chat:hover:not(:disabled) {
  color: var(--cp-accent-dark);
  border-color: var(--cp-border-strong);
  box-shadow: 0 8px 16px var(--cp-shadow);
}

.sidebar-profile {
  background: var(--cp-surface-elevated);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.84);
}

.sidebar-profile__avatar {
  background: linear-gradient(135deg, var(--cp-accent), var(--cp-accent-strong));
  box-shadow: 0 4px 14px var(--cp-accent-shadow);
}

.sidebar-profile__avatar.is-group {
  background: var(--cp-hover-bg);
  box-shadow: inset 0 0 0 1px var(--cp-border);
}

.sidebar-profile__meta small {
  color: var(--cp-text-muted);
}

.sidebar-profile__meta strong {
  color: var(--cp-text-strong);
}

.nav-item {
  color: var(--cp-text-muted);
}

.nav-item__icon {
  color: var(--cp-icon);
}

.nav-item__badge {
  background: var(--cp-soft-accent-bg);
  color: var(--cp-soft-accent-text);
}

.nav-item:hover {
  color: var(--cp-text);
  background: var(--cp-hover-bg);
}

.nav-item.active {
  color: var(--cp-text-strong);
  background: var(--cp-surface-elevated);
  box-shadow:
    0 8px 18px var(--cp-shadow),
    inset 0 1px 0 rgba(255, 255, 255, 0.88);
}

.nav-item.active .nav-item__icon {
  color: #ffffff;
  background: linear-gradient(135deg, var(--cp-accent), var(--cp-accent-strong));
}

.nav-item.active .nav-item__badge {
  background: var(--cp-soft-accent-bg-strong);
  color: var(--cp-soft-accent-text-strong);
}

.chat-list {
  border-right-color: var(--cp-border-200);
  background: var(--cp-surface);
}

.chat-list__header {
  border-bottom-color: var(--cp-border-200);
  background: var(--cp-surface);
}

.search-box {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text-muted);
}

.search-box input {
  color: var(--cp-text);
}

.search-box input::placeholder {
  color: var(--cp-text-muted);
}

.search-add {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-icon);
}

.search-add:hover {
  color: var(--cp-accent-dark);
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
}

.search-create-menu__popover {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  box-shadow: 0 14px 26px var(--cp-shadow);
}

.search-create-menu__item {
  border-top-color: var(--cp-border-200);
  color: var(--cp-text);
}

.search-create-menu__item:hover {
  background: var(--cp-hover-bg);
  color: var(--cp-accent-strong);
}

.agent-pane-tabs {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
}

.agent-pane-tab {
  color: var(--cp-text-muted);
}

.agent-pane-tab.active {
  color: var(--cp-text-strong);
  background: var(--cp-surface-elevated);
  box-shadow: 0 3px 10px var(--cp-shadow);
}

.agent-context-menu {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  box-shadow: 0 14px 28px var(--cp-shadow);
}

.agent-context-menu__item {
  border-top-color: var(--cp-border-200);
  color: var(--cp-text);
}

.agent-context-menu__item:hover {
  background: var(--cp-hover-bg);
  color: var(--cp-accent-strong);
}

.agent-item:hover {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.agent-item.active {
  border-color: var(--cp-border-strong);
  background: var(--cp-active-bg);
  color: var(--cp-text-strong);
}

.agent-item--drag-over {
  border-color: var(--cp-border-strong);
  background: var(--cp-active-bg);
}

.agent-group-collapse,
.agent-group-delete,
.agent-group-add {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-icon);
}

.agent-group-collapse:hover,
.agent-group-delete:hover,
.agent-group-add:hover {
  color: var(--cp-accent-dark);
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
}

.agent-group-delete {
  color: var(--cp-text-muted);
}

.agent-group-delete:hover {
  color: #c04747;
  border-color: #e0b7b7;
  background: #fff1f1;
}

.agent-context-menu__item--danger {
  color: #c04747;
}

.agent-context-menu__item--danger:hover {
  background: #fff1f1;
  color: #b53838;
}

.agent-avatar {
  color: var(--cp-text);
  background: var(--cp-hover-bg);
}

.agent-flat-head,
.agent-flat-head small {
  color: var(--cp-text-muted);
}

.group-avatar-stack__item {
  border-color: var(--cp-surface);
  background: var(--cp-hover-bg);
  color: var(--cp-text-muted);
}

.agent-channel {
  background: var(--cp-soft-accent-bg);
  color: var(--cp-soft-accent-text);
}

.agent-item.active .agent-channel {
  background: var(--cp-active-bg-strong);
  color: var(--cp-text);
}

.agent-preview,
.agent-status,
.agent-meta,
.list-empty {
  color: var(--cp-text-muted);
}

.agent-item.active .agent-preview,
.agent-item.active .agent-status,
.agent-item.active .agent-meta {
  color: var(--cp-text);
}

.agent-unread {
  background: var(--cp-accent);
}

.agent-item.active .agent-unread {
  background: var(--cp-accent-strong);
}

.list-empty--compact {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-channel-pane__chat-item,
.chat-channel-pane__catalog-card--interactive {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-channel-pane__chat-item:hover,
.chat-channel-pane__catalog-card--interactive:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  box-shadow: 0 8px 18px var(--cp-shadow);
}

.chat-channel-pane__chat-item.is-active {
  border-color: var(--cp-accent);
  background: var(--cp-active-bg);
  box-shadow: 0 10px 22px var(--cp-shadow);
}

.chat-channel-pane__chat-item-copy strong,
.chat-channel-pane__identity strong,
.chat-channel-pane__head h4,
.chat-window__header strong,
.chat-empty-action__content strong {
  color: var(--cp-text-strong);
}

.chat-channel-pane__chat-item-copy small,
.chat-channel-pane__head small,
.chat-channel-pane__placeholder small,
.chat-empty-state p,
.chat-empty-action__content small,
.chat-agent-header p {
  color: var(--cp-text-muted);
}

.chat-channel-pane__chat-item-config {
  border-color: var(--cp-border);
  background: var(--cp-surface);
  color: var(--cp-text-muted);
}

.chat-channel-pane__chat-item-config:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.chat-channel-pane__chat-item-dot,
.chat-channel-pane__status-dot {
  background: var(--cp-border-strong);
}

.chat-channel-pane__placeholder {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
}

.chat-channel-pane__placeholder p {
  color: var(--cp-text);
}

.chat-channel-pane__section {
  border-color: var(--cp-border);
  background: var(--cp-surface);
}

.chat-channel-pane__icon-shell {
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.chat-window,
.chat-window__header,
.chat-window__content,
.chat-window__composer,
.module-board {
  background: var(--cp-surface);
}

.chat-window__header {
  border-bottom-color: var(--cp-border-200);
}

.chat-window__composer {
  border-top-color: var(--cp-border-200);
}

.chat-agent-header__avatar {
  color: var(--cp-accent-dark);
  background: linear-gradient(135deg, #e0ecff, #c5dafe);
}

.chat-agent-header__avatar.is-group {
  color: var(--cp-text-muted);
  background: var(--cp-hover-bg);
  box-shadow: inset 0 0 0 1px var(--cp-border);
}

.chat-window__group-summary-text {
  color: var(--cp-text-muted);
}

.chat-window__group-summary--trigger:hover,
.chat-window__group-summary--trigger.is-active {
  background: var(--cp-hover-bg);
}

.chat-agent-header__avatar.is-clickable:hover {
  box-shadow: inset 0 0 0 1px var(--cp-border-strong);
}

.header-btn {
  color: var(--cp-icon);
}

.header-btn:hover,
.header-btn.is-active {
  color: var(--cp-accent-dark);
  background: var(--cp-hover-bg);
}

.chat-settings-sidebar {
  border-left-color: var(--cp-border-200);
  background: linear-gradient(180deg, var(--cp-surface) 0%, var(--cp-shell-bg-soft) 100%);
}

.chat-settings-sidebar__header {
  border-bottom-color: var(--cp-border-200);
}

.chat-settings-sidebar__close {
  color: var(--cp-text-muted);
}

.chat-settings-sidebar__close:hover {
  color: var(--cp-accent-dark);
  background: var(--cp-hover-bg);
}

.chat-settings-logs-head strong {
  color: var(--cp-text-strong);
}

.chat-group-info-card__header strong {
  color: var(--cp-text-strong);
}

.chat-group-info-card__header small,
.chat-group-info-card__section h5,
.chat-group-info-member small,
.chat-group-info-card__empty {
  color: var(--cp-text-muted);
}

.chat-group-info-card__close {
  border-color: var(--cp-border);
  color: var(--cp-text-muted);
  background: var(--cp-surface-elevated);
}

.chat-group-info-card__close:hover {
  border-color: var(--cp-border-strong);
  color: var(--cp-accent-dark);
  background: var(--cp-hover-bg);
}

.chat-settings-agent-card__close {
  border-color: var(--cp-border);
  color: var(--cp-text-muted);
  background: var(--cp-surface-elevated);
}

.chat-settings-agent-card__close:hover {
  border-color: var(--cp-border-strong);
  color: var(--cp-accent-dark);
  background: var(--cp-hover-bg);
}

.chat-group-info-card__section {
  border-top-color: var(--cp-border);
}

.chat-group-info-card__value {
  color: var(--cp-text);
}

.chat-group-info-card__edit {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-icon);
}

.chat-group-info-card__edit:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.chat-group-info-card__owner-dot {
  background: var(--cp-accent);
  box-shadow: 0 0 0 3px var(--cp-active-bg);
}

.chat-group-info-member__avatar {
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.chat-group-info-member__owner-badge {
  border-color: var(--cp-surface);
  background: var(--cp-accent);
  color: #ffffff;
}

.chat-group-info-member strong {
  color: var(--cp-text);
}

.chat-group-info-card__empty {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-group-policy-field span,
.chat-group-policy-check {
  color: var(--cp-text-muted);
}

.chat-group-policy-field input,
.chat-group-policy-field select {
  border-color: var(--cp-border);
  background: var(--cp-surface);
  color: var(--cp-text);
}

.chat-group-policy-field input:focus,
.chat-group-policy-field select:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

.conversation-group-rename-modal__field span {
  color: var(--cp-text-muted);
}

.conversation-group-rename-modal__field input {
  border-color: var(--cp-border);
  background: var(--cp-surface);
  color: var(--cp-text);
}

.conversation-group-rename-modal__field input:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

.conversation-group-rename-modal__submit {
  border-color: var(--cp-accent);
  background: var(--cp-accent);
  color: #ffffff;
}

.conversation-group-rename-modal__submit:hover {
  border-color: var(--cp-accent-strong);
  background: var(--cp-accent-strong);
}

.chat-agent-delete-modal__icon {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
}

.chat-agent-delete-modal__header p {
  color: var(--cp-text-muted);
}

.chat-agent-delete-modal__risk {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-agent-delete-modal__risk p {
  color: var(--cp-text-muted);
}

.chat-agent-delete-modal__risk strong {
  color: var(--cp-text);
}

.chat-agent-delete-modal__risk small {
  color: var(--cp-text-muted);
}

.chat-action-toast {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  box-shadow: 0 10px 24px var(--cp-shadow);
  color: var(--cp-text);
}

.chat-empty-state {
  color: var(--cp-text);
}

.chat-empty-state__logo,
.chat-empty-action {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-empty-action:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  box-shadow: 0 8px 16px var(--cp-shadow);
}

.chat-empty-action__icon {
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.composer-panel {
  border-color: var(--cp-border);
  background: linear-gradient(180deg, var(--cp-panel-bg-top), var(--cp-panel-bg-bottom));
}

.composer-panel:focus-within {
  border-color: var(--cp-border-strong);
  background: linear-gradient(180deg, var(--cp-surface-elevated), var(--cp-panel-bg-top));
  box-shadow: 0 8px 16px var(--cp-shadow);
}

.composer-panel.is-drag-over {
  border-color: var(--cp-border-strong);
  background: linear-gradient(180deg, var(--cp-surface-elevated), var(--cp-hover-bg));
  box-shadow: 0 10px 20px var(--cp-shadow);
}

.chat-window__composer textarea {
  color: var(--cp-text);
}

.chat-window__composer textarea:focus {
  color: var(--cp-text-strong);
}

.chat-window__composer textarea:disabled,
.chat-window__composer textarea::placeholder {
  color: var(--cp-text-muted);
}

.composer-mention-panel {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.composer-mention-empty {
  color: var(--cp-text-muted);
}

.composer-mention-item {
  color: var(--cp-text);
}

.composer-mention-item:hover,
.composer-mention-item.is-active {
  background: var(--cp-hover-bg);
  color: var(--cp-text-strong);
}

.composer-mention-item__avatar {
  background: var(--cp-hover-bg);
  color: var(--cp-text-muted);
}

.composer-mention-item__avatar.is-all {
  background: var(--cp-soft-accent-bg);
  color: var(--cp-soft-accent-text);
}

.composer-attachment-chip {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.composer-attachment-chip small,
.composer-attachment-chip button,
.composer-input-action,
.composer-model-chip,
.composer-archive-chip {
  color: var(--cp-text-muted);
}

.composer-voice-action {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.composer-voice-action.is-recording {
  border-color: #e9a1b2;
  background: rgba(224, 82, 117, 0.16);
  color: #c74c6a;
}

.composer-attachment-chip button:hover,
.composer-input-action:hover,
.composer-model-chip--trigger:hover:not(:disabled),
.composer-archive-chip:hover:not(:disabled) {
  background: var(--cp-active-bg);
  color: var(--cp-text);
}

.composer-send {
  background: var(--cp-accent);
}

.composer-send:hover:not(:disabled) {
  background: var(--cp-accent-strong);
}

.composer-send:disabled {
  background: #c5cfdf;
  color: #eff3fa;
}

.composer-new-chat {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.composer-new-chat:hover:not(:disabled) {
  border-color: var(--cp-border-strong);
  background: var(--cp-active-bg);
}

.utility-log-filter span {
  color: var(--cp-text-muted);
}

.utility-log-filter__select {
  border-color: var(--cp-border);
  background: var(--cp-surface);
  color: var(--cp-text);
}

.utility-log-filter__select:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

.chat-user-group-modal {
  border-color: var(--cp-border);
  background: linear-gradient(180deg, var(--cp-panel-bg-top), var(--cp-panel-bg-bottom));
  box-shadow: 0 30px 66px var(--cp-shadow);
  color: var(--cp-text-strong);
}

.chat-user-group-modal__header {
  border-bottom-color: var(--cp-border);
}

.chat-user-group-modal__header strong {
  color: var(--cp-text-strong);
}

.chat-user-group-modal__header p {
  color: var(--cp-text-muted);
}

.chat-user-group-modal__close {
  border-color: var(--cp-border);
  background: var(--cp-surface);
  color: var(--cp-icon);
}

.chat-user-group-modal__close:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.chat-user-group-modal__pane {
  border-color: var(--cp-border);
  background: var(--cp-surface);
}

.chat-user-group-modal__search {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-user-group-modal__search svg {
  stroke: var(--cp-icon);
}

.chat-user-group-modal__search input {
  color: var(--cp-text);
}

.chat-user-group-modal__search input::placeholder {
  color: var(--cp-text-muted);
}

.chat-user-group-modal__field span,
.chat-user-group-modal__members-head > span,
.chat-user-group-modal__selected-head span {
  color: var(--cp-text-muted);
}

.chat-user-group-modal__field input,
.chat-user-group-modal__field select {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text);
}

.chat-user-group-modal__field input:focus,
.chat-user-group-modal__field select:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

.chat-user-group-modal__owner-select {
  border-color: var(--cp-border);
  color: var(--cp-text);
  background:
    linear-gradient(45deg, transparent 50%, var(--cp-icon) 50%) calc(100% - 15px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(135deg, var(--cp-icon) 50%, transparent 50%) calc(100% - 10px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(180deg, var(--cp-surface-elevated) 0%, var(--cp-surface) 100%);
}

.chat-user-group-modal__owner-select:hover {
  border-color: var(--cp-border-strong);
  background:
    linear-gradient(45deg, transparent 50%, var(--cp-icon) 50%) calc(100% - 15px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(135deg, var(--cp-icon) 50%, transparent 50%) calc(100% - 10px) calc(50% - 1px) / 5px 5px no-repeat,
    linear-gradient(180deg, var(--cp-hover-bg) 0%, var(--cp-surface) 100%);
}

.chat-user-group-modal__owner-select:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

.chat-user-group-modal__owner-select option {
  background: var(--cp-surface-elevated);
  color: var(--cp-text);
}

.chat-user-group-modal__members-head button {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text-muted);
}

.chat-user-group-modal__members-head button:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.chat-user-group-modal__members-empty {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text-muted);
}

.chat-user-group-modal__member-row,
.chat-user-group-modal__selected-row {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.chat-user-group-modal__member-row:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
}

.chat-user-group-modal__member-row.is-selected {
  border-color: var(--cp-accent);
  background: var(--cp-active-bg);
  box-shadow: inset 0 0 0 1px var(--cp-active-bg-strong);
}

.chat-user-group-modal__member-avatar {
  border-color: var(--cp-border);
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.chat-user-group-modal__member-row strong {
  color: var(--cp-text);
}

.chat-user-group-modal__member-row small {
  color: var(--cp-text-muted);
}

.chat-user-group-modal__member-action {
  border-color: var(--cp-border-300);
  color: var(--cp-icon);
}

.chat-user-group-modal__member-row.is-selected .chat-user-group-modal__member-action {
  border-color: var(--cp-accent);
  background: var(--cp-accent);
  color: #ffffff;
}

.chat-user-group-modal__selected-owner,
.chat-user-group-modal__selected-remove,
.chat-user-group-modal__actions button {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
  color: var(--cp-text-muted);
}

.chat-user-group-modal__selected-owner:hover,
.chat-user-group-modal__selected-remove:hover,
.chat-user-group-modal__actions button:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.chat-user-group-modal__selected-owner.is-active,
.chat-user-group-modal__actions button:last-child {
  border-color: var(--cp-accent);
  background: var(--cp-accent);
  color: #ffffff;
}

.chat-user-group-modal__actions button:last-child:hover {
  border-color: var(--cp-accent-strong);
  background: var(--cp-accent-strong);
}

.chat-user-group-modal__error {
  border-color: rgba(222, 94, 133, 0.42);
  background: rgba(222, 94, 133, 0.14);
  color: #d1497c;
}

.utility-log-detail {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.utility-log-detail__head {
  border-color: var(--cp-border);
  background: var(--cp-surface-elevated);
}

.utility-log-detail__method {
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.utility-log-detail__header p,
.utility-log-detail__meta-item,
.utility-log-detail__stat,
.utility-log-detail-tabs {
  border-color: var(--cp-border);
  background: var(--cp-surface);
}

.utility-log-detail__header strong,
.utility-log-detail__stat strong {
  color: var(--cp-text);
}

.utility-log-detail__header p,
.utility-log-detail__meta-item,
.utility-log-detail__stat small {
  color: var(--cp-text-muted);
}

.utility-log-detail__content-wrap {
  border-color: var(--cp-border);
  background: var(--cp-surface);
}

.utility-log-detail-tab {
  border-color: transparent;
  background: transparent;
  color: var(--cp-text-muted);
}

.utility-log-detail-tab.is-active {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-text);
}

.utility-log-copy {
  border-color: var(--cp-border);
  background: rgba(255, 255, 255, 0.9);
  color: var(--cp-text-muted);
}

.utility-log-copy:hover {
  border-color: var(--cp-border-strong);
  background: var(--cp-hover-bg);
  color: var(--cp-accent-dark);
}

.utility-log-status {
  color: var(--cp-accent-dark);
  background: var(--cp-hover-bg);
}

.feishu-connect-modal__scan-button,
.feishu-connect-manual__actions button,
.channel-pane-binding-form__submit {
  border-color: var(--cp-accent);
  background: var(--cp-accent);
  color: #ffffff;
}

.feishu-connect-modal__scan-button:hover:not(:disabled),
.feishu-connect-manual__actions button:hover:not(:disabled),
.channel-pane-binding-form__submit:hover:not(:disabled) {
  border-color: var(--cp-accent-strong);
  background: var(--cp-accent-strong);
}

.feishu-connect-manual__field input:focus {
  border-color: var(--cp-border-strong);
  box-shadow: var(--cp-focus-ring);
}

html[data-app-theme-resolved="dark"] .sidebar-brand {
  box-shadow: inset 0 1px 0 rgba(173, 191, 226, 0.12);
}

html[data-app-theme-resolved="dark"] .sidebar-profile {
  box-shadow: inset 0 1px 0 rgba(173, 191, 226, 0.12);
}

html[data-app-theme-resolved="dark"] .nav-item.active {
  box-shadow:
    0 8px 18px var(--cp-shadow),
    inset 0 1px 0 rgba(173, 191, 226, 0.14);
}

html[data-app-theme-resolved="dark"] .utility-log-copy {
  background: rgba(24, 31, 45, 0.9);
}

html[data-app-theme-resolved="dark"] .composer-send:disabled {
  background: rgba(92, 109, 142, 0.72);
  color: rgba(227, 236, 250, 0.68);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(blockquote) {
  border-left-color: rgba(130, 156, 197, 0.48);
  color: rgba(198, 213, 238, 0.94);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(pre) {
  border-color: rgba(109, 133, 175, 0.4);
  background: rgba(25, 35, 54, 0.88);
  color: rgba(225, 236, 255, 0.95);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(code) {
  background: rgba(116, 140, 185, 0.22);
  color: rgba(230, 239, 255, 0.98);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(.message-md-copy) {
  border-color: rgba(119, 143, 184, 0.44);
  background: rgba(27, 37, 54, 0.9);
  color: rgba(214, 228, 250, 0.96);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(.message-md-copy:hover) {
  border-color: rgba(151, 176, 220, 0.68);
  background: rgba(37, 50, 73, 0.94);
  color: rgba(237, 244, 255, 0.98);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(.message-md-copy.is-copied) {
  border-color: rgba(92, 201, 143, 0.72);
  color: rgba(201, 255, 224, 0.98);
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(a) {
  color: #9ec4ff;
}

html[data-app-theme-resolved="dark"] .message-bubble__markdown :deep(hr) {
  border-top-color: rgba(118, 143, 184, 0.4);
}

html[data-app-theme-resolved="dark"] .message-file-output {
  border-color: rgba(115, 136, 173, 0.36);
  background: rgba(30, 39, 56, 0.78);
}

html[data-app-theme-resolved="dark"] .message-file-output__path {
  color: rgba(214, 226, 246, 0.94);
}

html[data-app-theme-resolved="dark"] .message-file-output__open-btn {
  border-color: rgba(117, 141, 184, 0.42);
  background: rgba(18, 26, 40, 0.88);
  color: rgba(206, 220, 245, 0.96);
}

html[data-app-theme-resolved="dark"] .message-file-output__open-btn:hover {
  border-color: rgba(151, 175, 218, 0.62);
  background: rgba(33, 45, 67, 0.94);
  color: rgba(232, 239, 252, 0.98);
}

html[data-app-theme-resolved="dark"] .message-file-output__preview.is-image,
html[data-app-theme-resolved="dark"] .message-file-output__preview.is-video,
html[data-app-theme-resolved="dark"] .message-file-output__iframe {
  border-color: rgba(112, 136, 180, 0.38);
  background: rgba(14, 21, 34, 0.88);
}

html[data-app-theme-resolved="dark"] .message-file-output__empty {
  color: rgba(185, 201, 229, 0.9);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-window__composer textarea::placeholder {
  color: rgba(203, 188, 230, 0.72);
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-window__composer textarea {
  color: #e7dcfb;
}

html[data-app-theme-resolved="dark"][data-app-theme-preset="frosted"] .chat-window__composer textarea:focus {
  color: #f4ecff;
}

@media (max-width: 1100px) {
  .chat-app {
    grid-template-columns: 186px 280px minmax(0, 1fr);
  }

  .module-board--dashboard {
    padding: 18px;
  }

  .dashboard-stats-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .dashboard-status-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .chat-settings-sidebar {
    width: 316px;
    max-width: min(100%, 316px);
  }

  .related-memory-layout {
    grid-template-columns: 240px minmax(0, 1fr);
  }

  .proxy-config-layout {
    grid-template-columns: 230px minmax(0, 1fr);
  }

  .sidebar-settings-modal__body {
    grid-template-columns: 200px minmax(0, 1fr);
  }

  .marketplace-surface {
    padding: 12px;
    gap: 12px;
  }

  .marketplan-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .marketplan-card {
    min-height: 250px;
  }

  .marketplan-card__title {
    font-size: 21px;
  }

  .marketplan-card__price-currency {
    font-size: 26px;
  }

  .marketplan-card__price-value {
    font-size: 42px;
  }

  .marketplan-card__description {
    font-size: 14px;
    min-height: 84px;
  }

  .marketplan-card__points {
    font-size: 17px;
  }

  .marketplan-card__action {
    height: 42px;
    font-size: 16px;
  }

  .task-board-creator {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .task-board-creator__button {
    grid-column: span 2;
  }

  .task-board-columns {
    grid-template-columns: repeat(5, minmax(220px, 1fr));
  }
}

@media (max-width: 880px) {
  .chat-page {
    padding: 0;
  }

  .task-reminder-stack {
    top: 10px;
    left: 10px;
    right: 10px;
    width: auto;
  }

  .task-reminder-toast {
    width: 100%;
  }

  .window-shell {
    border-radius: 0;
    border: 0;
  }

  .chat-app {
    border: 0;
    grid-template-columns: 78px minmax(0, 1fr);
  }

  .sidebar-icons {
    padding: 8px 8px 10px;
  }

  .sidebar-top {
    gap: 8px;
    padding-bottom: 8px;
  }

  .sidebar-brand,
  .sidebar-top__new-chat {
    display: none;
  }

  .sidebar-profile {
    grid-template-columns: 1fr;
    justify-items: center;
    padding: 6px;
  }

  .sidebar-system-menu {
    gap: 6px;
  }

  .sidebar-system-menu__panel {
    padding: 6px;
  }

  .sidebar-profile--system-menu {
    grid-template-columns: 1fr;
    padding: 6px;
  }

  .sidebar-profile--system-menu .sidebar-profile__toggle {
    display: none;
  }

  .sidebar-profile__meta,
  .nav-item__label,
  .nav-item__badge {
    display: none;
  }

  .sidebar-nav {
    align-items: center;
  }

  .sidebar-quick-actions {
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 4px;
    padding: 0;
  }

  .sidebar-quick-action {
    min-height: 28px;
    padding: 0;
    justify-content: center;
    border-radius: 8px;
    gap: 0;
  }

  .sidebar-quick-action--web-bar {
    grid-column: auto;
    padding: 0;
    justify-content: center;
  }

  .sidebar-quick-action__bubble {
    width: 16px;
    height: 16px;
    border-radius: 5px;
    box-shadow:
      0 4px 8px rgba(49, 64, 94, 0.16),
      inset 0 1px 0 rgba(255, 255, 255, 0.52);
  }

  .sidebar-quick-action__label {
    display: none;
  }

  .sidebar-quick-action__bubble svg {
    width: 10px;
    height: 10px;
    stroke-width: 2;
  }

  .sidebar-theme-popover {
    left: calc(100% + 8px);
    bottom: 0;
    width: 170px;
  }

  .sidebar-profile-panel-layer {
    padding: 10px;
  }

  .sidebar-profile-panel {
    width: min(360px, calc(100vw - 18px));
    max-height: calc(100vh - 20px);
    padding: 14px 12px 16px;
    border-radius: 22px;
    gap: 10px;
  }

  .sidebar-profile-panel__avatar {
    width: 76px;
    height: 76px;
  }

  .sidebar-profile-panel__name {
    font-size: 26px;
  }

  .sidebar-profile-panel__lobster {
    min-height: 34px;
    font-size: 13px;
    padding: 3px 6px 3px 10px;
    gap: 8px;
  }

  .sidebar-profile-panel__lobster-copy {
    width: 22px;
    height: 22px;
  }

  .sidebar-profile-panel__lobster svg {
    width: 12px;
    height: 12px;
  }

  .sidebar-profile-panel__tabs {
    gap: 6px;
    padding: 5px;
  }

  .sidebar-profile-panel__tab {
    height: 34px;
    border-radius: 10px;
    font-size: 11px;
  }

  .sidebar-profile-panel__avatar-row {
    gap: 6px;
    padding: 8px;
  }

  .sidebar-theme-switcher {
    padding: 6px;
    gap: 6px;
  }

  .sidebar-theme-switcher__mode,
  .sidebar-theme-switcher__preset {
    height: 24px;
    font-size: 10px;
    letter-spacing: 0;
    padding: 0 2px;
  }

  .nav-item {
    width: 42px;
    min-height: 42px;
    grid-template-columns: 1fr;
    justify-items: center;
    padding: 0;
